  { id:"mm3-dread-protector",name:"Dread Protector",source:"mm3",level:3,role:"Soldier",xp:150,size:"Medium",origin:"Natural",type:"Animate",keywords:["undead"],hp:47,ac:19,fort:16,ref:13,will:14,initiative:3,perception:1,speed:"5",senses:["Low-light vision"],powers:[{name:"Shield of Undeath",action:"Aura",description:"Aura 1 While the dread protector's master is within the protector's aura, the master takes half damage from melee and ranged attacks"},{name:"Eyes",action:"Trait",description:"of Undeath The dread protector's master can see or hear anything the protector can see or hear"},{name:"The",action:"Trait",description:"master can also speak through the protector"},{name:"Greataxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d12 + 4 damage, and the target is marked until the end of the protector's next turn."},{name:"Protector's Call",action:"Move",keywords:["teleportation"],description:"Effect: The protector teleports its speed to a square adjacent to its master."}],alignment:"Unaligned",languages:["understands Common Equipment : greataxe","scale armor . Monster Manual 3","page(s) 74."] },
  { id:"mm3-jackalwere-bravo",name:"Jackalwere Bravo",source:"mm3",level:3,role:"Brute",xp:150,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["shapechanger"],hp:56,ac:15,fort:16,ref:15,will:14,initiative:3,perception:1,speed:"6",powers:[{name:"Bravo's Fury",action:"Trait",description:"The bravo's attacks deal 1d6 extra damage against dazed, helpless, or prone creatures"},{name:"Bite",action:"Standard",description:"Requirement: The bravo must be in jackal form. Attack: Melee 1 (one creature); +8 vs. AC Hit: 2d6 + 2 damage, and the target falls prone."},{name:"Falchion",action:"Standard",keywords:["weapon"],description:"Requirement: The bravo must be in human form. Attack: Melee 1 (one creature); +8 vs. AC Hit: 4d4 + 4 damage. If the bravo scores a critical hit, this attack instead deals 2d4 + 20 damage."},{name:"Howling Frenzy",action:"Standard",recharge:"Recharge when first bloodied",description:"Effect: The bravo uses bite twice. If both attacks hit the same target, the target is dazed until the end of the bravo's next turn."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: The bravo alters its physical form to appear as a Medium jackal or a human until it uses change shape again or until it drops to 0 hit points. The creature retains its statistics in its new form. Its clothing, armor, and other possessions do not change. To assume a specific individual's form, the bravo must have seen that individual. Other creatures can make a DC 26 Insight check to discern that either form is a disguise. Skills Athletics +9, Bluff +8, Stealth +8"}],alignment:"Unaligned",languages:["Common Equipment : falchion . Monster Manual 3","page(s) 120."] },
  { id:"mm3-jackalwere-harrier",name:"Jackalwere Harrier",source:"mm3",level:3,role:"Soldier",roleModifier:"Minion",xp:38,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["shapechanger"],hp:1,ac:19,fort:16,ref:17,will:14,initiative:5,perception:1,speed:"6",powers:[{name:"Combat Advantage Whenever",action:"Trait",description:"the harrier hits a creature granting combat advantage to it, that creature falls prone"},{name:"Bite",action:"Standard",description:"Requirement: The harrier must be in jackal form. Attack: Melee 1 (one creature); +8 vs. AC Hit: 5 damage."},{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Requirement: The harrier must be in human form. Attack: Melee 1 (one creature); +8 vs. AC Hit: 3 damage, and the target grants combat advantage to the next attack made against it before the start of the harrier's next turn."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: The harrier alters its physical form to appear as a Medium jackal or a human until it uses change shape again or until it drops to 0 hit points. The creature retains its statistics in its new form. Its clothing, armor, and other possessions do not change. To assume a specific individual's form, the harrier must have seen that individual. Other creatures can make a DC 26 Insight check to discern that either form is a disguise. Skills Athletics +9, Stealth +8"}],alignment:"Unaligned",languages:["Common Equipment : dagger . Monster Manual 3","page(s) 121."] },
  { id:"mm3-shadow-stalker",name:"Shadow Stalker",source:"mm3",level:3,role:"Lurker",xp:150,size:"Medium",origin:"Shadow",type:"Humanoid",hp:25,ac:15,fort:14,ref:16,will:14,initiative:9,perception:3,speed:"8",senses:["Darkvision"],resist:["insubstantial"],vulnerable:["5 radiant"],powers:[{name:"Born",action:"Trait",description:"of Shadows The stalker can make a Stealth check to become hidden when it has concealment instead of needing total concealment"},{name:"Shadowy Touch",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 1 (one creature); +6 vs. Reflex Hit: 1d8 + 6 necrotic damage."},{name:"Shadow Stalk",action:"Standard",keywords:["necrotic"],recharge:"Recharge when the stalker uses shadow step",description:"Attack: Melee 1 (one creature); +8 vs. Reflex Hit: 1d6 + 8 necrotic damage, and the stalker shifts into the target's space and melds with its shadow (save ends). While the stalker is melded with the target's shadow, it moves when the target moves without provoking opportunity attacks, and it gains a +4 bonus to all defenses and a +5 bonus to attack rolls against the target. When the target saves, the stalker shifts to a square adjacent to the target."},{name:"Shadow Step",action:"Triggered",keywords:["teleportation"],description:"Trigger: A living creature within 5 squares of the stalker drops to 0 hit points or fewer. Effect (Free Action): The stalker teleports to a square adjacent to the triggering creature and gains a +2 bonus to attack rolls until the end of its next turn. Skills Stealth +10"}],alignment:"Evil",languages:["Common Monster Manual 3","page(s) 172","Dungeon Magazine 192","Dungeon Magazine 193."] },
  { id:"mm3-skulk-mesmerist",name:"Skulk Mesmerist",source:"mm3",level:3,role:"Controller",xp:150,size:"Medium",origin:"Natural",type:"Humanoid",hp:45,ac:16,fort:14,ref:15,will:16,initiative:4,perception:3,speed:"6",senses:["Low-light vision"],powers:[{name:"Stealthy Step",action:"Trait",description:"The mesmerist does not take a penalty to Stealth checks for moving more than 2 squares or for running"},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d6 + 6 damage."},{name:"Luring Charm",action:"Standard",keywords:["charm","implement"],description:"Attack: Ranged 5 (one creature); +6 vs. Will Hit: The mesmerist slides the target 4 squares, and the target is dazed until the end of the mesmerist's next turn."},{name:"Mesmerize",action:"Standard",keywords:["charm","implement","psychic"],recharge:"Recharge 4-6",description:"Attack: Ranged 5 (one creature); +6 vs. Will Hit: 2d6 + 6 psychic damage, and the target cannot see enemies other than the mesmerist (save ends)."},{name:"Deceptive Veil",action:"Minor",keywords:["illusion"],description:"Effect: The mesmerist can disguise itself to appear as any Medium or Small humanoid. A creature that succeeds on a DC 26 Insight check can see through the illusion. Skills Arcana +7, Bluff +10, Stealth +9"}],alignment:"Unaligned",languages:["Common Equipment : short sword","wand implement . Monster Manual 3","page(s) 176."] },
  { id:"mm3-skulk-murderer",name:"Skulk Murderer",source:"mm3",level:3,role:"Lurker",xp:150,size:"Medium",origin:"Natural",type:"Humanoid",hp:37,ac:17,fort:14,ref:16,will:15,initiative:8,perception:3,speed:"6",senses:["Low-light vision"],powers:[{name:"Peerless Camouflage",action:"Trait",description:"The murderer can make a Stealth check to become hidden when it has cover or concealment instead of needing superior cover or total concealment"},{name:"The",action:"Trait",description:"murderer remains hidden after moving if it has cover or concealment after it ends the move"},{name:"Stealthy Step",action:"Trait",description:"The murderer does not take a penalty to Stealth checks for moving more than 2 squares or for running"},{name:"Unseen Strike",action:"Trait",description:"The murderer deals 5 extra damage to any target that couldn't see it at the start of the skulk's turn"},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d6 + 6 damage."},{name:"Shuriken Volley",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Effect: The murderer makes the following attack three times. Attack: Ranged 6/12 (one creature); +8 vs. AC Hit: 1d4 + 2 damage, and the target is immobilized (save ends). Skills Bluff +6, Stealth +14, Streetwise +6, Thievery +9"}],alignment:"Unaligned",languages:["Common Equipment : leather armor","short sword","shuriken x3. Monster Manual 3","page(s) 177."] },
  { id:"mm3-yeti-hunter",name:"Yeti Hunter",source:"mm3",level:3,role:"Soldier",xp:150,size:"Medium",origin:"Natural",type:"Beast",hp:49,ac:19,fort:17,ref:15,will:13,initiative:6,perception:8,speed:"6 (ice walk)",senses:["Low-light vision"],resist:["5 cold"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 1d6 + 2 damage."},{name:"Twin Claw Grab",action:"Standard",description:"Effect: The hunter uses claw twice. If both attacks hit the same target, the hunter grabs the target."},{name:"Howl of Challenge",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 5 (one creature); +8 vs. Fortitude Hit: 1d6 + 2 psychic damage, and the target is marked until the end of the hunter's next turn."},{name:"Call for Blood",action:"Standard",keywords:["psychic"],recharge:"Recharge when first bloodied",description:"Attack: Close burst 3 (enemies in the burst); +6 vs. Will Hit: 2d6 + 2 psychic damage, and the target is marked (save ends)."},{name:"Fearsome Howl",action:"Standard",keywords:["fear","thunder"],recharge:"Encounter",description:"Attack: Close blast 4 (enemies in the blast); +6 vs. Will Hit: 1d6 + 3 thunder damage, and the hunter pushes the target 3 squares. Skills Intimidate +7"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 210."] },
  { id:"mm3-cave-fisher-line-spiker",name:"Cave Fisher Line Spiker",source:"mm3",level:4,role:"Artillery",roleModifier:"Minion",xp:44,size:"Medium",origin:"Natural",type:"Beast",hp:1,ac:16,fort:14,ref:16,will:15,initiative:5,perception:9,speed:"6, climb 5 (spider climb)",senses:["Darkvision"],powers:[{name:"Pincers",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 4 damage."},{name:"Slowing Spike",action:"Standard",description:"Attack: Ranged 10 (one creature); +7 vs. Reflex Hit: 4 damage, and the target is slowed until the end of the spiker's next turn."},{name:"Toppling Spike",action:"Standard",recharge:"Encounter",description:"Attack: Ranged 10 (one creature); +7 vs. Reflex Hit: 6 damage, and the target falls prone."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 29."] },
  { id:"mm3-craud-crusher",name:"Craud Crusher",source:"mm3",level:4,role:"Brute",xp:175,size:"Medium",origin:"Natural",type:"Beast",keywords:["aquatic"],hp:70,ac:16,fort:17,ref:16,will:15,initiative:5,perception:4,speed:"5, swim 6",senses:["Darkvision"],powers:[{name:"Aquatic",action:"Trait",description:"The crusher can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Red Tide Whenever",action:"Trait",description:"the crusher reduces a target to 0 hit points or fewer, the crusher gains a +5 bonus to its next damage roll before the end of the encounter"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d12 + 2 damage, and the crusher grabs the target. The crusher can grab only one creature at a time. Sustain Minor: The crusher sustains the grab, and the grabbed creature takes 1d6 + 3 damage."},{name:"Hammerclaw",action:"Standard",recharge:"Encounter",description:"Attack: Melee 2 (one creature); +7 vs. Reflex Hit: 2d12 + 10 damage, and the crusher pushes the target 1 square and knocks it prone."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 37."] },
  { id:"mm3-earthquake-dragon-wyrmling",name:"Earthquake Dragon Wyrmling",source:"mm3",level:4,role:"Soldier",xp:175,size:"Medium",origin:"Elemental",type:"Magical beast",keywords:["dragon","earth"],hp:58,ac:20,fort:17,ref:17,will:15,initiative:7,perception:4,speed:"6 (earth walk), burrow 2, fly 2 (clumsy)",senses:["Darkvision"],powers:[{name:"Quaking Earth",action:"Aura",description:"Aura 1 When any enemy within the aura makes an attack that does not include the dragon as a target, that enemy falls prone and takes 5 damage."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d8 + 4 damage."},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d6 + 2 damage."},{name:"Wyrmling Fury",action:"Standard",description:"Requirement: The dragon must be bloodied. Effect: The wyrmling uses bite and claw."},{name:"Sudden Quake",action:"Triggered",description:"Trigger: The dragon is pulled, pushed, slid, or knocked prone. Effect (Free Action): Each enemy in the dragon's aura falls prone."}],alignment:"Unaligned",languages:["Draconic","Primordial Monster Manual 3","page(s) 69."] },
  { id:"mm3-ghoul-flesh-seeker",name:"Ghoul Flesh Seeker",source:"mm3",level:4,role:"Lurker",xp:175,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:45,ac:18,fort:14,ref:16,will:15,initiative:10,perception:9,speed:"8",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],vulnerable:["5 radiant"],powers:[{name:"Shadow Skulk",action:"Trait",description:"The ghoul flesh seeker can make a Stealth check to become hidden when it has cover or concealment instead of needing superior cover or total concealment"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d6 + 4 damage, and the target is immobilized (save ends)."},{name:"Prepare for Sacrifice",action:"Standard",description:"Attack: Melee 1 (one creature the flesh seeker was hidden from at the start of the flesh seeker's turn); +9 vs. AC Hit: 2d6 + 4 damage, and the flesh seeker knocks the target prone and grabs it. The target takes a -2 penalty to attempts to escape the grab and cannot stand up until the grab ends."},{name:"Render unto Orcus",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one prone creature grabbed by the flesh seeker); +9 vs. AC Hit: 2d8 + 9 damage. Skills Acrobatics +11, Stealth +11"}],alignment:"Unaligned",languages:["Common Equipment : dagger . Monster Manual 3","page(s) 94","Dungeon Magazine 218."] },
  { id:"mm3-great-ape",name:"Great Ape",source:"mm3",level:4,role:"Skirmisher",xp:175,size:"Medium",origin:"Natural",type:"Beast",hp:55,ac:18,fort:18,ref:16,will:16,initiative:6,perception:4,speed:"7, climb 6",senses:["Low-light vision"],powers:[{name:"Swift Climber",action:"Trait",description:"The ape does not provoke opportunity attacks by climbing"},{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 2d6+5 damage."},{name:"On the Run",action:"Standard",description:"Effect: The ape shifts or climbs half its speed and uses slam at any point during the move."},{name:"Felling Blow",action:"Standard",recharge:"Recharge 5-6",description:"Effect: The ape uses slam twice against the same target. If both attacks hit, the target falls prone. Skills Athletics +11"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 10","Dungeon Magazine 192."] },
  { id:"mm3-hex-knight",name:"Hex Knight",source:"mm3",level:4,role:"Soldier",xp:175,size:"Small",origin:"Natural",type:"Humanoid",hp:54,ac:20,fort:15,ref:16,will:15,initiative:7,perception:3,speed:"6",senses:["Darkvision"],powers:[{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Effect: The hex knight makes the following attack twice. Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d6 + 4 damage, and the target is slowed until the end of the hex knight's next turn."},{name:"Hand Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10/20 (one creature); +9 vs. AC Hit: 1d6 + 4 damage."},{name:"Vicious Flurry",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one or two creatures); +9 vs. AC Hit: 1d6 + 4 damage, and the target is slowed and takes ongoing 5 damage (save ends both)."},{name:"Dark Step",action:"Move",description:"Effect: The hex knight moves 4 squares, gains a +4 bonus to AC against opportunity attacks provoked by this movement, and gains combat advantage against each creature that it ends its move adjacent to until the end of the hex knight's next turn."},{name:"Shadow Hex",action:"Minor",description:"Effect: One creature within 3 squares of the hex knight is marked until the end of the encounter or until the hex knight uses shadow hex again. While the creature is marked by the hex knight, whenever it makes an attack that does not include the hex knight as a target, it grants combat advantage until the end of its next turn."}],alignment:"Unaligned",languages:["Common Equipment : crossbow bolt x10","hand crossbow","hide armor","short sword x2. Monster Manual 3","page(s) 38","Dungeon Magazine 192."] },
  { id:"mm3-jackalwere-deceiver",name:"Jackalwere Deceiver",source:"mm3",level:4,role:"Controller",xp:175,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["shapechanger"],hp:54,ac:18,fort:15,ref:16,will:16,initiative:5,perception:3,speed:"6",powers:[{name:"Bite",action:"Standard",description:"Requirement: The deceiver must be in jackal form. Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d6 + 4 damage, and the target falls prone."},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Requirement: The deceiver must be in human form. Attack: Melee 1 (one creature); +9 vs. AC Hit: 2d6 + 5 damage."},{name:"Vicious Howl",action:"Standard",keywords:["thunder"],description:"Requirement: The deceiver must be in jackal form. Attack: Close blast 3 (enemies in the blast); +7 vs. Fortitude Hit: 1d6 + 3 thunder damage, and the target falls prone."},{name:"Gaze of Sleep",action:"Standard",keywords:["sleep"],recharge:"Recharge 4-6",description:"Attack: Ranged 5 (one creature); +7 vs. Will Hit: The target falls unconscious (save ends). Whenever the target takes damage, it can make a saving throw against the effect."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: The deceiver alters its physical form to appear as a Medium jackal or a human until it uses change shape again or until it drops to 0 hit points. The creature retains its statistics in its new form. Its clothing, armor, and other possessions do not change. To assume a specific individual's form, the deceiver must have seen that individual. Other creatures can make a DC 26 Insight check to discern that either form is a disguise. Skills Bluff +10, Diplomacy +10, Insight +8, Streetwise +10"}],alignment:"Unaligned",languages:["Common Equipment : short sword . Monster Manual 3","page(s) 121","Halls of Undermountain","page(s) 96."] },
  { id:"mm3-rot-grub-swarm",name:"Rot Grub Swarm",source:"mm3",level:4,role:"Brute",xp:175,size:"Medium",origin:"Natural",type:"Beast",keywords:["swarm"],hp:63,ac:15,fort:15,ref:14,will:15,initiative:3,perception:2,speed:"5",senses:["Darkvision"],resist:["half damage from melee and ranged attacks"],vulnerable:["10 against close and area attacks"],powers:[{name:"Swarm Attack",action:"Aura",description:"Aura 1 Any enemy that starts its turn within the aura takes 5 damage plus 2 extra damage for each additional rot grub swarm adjacent to the enemy"},{name:"Swarm",action:"Trait",description:"The swarm can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"The",action:"Trait",description:"swarm cannot be pulled, pushed, or slid by melee or ranged attacks"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for at least one of the creatures it comprises"},{name:"Clumsy Attacker",action:"Trait",description:"The rot grub swarm cannot make basic attacks"},{name:"Infesting Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: The target takes ongoing 5 damage (save ends). First Failed Saving Throw: The target takes ongoing 10 damage (save ends). Second Failed Saving Throw: The target takes ongoing 15 damage (save ends)."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 166","Dungeon Magazine 183","Dungeon Magazine 188","The Book of Vile Darkness","page(s) 2-39","Halls of Undermountain","page(s) 96","Dungeon Magazine 211."] },
  { id:"mm3-spiderling",name:"Spiderling",source:"mm3",level:4,role:"Skirmisher",roleModifier:"Minion",xp:44,size:"Small",origin:"Natural",type:"Beast",keywords:["spider"],hp:1,ac:18,fort:14,ref:16,will:15,initiative:6,perception:3,speed:"6, climb 6 (spider climb)",senses:["Tremorsense 5"],vulnerable:["5 poison until the end of the spiderling's next turn. If the target already has vulnerability to poison damage, increase the vulnerability by","2. Skills Acrobatics +9"],powers:[{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 2 poison damage, and the target gains vulnerable 5 poison until the end of the spiderling's next turn. If the target already has vulnerability to poison damage, increase the vulnerability by 2. Skills Acrobatics +9"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 182","Dungeon Magazine 180","Dungeon Magazine 183","Dungeon Magazine 193."] },
  { id:"mm3-wilden-ancient",name:"Wilden Ancient",source:"mm3",level:4,role:"Artillery",xp:0,size:"Medium",origin:"Fey",type:"Humanoid",hp:45,ac:16,fort:13,ref:12,will:15,initiative:2,perception:11,speed:"6",senses:["Low-light vision"],powers:[{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d8 damage, and one ally adjacent to the target can make a melee basic attack against the target as a free action with a +4 bonus to the attack roll."},{name:"Spectral Vine",action:"Standard",keywords:["implement"],description:"Attack: Ranged 20 (one creature); +9 vs. Reflex Hit: 1d8 + 7 damage, and the ancient pulls the target 2 squares."},{name:"Rumbling Earth",action:"Standard",keywords:["implement"],recharge:"Recharge 4-6",description:"Attack: Area burst 1 within 10 (creatures in the burst); +9 vs. Will Hit: 1d6 + 4 damage, and the target is immobilized (save ends)."},{name:"Lightning Storm",action:"Standard",keywords:["lightning","implement"],recharge:"Encounter",description:"Attack: Area burst 1 within 20 (enemies in the burst); +9 vs. Fortitude Hit: 3d6 + 4 lightning damage. Miss: Half damage."},{name:"Wisdom of the Ancient",action:"Minor",description:"1/round Effect: One ally within 5 squares of the ancient gains a +2 power bonus to attack rolls until the end of the ally's next turn."},{name:"Voyage of the Ancients",action:"Triggered",keywords:["teleportation"],recharge:"Encounter",description:"Trigger: The ancient hits an enemy with a close or an area attack. Effect (Free Action): The ancient teleports 3 squares. One enemy of the ancient's choice that was hit by the attack grants combat advantage until the end of the ancient's next turn. Skills Arcana +9, History +9, Nature +11"}],alignment:"Unaligned",languages:["Common","Elven Equipment : hide armor","spear","totem . Monster Manual 3","page(s) 207."] },
  { id:"mm3-yeti-howler",name:"Yeti Howler",source:"mm3",level:4,role:"Controller",xp:175,size:"Medium",origin:"Natural",type:"Beast",hp:58,ac:18,fort:16,ref:15,will:16,initiative:5,perception:11,speed:"6 (ice walk)",senses:["Low-light vision"],resist:["5 cold"],powers:[{name:"Chilling Wail",action:"Aura",description:"Aura 3 Any enemy that ends its turn within the aura takes 5 psychic damage and takes a -2 penalty to defenses until the end of its next turn."},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d6 + 5 damage."},{name:"Hurl Boulder",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Area burst 1 within 5 (creatures in the burst); +9 vs. AC Hit: 1d10 + 3 damage."},{name:"Fearsome Howl",action:"Standard",keywords:["fear","thunder"],recharge:"Encounter",description:"Attack: Close blast 4 (enemies in the blast); +7 vs. Will Hit: 1d8 + 4 thunder damage, and the yeti pushes the target 3 squares."},{name:"Piercing Shriek",action:"Standard",keywords:["thunder"],recharge:"Encounter",description:"Attack: Close burst 3 (enemies in the burst); +7 vs. Will Hit: 1d10 + 5 damage, and if the target ends its next turn within 5 squares of the yeti, it takes 5 thunder damage. Skills Intimidate +9"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 211."] },
  { id:"mm3-chitine-grunt",name:"Chitine Grunt",source:"mm3",level:5,role:"Brute",roleModifier:"Minion",xp:50,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["spider"],hp:1,ac:17,fort:17,ref:17,will:16,initiative:4,perception:3,speed:"6, climb 6 (spider climb)",senses:["Darkvision"],powers:[{name:"Daggers",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one or two creatures); +10 vs. AC Hit: 6 damage."},{name:"Flying Daggers",action:"Standard",description:"Attack: Ranged 5/10 (one creature); +10 vs. AC Hit: 8 damage."},{name:"Web Line",action:"Move",recharge:"Encounter",description:"Requirement: The grunt must be climbing. Effect: The grunt flies up to 5 squares."},{name:"Dying Shriek",action:"Triggered",recharge:"Encounter",description:"Trigger: The grunt drops to 0 hit points. Effect (Immediate Interrupt): Each enemy adjacent to the grunt takes a -2 penalty to all defenses until the end of the enemy's next turn."}],alignment:"Chaotic Evil",languages:["Common","Elven Equipment : dagger x4. Monster Manual 3","page(s) 31","Dungeon Magazine 209."] },
  { id:"mm3-chitine-scout",name:"Chitine Scout",source:"mm3",level:5,role:"Artillery",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["spider"],hp:48,ac:17,fort:17,ref:17,will:16,initiative:6,perception:3,speed:"6, climb 6 (spider climb)",senses:["Darkvision"],powers:[{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d4 + 3 damage."},{name:"Hand Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10/20 (one creature); +12 vs. AC Hit: 1d6 + 4 damage."},{name:"Furious Volley",action:"Standard",keywords:["weapon"],description:"Effect: The scout uses dagger twice or hand crossbow twice."},{name:"Poisoned Bolt",action:"Standard",keywords:["poison","weapon"],recharge:"Encounter",description:"Attack: Ranged 10/20 (one creature); +10 vs. Fortitude Hit: 1d6 + 4 damage, and ongoing 10 poison damage (save ends)."},{name:"Web Line",action:"Move",recharge:"Encounter",description:"Requirement: The scout must be climbing. Effect: The scout flies 5 squares. Skills Acrobatics +11"}],alignment:"Unaligned",languages:["Common","Elven Equipment : crossbow bolt x40","dagger x2","hand crossbow x2. Monster Manual 3","page(s) 32","Dungeon Magazine 209."] },
  { id:"mm3-chitine-warrior",name:"Chitine Warrior",source:"mm3",level:5,role:"Brute",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["spider"],hp:72,ac:17,fort:17,ref:18,will:16,initiative:5,perception:3,speed:"6, climb 6 (spider climb)",senses:["Darkvision"],powers:[{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 3d4 + 5 damage."},{name:"Flying Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 5/10 (one creature); +10 vs. AC Hit: 3d4 + 5 damage."},{name:"Four Blade Strike",action:"Standard",keywords:["weapon"],description:"Effect: The warrior makes the following attack four times. Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d4 + 3 damage."},{name:"Web Line",action:"Move",recharge:"Encounter",description:"Requirement: The warrior must be climbing. Effect: The warrior flies up to 5 squares. Skills Acrobatics +10"}],alignment:"Chaotic Evil",languages:["Common","Elven Equipment : dagger x8. Monster Manual 3","page(s) 31","Dungeon Magazine 209."] },
  { id:"mm3-craud-king",name:"Craud King",source:"mm3",level:5,role:"Soldier",xp:0,size:"Medium",origin:"Natural",type:"Beast",keywords:["aquatic"],hp:67,ac:21,fort:16,ref:15,will:17,initiative:7,perception:4,speed:"5, swim 6",senses:["Darkvision"],powers:[{name:"Blood in the Water",action:"Aura",description:"Aura 3 Allies within the aura gain a +2 bonus to attack rolls against bloodied creatures"},{name:"Aquatic",action:"Trait",description:"The king can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d6 + 6 damage, and the king slides the target 1 square to another square adjacent to the king."},{name:"Claw Flurry",action:"Standard",recharge:"Recharge 4-6",description:"Effect: The king uses claw against two different creatures. If the king slides a target with this attack, one ally adjacent to the target after the slide can make a melee basic attack against the target as a free action."},{name:"Angler's Lure",action:"Minor",keywords:["charm"],description:"1/round Attack: Close burst 5 (one creature in the burst); +10 vs. Will Hit: The king pulls the target 3 squares, and the target is marked until the end of the king's next turn."},{name:"For the King",action:"Triggered",recharge:"Encounter",description:"Trigger: The king is first bloodied. Effect (No Action): Each ally within 5 squares of the king shifts 4 squares as a free action and must end the shift closer to the king than it was when it began the shift. It then can make a melee basic attack as a free action."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 37."] },
  { id:"mm3-dread-marauder",name:"Dread Marauder",source:"mm3",level:5,role:"Skirmisher",xp:200,size:"Medium",origin:"Natural",type:"Animate",keywords:["undead"],hp:63,ac:19,fort:17,ref:17,will:16,initiative:7,perception:9,speed:"6",senses:["Low-light vision"],powers:[{name:"Combat Advantage",action:"Trait",description:"The dread marauder deals 1d6 extra damage against any creature granting combat advantage to it. In the Master's Defense The dread marauder has combat advantage against each target adjacent to its master"},{name:"Eyes",action:"Trait",description:"of Undeath The dread marauder's master can see or hear anything the marauder can see or hear"},{name:"The",action:"Trait",description:"master can also speak through the marauder"},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d6 + 6 damage."},{name:"Longbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20/40 (one creature); +10 vs. AC Hit: 1d10 + 4 damage."},{name:"Skirmish Strike",action:"Standard",description:"Effect: The marauder shifts 3 squares and uses short sword or longbow."}],alignment:"Unaligned",languages:["understands Common Equipment : arrow x20","leather armor","longbow","short sword . Monster Manual 3","page(s) 74","Dungeon Magazine 207."] },
  { id:"mm3-fire-lord-cultist",name:"Fire Lord Cultist",source:"mm3",level:5,role:"Brute",roleModifier:"Minion",xp:50,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:16,fort:17,ref:16,will:15,initiative:3,perception:1,speed:"6",powers:[{name:"Club",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 6 damage, or 10 while the cultist is adjacent to any ally."},{name:"Ignite",action:"Standard",keywords:["fire"],recharge:"Encounter",description:"Attack: Melee 1 (one creature); +8 vs. Reflex Hit: Ongoing 5 fire damage (save ends)."}],alignment:"Unaligned",languages:["Common Equipment : club . Monster Manual 3","page(s) 114."] },
  { id:"mm3-gnoll-skulker",name:"Gnoll Skulker",source:"mm3",level:5,role:"Lurker",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:51,ac:19,fort:17,ref:19,will:15,initiative:10,perception:4,speed:"7",senses:["Low-light vision"],powers:[{name:"Peerless Camouflage",action:"Trait",description:"The skulker can make a Stealth check to become hidden when it has cover or concealment instead of needing superior cover or total concealment"},{name:"If",action:"Trait",description:"the skulker is hidden from one or more creatures and moves to a square that does not provide it any cover or any concealment, it remains hidden from those creatures until the start of its next turn"},{name:"Something",action:"Trait",description:"to Prove The skulker deals 5 extra damage on ranged and melee attacks against a target that has none of the skulker's allies adjacent to it"},{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d4 + 8 damage."},{name:"Shortbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 15/30 (one creature); +10 vs. AC Hit: 2d8 + 4 damage."},{name:"Hit and Run",action:"Triggered",description:"Requirement: The skulker must be hidden. Trigger: The skulker hits with shortbow. Effect (Free Action): The skulker shifts 2 squares. Skills Stealth +11"}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : arrow x20","dagger","shortbow . Monster Manual 3","page(s) 104."] },
  { id:"mm3-gremlin-deceiver",name:"Gremlin Deceiver",source:"mm3",level:5,role:"Controller",xp:200,size:"Small",origin:"Fey",type:"Humanoid",hp:63,ac:19,fort:16,ref:18,will:17,initiative:4,perception:10,speed:"6",senses:["Low-light vision"],powers:[{name:"Sabotaging Presence",action:"Aura",description:"Aura 5 Enemies within the aura take a -5 penalty to skill checks."},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 2d6 + 6 damage."},{name:"Befuddling Burst",action:"Standard",keywords:["charm","psychic"],recharge:"Recharge 3-6",description:"Attack: Area burst 2 within 10 (enemies in the burst); +8 vs. Will Hit: 1d8 + 5 psychic damage, and the target cannot shift or stand up (save ends). Miss: The target cannot shift or stand up until the end of its next turn."},{name:"Slip Up",action:"Minor",description:"1/round Attack: Ranged 5 (one creature); +8 vs. Will Hit: The target falls prone."},{name:"Gremlin Tactics",action:"Triggered",description:"Trigger: An enemy adjacent to the deceiver misses it with a melee attack. Effect (Immediate Reaction): The deceiver swaps positions with the triggering enemy. Skills Bluff +8, Stealth +9, Thievery +9"}],alignment:"Unaligned",languages:["Common","Elven","Goblin Monster Manual 3","page(s) 106","Dungeon Magazine 185."] },
  { id:"mm3-shadow-bolter",name:"Shadow Bolter",source:"mm3",level:5,role:"Artillery",xp:200,size:"Small",origin:"Natural",type:"Humanoid",hp:50,ac:17,fort:16,ref:17,will:16,initiative:6,perception:9,speed:"6",senses:["Darkvision"],powers:[{name:"Combat Advantage",action:"Trait",keywords:["necrotic"],description:"Whenever the shadow bolter hits a creature granting combat advantage to it, the bolter deals 5 extra necrotic damage, and each of that creature's adjacent allies takes 5 necrotic damage"},{name:"Deadly Precision",action:"Trait",description:"The shadow bolter's ranged attacks have combat advantage against any enemy that the bolter's allies are flanking"},{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d4 + 5 damage."},{name:"Black Bolt",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 15/30 (one creature); +10 vs. Fortitude Hit: 1d8 + 5 damage, and the target takes 5 damage each time it provokes an opportunity attack (save ends)."},{name:"Dark Step",action:"Move",description:"Effect: The bolter moves 4 squares, gains a +4 bonus to AC against opportunity attacks provoked by this movement, and gains combat advantage against each creature that it ends its move adjacent to until the end of the bolter's next turn."}],alignment:"Unaligned",languages:["Common Equipment : silk rope (50 ft.)","grappling hook","crossbow","crossbow bolt x20","dagger . Monster Manual 3","page(s) 39","Dungeon Magazine 192."] },
  { id:"mm3-silverback-ape",name:"Silverback Ape",source:"mm3",level:5,role:"Brute",xp:0,size:"Medium",origin:"Natural",type:"Beast",hp:75,ac:17,fort:19,ref:15,will:17,initiative:3,perception:4,speed:"6, climb 4",senses:["Low-light vision"],powers:[{name:"Swift Climber",action:"Trait",description:"The ape does not provoke opportunity attacks by climbing"},{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +8 vs. AC Hit: 2d10+5 damage, and the target grants combat advantage until the end of the ape's next turn."},{name:"Fling",action:"Standard",recharge:"Recharge 5-6",description:"Attack: Melee 1 (one creature); +6 vs. Reflex Hit: 3d10+8 damage, and the ape slides the target 3 squares and knocks it prone."},{name:"Chest Beat",action:"Minor",recharge:"Encounter",description:"Effect: Each beast ally within 5 squares of the ape gains a +2 power bonus to attack rolls until the end of the ape's next turn. Skills Athletics +12, Intimidate +6"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 11","Dungeon Magazine 192","Dungeon Magazine 213."] },
  { id:"mm3-skulk-hunter",name:"Skulk Hunter",source:"mm3",level:5,role:"Soldier",xp:200,size:"Medium",origin:"Natural",type:"Humanoid",hp:61,ac:21,fort:18,ref:16,will:17,initiative:6,perception:9,speed:"6",senses:["Low-light vision"],powers:[{name:"Stealthy Step",action:"Trait",description:"The hunter does not take a penalty to Stealth checks for moving more than 2 squares or for running"},{name:"Baffling Blade",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d8 + 6 damage, and the hunter remains hidden from the target if it was hidden from the target when it attacked. Effect: The target is marked until the end of the hunter's next turn."},{name:"Invisible Blade",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature that cannot see the hunter); +10 vs. AC Hit: 2d8 + 6 damage, and ongoing 5 damage (save ends). Effect: The target is marked until the end of the hunter's next turn."},{name:"Watchful Hunter",action:"Triggered",description:"Trigger: An enemy marked by the hunter shifts. Effect (Opportunity Action): The hunter can use baffling blade against the triggering enemy. Skills Arcana +9, Bluff +12, Stealth +9"}],alignment:"Unaligned",languages:["Common Equipment : leather armor","longsword . Monster Manual 3","page(s) 177."] },
  { id:"mm3-spring-nymph",name:"Spring Nymph",source:"mm3",level:5,role:"Controller",xp:200,size:"Medium",origin:"Fey",type:"Humanoid",hp:63,ac:19,fort:16,ref:17,will:18,initiative:6,perception:3,speed:"6 (forest walk)",senses:["Low-light vision"],powers:[{name:"Charmed Defense",action:"Trait",description:"The spring nymph gains a +3 bonus to all defenses while it is adjacent to a creature dominated by it"},{name:"Passion's Kiss",action:"Standard",keywords:["charm","psychic"],description:"Attack: Melee 1 (one creature); +8 vs. Will Hit: 1d6 + 3 psychic damage, and the target is dazed (save ends)."},{name:"Song of the Spring",action:"Standard",keywords:["charm","psychic"],description:"Attack: Ranged 5 (one creature); +8 vs. Will Hit: 1d8 + 5 psychic damage, and the target is slowed (save ends)."},{name:"Floral Perfume",action:"Standard",keywords:["charm"],recharge:"Recharge when no enemy is dominated by this power",description:"Attack: Ranged 10 (one slowed or dazed creature); +8 vs. Will Hit: The nymph pulls the target 3 squares, and the target is dominated (save ends)."},{name:"Cloud of Blossoms",action:"Standard",keywords:["sleep"],recharge:"Encounter",description:"Attack: Area burst 2 within 10 (nondominated enemies in the burst); +10 vs. Will Hit: The target is slowed (save ends). First Failed Saving Throw: The target falls unconscious (save ends). Skills Bluff +13, Diplomacy +13, Nature +8"}],alignment:"Unaligned",languages:["Common","Elven Monster Manual 3","page(s) 151."] },
  { id:"mm3-volcanic-dragon-wyrmling",name:"Volcanic Dragon Wyrmling",source:"mm3",level:5,role:"Brute",xp:200,size:"Medium",origin:"Elemental",type:"Magical beast",keywords:["dragon","fire"],hp:77,ac:17,fort:18,ref:16,will:17,initiative:5,perception:6,speed:"6, fly 6 (clumsy)",senses:["Darkvision"],powers:[{name:"Noxious Fumes",action:"Aura",keywords:["poison"],description:"Aura 1 Any enemy that ends its turn within the aura takes 3 poison damage."},{name:"Bite",action:"Standard",keywords:["fire"],description:"Attack: Melee 1 (one creature); +9 vs. AC Hit: 1d10 damage, and ongoing 5 fire damage (save ends)."},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d8 damage, and the target loses all fire resistance until the end of the dragon's next turn."},{name:"Wyrmling Fury",action:"Standard",description:"Requirement: The dragon must be bloodied. Effect: The wyrmling uses bite and claw."},{name:"Sudden Flare",action:"Triggered",keywords:["fire"],description:"Trigger: The dragon is hit by a fire attack. Effect (Free Action): Each enemy in the dragon's aura takes 5 fire damage."}],alignment:"Unaligned",languages:["Draconic","Primordial Monster Manual 3","page(s) 72."] },
  { id:"mm3-yeti-rampager",name:"Yeti Rampager",source:"mm3",level:5,role:"Skirmisher",xp:200,size:"Medium",origin:"Natural",type:"Beast",hp:67,ac:19,fort:19,ref:17,will:15,initiative:7,perception:6,speed:"7 (ice walk)",senses:["Low-light vision"],resist:["5 cold"],powers:[{name:"Furious Charger",action:"Trait",description:"The rampager deals 5 extra damage on charge attacks"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +10 vs. AC Hit: 1d6 + 6 damage."},{name:"Battle Howl",action:"Standard",keywords:["fear","psychic"],description:"Attack: Ranged 7 (one creature); +8 vs. Will Hit: 1d6 + 4 psychic damage, and the rampager charges the target."},{name:"Trample",action:"Standard",recharge:"Encounter",description:"Effect: The rampager shifts its speed and can enter enemies' spaces during the shift. Each time the rampager enters an enemy's space for the first time during the shift, it makes the following attack against that enemy. Attack: Melee 0 (one creature); +8 vs. Reflex Hit: 1d6 + 4 damage, and the enemy falls prone."},{name:"Fearsome Howl",action:"Standard",keywords:["fear","thunder"],recharge:"Encounter",description:"Attack: Close blast 4 (enemies in the blast); +8 vs. Will Hit: 1d10 + 6 thunder damage, and the rampager pushes the target 3 squares."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 211."] },
  { id:"mm3-adept-of-orcus",name:"Adept of Orcus",source:"mm3",level:6,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:71,ac:20,fort:16,ref:19,will:18,initiative:7,perception:5,speed:"8",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],vulnerable:["5 radiant"],powers:[{name:"Uneasy Grave",action:"Aura",description:"Aura 5 Any nonminion ghoul ally within the aura that drops to 0 hit points becomes a zombie rotter at the start of its next turn."},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d6 + 4 damage, and the target is immobilized (save ends)."},{name:"Grave Grasp",action:"Standard",keywords:["implement"],description:"Attack: Ranged 5 (one creature); +9 vs. Reflex Hit: The target is restrained (save ends)."},{name:"Call to Feast",action:"Standard",keywords:["implement"],recharge:"Recharge 4-6",description:"Attack: Ranged 5 (one creature); +9 vs. Will Hit: The target is immobilized (save ends). One of the adept's allies that is adjacent to the target can make a melee basic attack against the target as a free action."},{name:"Grave Dust Cloud",action:"Standard",keywords:["implement","necrotic","zone"],recharge:"Encounter",description:"Attack: Area burst 1 within 5 (living creatures in the burst); +9 vs. Fortitude Hit: 2d6 + 7 necrotic damage. Effect: The burst creates a zone that lasts until the end of the encounter. Any living creature that enters the zone or ends its turn there takes 5 necrotic damage. Skills Religion +9, Stealth +12"}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : holy symbol of Orcus","rod implement . Monster Manual 3","page(s) 95","Dungeon Magazine 218."] },
  { id:"mm3-ape-temple-guardian",name:"Ape Temple Guardian",source:"mm3",level:6,role:"Soldier",xp:250,size:"Medium",origin:"Natural",type:"Beast",hp:75,ac:22,fort:21,ref:19,will:17,initiative:9,perception:5,speed:"7, climb 5",senses:["Low-light vision"],powers:[{name:"Swift Climber",action:"Trait",description:"The ape does not provoke opportunity attacks by climbing"},{name:"Club",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d6+7 damage, and the target falls prone."},{name:"Swaying Strike",action:"Standard",description:"Effect: The ape uses club and then shifts 3 squares."},{name:"Feast",action:"Standard",description:"Attack: Melee 1 (one prone creature); +11 vs. Fortitude Hit: 1d10+9 damage, and the ape gains 10 temporary hit points. Skills Athletics +14, Intimidate +7"}],alignment:"Unaligned",languages:["understands Common Monster Manual 3","page(s) 11","Dungeon Magazine 192."] },
  { id:"mm3-bone-crown-behemoth",name:"Bone Crown Behemoth",source:"mm3",level:6,role:"Soldier",xp:250,size:"Large",origin:"Natural",type:"Beast",keywords:["mount","reptile"],hp:71,ac:22,fort:19,ref:17,will:17,initiative:7,perception:4,speed:"7",powers:[{name:"Head Butt",action:"Standard",description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d8 + 5 damage, and the target is marked until the end of the bone crown's next turn. When charging, the bone crown also pushes the target 1 square. Special: Whenever the bone crown hits a creature with an opportunity attack, that creature falls prone."},{name:"Threatening Bash",action:"Triggered",description:"Trigger: An enemy marked by the bone crown shifts. Effect (Immediate Interrupt): The bone crown uses head butt against the triggering enemy. Insult to Injury (mount) ✦ At-Will Trigger: The bone crown has a friendly rider of 6th level or higher mounted on it, and the rider hits with a charge attack. Effect (Free Action): The bone crown pushes the target of the charge 1 square."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 20","Dungeon Magazine 218."] },
  { id:"mm3-chitine-marauder",name:"Chitine Marauder",source:"mm3",level:6,role:"Skirmisher",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["spider"],hp:72,ac:20,fort:18,ref:19,will:17,initiative:9,perception:10,speed:"6, climb 6 (spider climb)",senses:["Darkvision"],powers:[{name:"Combat Advantage",action:"Trait",description:"The marauder deals 1d6 extra damage against any creature granting combat advantage to it"},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d6 + 4 damage."},{name:"Quick Jabs",action:"Standard",description:"Effect: The marauder uses short sword twice. It can shift 2 squares after each attack."},{name:"Web Line",action:"Move",recharge:"Encounter",description:"Requirement: The marauder must be climbing. Effect: The marauder flies 5 squares. Skills Acrobatics +12, Stealth +12"}],alignment:"Unaligned",languages:["Common","Elven Equipment : short sword x2. Monster Manual 3","page(s) 32."] },
  { id:"mm3-chitine-web-crafter",name:"Chitine Web Crafter",source:"mm3",level:6,role:"Controller",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["spider"],hp:72,ac:19,fort:17,ref:18,will:16,initiative:7,perception:10,speed:"6, climb 6 (spider climb)",senses:["Darkvision"],vulnerable:["5 fire. Move Actions Web Line ✦ Encounter Requirement: The web crafter must be climbing. Effect: The web crafter flies","5 squares. Skills Acrobatics +12, Stealth +12"],powers:[{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d8 + 5 damage, and the target is slowed until the end of the web crafter's next turn."},{name:"Poisoned Web Orb",action:"Standard",keywords:["poison"],description:"Attack: Ranged 5 (one creature); +11 vs. AC Hit: 2d10 + 3 poison damage, and the target is slowed until the end of the web crafter's next turn."},{name:"Web Ball",action:"Standard",recharge:"Recharge 3-6",description:"Attack: Ranged 5 (one creature); +9 vs. Reflex Hit: 2d10 + 5 damage, and the target is restrained (save ends). Wall of Webs ✦ Encounter Effect: The web crafter creates an area wall 6 within 10 squares that lasts until the end of the encounter or until the wall is destroyed. The wall can be up to 3 squares high. The wall is blocking terrain, and it can be attacked. Any creature adjacent to the wall that hits it with a melee attack is immobilized (save ends). The wall has the web crafter's defenses, and each square of the wall has 10 hit points. The wall has vulnerable 5 fire."},{name:"Web Line",action:"Move",recharge:"Encounter",description:"Requirement: The web crafter must be climbing. Effect: The web crafter flies 5 squares. Skills Acrobatics +12, Stealth +12"}],alignment:"Unaligned",languages:["Common","Elven Equipment : spear . Monster Manual 3","page(s) 33","Dungeon Magazine 209."] },
  { id:"mm3-dread-archer",name:"Dread Archer",source:"mm3",level:6,role:"Artillery",xp:250,size:"Medium",origin:"Natural",type:"Animate",keywords:["undead"],hp:57,ac:18,fort:18,ref:18,will:17,initiative:6,perception:5,speed:"6",senses:["Low-light vision"],powers:[{name:"Eyes",action:"Trait",description:"of Undeath The dread archer's master can see or hear anything the archer can see or hear"},{name:"The",action:"Trait",description:"master can also speak through the archer"},{name:"Channel",action:"Trait",description:"of Undeath While the dread archer's master has line of sight to the archer, the master can make implement attacks as if it occupied the archer's square"},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d6 + 7 damage."},{name:"Longbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20/40 (one creature); +13 vs. AC Hit: 1d10 + 3 damage."},{name:"Arcing Volley",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Attack: Area burst 1 within 10 (enemies in the burst); +13 vs. AC Hit: 1d10 + 3 damage."},{name:"Sustained Attack",action:"Triggered",keywords:["weapon"],description:"Trigger: An enemy is hit by the archer's master. Attack (Immediate Reaction): Ranged 10 (the triggering enemy); +13 vs. AC Hit: 1d10 + 3 damage."}],alignment:"Unaligned",languages:["understands Common Equipment : arrow x40","longbow","short sword . Monster Manual 3","page(s) 75","Dungeon Magazine 207."] },
  { id:"mm3-ghast",name:"Ghast",source:"mm3",level:6,role:"Brute",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:85,ac:18,fort:18,ref:17,will:16,initiative:6,perception:5,speed:"6",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, poison"],vulnerable:["5 radiant"],powers:[{name:"Stench of Death",action:"Aura",description:"Aura 1 Any living creature that starts its turn within the aura is slowed until the end of the ghast's next turn."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d12 + 6 damage, and the target is immobilized until the end of the ghast's next turn."},{name:"Rabid Claws",action:"Standard",description:"Effect: The ghast makes the following attack twice. Attack: Melee 1 (one immobilized creature); +11 vs. AC Hit: 1d12 + 4 damage."},{name:"Devouring Bite",action:"Standard",description:"Recharge if the power misses Attack: Melee 1 (one immobilized or unconscious creature); +11 vs. AC Hit: 3d12 + 7 damage."},{name:"Death Burst",action:"Triggered",keywords:["necrotic"],recharge:"Encounter",description:"Trigger: The ghast drops to 0 hit points. Attack (No Action): Close burst 2 (living creatures in the burst); +9 vs. Fortitude Hit: 1d12 + 5 necrotic damage, and ongoing 5 necrotic damage (save ends). Skills Athletics +12, Stealth +11"}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 95","Madness at Gardmore Abbey","page(s) 4-17","Dungeon Magazine 211."] },
  { id:"mm3-gnoll-war-fang",name:"Gnoll War Fang",source:"mm3",level:6,role:"Soldier",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:72,ac:22,fort:17,ref:16,will:20,initiative:7,perception:5,speed:"7",senses:["Low-light vision"],powers:[{name:"War Fang Defense",action:"Aura",description:"Aura 1 Allies within the aura gain a +2 bonus to AC"},{name:"Pack Attack",action:"Trait",description:"The war fang's melee attacks deal 5 extra damage against an enemy that has two or more gnoll allies adjacent to it"},{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 1d8 + 6 damage, or 1d8 + 10 while the war fang is bloodied."},{name:"Demonic Challenge",action:"Minor",keywords:["fire"],description:"1/round Effect: The war fang marks one enemy within 3 squares until the end of the enconter or until the war fang uses this power again. Until the mark ends, whenever the marked enemy makes an attack that does not include the war fang as a target, the marked enemy takes 10 fire damage."},{name:"No Mercy",action:"Triggered",description:"Trigger: An enemy misses the war fang with a melee attack. Effect (Immediate Reaction): One ally adjacent to the triggering enemy can make a melee basic attack against it as a free action. Skills Intimidate +12"}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : longsword","plate armor . Monster Manual 3","page(s) 105","Dungeon Magazine 182."] },
  { id:"mm3-servant-of-the-fire-lord",name:"Servant of the Fire Lord",source:"mm3",level:6,role:"Skirmisher",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:73,ac:20,fort:18,ref:18,will:17,initiative:8,perception:3,speed:"6",senses:["Low-light vision"],powers:[{name:"Wildfire Stride",action:"Trait",keywords:["fire"],description:"Whenever the servant of the Fire Lord moves at least 3 squares from where it began its turn, its melee attacks deal 5 extra fire damage until the end of its next turn"},{name:"Scimitar",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 1d8 + 6 damage."},{name:"Immolating Slash",action:"Standard",keywords:["fire","weapon"],description:"Attack: Melee 1 (one creature); +10 vs. Reflex Hit: 1d8 damage, and ongoing 5 fire damage (save ends)."},{name:"Gift of Fire",action:"Minor",keywords:["fire"],recharge:"Recharge 4-6",description:"Effect: The servant grants each ally within 5 squares the gift of fire until the end of the servant's next turn. These allies' melee attacks deal 5 extra fire damage. Skills Diplomacy +10"}],alignment:"Unaligned",languages:["Common","Elven","Primordial Monster Manual 3","page(s) 115."] },
  { id:"mm3-shadow-speaker",name:"Shadow Speaker",source:"mm3",level:6,role:"Controller",xp:250,size:"Small",origin:"Natural",type:"Humanoid",hp:70,ac:20,fort:16,ref:18,will:18,initiative:7,perception:7,speed:"6",senses:["Darkvision"],powers:[{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d6 + 7 damage."},{name:"Shadow Curse",action:"Standard",keywords:["implement","necrotic"],description:"Attack: Ranged 5 (one creature); +9 vs. Reflex Hit: 2d6 + 7 necrotic damage, and the target grants combat advantage and takes 5 damage each time it provokes an opportunity attack (save ends both)."},{name:"Choking Shadow",action:"Standard",keywords:["implement","necrotic"],recharge:"Recharge 4-6",description:"Attack: Ranged 5 (one creature); +9 vs. Will Hit: 3d6 + 11 necrotic damage, and the target is immobilized until the end of the speaker's next turn."},{name:"Dark Step",action:"Move",description:"Effect: The speaker moves 4 squares, gains a +4 bonus to AC against opportunity attacks provoked by this movement, and gains combat advantage against each creature that it ends its move adjacent to until the end of the shadow speaker's next turn."}],alignment:"Unaligned",languages:["Common Equipment : 3 jars of Shadowfell soil","short sword","wand implement . Monster Manual 3","page(s) 39","Dungeon Magazine 192."] },
  { id:"mm3-shardmind-warseeker",name:"Shardmind Warseeker",source:"mm3",level:6,role:"Soldier",xp:250,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["living construct"],hp:70,ac:22,fort:18,ref:16,will:20,initiative:5,perception:5,speed:"5",resist:["5 psychic"],powers:[{name:"Broadsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d10 + 9 damage. Effect: The target is marked until the end of the warseeker's next turn."},{name:"Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 15/30 (one creature); +11 vs. AC Hit: 1d8 + 5 damage. Effect: The target is marked until the end of the warseeker's next turn."},{name:"Shardswarm",action:"Move",keywords:["teleportation"],recharge:"Encounter",description:"Effect: Each enemy adjacent to the warseeker grants combat advantage until the end of the warseeker's next turn. The warseeker then teleports 2 squares."},{name:"Psionic Rebuke",action:"Triggered",keywords:["psychic"],description:"Trigger: An enemy marked by the warseeker and within 5 squares of it makes an attack that does not include the warseeker as a target. Effect (Immediate Reaction): The triggering enemy takes 5 psychic damage and is dazed until the end of its next turn."},{name:"Furious Mind",action:"Triggered",description:"Trigger: The warseeker is first bloodied. Effect (No Action): The warseeker gains 10 temporary hit points. Until the end of the encounter, the warseeker takes a -2 penalty to attack rolls and gains a +4 bonus to damage rolls. Skills Diplomacy +8, Insight +10, Intimidate +8"}],alignment:"Unaligned",languages:["Common","Deep Speech","telepathy 5 Equipment : heavy crossbow","broadsword","crossbow bolt x20","plate armor . Monster Manual 3","page(s) 174."] },
  { id:"mm3-thri-kreen-ambusher",name:"Thri-Kreen Ambusher",source:"mm3",level:6,role:"Lurker",xp:250,size:"Medium",origin:"Natural",type:"Humanoid",hp:58,ac:20,fort:17,ref:19,will:17,initiative:11,perception:11,speed:"8",senses:["Low-light vision"],powers:[{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 2d8 + 4 damage."},{name:"Spinning Spears",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 1d8 + 2 damage, and the ambusher gains a +5 bonus to all defenses until the end of its next turn. In addition, the ambusher's psionic boost recharges."},{name:"Mind Stab",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 5 (one creature); +9 vs. Will Hit: 1d6 + 2 psychic damage, and the target is dazed until the end of the ambusher's next turn."},{name:"Mantis Jump",action:"Move",recharge:"Encounter",description:"Effect: The ambusher jumps a number of squares equal to its speed. This movement does not provoke opportunity attacks."},{name:"Psionic Boost",action:"Triggered",keywords:["psychic"],recharge:"Encounter",description:"Trigger: The ambusher hits with spear or mind stab. Effect (Free Action): The attack deals 2d6 extra psychic damage. Skills Endurance +11, Stealth +12"}],alignment:"Unaligned",languages:["Common Equipment : spear x2. Monster Manual 3","page(s) 192."] },
  { id:"mm3-chosen-of-yeenoghu",name:"Chosen of Yeenoghu",source:"mm3",level:7,role:"Controller",roleModifier:"Elite",xp:600,size:"Medium",origin:"Natural",type:"Humanoid",hp:156,ac:21,fort:19,ref:17,will:19,initiative:5,perception:8,speed:"7",senses:["Low-light vision"],powers:[{name:"Pack Attack",action:"Trait",description:"The chosen of Yeenoghu's melee attacks deal 5 extra damage against an enemy that has two or more gnoll allies adjacent to it"},{name:"Staff",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d8 + 4 damage."},{name:"Bolt of Ruination",action:"Standard",keywords:["implement","necrotic","teleportation"],description:"Attack: Ranged 5 (one creature); +10 vs. Fortitude Hit: 2d6 + 4 necrotic damage, and one hyena spirit within 10 squares of the chosen teleports to a square adjacent to the target."},{name:"Call Beyond the Grave",action:"Minor",recharge:"Encounter",description:"Effect: Four hyena spirits appear in unoccupied squares within 10 squares of the chosen. The chosen takes 5 damage whenever one of its hyena spirits drops to 0 hit points. The spirits disappear at the end of the encounter."},{name:"Hyena Spirit",action:"Minor",description:"1/round Effect: One hyena spirit appears in an unoccupied square within 10 squares of the chosen. The chosen takes 5 damage when the hyena spirit drops to 0 hit points. The spirit disappears at the end of the encounter."},{name:"Spirit Strike",action:"Minor",description:"1/round Effect: One hyena spirit within 10 squares of the chosen can make a bite attack as a free action, with a +2 bonus to the attack roll. To the Front (teleportation) ✦ At-Will 1/round Effect: Each ally adjacent to the chosen can teleport 10 squares. Skills Arcana +13, Religion +13"}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : hide armor","staff implement . Monster Manual 3","page(s) 105","Dungeon Magazine 212."] },
  { id:"mm3-dread-guardian",name:"Dread Guardian",source:"mm3",level:7,role:"Soldier",xp:300,size:"Medium",origin:"Natural",type:"Animate",keywords:["undead"],hp:79,ac:23,fort:19,ref:17,will:18,initiative:6,perception:5,speed:"5",senses:["Low-light vision"],powers:[{name:"Shield of Undeath",action:"Aura",description:"Aura 1 While the dread guardian's master is within the guardian's aura, the master takes half damage from all attacks"},{name:"Eyes",action:"Trait",description:"of Undeath The dread guardian's master can see or hear anything the guardian can see or hear"},{name:"The",action:"Trait",description:"master can also speak through the guardian"},{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d8 + 6 damage. Effect: The target is marked until the end of the guardian's next turn."},{name:"Longbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 20/40 (one creature); +12 vs. AC Hit: 1d10 + 6 damage. Effect: The target is marked until the end of the guardian's next turn."},{name:"Iron Rebuke",action:"Triggered",keywords:["weapon"],description:"Trigger: An enemy marked by the guardian attacks the guardian's master. Attack (Opportunity Action): Melee 1 (the triggering enemy); +14 vs. AC Hit: 2d8 + 6 damage."}],alignment:"Unaligned",languages:["understands Common Equipment : arrow x20","heavy shield","longbow","longsword","scale armor . Monster Manual 3","page(s) 75","Dungeon Magazine 183","Dungeon Magazine 189","Dungeon Magazine 214."] },
  { id:"mm3-feyspitter-spider",name:"Feyspitter Spider",source:"mm3",level:7,role:"Controller",xp:300,size:"Medium",origin:"Fey",type:"Beast",keywords:["spider"],hp:80,ac:21,fort:19,ref:19,will:18,initiative:6,perception:5,speed:"6, climb 6 (spider climb)",senses:["Tremorsense 5"],powers:[{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 1d6 + 7 damage, and ongoing 5 poison damage (save ends). Each Failed Saving Throw: The spider slides the target 3 squares."},{name:"Poison Spittle",action:"Standard",keywords:["poison"],description:"Attack: Close blast 3 (creatures in the blast); +10 vs. Will Hit: Ongoing 10 poison damage (save ends). Each Failed Saving Throw: The spider slides the target 3 squares."},{name:"Fey Leap",action:"Triggered",keywords:["teleportation"],recharge:"Recharge 4-6",description:"Trigger: An enemy hits the spider with a melee attack. Effect (Immediate Interrupt): The spider teleports 3 squares. Skills Acrobatics +11"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 183","Dungeon Magazine 180","Dungeon Magazine 189."] },
  { id:"mm3-fire-temple-elect",name:"Fire Temple Elect",source:"mm3",level:7,role:"Skirmisher",roleModifier:"Minion",xp:75,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:19,fort:18,ref:17,will:17,initiative:6,perception:2,speed:"7",powers:[{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 7 damage."},{name:"Self-Immolation",action:"Triggered",keywords:["fire"],description:"Trigger: The elect drops to 0 hit points. If fire damage reduces the elect to 0 hit points, it can move its speed before making the following attack.. Close burst 1 (creatures in the burst); +10 vs. Reflex Hit: 5 fire damage."}],alignment:"Unaligned",languages:["Common Equipment : leather armor","short sword . Monster Manual 3","page(s) 115."] },
  { id:"mm3-foulspawn-wretch",name:"Foulspawn Wretch",source:"mm3",level:7,role:"Skirmisher",roleModifier:"Minion",xp:75,size:"Small",origin:"Aberrant",type:"Humanoid",hp:1,ac:21,fort:19,ref:20,will:19,initiative:10,perception:5,speed:"6, teleport 2",senses:["Low-light vision"],powers:[{name:"Ceaseless Murmurs",action:"Trait",description:"Any enemy adjacent to two or more foulspawn wretches takes a -2 penalty to Will"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 7 damage, and a foulspawn wretch ally within 6 squares can teleport to a square adjacent to the target."}],alignment:"Unaligned",languages:["Deep Speech","telepathy 10 Monster Manual 3","page(s) 88","Dungeon Magazine 196."] },
  { id:"mm3-gremlin-skulker",name:"Gremlin Skulker",source:"mm3",level:7,role:"Lurker",xp:300,size:"Small",origin:"Fey",type:"Humanoid",hp:64,ac:21,fort:18,ref:21,will:18,initiative:11,perception:6,speed:"6",senses:["Low-light vision"],powers:[{name:"Sabotaging Presence",action:"Aura",description:"Aura 5 Enemies within the aura take a -5 penalty to skill checks"},{name:"Shadow Sneak",action:"Trait",keywords:["illusion"],description:"While adjacent to any enemy, the skulker is invisible"},{name:"Opportunistic Advantage",action:"Trait",description:"The skulker deals 2d6 extra damage with opportunity attacks"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d6 + 4 damage. If the target moves away from the skulker before the end of its next turn, the target falls prone at the end of its move."},{name:"Gremlin Tactics",action:"Triggered",description:"Trigger: An enemy adjacent to the skulker misses it with a melee attack. Effect (Immediate Reaction): The skulker swaps positions with the triggering enemy."},{name:"Shadow Skulk",action:"Triggered",recharge:"Encounter",description:"Trigger: An enemy adjacent to the skulker moves. Effect (Immediate Reaction): The skulker shifts 6 squares, moving with the triggering enemy as it completes the move. The skulker remains adjacent to the enemy during the move and must end the shift adjacent to the enemy. Skills Stealth +12, Thievery +12"}],alignment:"Unaligned",languages:["Common","Elven","Goblin Monster Manual 3","page(s) 107","Dungeon Magazine 185","Dungeon Magazine 214."] },
  { id:"mm3-hyena-spirit",name:"Hyena Spirit",source:"mm3",level:7,role:"Soldier",roleModifier:"Minion",xp:75,size:"Medium",origin:"Shadow",type:"Beast",keywords:["undead"],hp:1,ac:21,fort:19,ref:19,will:17,initiative:9,perception:5,speed:"8",senses:["Darkvision"],powers:[{name:"Spectral Jaws",action:"Aura",description:"Aura 1 Any enemy that starts its turn within the aura is slowed until the end of its next turn."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 7 damage."}],alignment:"Chaotic Evil",languages:["- Monster Manual 3","page(s) 105","Dungeon Magazine 212."] },
  { id:"mm3-ironstone-gargoyle",name:"Ironstone Gargoyle",source:"mm3",level:7,role:"Skirmisher",xp:300,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["earth"],hp:80,ac:21,fort:19,ref:19,will:17,initiative:9,perception:5,speed:"6, fly 8",senses:["Darkvision"],immune:["petrification"],powers:[{name:"Lurking Presence",action:"Trait",description:"The ironstone gargoyle gains a +10 bonus to Stealth checks against enemies' passive Perception"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d6 + 4 damage."},{name:"Crashing Stride",action:"Standard",recharge:"Recharge 4-6",description:"Effect: The gargoyle shifts 4 squares and uses claw against two different targets at any point during the shift. When an attack hits, the gargoyle slides the target 1 square and knocks it prone."},{name:"Leaping Glide",action:"Move",description:"Effect: The gargoyle flies 4 squares without provoking opportunity attacks. Skills Athletics +12, Stealth +12"}],alignment:"Unaligned",languages:["Primordial Monster Manual 3","page(s) 92."] },
  { id:"mm3-quasit",name:"Quasit",source:"mm3",level:7,role:"Controller",xp:300,size:"Tiny",origin:"Elemental",type:"Humanoid",keywords:["demon"],hp:75,ac:23,fort:16,ref:21,will:19,initiative:8,perception:10,speed:"8",senses:["Darkvision"],resist:["10 to the triggering damage type until the end of the encounter. Skills Arcana +8, Bluff +11, Stealth +13"],powers:[{name:"Tempter's Influence",action:"Aura",description:"Aura 2 Enemies within the aura take a -2 penalty to saving throws."},{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 0 (one creature); +12 vs. AC Hit: 2d6 + 5 damage, and the target grants combat advantage (save ends)."},{name:"Evil Temptation",action:"Minor",description:"1/round Attack: Close burst 3 (one creature in the burst); +10 vs. Will Hit: The target is dazed (save ends). The effect also ends if the target makes an attack against one of its allies. Invisibility (illusion) ✦ At-Will 1/round Effect: The quasit becomes invisible until it makes an attack roll."},{name:"Variable Resistance",action:"Triggered",recharge:"Encounter",description:"Trigger: The quasit takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The quasit gains resist 10 to the triggering damage type until the end of the encounter. Skills Arcana +8, Bluff +11, Stealth +13"}],alignment:"Unaligned",languages:["Abyssal","Common Monster Manual 3","page(s) 46","Dungeon Magazine 214","Dungeon Magazine 218."] },
  { id:"mm3-skinwing-behemoth",name:"Skinwing Behemoth",source:"mm3",level:7,role:"Skirmisher",xp:300,size:"Large",origin:"Natural",type:"Beast",keywords:["mount","reptile"],hp:79,ac:21,fort:19,ref:21,will:19,initiative:9,perception:3,speed:"2 (clumsy), fly 8 (hover)",powers:[{name:"Strafe",action:"Trait",keywords:["mount"],description:"When the behemoth uses flyby attack while it has a friendly rider of 7th level or higher mounted on it, its rider can make a melee basic attack in place of the skinwing's bite"},{name:"Drag Off",action:"Trait",description:"When the behemoth moves, it pulls with it any creature grabbed by it. In addition, the creature remains grabbed, and the behemoth does not provoke an opportunity attack from the grabbed creature"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d6 + 8 damage."},{name:"Flyby Attack",action:"Standard",description:"Effect: The skinwing flies its speed and uses bite at any point during the movement. The skinwing does not provoke an opportunity attack from the target when moving away from it."},{name:"Grasping Talons",action:"Standard",recharge:"Recharge 4-6",description:"Requirement: The skinwing must be flying. Effect: The skinwing uses flyby attack, and if the attack hits, the skinwing grabs the target of the attack."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 21."] },
  { id:"mm3-thri-kreen-scout",name:"Thri-Kreen Scout",source:"mm3",level:7,role:"Skirmisher",xp:300,size:"Medium",origin:"Natural",type:"Humanoid",hp:80,ac:21,fort:20,ref:20,will:18,initiative:9,perception:10,speed:"8",senses:["Low-light vision"],powers:[{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 2d8 + 5 damage."},{name:"Shuriken",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10/20 (one creature); +12 vs. AC Hit: 2d4 + 7 damage."},{name:"Leaping Strike",action:"Standard",keywords:["weapon"],description:"Effect: The scout moves its speed and makes the following attack at any point during the move. Attack: Melee 2 (one creature); +12 vs. AC Hit: 3d8 + 5 damage."},{name:"Mantis Jump",action:"Move",recharge:"Encounter",description:"Effect: The scout jumps a number of squares equal to its speed. This movement does not provoke opportunity attacks."},{name:"Sudden Recoil",action:"Triggered",description:"Trigger: The scout is hit by an attack. Effect (Immediate Reaction): The scout shifts 1 square (or 4 squares if the attack bloodies the scout). Psionic Boost (psychic) ✦ Recharge ⚄ ⚅ Trigger: The scout hits with spear or shuriken. Effect (Free Action): The attack deals 2d6 extra psychic damage. Skills Athletics +12, Endurance +11"}],alignment:"Unaligned",languages:["Common Equipment : shuriken x10","spear . Monster Manual 3","page(s) 192","Dungeon Magazine 187."] },
  { id:"mm3-umber-ravager",name:"Umber Ravager",source:"mm3",level:7,role:"Brute",xp:300,size:"Medium",origin:"Natural",type:"Magical beast",hp:95,ac:19,fort:20,ref:18,will:19,initiative:4,perception:5,speed:"5, burrow 2 (tunneling)",senses:["Darkvision"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 1d10 + 5 damage."},{name:"Claw Flurry",action:"Standard",description:"Effect: The ravager uses claw twice."},{name:"Crushing Gaze",action:"Standard",keywords:["psychic"],description:"Attack: Close blast 3 (enemies in the blast); +10 vs. Will Hit: 3d8 psychic damage, and the target falls prone."},{name:"Disarming Gaze",action:"Minor",recharge:"Recharge 5-6",description:"Attack: Ranged 3 (one creature); +10 vs. Will Hit: The target is stunned (save ends)."}],alignment:"Unaligned",languages:["understands Deep Speech Monster Manual 3","page(s) 198."] },
  { id:"mm3-ustilagor",name:"Ustilagor",source:"mm3",level:7,role:"Lurker",xp:300,size:"Small",origin:"Aberrant",type:"Magical beast",keywords:["blind"],hp:59,ac:21,fort:19,ref:17,will:20,initiative:9,perception:11,speed:"6",senses:["Blindsight 10"],immune:["blinded, gaze"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 3d6 + 5 damage."},{name:"Clinging Menace",action:"Standard",keywords:["psychic"],description:"Requirement: The ustilagor must not have a creature grabbed. Effect: The ustilagor jumps 4 squares without provoking opportunity attacks and then makes the following attack. Attack: Melee 1 (one creature granting combat advantage to the ustilagor); +12 vs. AC Hit: 1d6 + 3 damage, and the ustilagor grabs the target. While the target is grabbed by the ustilagor, the target is dazed and takes ongoing 5 psychic damage."},{name:"Thought Lash",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 10 (one creature); +10 vs. Will Hit: 2d6 + 5 psychic damage, and the target grants combat advantage until the end of the ustilagor's next turn."},{name:"Cloud Thoughts",action:"Minor",keywords:["illusion"],description:"1/round Attack: Ranged 10 (one creature); +10 vs. Will Hit: The ustilagor becomes invisible to the target (save ends)."},{name:"Mind's Resilience",action:"Triggered",description:"Trigger: The ustilagor takes damage while subject to an effect that a save can end. Effect (No Action): The ustilagor makes a saving throw. Skills Stealth +10"}],alignment:"Unaligned",languages:["telepathy 10 Monster Manual 3","page(s) 118."] },
  { id:"mm3-vizier-devil",name:"Vizier Devil",source:"mm3",level:7,role:"Controller",xp:0,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["devil"],hp:80,ac:21,fort:19,ref:19,will:21,initiative:4,perception:6,speed:"6, teleport 4",senses:["Darkvision"],resist:["10 fire"],powers:[{name:"Scepter",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +12 vs. AC Hit: 2d8 + 4 damage, and the devil slides the target 1 square."},{name:"Hellfire Bolt",action:"Standard",keywords:["fire"],description:"Attack: Ranged 5 (one creature); +10 vs. Reflex Hit: 2d10 + 2 fire damage, and the target grants combat advantage until the end of the devil's next turn. Word of Command (charm) ✦ At-Will Effect: Choose one creature within 2 squares of the devil. The devil slides that creature 3 squares, and the creature makes a melee basic attack as a free action against a creature of the devil's choice."},{name:"Hellfire Enchantment",action:"Minor",keywords:["fire"],description:"Effect: One ally within 5 squares of the devil deals 5 extra fire damage with melee attacks until the end of the ally's next turn."},{name:"Infernal Advice",action:"Triggered",recharge:"Recharge 5-6",description:"Trigger: An ally within 10 squares of the devil misses with an attack roll or fails a skill check. Effect (Immediate Interrupt): The triggering ally can reroll the attack roll or the skill check, gaining a +2 bonus to the reroll. Skills Bluff +12, Diplomacy +12, Insight +11"}],alignment:"Unaligned",languages:["Supernal Equipment : scepter Monster Manual 3","page(s) 63","Dungeon Magazine 193","Dungeon Magazine 218."] },
  { id:"mm3-young-blizzard-dragon",name:"Young Blizzard Dragon",source:"mm3",level:7,role:"Controller",roleModifier:"Elite",xp:600,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["cold","dragon"],hp:166,ac:21,fort:19,ref:20,will:18,initiative:8,perception:6,speed:"8 (ice walk), fly 8 (clumsy)",senses:["Darkvision"],powers:[{name:"Freezing Winds",action:"Aura",description:"Aura 1 The dragon slides any enemy that ends its turn in the aura 1 square."},{name:"Bite",action:"Standard",keywords:["cold"],description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 2d8 + 3 cold damage, and the target is immobilized until the end of the dragon's next turn."},{name:"Claw",action:"Standard",keywords:["cold"],description:"Attack: Melee 2 (one creature); +12 vs. AC Hit: 2d6 + 8 cold damage, and the dragon slides the target 2 squares."},{name:"Double Attack",action:"Standard",description:"Effect: The dragon uses bite and claw or uses claw twice."},{name:"Rising Winds",action:"Minor",keywords:["cold"],description:"Recharge at the start of any turn when freezing winds is aura 1 Effect: The freezing winds expands to aura 3. At the start of the dragon's next turn, the freezing winds expands to aura 5. At the start of its following turn, the dragon makes the following attack. Attack (No Action): Close burst 5 (enemies in the burst); +10 vs. Fortitude Hit: 2d8 + 5 cold damage, and the target is slowed and blinded (save ends both). Effect: The freezing winds aura reverts to its original state and size (aura 1)."},{name:"Chill Rebuke",action:"Triggered",keywords:["cold"],recharge:"Recharge when first bloodied",description:"Trigger: An enemy's melee attack deals damage to the dragon. Attack (Immediate Reaction): Close blast 5 (enemies in the blast); +11 vs. Fortitude Hit: 1d10 + 5 cold damage, and the target is slowed (save ends). Sudden Flurry ✦ At-Will Trigger: The dragon is hit by a cold attack. Effect (Free Action): The dragon slides each enemy in its aura 1 square."}],alignment:"Unaligned",languages:["Common","Draconic","Primordial Monster Manual 3","page(s) 66."] },
  { id:"mm3-autumn-nymph",name:"Autumn Nymph",source:"mm3",level:8,role:"Skirmisher",xp:350,size:"Medium",origin:"Fey",type:"Humanoid",hp:89,ac:22,fort:21,ref:19,will:20,initiative:11,perception:7,speed:"6, fly 6 (clumsy)",senses:["Low-light vision"],powers:[{name:"Oaken Strength",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d6 + 9 damage, and the nymph pushes the target 1 square."},{name:"Dark Revelation",action:"Standard",keywords:["charm","psychic"],recharge:"Recharge 5-6",description:"Attack: Melee 1 (one creature); +11 vs. Will Hit: 1d8 + 4 psychic damage, and the target is stunned (save ends)."},{name:"Whisper Game",action:"Standard",keywords:["psychic"],description:"Recharge if the power misses Attack: Ranged 10 (one creature); +11 vs. Will Hit: 1d8 + 4 psychic damage, and ongoing 5 psychic damage (save ends). Until the end of the encounter or until the nymph drops to 0 hit points, whenever any creature saves against this ongoing damage, the nearest ally within 10 squares of it gains the ongoing damage. When the nymph drops to 0 hit points, the effect ends and the creature currently affected by the ongoing damage takes 15 psychic damage."},{name:"Autumn Wind",action:"Move",description:"1/round Effect: The nymph either shifts 1 square or moves its speed and then uses oaken strength."},{name:"Secret of Autumn Leaves",action:"Triggered",description:"Trigger: An enemy misses the nymph with a melee attack. Effect (Immediate Reaction): The nymph shifts 3 squares. Skills Acrobatics +14, Bluff +14, Nature +12"}],alignment:"Unaligned",languages:["Common","Elven Monster Manual 3","page(s) 151","Madness at Gardmore Abbey","page(s) 3-17."] },
  { id:"mm3-choldrith",name:"Choldrith",source:"mm3",level:8,role:"Controller",xp:0,size:"Large",origin:"Natural",type:"Humanoid",keywords:["spider"],hp:90,ac:22,fort:19,ref:21,will:17,initiative:6,perception:14,speed:"6, climb 6 (spider climb)",senses:["Darkvision"],powers:[{name:"Claws",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d8 + 7 poison damage, and the target is immobilized until the end of the choldrith's next turn."},{name:"Web",action:"Standard",description:"Attack: Ranged 5 (one creature); +11 vs. Reflex Hit: 1d10 + 7 damage, and the target is restrained until the end of the choldrith's next turn."},{name:"Shadow Spider Curse",action:"Standard",keywords:["poison"],description:"Attack: Ranged 10 (one creature); +11 vs. Will Hit: 2d10 + 5 poison damage, and the target grants combat advantage to spiders (save ends)."},{name:"Choking Vapors",action:"Standard",keywords:["poison","zone"],recharge:"Encounter",description:"Attack: Area burst 1 within 10 (creatures in the burst); +11 vs. Fortitude Hit: 2d6 + 4 poison damage, and ongoing 5 poison damage (save ends). Effect: The burst creates a zone that lasts until the end of the encounter. Any enemy that enters the zone or ends its turn there takes 5 poison damage."},{name:"Spider Queen's Enforcer",action:"Triggered",description:"Trigger: An ally within 5 squares of the choldrith misses with an attack roll. Effect (Immediate Interrupt): The triggering ally takes 5 damage and rerolls the attack roll."},{name:"For the Spider Queen",action:"Triggered",recharge:"Recharge when first bloodied",description:"Trigger: A melee or a ranged attack hits the choldrith. Effect (Immediate Interrupt): The triggering attack instead hits one of the choldrith's adjacent allies. Skills Diplomacy +12, Intimidate +12, Religion +12"}],alignment:"Unaligned",languages:["Common","Elven Equipment : holy symbol of Lolth Monster Manual 3","page(s) 33","Dungeon Magazine 209."] },
  { id:"mm3-earth-cultist",name:"Earth Cultist",source:"mm3",level:8,role:"Controller",roleModifier:"Minion",xp:88,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:22,fort:23,ref:21,will:18,initiative:7,perception:3,speed:"5",powers:[{name:"Warhammer",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +11 vs. AC Hit: 8 damage."}],alignment:"Unaligned",languages:["Common Equipment : leather armor","warhammer . Monster Manual 3","page(s) 163."] },
  { id:"mm3-fire-temple-champion",name:"Fire Temple Champion",source:"mm3",level:8,role:"Soldier",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:88,ac:24,fort:22,ref:17,will:21,initiative:6,perception:5,speed:"5",powers:[{name:"Wildfire Stride",action:"Trait",keywords:["fire"],description:"Whenever the fire temple champion moves at least 3 squares from where it began its turn, its melee attacks deal 5 extra fire damage until the end of its next turn"},{name:"Fullblade",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 1d12 + 8 damage, and the target is marked until the end of the champion's next turn."},{name:"Dragon Breath",action:"Minor",keywords:["fire"],recharge:"Encounter",description:"Attack: Close blast 3 (creatures in the blast); +11 vs. Reflex Hit: 3d6 + 5 fire damage, and the target is marked (save ends)"},{name:"Fiery Assault",action:"Triggered",keywords:["fire","weapon"],description:"Trigger: An enemy marked by the champion moves on its turn. Attack (Opportunity Action): Melee 1 (the triggering enemy); +13 vs. AC Hit: 1d12 + 8 damage, and ongoing 5 fire damage (save ends)."},{name:"Fiery Rebuke",action:"Triggered",keywords:["fire"],description:"Trigger: An enemy marked by the champion makes an attack that does not include the champion as a target. Attack (Immediate Reaction): Close blast 3 (the triggering enemy in the blast); +11 vs. Reflex Hit: 2d6 + 5 fire damage."}],alignment:"Unaligned",languages:["Common","Draconic Equipment : fullblade","plate armor . Monster Manual 3","page(s) 115","Dungeon Magazine 202."] },
  { id:"mm3-green-arcanian",name:"Green Arcanian",source:"mm3",level:8,role:"Artillery",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:67,ac:20,fort:17,ref:20,will:21,initiative:4,perception:7,speed:"6",powers:[{name:"Acid Touch",action:"Standard",keywords:["acid"],description:"Attack: Melee 1 (one creature); +9 vs. Reflex Hit: 2d6+9 acid damage."},{name:"Acid Bolt",action:"Standard",keywords:["acid","implement"],description:"Attack: Ranged 10 (one creature); +11 vs. Reflex Hit: 2d10+3 acid damage, and each enemy adjacent to the target takes 3 acid damage."},{name:"Stream of Acid",action:"Standard",keywords:["acid","implement"],recharge:"Recharge 4-6",description:"Attack: Ranged 10 (one creature); +11 vs. Reflex Hit: 2d6+10 acid damage, and the target takes a -2 penalty to AC and ongoing 5 acid damage (save ends both)."},{name:"Orb of Denial",action:"Triggered",keywords:["implement"],recharge:"Encounter",description:"Trigger: An enemy makes a successful saving throw. Attack (Immediate Interrupt): Ranged 10 (one creature); +13 vs. Will Hit: The target fails the saving throw. Arcane Surge ✦ Encounter Trigger: The arcanian hits an enemy with an implement attack. Effect (Free Action): The attack deals maximum damage to the enemy. Skills Arcana +13"}],alignment:"Chaotic Evil",languages:["Common Equipment : orb implement . Monster Manual 3","page(s) 16","Dungeon Magazine 183."] },
  { id:"mm3-hornstone-gargoyle",name:"Hornstone Gargoyle",source:"mm3",level:8,role:"Brute",xp:350,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["earth"],hp:107,ac:20,fort:22,ref:19,will:19,initiative:7,perception:12,speed:"6, fly 8",senses:["Darkvision"],immune:["petrification"],powers:[{name:"Lurking Presence",action:"Trait",description:"The hornstone gargoyle gains a +10 bonus to Stealth checks against enemies' passive Perception"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d10 + 5 damage, and the gargoyle can use skewering drag as a free action."},{name:"Impaling Charge",action:"Standard",description:"Effect: The gargoyle charges and makes the following attack in place of a melee basic attack. Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d12 + 5 damage, and the target is grabbed and takes ongoing 5 damage until the grab ends."},{name:"Skewering Drag",action:"Move",description:"Effect: The gargoyle moves half its speed, pulling a creature grabbed by the gargoyle with it. The gargoyle and the creature grabbed by it do not provoke opportunity attacks from each other for this movement. Skills Stealth +12"}],alignment:"Unaligned",languages:["Primordial Monster Manual 3","page(s) 93."] },
  { id:"mm3-object-mimic",name:"Object Mimic",source:"mm3",level:8,role:"Lurker",xp:350,size:"Medium",origin:"Aberrant",type:"Magical beast",hp:71,ac:23,fort:21,ref:19,will:21,initiative:11,perception:14,speed:"5",senses:["Darkvision"],resist:["5 acid"],powers:[{name:"Ambush",action:"Trait",description:"The object mimic deals 2d6 extra damage against surprised creatures"},{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d8 + 7 damage."},{name:"Crushing Tendrils",action:"Standard",keywords:["acid"],description:"Attack: Melee 3 (one creature); +13 vs. AC Hit: 1d8 + 4 damage, and the mimic grabs the target. The target takes a -5 penalty to attempts to escape the grab. Sustain Standard: The object mimic sustains the grab, and the target takes 15 acid damage."},{name:"Ravening Maw",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 2d8 + 11 damage, and the target is slowed (save ends)."},{name:"Shapeshift",action:"Minor",keywords:["polymorph"],description:"1/round Effect: The mimic assumes one of the following forms. It can't change its size. It remains in the chosen form until it uses this power again. Ooze Form: The mimic becomes an ooze. When it squeezes while it is in this form, it moves at full speed rather than half speed, it doesn't take the -5 penalty to attack rolls, and it doesn't grant combat advantage for squeezing, Object Form: While in this form, the mimic has resist 10 to all damage, is immobilized, and cannot attack. In addition, a creature must succeed on a DC 24 Perception check to notice that the mimic is a living creature. Skills Bluff +11, Stealth +12"}],alignment:"Unaligned",languages:["Common","Deep Speech Monster Manual 3","page(s) 134","Madness at Gardmore Abbey","page(s) 3-25","Dungeon Magazine 214."] },
  { id:"mm3-obsidian-gargoyle",name:"Obsidian Gargoyle",source:"mm3",level:8,role:"Soldier",roleModifier:"Minion",xp:88,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["earth"],hp:1,ac:24,fort:22,ref:20,will:19,initiative:8,perception:7,speed:"6, fly 8",senses:["Darkvision"],immune:["petrification"],powers:[{name:"Cruel Claws Whenever",action:"Trait",description:"an enemy leaves a square adjacent to the obsidian gargoyle, that enemy takes 4 damage"},{name:"Lurking Presence",action:"Trait",description:"The obsidian gargoyle gains a +10 bonus to Stealth checks against enemies' passive Perception"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 8 damage. Skills Athletics +14, Stealth +11"}],alignment:"Unaligned",languages:["Primordial Monster Manual 3","page(s) 93","Dungeon Magazine 187."] },
  { id:"mm3-ogre-cave-hunter",name:"Ogre Cave Hunter",source:"mm3",level:8,role:"Lurker",xp:350,size:"Large",origin:"Natural",type:"Humanoid",hp:70,ac:22,fort:20,ref:19,will:18,initiative:12,perception:4,speed:"8",powers:[{name:"Club",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 2d8 + 7 damage."},{name:"Skull Bash",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one dazed creature); +13 vs. AC Hit: 4d8 + 7 damage."},{name:"Smash and Swing",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +13 vs. AC Hit: 1d8 + 3 damage, and the target is dazed until the end of the cave hunter's next turn. In addition, the cave hunter slides the target 5 squares to a square within 2 squares of the ogre."},{name:"Victim Shield",action:"Triggered",description:"Requirement: A dazed enemy must be within 2 squares of the cave hunter. Trigger: The cave hunter is hit by a melee or a ranged attack. Effect (Immediate Interrupt): The cave hunter gains a +4 bonus to all defenses against the attack. If the attack misses the cave hunter, one dazed enemy takes damage as if it had been hit by the attack. The cave hunter then slides that enemy 4 squares to a square within 2 squares of it."}],alignment:"Chaotic Evil",languages:["Giant Equipment : club","hide armor . Monster Manual 3","page(s) 158."] },
  { id:"mm3-rot-grub-zombie",name:"Rot Grub Zombie",source:"mm3",level:8,role:"Skirmisher",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:86,ac:22,fort:20,ref:19,will:17,initiative:9,perception:2,speed:"6",immune:["rot grub infestation"],powers:[{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d6 + 9 damage."},{name:"Flailing Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d6 + 9 damage. Effect: Before or after the attack, the zombie can shift 1 square."},{name:"Rot Grub Hunger",action:"Standard",keywords:["disease","necrotic"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d6 + 9 damage plus 2d6 necrotic damage. Effect: If the target is bloodied, it must make a saving throw at the end of the encounter. On a failed saving throw, it contracts rot grub infestation (stage 1)."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 167","The Book of Vile Darkness","page(s) 2-39","Dungeon Magazine 215."] },
  { id:"mm3-runic-gargoyle",name:"Runic Gargoyle",source:"mm3",level:8,role:"Soldier",xp:350,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["earth"],hp:87,ac:24,fort:20,ref:19,will:22,initiative:8,perception:12,speed:"6, fly 8",senses:["Darkvision"],immune:["petrification"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d8 + 7 damage. Effect: The target is marked until the end of the gargoyle's next turn."},{name:"Avenging Claws",action:"Standard",recharge:"Recharge when the gargoyle's master is first bloodied.",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d8 + 7 damage, and the target is dazed until the end of the gargoyle's next turn."},{name:"To the Master",action:"Move",keywords:["teleportation"],description:"Effect: The gargoyle teleports to a square within 2 squares of its master."},{name:"Shielding Wings",action:"Triggered",description:"Requirement: The gargoyle must be adjacent to its master. Trigger: The gargoyle's master takes damage. Effect (Immediate Interrupt): The gargoyle takes the damage instead of its master. Skills Athletics +14, Stealth +11"}],alignment:"Unaligned",languages:["Common","Primordial Monster Manual 3","page(s) 93","Dungeon Magazine 186","Dungeon Magazine 214."] },
  { id:"mm3-shardmind-dominator",name:"Shardmind Dominator",source:"mm3",level:8,role:"Controller",xp:350,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["living construct"],hp:86,ac:22,fort:17,ref:19,will:21,initiative:4,perception:13,speed:"6",resist:["5 psychic"],powers:[{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 3d4 + 9 damage. Overwhelming Mind (charm) ✦ At-Will Effect: One creature within 5 squares of the dominator makes a melee or a ranged basic attack as a free action against a target of the dominator's choice. If the attack hits, the dominator slides the attacking creature 3 squares."},{name:"Psionic Puppet",action:"Standard",keywords:["charm"],recharge:"Recharge 4-6",description:"Attack: Ranged 10 (one creature); +11 vs. Will Hit: The target is dominated (save ends)."},{name:"Mind Swarm",action:"Standard",keywords:["psychic","zone"],recharge:"Encounter",description:"Attack: Area burst 1 within 5 (enemies in the burst); +11 vs. Will Hit: 2d10 + 7 psychic damage. Effect: The burst creates a zone that lasts until the end of the encounter. When any enemy ends its turn within the zone, the dominator can slide it 3 squares as a free action."},{name:"Shardswarm",action:"Move",keywords:["teleportation"],recharge:"Encounter",description:"Effect: Each enemy adjacent to the dominator grants combat advantage until the end of the dominator's next turn. The dominator then teleports 3 squares. Skills Arcana +12, Bluff +10"}],alignment:"Unaligned",languages:["Common","Deep Speech","telepathy 5 Equipment : dagger","orb implement . Monster Manual 3","page(s) 175."] },
  { id:"mm3-thri-kreen-desert-talker",name:"Thri-Kreen Desert Talker",source:"mm3",level:8,role:"Controller",xp:350,size:"Medium",origin:"Natural",type:"Humanoid",hp:88,ac:22,fort:19,ref:20,will:21,initiative:6,perception:9,speed:"7",senses:["Low-light vision"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +13 vs. AC Hit: 2d6 + 6 damage."},{name:"Shuriken",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10/20 (one or two creatures); +13 vs. AC Hit: 2d4 + 4 damage."},{name:"Shifting Dune Rend",action:"Standard",description:"Attack: Area burst 1 within 10 (enemies in the burst); +11 vs. Reflex Hit: The target falls prone. Effect: The desert talker slides the target 2 squares."},{name:"Desert Tempest",action:"Standard",recharge:"Recharge when first bloodied",description:"Attack: Close blast 5 (enemies in the blast); +11 vs. Reflex Hit: 1d6 + 5 damage, and the desert talker pushes the target 2 squares. In addition, the target is blinded (save ends)."},{name:"Mantis Jump",action:"Move",recharge:"Encounter",description:"Effect: The desert talker jumps a number of squares equal to its speed. This movement does not provoke opportunity attacks."},{name:"Sand Trap",action:"Minor",recharge:"Recharge when all this power's sand traps have ended",description:"Effect: The desert talker creates sand traps in three unoccupied squares within 10 squares of it. The sand traps must be created on a solid surface. Until the end of the encounter, any enemy that enters a sand trap's square is restrained until the end of its next turn, and that sand trap disappears. Skills Diplomacy +12, Insight +14, Nature +14"}],alignment:"Unaligned",languages:["Common","Thri-kreen Equipment : shuriken x10. Monster Manual 3","page(s) 193","Dungeon Magazine 187."] },
  { id:"mm3-cambion-wrathborn",name:"Cambion Wrathborn",source:"mm3",level:9,role:"Skirmisher",xp:400,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["devil"],hp:100,ac:23,fort:21,ref:24,will:18,initiative:11,perception:6,speed:"6, fly 8 (clumsy)",senses:["Darkvision"],resist:["10 fire"],powers:[{name:"Burning Anger",action:"Aura",keywords:["fire"],description:"Aura 1 While the wrathborn is bloodied, any enemy that ends its turn within the aura takes 5 fire damage."},{name:"Pain Blade",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d8 + 8 damage, and the target grants combat advantage until the end of the wrathborn's next turn."},{name:"Path of Pain",action:"Standard",keywords:["weapon"],description:"Effect: The wrathborn shifts 4 squares and uses pain blade at any point during the shift."},{name:"Fire Bolt",action:"Standard",keywords:["fire","implement"],description:"Attack: Ranged 5 (one creature); +12 vs. Reflex Hit: 2d6 + 5 fire damage."},{name:"Burst Skyward",action:"Standard",keywords:["fire","implement"],recharge:"Encounter",description:"Requirement: The wrathborn must be bloodied. Attack: Close burst 2 (enemies in the burst); +12 vs. Reflex Hit: 2d10 + 5 fire damage, and the wrathborn flies 8 squares without provoking opportunity attacks."},{name:"Wicked Guise",action:"Minor",keywords:["illusion"],description:"Requirement: The wrathborn must not be bloodied. Effect: The wrathborn assumes the appearance of a specific Medium humanoid. Skills Acrobatics +14, Bluff +14, Intimidate +14"}],alignment:"Unaligned",languages:["Supernal Equipment : leather armor","short sword","wand implement . Monster Manual 3","page(s) 24","Dungeon Magazine 218."] },
  { id:"mm3-fist-of-the-stone-tyrant",name:"Fist of the Stone Tyrant",source:"mm3",level:9,role:"Soldier",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:98,ac:25,fort:23,ref:18,will:21,initiative:6,perception:7,speed:"5 (earth walk)",senses:["Low-light vision"],powers:[{name:"Rotting Earth",action:"Aura",description:"Aura 1 Any enemy that starts its turn within the aura is slowed until the start of its next turn."},{name:"Stone Tyrant's Boon",action:"Aura",description:"Aura 1 Allies within the aura gain a +2 power bonus to AC and Fortitude"},{name:"Stand",action:"Trait",description:"the Ground Whenever the fist of the Stone Tyrant is pulled, pushed, or slid, it can move 1 square less than the effect specifies"},{name:"War Pick",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d8 + 7 damage, and the target is marked until the end of the fist's next turn."},{name:"Stone Tyrant's Grasp",action:"Triggered",keywords:["necrotic"],description:"Trigger: An enemy marked by the fist leaves the rotting earth aura. Effect (Immediate Reaction): The fist shifts 1 square and makes the following attack. Attack: Melee 1 (the triggering enemy); +16 vs. AC Hit: 1d8 + 5 damage plus 5 necrotic damage, and the target is immobilized until the end of the fist's next turn. Steady Footed ✦ At-Will Trigger: An effect knocks the fist prone. Effect (No Action): The fist makes a saving throw. If the fist saves, it remains standing."}],alignment:"Chaotic Evil",languages:["Common","Dwarven","Primordial Equipment : heavy shield","plate armor","war pick . Monster Manual 3","page(s) 163."] },
  { id:"mm3-howler-dread-hound",name:"Howler Dread Hound",source:"mm3",level:9,role:"Controller",roleModifier:"Minion",xp:100,size:"Medium",origin:"Elemental",type:"Magical beast",hp:1,ac:23,fort:22,ref:22,will:21,initiative:7,perception:6,speed:"8",senses:["Darkvision"],powers:[{name:"Piercing Spines Whenever",action:"Trait",description:"a creature adjacent to the dread hound misses it with a melee attack, that creature takes 6 damage"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 6 damage, and the dread hound slides the target 1 square."},{name:"Dread Howl",action:"Standard",keywords:["fear","psychic"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +12 vs. Will Hit: 4 psychic damage, and the target grants combat advantage until the end of its next turn."}],alignment:"Unaligned",languages:["understands Abyssal Monster Manual 3","page(s) 110","Dungeon Magazine 209."] },
  { id:"mm3-meenlock-stalker",name:"Meenlock Stalker",source:"mm3",level:9,role:"Controller",xp:400,size:"Small",origin:"Aberrant",type:"Humanoid",hp:97,ac:23,fort:20,ref:21,will:22,initiative:8,perception:4,speed:"5",senses:["Darkvision"],immune:["meenlock corruption"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 2d6 + 7 damage."},{name:"Maddening Whispers",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 10 (one creature affected by this stalker's horrid link); +12 vs. Will Hit: 1d6 + 4 psychic damage, and the target is dazed (save ends)."},{name:"Twisting Whispers",action:"Standard",keywords:["charm","disease","psychic"],description:"Attack: Ranged 10 (one creature affected by this stalker's horrid link); +12 vs. Will Hit: 1d6 + 4 psychic damage, and the target makes a basic attack against one creature of the stalker's choice. The target is then exposed to meenlock corruption."},{name:"Dimension Step",action:"Move",keywords:["teleportation"],recharge:"Recharge 3-6",description:"Effect: The stalker teleports 8 squares."},{name:"Horrid Link",action:"Minor",keywords:["psychic"],recharge:"Recharge 3-6",description:"Effect: The stalker forges a link with one creature within 10 squares of it. The link lasts until the start of the stalker's next turn or until the stalker uses horrid link again. Whenever the stalker takes damage, the target of its horrid link takes 1d10 + 5 psychic damage. Skills Athletics +9, Stealth +13"}],alignment:"Unaligned",languages:["Common","Deep Speech Meenlock Corruption Level 9 Disease Stage 0 : The target recovers from the disease. Stage 1 : Initial Effect: The target takes a -4 penalty to Will. Stage 2 : The target grants combat advantage. Stage 3 : Final State: Unless prevented from doing so","the target moves toward the lair of the meenlocks that infected it. Treat the target as dominated by meenlocks until the disease is cured. Check : At the end of each extended rest","the target makes an Insight check if it is at stage 1 or 2. 14 or lower : The stage of the disease increases by one. 15-19 : No Change 20 or higher : The stage of the disease decreases by one. Monster Manual 3","page(s) 132","Dungeon Magazine 190","Dungeon Magazine 214."] },
  { id:"mm3-nagpa-corruptor",name:"Nagpa Corruptor",source:"mm3",level:9,role:"Controller",xp:400,size:"Medium",origin:"Elemental",type:"Humanoid",hp:97,ac:23,fort:19,ref:21,will:21,initiative:6,perception:8,speed:"6",senses:["Low-light vision"],powers:[{name:"Withering Staff",action:"Standard",keywords:["necrotic","weapon"],description:"Attack: Melee 1 (one creature); +13 vs. Reflex Hit: 2d6 + 10 necrotic damage, and the nagpa pushes the target 2 squares."},{name:"Withering Blast",action:"Standard",keywords:["implement","necrotic"],description:"Attack: Ranged 5 (one creature); +13 vs. Will Hit: 2d8 + 4 necrotic damage, and the target is immobilized (save ends)."},{name:"Devouring Fire",action:"Standard",keywords:["implement","fire"],recharge:"Recharge 4-6",description:"Attack: Ranged 5 (one creature); +13 vs. Fortitude Hit: 2d10 + 10 fire damage, and ongoing 5 fire damage (save ends). Each Failed Saving Throw: Each ally within 3 squares of the target takes 5 fire damage."},{name:"Corrupting Curse",action:"Standard",keywords:["necrotic","zone"],recharge:"Encounter",description:"Attack: Area burst 3 within 10 (enemies in the burst); +13 vs. Fortitude Hit: 2d6 + 5 necrotic damage. Effect: The burst creates a zone that lasts until the end of the encounter. Any enemy within the zone cannot regain hit points."},{name:"Enervating Blast",action:"Minor",keywords:["implement"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +13 vs. Will Hit: The target is weakened until the end of the nagpa's next turn. Skills Arcana +13, Bluff +12, Diplomacy +12, History +13"}],alignment:"Evil",languages:["Common","Primordial Equipment : staff implement . Monster Manual 3","page(s) 142."] },
  { id:"mm3-ogre-ironclad",name:"Ogre Ironclad",source:"mm3",level:9,role:"Soldier",xp:400,size:"Large",origin:"Natural",type:"Humanoid",hp:96,ac:0,fort:0,ref:0,will:0,initiative:9,perception:3,speed:"8",powers:[{name:"Barreling Charge",action:"Trait",description:"While bloodied, the ironclad uses a melee basic attack against one or two targets at the end of a charge instead of against one target"},{name:"Maul",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +14 vs. AC Hit: 2d8 + 8 damage, and the target is marked until the end of the ironclad's next turn."},{name:"Ironclad Reaction",action:"Triggered",keywords:["weapon"],description:"Trigger: An enemy marked by the ironclad makes an attack that does not include the ironclad as a target. Attack (Immediate Reaction): Melee 2 (the triggering enemy); +14 vs. AC Hit: 2d8 + 8 damage, and the ironclad pushes the target 1 square and knocks it prone."}],alignment:"Chaotic Evil",languages:["Giant Equipment : chainmail","maul . Monster Manual 3","page(s) 158."] },
  { id:"mm3-shadow-strangler",name:"Shadow Strangler",source:"mm3",level:9,role:"Artillery",xp:400,size:"Medium",origin:"Shadow",type:"Humanoid",hp:53,ac:23,fort:18,ref:21,will:22,initiative:8,perception:6,speed:"8",senses:["Darkvision"],resist:["insubstantial"],vulnerable:["5 radiant"],powers:[{name:"Born",action:"Trait",description:"of Shadows The strangler can make a Stealth check to become hidden when it has concealment instead of needing total concealment"},{name:"Shadowy Touch",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 1 (one creature); +12 vs. Reflex Hit: 2d6 + 5 necrotic damage, and the strangler becomes invisible to the target until the end of the strangler's next turn."},{name:"Blinding Shadows",action:"Standard",keywords:["necrotic"],description:"Attack: Ranged 10 (one creature); +14 vs. Reflex Hit: 2d6 + 5 necrotic damage, and the target cannot see anything more than 3 squares away from it until the end of the strangler's next turn."},{name:"Strangling Darkness",action:"Standard",keywords:["necrotic"],recharge:"Recharge 4-6",description:"Attack: Ranged 10 (one creature); +14 vs. Fortitude Hit: The target is restrained and takes ongoing 15 necrotic damage (save ends both)."},{name:"Devouring Dark",action:"Standard",keywords:["necrotic"],recharge:"Encounter",description:"Attack: Area burst 2 within 10 (enemies in the burst); +14 vs. Reflex Hit: 1d10 + 7 necrotic damage, and the target is blinded until the end of the strangler's next turn. Miss: Half damage. Skills Arcana +10, Stealth +13"}],alignment:"Evil",languages:["Common Monster Manual 3","page(s) 172","Dungeon Magazine 192","Dungeon Magazine 214","Dungeon Magazine 215","Dungeon Magazine 218."] },
  { id:"mm3-spirehorn-behemoth",name:"Spirehorn Behemoth",source:"mm3",level:9,role:"Brute",roleModifier:"Elite",xp:800,size:"Huge",origin:"Natural",type:"Beast",keywords:["mount","reptile"],hp:234,ac:21,fort:23,ref:19,will:21,initiative:6,perception:7,speed:"6",powers:[{name:"Beastmaster",action:"Trait",keywords:["mount"],description:"While the behemoth has a friendly rider of 9th level or higher mounted on it, the rider gains a +1 bonus to AC and Reflex"},{name:"Gore",action:"Standard",description:"Attack: Melee 1 (one creature); +14 vs. AC Hit: 3d10 + 5 damage."},{name:"Double Attack",action:"Standard",description:"Effect: The spirehorn uses gore twice."},{name:"Trample",action:"Standard",recharge:"Encounter",description:"Effect: The spirehorn shifts twice its speed and can enter enemies' spaces during the move. Each time the spirehorn enters an enemy's space for the first time during the move, it can use gore against that enemy."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 21","Dungeon Magazine 218."] },
  { id:"mm3-verbeeg-rowdy",name:"Verbeeg Rowdy",source:"mm3",level:9,role:"Skirmisher",xp:400,size:"Large",origin:"Fey",type:"Humanoid",keywords:["giant"],hp:99,ac:23,fort:21,ref:20,will:18,initiative:8,perception:4,speed:"8",senses:["Low-light vision"],powers:[{name:"Combat Advantage",action:"Trait",description:"The rowdy deals 5 extra damage against any creature granting combat advantage to it"},{name:"Verbeeg Stealth",action:"Trait",description:"The rowdy can make a Stealth check to become hidden as long as one square it occupies has superior cover or total concealment from the creature it is attempting to hide from"},{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +14 vs. AC Hit: 2d8 + 8 damage."},{name:"Skewering Strike",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Attack: Melee 2 (one creature); +12 vs. Reflex Hit: 2d12 + 8 damage, and the rowdy slides the target 5 squares to a square within 2 squares of the rowdy."},{name:"Bounding Maneuver",action:"Move",description:"Effect: The rowdy is no longer marked, and it shifts 3 squares and can move through enemies' spaces during the shift."},{name:"Cunning Trick",action:"Minor",recharge:"Recharge 4-6",description:"Attack: Melee 3 (one creature); +12 vs. Will Hit: The rowdy knocks the target prone or slides it 3 squares. Skills Bluff +11, Stealth +11, Thievery +11"}],alignment:"Unaligned",languages:["Common","Elven","Giant Equipment : hide armor","light shield","spear . Monster Manual 3","page(s) 200."] },
  { id:"mm3-young-earthquake-dragon",name:"Young Earthquake Dragon",source:"mm3",level:9,role:"Soldier",roleModifier:"Elite",xp:800,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["dragon","earth"],hp:206,ac:25,fort:22,ref:22,will:20,initiative:12,perception:9,speed:"8 (earth walk), burrow 4, fly 4 (clumsy)",senses:["Darkvision"],powers:[{name:"Quaking Earth",action:"Aura",description:"Aura 1 When any enemy within the aura makes an attack that does not include the dragon as a target, that enemy falls prone and takes 5 damage."},{name:"Bite",action:"Standard",description:"Attack: Melee 2 (one creature); +14 vs. AC Hit: 2d8 + 8 damage."},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +16 vs. AC Hit: 2d6 + 6 damage."},{name:"Double Attack",action:"Standard",description:"Effect: The dragon uses bite and claw or uses claw twice."},{name:"Earthen Maw",action:"Standard",recharge:"Recharge 5-6",description:"Attack: Melee 2 (one creature); +14 vs. Reflex Hit: 2d10 + 6 damage, and the target is restrained (save ends). First Failed Saving Throw: The target is instead petrified (save ends)."},{name:"Rising Tremors",action:"Minor",description:"Recharge at the start of any turn when quaking earth is aura 1 Effect: The quaking earth expands to aura 3. At the start of the dragon's next turn, the quaking earth expands to aura 5. At the start of its following turn, the dragon makes the following attack. Attack (No Action): Close burst 5 (enemies in the burst); +12 vs. Reflex Hit: 3d8 + 5 damage, and the target falls prone and cannot stand up (save ends). Effect: The quaking earth aura reverts to its original state and size (aura 1)."},{name:"Sudden Quake",action:"Triggered",description:"Trigger: The dragon is pulled, pushed, slid, or knocked prone. Effect (Free Action): Each enemy in the dragon's aura falls prone."}],alignment:"Unaligned",languages:["Common","Draconic","Primordial Monster Manual 3","page(s) 69","Dungeon Magazine 218."] },
  { id:"mm3-air-elemental",name:"Air Elemental",source:"mm3",level:10,role:"Lurker",xp:500,size:"Medium",origin:"Elemental",type:"Magical beast",keywords:["air"],hp:81,ac:24,fort:21,ref:23,will:22,initiative:15,perception:5,speed:"0, fly 8 (hover)",vulnerable:["5 fire"],powers:[{name:"Phantom",action:"Trait",description:"on the Wind The air elemental becomes invisible whenever it starts its turn without an enemy adjacent to it"},{name:"The",action:"Trait",description:"invisibility lasts until the end of its next turn or until it attacks"},{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d8 + 5 damage."},{name:"Rampant Storm",action:"Standard",description:"Attack: Close blast 3 (enemies in the blast); +13 vs. Reflex Hit: 3d8 + 5 damage, and the target is dazed until the end of the air elemental's next turn if it could not see the elemental before the attack. Skills Stealth +16"}],alignment:"Unaligned",languages:["understands Primordial Monster Manual 3","page(s) 80."] },
  { id:"mm3-awakened-rot-grub-swarm",name:"Awakened Rot Grub Swarm",source:"mm3",level:10,role:"Brute",xp:500,size:"Medium",origin:"Natural",type:"Beast",keywords:["swarm"],hp:123,ac:21,fort:20,ref:19,will:22,initiative:6,perception:5,speed:"5",senses:["Darkvision"],resist:["half damage from melee and ranged attacks"],vulnerable:["10 against close and area attacks"],powers:[{name:"Swarm Attack",action:"Aura",description:"Aura 1 Any enemy that starts its turn within the aura takes 10 damage plus 2 extra damage for each additional rot grub swarm adjacent to the enemy"},{name:"Swarm",action:"Trait",description:"The awakened rot grub swarm can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"The",action:"Trait",description:"awakened rot grub swarm cannot be pulled, pushed, or slid by melee or ranged attacks"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for at least one of the creatures it comprises"},{name:"Clumsy Attacker",action:"Trait",description:"The awakened rot grub swarm lacks a melee basic attack"},{name:"Infesting Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: Ongoing 10 damage (save ends). First Failed Saving Throw: Ongoing 15 damage (save ends). Second Failed Saving Throw: Ongoing 20 damage (save ends)."},{name:"Psychic Shock",action:"Standard",recharge:"Recharge 3-6",description:"Attack: Close burst 2 (enemies in the burst); +13 vs. Will Hit: The target is immobilized until the end of the awakened swarm's next turn."},{name:"Telepathic Lure",action:"Minor",description:"1/round Attack: Ranged 5 (one creature); +13 vs. Will Hit: The swarm pulls the target 4 squares."}],alignment:"Unaligned",languages:["Deep Speech","telepathy 10 Monster Manual 3","page(s) 167","Dungeon Magazine 188."] },
  { id:"mm3-blue-arcanian",name:"Blue Arcanian",source:"mm3",level:10,role:"Controller",xp:500,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:105,ac:24,fort:22,ref:21,will:19,initiative:5,perception:6,speed:"5",powers:[{name:"Frost Staff",action:"Standard",keywords:["cold","weapon"],description:"Attack: Melee 1 (one creature); +13 vs. Fortitude Hit: 2d8 + 9 cold damage, and the arcanian pushes the target 2 squares. The target is immobilized until the end of the arcanian's next turn."},{name:"Bolt of Frost",action:"Standard",keywords:["cold","implement"],description:"Attack: Ranged 5 (one creature); +13 vs. Fortitude Hit: 2d8 + 9 cold damage, and the target's space and all squares adjacent to it are difficult terrain until the end of the arcanian's next turn."},{name:"Swirling Blizzard",action:"Standard",keywords:["cold","implement"],recharge:"Encounter",description:"Attack: Area burst 2 within 5 (enemies in the burst); +13 vs. Reflex Hit: 2d8 + 9 cold damage. Miss: Half damage."},{name:"Staff of Shielding",action:"Triggered",recharge:"Encounter",description:"Trigger: An attack hits the arcanian. Effect (Immediate Interrupt): The arcanian gains a +4 bonus to all defenses against the triggering attack."},{name:"Arcane Surge",action:"Triggered",recharge:"Encounter",description:"Trigger: The arcanian hits an enemy with an implement attack. Effect (Free Action): The attack deals maximum damage to the enemy. Skills Arcana +14"}],alignment:"Unaligned",languages:["Common Equipment : staff implement . Monster Manual 3","page(s) 17","Dungeon Magazine 189."] },
  { id:"mm3-catoblepas-harbinger",name:"Catoblepas Harbinger",source:"mm3",level:10,role:"Controller",roleModifier:"Elite",xp:1000,size:"Large",origin:"Shadow",type:"Beast",hp:220,ac:24,fort:22,ref:20,will:22,initiative:7,perception:15,speed:"6",senses:["Blindsight 5"],resist:["5 necrotic"],vulnerable:["5 to all damage (save ends both). Aftereffect:","10 necrotic damage."],powers:[{name:"Raven Queen's Presence",action:"Aura",description:"Aura 5 Any creature within the aura that fails a death saving throw takes damage equal to half its bloodied value."},{name:"Gore",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d8 + 9 damage."},{name:"Poison Breath",action:"Standard",keywords:["poison"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (creatures in the blast); +13 vs. Fortitude Hit: 2d6 + 6 poison damage, and ongoing 5 poison damage (save ends)."},{name:"Final Glance",action:"Triggered",keywords:["charm","necrotic"],description:"Trigger: An enemy within 5 squares of the harbinger willingly moves away from it. Attack (Opportunity Action): Close burst 10 (the triggering enemy in the burst); +13 vs. Will Hit: 5 necrotic damage, and the target is immobilized and gains vulnerable 5 to all damage (save ends both). Aftereffect: 10 necrotic damage."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 27."] },
  { id:"mm3-chained-cambion",name:"Chained Cambion",source:"mm3",level:10,role:"Controller",xp:500,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["devil"],hp:110,ac:24,fort:22,ref:20,will:24,initiative:8,perception:9,speed:"6",senses:["Darkvision"],resist:["10 fire"],powers:[{name:"Binding Field",action:"Aura",description:"Aura 3 Squares within the aura are difficult terrain for enemies"},{name:"Child",action:"Trait",description:"of Chains While immobilized or restrained, the chained cambion gains a +2 bonus to attack rolls and gains a +2 bonus to attempts to escape a grab and to saving throws against effects that immobilize or restrain"},{name:"Chain Lash",action:"Standard",description:"Attack: Melee 3 (one creature); +15 vs. AC Hit: 3d6 + 8 damage, and a dazed target is immobilized (save ends)."},{name:"Vile Fetters",action:"Standard",keywords:["psychic"],description:"Attack: Melee 5 (one creature); +13 vs. Will Hit: 2d6 + 6 psychic damage, and if the target ends its next turn closer to the chained cambion, it is dazed (save ends)."},{name:"Unfettered Scream",action:"Standard",keywords:["psychic"],recharge:"Recharge 4-6",description:"Attack: Close blast 3 (creatures in the blast); +13 vs. Fortitude Hit: 2d6 + 6 psychic damage, and the chained cambion pushes the target 2 squares. The target is also dazed (save ends)."},{name:"Mind Shackles",action:"Minor",keywords:["psychic"],recharge:"Recharge when first bloodied",description:"Effect: Two enemies adjacent to each other in a close burst 5 are psychically shackled (save ends; each enemy makes a separate saving throw against this effect). While psychically shackled, an enemy takes 10 psychic damage at the start and the end of its turn if it isn't adjacent to the other creature that was affected by this power. Aftereffect: The effect persists, and the damage decreases to 5 (save ends)."}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 25","Dungeon Magazine 218."] },
  { id:"mm3-foulspawn-mockery",name:"Foulspawn Mockery",source:"mm3",level:10,role:"Controller",xp:500,size:"Medium",origin:"Aberrant",type:"Humanoid",hp:104,ac:24,fort:19,ref:22,will:20,initiative:8,perception:9,speed:"6, teleport 3",senses:["Low-light vision"],powers:[{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 3d6 + 6 damage."},{name:"Mind Harrier",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 5 (one creature); +13 vs. Will Hit: 2d6 + 6 psychic damage. At the end of the target's next turn, if it is not adjacent to any of its allies, it takes 10 psychic damage and ongoing 10 psychic damage (save ends)."},{name:"Maddening Burst",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Area burst 1 within 10 (enemies in the burst); +13 vs. Will Hit: 2d6 + 6 psychic damage, and the target is dazed (save ends)."}],alignment:"Unaligned",languages:["Deep Speech","telepathy 10 Monster Manual 3","page(s) 89","Dungeon Magazine 196."] },
  { id:"mm3-scarecrow-shambler",name:"Scarecrow Shambler",source:"mm3",level:10,role:"Brute",roleModifier:"Minion",xp:125,size:"Medium",origin:"Fey",type:"Animate",keywords:["construct"],hp:1,ac:22,fort:22,ref:21,will:21,initiative:7,perception:7,speed:"6",senses:["Low-light vision"],immune:["disease, poison, sleep"],powers:[{name:"Claws",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 11 damage."},{name:"Toxic Straw",action:"Triggered",keywords:["poison","zone"],recharge:"Encounter",description:"Trigger: The shambler drops to 0 hit points. Effect (No Action): The shambler's death creates a zone in a close burst 1 that lasts until the end of the encounter. The zone is lightly obscured, and any creature that ends its turn within the zone takes 10 poison damage."}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 168."] },
  { id:"mm3-sea-kraken",name:"Sea Kraken",source:"mm3",level:10,role:"Soldier",roleModifier:"Solo",xp:2500,size:"Gargantuan",origin:"Aberrant",type:"Magical beast",keywords:["aquatic"],hp:432,ac:24,fort:26,ref:22,will:22,initiative:13,perception:15,speed:"6, swim 10",senses:["Darkvision"],powers:[{name:"Aquatic",action:"Trait",description:"The sea kraken can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Threatening Reach",action:"Trait",description:"The sea kraken can make opportunity attacks against all enemies within 3 squares of it"},{name:"Crushing Tentacles",action:"Standard",description:"Attack: Melee 3 (one creature); +15 vs. AC Hit: 2d8 + 5 damage, and the kraken grabs the target. The kraken can grab up to eight creatures at one time. Sustain Minor: The kraken sustains all its grabs, and each creature grabbed by the kraken takes 5 damage."},{name:"Devourer of Ships",action:"Standard",description:"Attack: Melee 3 (one vehicle); +13 vs. Fortitude Hit: 2d10 + 10 damage, and the target is restrained while the kraken remains within 3 squares of it. While restrained by this power, the vehicle takes 20 damage at the start of the kraken's turn. The pilot of the vehicle can spend a standard action to give the vehicle a saving throw. On a save, the vehicle is no longer restrained."},{name:"Coils of Doom",action:"Standard",description:"Effect: The kraken uses crushing tentacles twice and devourer of ships once. Wavewrack (zone) ✦ Encounter Effect: The kraken creates a zone in a close burst 3 that lasts until the end of the encounter. The zone is difficult terrain. Any creature that starts its turn within the zone takes 5 damage and is slid 2 squares. Once per round as a minor action, the kraken can move the zone up to 3 squares."},{name:"Fatal Plunge",action:"Minor",description:"Attack: Melee 1 (one creature grabbed by the kraken); +13 vs. Fortitude Hit: 1d8 + 5 damage, and the kraken slides the target 3 squares."},{name:"Fling",action:"Minor",description:"Effect: The kraken slides a creature grabbed by it 5 squares to a square adjacent to a creature. The grab ends, and the kraken makes the following melee attack against both creatures. Attack: Melee 6 (two creatures); +13 vs. Fortitude Hit: 1d8 + 5 damage, and the target falls prone."},{name:"Venom Bolt",action:"Minor",keywords:["poison"],description:"1/round Attack: Ranged 10 (one creature); +13 vs. Fortitude Hit: 2d8 + 4 poison damage, and the target is blinded (save ends)."},{name:"Vengeful Constriction",action:"Triggered",description:"Trigger: A creature grabbed by the kraken deals damage to it. Effect (Immediate Reaction): Each creature grabbed by the kraken takes 5 damage."}],alignment:"Unaligned",languages:["telepathy 20 Monster Manual 3","page(s) 122."] },
  { id:"mm3-shardmind-executioner",name:"Shardmind Executioner",source:"mm3",level:10,role:"Lurker",xp:500,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["living construct"],hp:81,ac:22,fort:18,ref:20,will:21,initiative:11,perception:14,speed:"6",resist:["5 psychic"],powers:[{name:"Shardblade",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d10 + 7 damage."},{name:"Mind Shadows",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 10 (one creature); +13 vs. Will Hit: 1d8 + 4 psychic damage, and the target is blinded until the end of the executioner's next turn."},{name:"Psychic Infiltration",action:"Standard",keywords:["psychic","weapon"],description:"Attack: Melee 1 (one creature that cannot see the executioner); +13 vs. Will Hit: The target takes ongoing 20 psychic damage and is dazed (save ends both). Until the target saves against this effect or drops to 0 hit points or fewer, the executioner is removed from play. When this effect ends, the executioner appears in an unoccupied square of its choice adjacent to the target."},{name:"Shardswarm",action:"Move",keywords:["teleportation"],recharge:"Encounter",description:"Effect: Each enemy adjacent to the executioner grants combat advantage until the end of the executioner's next turn. The executioner then teleports 3 squares."},{name:"Psionic Boost",action:"Triggered",keywords:["psychic"],recharge:"Recharge 4-6",description:"Trigger: The executioner hits with shardblade or mind shadows. Effect (Free Action): The attack deals 2d6 extra psychic damage. Skills Athletics +11, Bluff +11, Stealth +12"}],alignment:"Unaligned",languages:["Common","Deep Speech","telepathy 5 Equipment : greatsword . Monster Manual 3","page(s) 175."] },
  { id:"mm3-su-sentinel",name:"Su Sentinel",source:"mm3",level:10,role:"Skirmisher",xp:500,size:"Medium",origin:"Fey",type:"Beast",hp:107,ac:24,fort:22,ref:24,will:21,initiative:12,perception:13,speed:"7 (forest walk), climb 7",senses:["Darkvision"],powers:[{name:"Skirmish",action:"Trait",description:"If the sentinel moves at least 4 squares away from its starting square, its attacks deal 5 extra damage until the start of its next turn"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 3d6 + 7 damage."},{name:"Flashing Talons",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d6 + 4 damage, and if the target moves willingly into a space adjacent to the sentinel before the end of the target's next turn, the sentinel can use this attack against the target as an immediate reaction. Effect: The sentinel shifts 2 squares."},{name:"Mind-Rending Bite",action:"Standard",keywords:["psychic"],recharge:"Recharge 3-6",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 1d6 + 5 damage, and ongoing 10 psychic damage (save ends)."},{name:"Psionic Boost",action:"Triggered",keywords:["psychic"],recharge:"Recharge when the sentinel takes psychic damage",description:"Trigger: The sentinel hits with claw or flashing talons. Effect (Free Action): The attack deals 2d6 extra psychic damage."},{name:"Tribal Fury",action:"Triggered",description:"Trigger: An ally within 3 squares is first bloodied. Effect (Free Action): The sentinel uses claw. Skills Acrobatics +15, Athletics +13, Stealth +15"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 188."] },
  { id:"mm3-wood-nymph",name:"Wood Nymph",source:"mm3",level:10,role:"Soldier",xp:500,size:"Medium",origin:"Fey",type:"Humanoid",hp:104,ac:26,fort:21,ref:21,will:24,initiative:10,perception:13,speed:"6 (forest walk)",senses:["Low-light vision"],powers:[{name:"Regeneration",action:"Trait",keywords:["healing"],description:"Whenever the wood nymph has at least 1 hit point and starts its turn adjacent to or within its tree, it regains 5 hit points"},{name:"Treebound",action:"Trait",description:"Each wood nymph is bound to a tree that occupies 1 square"},{name:"The",action:"Trait",description:"wood nymph can enter this square and has superior cover while there. In addition, the wood nymph treats the tree as an ally for the purpose of flanking"},{name:"Wooden Hands",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 3d8 + 5 damage, and the target is slowed until the end of the nymph's next turn."},{name:"Trapped in the Wood",action:"Standard",keywords:["teleportation"],recharge:"Recharge when no enemy is within the nymph's tree",description:"Attack: Melee 1 (one creature); +13 vs. Reflex Hit: The nymph teleports the target 6 squares to the square containing the nymph's tree, and the target is removed from play (save ends). When the effect ends, the target appears in an unoccupied square of its choice adjacent to the tree. Effect: The nymph teleports 8 squares to a square adjacent to its tree."},{name:"Lonely Keening",action:"Standard",keywords:["charm","psychic"],recharge:"Encounter",description:"Attack: Ranged 20 (one creature); +15 vs. Will Hit: 2d8 + 9 psychic damage. Effect: Until the end of the encounter or until the nymph drops to 0 hit points, the target is marked and takes 5 damage at the end of any turn in which it is not either adjacent to the nymph or closer to the nymph than when it began its turn."},{name:"Tree Home",action:"Minor",keywords:["teleportation"],description:"Requirement: The nymph must be within 6 squares of its tree. Effect: The nymph teleports to a square adjacent to its tree. Skills Diplomacy +15, Insight +13, Nature +13"}],alignment:"Unaligned",languages:["Common","Elven Monster Manual 3","page(s) 152."] },
  { id:"mm3-earth-elemental",name:"Earth Elemental",source:"mm3",level:11,role:"Soldier",xp:600,size:"Medium",origin:"Elemental",type:"Magical beast",keywords:["earth"],hp:119,ac:26,fort:24,ref:21,will:22,initiative:5,perception:5,speed:"7, burrow 7",senses:["Tremorsense 5"],vulnerable:["thunder (see brittle skin)"],powers:[{name:"Earth Glide",action:"Trait",description:"The earth elemental can pass through earth and rock as if it were phasing"},{name:"Brittle Skin Whenever",action:"Trait",description:"the earth elemental takes thunder damage, it takes a -2 penalty to all defenses until the end of its next turn"},{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +16 vs. AC Hit: 3d8 + 6 damage, and the target cannot shift until the end of the elemental's next turn."},{name:"Quake Stomp",action:"Standard",recharge:"Recharge when first bloodied",description:"Attack: Close burst 4 (enemies in the burst); +14 vs. Fortitude Hit: 2d8 + 6 damage, and the elemental slides the target 2 squares and knocks it prone."}],alignment:"Unaligned",languages:["understands Primordial Monster Manual 3","page(s) 81","Dungeon Magazine 218."] },
  { id:"mm3-fire-elemental",name:"Fire Elemental",source:"mm3",level:11,role:"Skirmisher",xp:600,size:"Medium",origin:"Elemental",type:"Magical beast",keywords:["fire"],hp:107,ac:24,fort:22,ref:24,will:23,initiative:14,perception:6,speed:"10, fly 6 (clumsy)",vulnerable:["cold (see frozen in place)"],powers:[{name:"Frozen",action:"Trait",description:"in Place Whenever the fire elemental takes cold damage, it cannot shift until the end of its next turn"},{name:"Slam",action:"Standard",keywords:["fire"],description:"Attack: Melee 1 (one creature); +14 vs. Reflex Hit: Ongoing 10 fire damage (save ends)."},{name:"Flickering Flame",action:"Minor",description:"Effect: The elemental shifts 2 squares."},{name:"Seething Fire",action:"Triggered",keywords:["fire"],description:"Trigger: An attack hits the elemental. Effect (Free Action): Each enemy adjacent to the elemental takes 5 fire damage."}],alignment:"Unaligned",languages:["understands Primordial Monster Manual 3","page(s) 82","Dungeon Magazine 186","Dungeon Magazine 197","Dungeon Magazine 215."] },
  { id:"mm3-hill-giant-smasher",name:"Hill Giant Smasher",source:"mm3",level:11,role:"Brute",xp:600,size:"Large",origin:"Natural",type:"Humanoid",keywords:["giant"],hp:137,ac:23,fort:24,ref:20,will:23,initiative:7,perception:8,speed:"8",powers:[{name:"Mobility At",action:"Trait",description:"the start of each of its turns, the smasher can make a saving throw against one effect that a save can end"},{name:"The",action:"Trait",description:"effect must include the immobilized, restrained, or slowed condition"},{name:"Greatclub",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +16 vs. AC Hit: 2d10 + 10 damage, and a different enemy adjacent to the smasher takes 7 damage."},{name:"Brutal Smash",action:"Standard",keywords:["weapon"],description:"Recharge if the power misses Attack: Melee 2 (one creature); +16 vs. AC Hit: 4d10 + 14 damage."},{name:"Whirling Crush",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Attack: Close burst 2 (enemies in the burst); +16 vs. AC Hit: 2d10 + 8 damage."},{name:"Persistent Smash",action:"Triggered",description:"Trigger: The smasher drops to 0 hit points.. The smasher moves half its speed and uses greatclub. Skills Athletics +15"}],alignment:"Unaligned",languages:["Giant Equipment : greatclub","hide armor . Monster Manual 3","page(s) 100","Dungeon Magazine 220."] },
  { id:"mm3-meazel-bravo",name:"Meazel Bravo",source:"mm3",level:11,role:"Brute",xp:600,size:"Medium",origin:"Natural",type:"Humanoid",hp:136,ac:23,fort:24,ref:22,will:22,initiative:7,perception:7,speed:"6",senses:["Darkvision"],immune:["disease"],vulnerable:["5 to all damage. In addition, any ally of that creature that starts its turn adjacent to the cursed creature becomes affected by the curse of Baalzebul until the end of its next turn. Multiple curses do not stack."],powers:[{name:"Wretched Curse of Baalzebul",action:"Aura",description:"Aura 1 Any enemy that starts its turn within the aura is affected by the curse of Baalzebul until the end of its next turn"},{name:"While",action:"Trait",description:"a creature is affected by the curse of Baalzebul, it takes a -2 penalty to all defenses and gains vulnerable 5 to all damage. In addition, any ally of that creature that starts its turn adjacent to the cursed creature becomes affected by the curse of Baalzebul until the end of its next turn"},{name:"Multiple",action:"Trait",description:"curses do not stack"},{name:"Morningstar",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +16 vs. AC Hit: 2d10 + 10 damage."},{name:"Gut Shot",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +14 vs. Fortitude Hit: 2d10 + 6 damage, and the target is weakened until the end of the bravo's next turn. Skills Athletics +14, Stealth +12"}],alignment:"Unaligned",languages:["Common Equipment : leather armor","morningstar . Monster Manual 3","page(s) 130."] },
  { id:"mm3-meenlock-corruptor",name:"Meenlock Corruptor",source:"mm3",level:11,role:"Lurker",xp:600,size:"Small",origin:"Aberrant",type:"Humanoid",hp:89,ac:25,fort:22,ref:23,will:24,initiative:13,perception:6,speed:"5",senses:["Darkvision"],immune:["meenlock corruption"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +16 vs. AC Hit: 3d6 + 5 damage."},{name:"Corrupting Mind",action:"Standard",keywords:["charm","disease","illusion"],description:"Attack: Ranged 10 (one creature); +14 vs. Will Hit: The target is exposed to meenlock corruption. In addition, the target is affected by mental disarray (save ends). While the target is affected by mental disarray, it is dominated, it deals 2d6 extra damage with all attacks, and the corruptor is invisible to the target. First Failed Saving Throw: The target is affected by mental disarray until the end of the encounter. Whenever the target takes 10 damage or more, the corruptor takes an equal amount of damage, and the target can make a saving throw to end the mental disarray."},{name:"Psychic Shriek",action:"Standard",keywords:["psychic"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +14 vs. Will Hit: 2d6 + 5 psychic damage, and the target falls prone. Miss: Half damage."},{name:"Dimension Step",action:"Move",keywords:["teleportation"],recharge:"Recharge 3-6",description:"Effect: The corruptor teleports 8 squares. Skills Athletics +10, Stealth +14"}],alignment:"Chaotic Evil",languages:["Common","Deep Speech Monster Manual 3","page(s) 133."] },
  { id:"mm3-ogre-storm-shaman",name:"Ogre Storm Shaman",source:"mm3",level:11,role:"Controller",xp:600,size:"Large",origin:"Natural",type:"Humanoid",hp:114,ac:25,fort:23,ref:20,will:22,initiative:8,perception:8,speed:"8",powers:[{name:"Thunder Staff",action:"Standard",keywords:["thunder","weapon"],description:"Attack: Melee 2 (one creature); +16 vs. AC Hit: 3d6 + 9 thunder damage. A blinded or deafened target is also dazed (save ends)."},{name:"Thunder Blast",action:"Standard",keywords:["thunder"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (enemies in the blast); +14 vs. Fortitude Hit: 2d6 + 6 thunder damage, and the target is deafened (save ends)."},{name:"Call Lightning",action:"Standard",keywords:["lightning"],recharge:"Recharge when first bloodied",description:"Attack: Area burst 1 within 10 (enemies in the burst); +14 vs. Reflex Hit: 3d6 + 6 lightning damage, and the target is blinded (save ends)."},{name:"Drenching Rain",action:"Minor",description:"Effect: The storm shaman creates a zone in an area burst 3 within 10 squares that lasts until the end of the encounter or until the storm shaman uses this power again. Any enemy within the zone takes a -2 penalty to attack rolls and a -2 penalty to all defenses."}],alignment:"Chaotic Evil",languages:["Giant Equipment : hide armor","staff implement . Monster Manual 3","page(s) 159","Dungeon Magazine 218."] },
  { id:"mm3-pact-hag",name:"Pact Hag",source:"mm3",level:11,role:"Controller",xp:0,size:"Medium",origin:"Fey",type:"Humanoid",hp:115,ac:25,fort:23,ref:23,will:24,initiative:7,perception:15,speed:"6",senses:["Low-light vision"],powers:[{name:"Pact of Obedience",action:"Aura",description:"Aura 5 Any ally within the aura that misses with a melee attack can take 5 damage to gain a +2 power bonus to the attack roll."},{name:"Compelling Staff",action:"Standard",keywords:["charm","weapon"],description:"Attack: Melee 1 (one creature); +16 vs. AC Hit: 1d6 + 5 damage, and the target makes a melee basic attack as a free action against a creature of the hag's choice."},{name:"Pact of Compelled Alliance",action:"Standard",keywords:["charm"],description:"Attack: Ranged 10 (one creature); +14 vs. Will Hit: The target is dominated until the end of the hag's next turn."},{name:"Pact of Choked Aggression",action:"Standard",keywords:["charm","psychic"],recharge:"Recharge when no creature is affected by this power",description:"Attack: Ranged 10 (one creature); +14 vs. Will Hit: The target is affected by a pact of choked aggression until the end of the encounter or until the hag or one of its allies attacks the target. While affected by the pact, the target takes 10 psychic damage the first time it hits a creature during each of its turns."},{name:"Pact of Shared Agony",action:"Standard",keywords:["psychic"],description:"Recharge if the power misses Requirement: The hag must be bloodied. Attack: Ranged 10 (one creature); +14 vs. Fortitude Hit: Until the end of the encounter, while the target is within 10 squares of the hag, the target takes 10 psychic damage whenever the hag takes damage. Skills Arcana +14, Bluff +13, Diplomacy +13, Insight +15"}],alignment:"Unaligned",languages:["Common","Elven","Giant Equipment : staff implement . Monster Manual 3","page(s) 108."] },
  { id:"mm3-rage-devil",name:"Rage Devil",source:"mm3",level:11,role:"Brute",xp:600,size:"Large",origin:"Immortal",type:"Humanoid",keywords:["devil"],hp:138,ac:23,fort:24,ref:21,will:23,initiative:7,perception:9,speed:"6",senses:["Darkvision"],resist:["20 fire"],powers:[{name:"Blood Rage",action:"Trait",description:"The rage devil deals 2d6 extra damage against bloodied enemies"},{name:"Disrupting Maul",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +16 vs. AC Hit: 2d12 + 5 damage, and the target loses all resistances until the end of its next turn."},{name:"Maul Storm",action:"Standard",keywords:["weapon"],description:"Attack: Close burst 2 (enemies in the burst); +16 vs. AC Hit: 1d12 + 5 damage, and the devil pushes the target 3 squares. If the target is bloodied after this attack, it falls prone."},{name:"Demonscourge Crush",action:"Standard",recharge:"Recharge 3-6",description:"Attack: Melee 2 (one creature); +14 vs. Fortitude Hit: 2d12 + 5 damage, and the target is weakened and loses all resistances (save ends both). Skills Athletics +15, Endurance +14"}],alignment:"Unaligned",languages:["Supernal Equipment : maul . Monster Manual 3","page(s) 60","Dungeon Magazine 218."] },
  { id:"mm3-su-ambusher",name:"Su Ambusher",source:"mm3",level:11,role:"Soldier",roleModifier:"Minion",xp:150,size:"Medium",origin:"Fey",type:"Beast",hp:1,ac:27,fort:21,ref:25,will:23,initiative:13,perception:14,speed:"7 (forest walk), climb 7",senses:["Darkvision"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 8 damage."},{name:"Seize Prey",action:"Standard",description:"Effect: The ambusher moves its speed and makes the following attack at any point during the move. Attack: Melee 1 (one creature); +14 vs. Fortitude Hit: 8 damage. If the ambusher continues the move after the attack, it pulls the target with it and does not provoke opportunity attacks from the target."},{name:"Tribal Fury",action:"Triggered",recharge:"Encounter",description:"Trigger: An ally within 3 squares is first bloodied. Effect (Free Action): The ambusher uses claw."},{name:"Grasping Claws",action:"Triggered",recharge:"Encounter",description:"Trigger: The ambusher drops to 0 hit points. Effect (Immediate Interrupt): The ambusher uses claw. Skills Acrobatics +16, Athletics +13, Stealth +16"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 189","Dungeon Magazine 215."] },
  { id:"mm3-verbeeg-ringleader",name:"Verbeeg Ringleader",source:"mm3",level:11,role:"Artillery",xp:0,size:"Large",origin:"Fey",type:"Humanoid",keywords:["giant"],hp:91,ac:25,fort:23,ref:23,will:24,initiative:7,perception:10,speed:"8",senses:["Low-light vision"],powers:[{name:"Cunning Insight",action:"Aura",description:"Aura 5 Any ally within the aura gains a +5 power bonus to damage rolls against any creature granting combat advantage to that ally"},{name:"Verbeeg Stealth",action:"Trait",description:"The ringleader can make a Stealth check to become hidden as long as one square it occupies has superior cover or total concealment from the creature it is attempting to hide from"},{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +16 vs. AC Hit: 2d8 + 5 damage."},{name:"Longbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 15/30 (one creature); +18 vs. AC Hit: 2d10 + 8 damage, and the target grants combat advantage until the end of the ringleader's next turn."},{name:"Distracting Shot",action:"Standard",recharge:"Recharge 4-6",description:"Effect: The ringleader uses longbow. If the attack hits, one of the ringleader's allies can make a melee basic attack against the target of the attack as a free action. Get Them! ✦ Encounter Effect: Three of the ringleader's allies within 5 squares of it can charge one creature of the ringleader's choice as a free action. Skills Arcana +13, Stealth +12, Thievery +12"}],alignment:"Unaligned",languages:["Common","Elven","Giant Equipment : arrow x40","hide armor","longbow","spear . Monster Manual 3","page(s) 201."] },
  { id:"mm3-verbeeg-trickster",name:"Verbeeg Trickster",source:"mm3",level:11,role:"Controller",xp:600,size:"Large",origin:"Fey",type:"Humanoid",keywords:["giant"],hp:115,ac:25,fort:23,ref:21,will:19,initiative:7,perception:5,speed:"8",senses:["Low-light vision"],powers:[{name:"Verbeeg Stealth",action:"Trait",description:"The trickster can make a Stealth check to become hidden as long as one square it occupies has superior cover or total concealment from the creature it is attempting to hide from"},{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +16 vs. AC Hit: 2d8 + 10 damage, and the target falls prone."},{name:"Staggering Bolt",action:"Standard",keywords:["force","implement"],description:"Attack: Ranged 5 (one creature); +14 vs. Reflex Hit: 3d6 + 9 force damage, and the trickster slides the target 1 square."},{name:"Blinding Blast",action:"Standard",keywords:["implement","radiant"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (enemies in the blast); +14 vs. Fortitude Hit: 1d6 + 5 radiant damage, and the target is blinded until the end of the trickster's next turn."},{name:"Bewildering Bolt",action:"Standard",keywords:["implement","psychic"],recharge:"Encounter",description:"Attack: Ranged 10 (one creature); +14 vs. Will Hit: 1d10 + 7 psychic damage, and the target cannot attack (save ends). Concealing Mist (zone) ✦ Encounter Effect: The trickster creates a zone in a close burst 2 that is lightly obscured and lasts until the end of the encounter. Any verbeeg that starts its turn within the zone gains combat advantage against creatures outside the zone until the end of the verbeeg's turn. Skills Arcana +13, Stealth +12, Thievery +12"}],alignment:"Unaligned",languages:["Common","Elven","Giant Equipment : hide armor","spear","wand implement . Monster Manual 3","page(s) 201."] },
  { id:"mm3-water-elemental",name:"Water Elemental",source:"mm3",level:11,role:"Controller",xp:600,size:"Medium",origin:"Elemental",type:"Magical beast",keywords:["aquatic","water"],hp:111,ac:25,fort:24,ref:23,will:22,initiative:8,perception:5,speed:"6, swim 6",vulnerable:["cold (see sensitive to cold)"],powers:[{name:"Aquatic",action:"Trait",description:"The elemental can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Sensitive",action:"Trait",description:"to Cold Whenever the water elemental takes cold damage, it gains vulnerable 5 against the next attack that hits it before the end of its next turn"},{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +14 vs. Reflex Hit: 2d6 damage, and ongoing 10 damage (save ends)."},{name:"Whirlpool",action:"Standard",recharge:"Encounter",description:"Attack: Close burst 2 (enemies in the burst); +14 vs. Fortitude Hit: 4d6 + 7 damage, and the elemental slides the target 3 squares."},{name:"Drowning Essence",action:"Minor",description:"1/round Effect: The elemental slides each creature that has ongoing damage from its slam 2 squares."}],alignment:"Unaligned",languages:["understands Primordial Monster Manual 3","page(s) 83","Dungeon Magazine 186","Dungeon Magazine 202","Dungeon Magazine 215."] },
  { id:"mm3-adult-blizzard-dragon",name:"Adult Blizzard Dragon",source:"mm3",level:12,role:"Controller",roleModifier:"Elite",xp:1400,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["cold","dragon"],hp:252,ac:26,fort:24,ref:25,will:23,initiative:12,perception:11,speed:"8 (ice walk), fly 8 (clumsy)",senses:["Darkvision"],powers:[{name:"Freezing Winds",action:"Aura",description:"Aura 1 The dragon slides any enemy that ends its turn in the aura 1 square."},{name:"Bite",action:"Standard",keywords:["cold"],description:"Attack: Melee 2 (one creature); +17 vs. AC Hit: 2d8 + 6 cold damage, and the target is immobilized until the end of the dragon's next turn."},{name:"Claw",action:"Standard",keywords:["cold"],description:"Attack: Melee 2 (one creature); +17 vs. AC Hit: 3d6 + 10 cold damage, and the dragon slides the target 2 squares."},{name:"Double Attack",action:"Standard",description:"Effect: The dragon uses bite and claw or uses claw twice."},{name:"Rising Winds",action:"Minor",keywords:["cold"],description:"Recharge at the start of any turn when freezing winds is aura 1 Effect: The freezing winds expands to aura 3. At the start of the dragon's next turn, the freezing winds expands to aura 5. At the start of its following turn, the dragon makes the following attack. Attack (No Action): Close burst 5 (enemies in the burst); +15 vs. Fortitude Hit: 3d8 + 6 cold damage, and the target is immobilized and blinded (save ends both). Effect: The freezing winds aura reverts to its original state and size (aura 1)."},{name:"Chill Rebuke",action:"Triggered",keywords:["cold"],recharge:"Recharge when first bloodied",description:"Trigger: An enemy's melee attack deals damage to the dragon. Attack (Immediate Reaction): Close blast 5 (enemies in the blast); +15 vs. Fortitude Hit: 1d10 + 9 cold damage, and the target is slowed (save ends). Sudden Flurry ✦ At-Will Trigger: The dragon is hit by a cold attack. Effect (Free Action): The dragon slides each enemy in its aura 1 square."}],alignment:"Unaligned",languages:["Common","Draconic","Primordial Monster Manual 3","page(s) 66."] },
  { id:"mm3-cambion-infernal-scion",name:"Cambion Infernal Scion",source:"mm3",level:12,role:"Soldier",roleModifier:"Elite",xp:1400,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["devil"],hp:250,ac:28,fort:24,ref:21,will:25,initiative:14,perception:10,speed:"6, fly 8 (clumsy)",senses:["Darkvision"],resist:["10 fire"],vulnerable:["10 fire until the end of the scion's next turn. Triggered Actions ⚔ Majestic Stride ✦ At-Will Trigger: An enemy marked by the scion and within","5 squares of it makes an attack that does not include the scion as a target. Effect (Immediate Reaction): The scion teleports to a square adjacent to the triggering enemy and uses burning longsword against it. Skills Diplomacy +17, History +15, Intimidate +17"],powers:[{name:"Burning Longsword",action:"Standard",keywords:["fire","weapon"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 2d8 + 11 fire damage. Effect: The target is marked until the end of the scion's next turn."},{name:"Fiend Razor",action:"Standard",description:"Requirement: The scion must be bloodied. Effect: The scion uses burning longsword twice."},{name:"Dread Command",action:"Minor",keywords:["charm"],description:"1/round Requirement: The scion must not be bloodied. Attack: Ranged 5 (one enemy marked by the scion); +15 vs. Will Hit: The target is dominated until the end of the scion's next turn. Oath of the Nine ✦ At-Will 1/round Effect: One creature within 3 squares of the scion is marked and gains vulnerable 10 fire until the end of the scion's next turn."},{name:"Majestic Stride",action:"Triggered",description:"Trigger: An enemy marked by the scion and within 5 squares of it makes an attack that does not include the scion as a target. Effect (Immediate Reaction): The scion teleports to a square adjacent to the triggering enemy and uses burning longsword against it. Skills Diplomacy +17, History +15, Intimidate +17"}],alignment:"Unaligned",languages:["Supernal Equipment : chainmail","longsword . Monster Manual 3","page(s) 25","Dungeon Magazine 218."] },
  { id:"mm3-cloaker-ambusher",name:"Cloaker Ambusher",source:"mm3",level:12,role:"Lurker",xp:700,size:"Large",origin:"Aberrant",type:"Magical beast",hp:95,ac:24,fort:24,ref:23,will:20,initiative:13,perception:13,speed:"2 (clumsy), fly 8 (hover)",senses:["Darkvision"],powers:[{name:"Unnerving Moan",action:"Aura",keywords:["fear"],description:"Aura 2 Nondeafened enemies within the aura take a -2 penalty to attack rolls."},{name:"Tail Slap",action:"Standard",description:"Attack: Melee 2 (one creature); +17 vs. AC Hit: 2d8 + 11 damage."},{name:"Envelop",action:"Standard",description:"Requirement: The ambusher must not have a creature grabbed. Attack: Melee 1 (one creature); +15 vs. Reflex Hit: The ambusher slides the target 1 square to a square within the ambusher's space, and the target is grabbed. While the target is grabbed by the ambusher, it is blinded, dazed, restrained, and takes ongoing 10 damage. In addition, whenever an attack deals damage to the ambusher while it has the target grabbed, the attack deals half damage to the ambusher and half damage to the target."},{name:"Shadow Shift",action:"Minor",keywords:["illusion"],description:"Effect: The ambusher gains concealment until the start of its next turn. If the ambusher is in an obscured square, it gains total concealment until the start of its next turn. Skills Stealth +14"}],alignment:"Unaligned",languages:["Deep Speech Monster Manual 3","page(s) 34","Dungeon Magazine 209."] },
  { id:"mm3-eye-of-shadow",name:"Eye of Shadow",source:"mm3",level:12,role:"Lurker",roleModifier:"Elite",xp:1400,size:"Large",origin:"Aberrant",type:"Magical beast",hp:194,ac:26,fort:24,ref:25,will:24,initiative:16,perception:15,speed:"0, fly 6 (hover)",senses:["Darkvision"],powers:[{name:"All-Around Vision",action:"Trait",description:"Enemies can't gain combat advantage by flanking the eye of shadow"},{name:"Combat Advantage",action:"Trait",description:"The eye of shadow deals 2d6 extra damage to any creature granting combat advantage to it"},{name:"Shadow Surge",action:"Trait",keywords:["healing"],description:"The eye of shadow regains 20 hit points at the end of its turn if it has remained invisible since the start of its turn"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. AC Hit: 2d8 + 11 damage."},{name:"Eye Rays",action:"Standard",description:"Effect: The beholder uses one or two of the following eye rays without provoking an opportunity attack. Each eye ray must target a different enemy. 1. Blinding Ray (radiant) Attack: Ranged 10 (one creature); +15 vs. Reflex Hit: 1d8 + 6 radiant damage, and the target is blinded until the end of its next turn. 2. Thundering Ray (thunder) Attack: Ranged 10 (one creature); +15 vs. Fortitude Hit: 3d6 + 10 thunder damage, and the target is deafened until the end of its next turn. 3. Shadowbond Ray (necrotic) Attack: Ranged 10 (one creature); +15 vs. Will Hit: 3d6 + 5 necrotic damage, and the target is immobilized (save ends). Until the effect ends, the beholder and shadow creatures have concealment while within 5 squares of the target."},{name:"Vanish into Shadow",action:"Move",keywords:["illusion","teleportation"],recharge:"Recharge 3-6",description:"Effect: The beholder teleports 20 squares and becomes invisible until it attacks or until the end of its next turn."},{name:"Central Eye",action:"Minor",keywords:["fear"],description:"1/round Attack: Ranged 5 (one creature); +15 vs. Will Hit: The target grants combat advantage until the end of the beholder's next turn. Skills Stealth +17"}],alignment:"Unaligned",languages:["Deep Speech Monster Manual 3","page(s) 22."] },
  { id:"mm3-foulspawn-warpcaller",name:"Foulspawn Warpcaller",source:"mm3",level:12,role:"Controller",xp:0,size:"Medium",origin:"Aberrant",type:"Humanoid",hp:126,ac:26,fort:24,ref:22,will:24,initiative:9,perception:9,speed:"6, teleport 3",senses:["Darkvision"],vulnerable:["5 psychic."],powers:[{name:"Droning Pipe",action:"Aura",description:"Aura 3 Enemies within the aura gain vulnerable 5 psychic."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 3d8 + 5 damage."},{name:"Warped Sending",action:"Standard",keywords:["psychic","teleportation"],description:"Attack: Ranged 10 (one creature); +15 vs. Fortitude Hit: 2d8 + 5 psychic damage, and one of the warpcaller's aberrant allies within 5 squares of the target teleports to a square adjacent to the target."},{name:"Twisted Dismissal",action:"Standard",keywords:["psychic","teleportation"],description:"Attack: Melee 1 (one enemy); +15 vs. Will Hit: 2d8 + 5 psychic damage, and the target is immobilized (save ends). The warpcaller then teleports the target 2 squares."},{name:"Warpmind Field",action:"Standard",keywords:["psychic","zone"],recharge:"Encounter",description:"Attack: Area burst 2 within 5 (enemies in the burst); +15 vs. Will Hit: 2d6 + 6 psychic damage. Effect: The burst creates a zone that lasts until the end of the warpcaller's next turn. Any enemy that enters the zone or ends its turn there takes 10 psychic damage. In addition, any enemy within the zone can attack only targets within 3 squares of it. As a move action, the warpcaller can move the zone up to 4 squares. Sustain Minor: The zone persists until the end of the warpcaller's next turn. Skills Arcana +15"}],alignment:"Unaligned",languages:["Deep Speech","telepathy 10 Equipment : musical pipe Monster Manual 3","page(s) 89","Dungeon Magazine 197."] },
  { id:"mm3-girallon-marauder",name:"Girallon Marauder",source:"mm3",level:12,role:"Brute",xp:700,size:"Large",origin:"Natural",type:"Beast",hp:145,ac:24,fort:24,ref:23,will:22,initiative:11,perception:10,speed:"8, climb 6",powers:[{name:"Threatening Claws",action:"Aura",description:"Aura 1 Enemies within the aura grant combat advantage"},{name:"Combat Climber",action:"Trait",description:"The marauder does not provoke opportunity attacks by climbing"},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +16 vs. AC Hit: 2d12 + 10 damage."},{name:"Claw Flurry",action:"Standard",recharge:"Recharge 4-6",description:"Effect: The marauder makes the following attack four times. Attack: Melee 2 (one creature); +16 vs. AC Hit: 1d12 + 6 damage. Skills Acrobatics +16, Athletics +18"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 102."] },
  { id:"mm3-hill-giant-rockthrower",name:"Hill Giant Rockthrower",source:"mm3",level:12,role:"Artillery",xp:700,size:"Large",origin:"Natural",type:"Humanoid",keywords:["giant"],hp:97,ac:24,fort:25,ref:25,will:22,initiative:10,perception:9,speed:"8",powers:[{name:"Greatclub",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +17 vs. AC Hit: 2d10 + 4 damage."},{name:"Knockdown Throw",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10/20 (one creature); +17 vs. Reflex Hit: 2d8 + 7 damage, and the rockthrower pushes the target 2 squares or knocks it prone."},{name:"Shattering Rockburst",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Area burst 1 within 10 (creatures in the burst); +17 vs. Fortitude Hit: 2d8 + 6 damage, and the target is dazed (save ends). Skills Athletics +17"}],alignment:"Unaligned",languages:["Giant Equipment : 10 rocks","greatclub","hide armor . Monster Manual 3","page(s) 101","Dungeon Magazine 197","Dungeon Magazine 220."] },
  { id:"mm3-kuo-toa-mad-one",name:"Kuo-Toa Mad One",source:"mm3",level:12,role:"Skirmisher",roleModifier:"Minion",xp:175,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["aquatic"],hp:1,ac:26,fort:23,ref:23,will:25,initiative:12,perception:7,speed:"6, swim 6",senses:["Darkvision"],vulnerable:["5 psychic. Aquatic The mad one can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures."],powers:[{name:"Spreading Madness",action:"Aura",description:"Aura 1 Enemies within the aura gain vulnerable 5 psychic"},{name:"Aquatic",action:"Trait",description:"The mad one can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 10 damage, and the mad one shifts 1 square."},{name:"Eldritch Scream",action:"Standard",keywords:["psychic"],description:"Attack: Close blast 3 (enemies in the blast); +15 vs. Will Hit: 5 psychic damage."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 124","Dungeon Magazine 204."] },
  { id:"mm3-meazel-hunter",name:"Meazel Hunter",source:"mm3",level:12,role:"Artillery",xp:700,size:"Medium",origin:"Natural",type:"Humanoid",hp:88,ac:24,fort:23,ref:25,will:25,initiative:11,perception:14,speed:"6, climb 6",senses:["Darkvision"],immune:["disease"],vulnerable:["5 to all damage. In addition, any ally of that creature that starts its turn adjacent to the cursed creature becomes affected by the curse of Baalzebul until the end of its next turn. Multiple curses do not stack."],powers:[{name:"Wretched Curse of Baalzebul",action:"Aura",description:"Aura 1 Any enemy that starts its turn within the aura is affected by the curse of Baalzebul until the end of its next turn"},{name:"While",action:"Trait",description:"a creature is affected by the curse of Baalzebul, it takes a -2 penalty to all defenses and gains vulnerable 5 to all damage. In addition, any ally of that creature that starts its turn adjacent to the cursed creature becomes affected by the curse of Baalzebul until the end of its next turn"},{name:"Multiple",action:"Trait",description:"curses do not stack"},{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 2d8 + 5 damage."},{name:"Longbow",action:"Standard",keywords:["poison","weapon"],description:"Attack: Ranged 20/40 (one creature); +19 vs. AC Hit: 2d8 + 5 poison damage, and the target is slowed until the end of the hunter's next turn."},{name:"Distracting Shot",action:"Standard",keywords:["weapon"],description:"Requirement: The hunter must be wielding a ranged weapon. Attack: Ranged 20/40 (one creature); +17 vs. Will Hit: 2d8 + 5 damage, and the target grants combat advantage until the end of the hunter's next turn."},{name:"Plague-Tainted Shot",action:"Standard",keywords:["necrotic","weapon"],recharge:"Encounter",description:"Requirement: The hunter must be wielding a ranged weapon. Attack: Ranged 20/40 (one creature); +17 vs. Fortitude Hit: 2d8 + 5 damage, and ongoing 10 necrotic damage (save ends). Until the target saves, any ally of the target that starts its turn adjacent to the target takes 10 necrotic damage. Skills Stealth +16"}],alignment:"Unaligned",languages:["Common Equipment : arrow x40","longbow","spear . Monster Manual 3","page(s) 131."] },
  { id:"mm3-mossling-creeper",name:"Mossling Creeper",source:"mm3",level:12,role:"Skirmisher",roleModifier:"Minion",xp:175,size:"Small",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:1,ac:26,fort:23,ref:25,will:24,initiative:14,perception:11,speed:"8 (forest walk)",senses:["Blindsight 10"],powers:[{name:"Combat Advantage",action:"Trait",description:"The creeper deals 2 extra damage against any creature granting combat advantage to it"},{name:"Mindmaster's Thrall",action:"Trait",description:"If the creeper was created by an oblivion moss mindmaster, it acts immediately after its creator's turn"},{name:"Tendril Strike",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 10 damage. Effect: The creeper shifts 2 squares."},{name:"Simulacrum Attack",action:"Standard",description:"Effect: When the creeper first acts during the encounter, choose one at-will melee attack power belonging to an enemy that the creeper can see. If the creeper was created by an oblivion moss mindmaster, choose one at-will melee attack power belonging to the enemy that the mindmaster hit to create the creeper. Attack: Melee 1 (one creature); +17 vs. AC Hit: The target takes damage and is subject to effects as though it were hit by the chosen attack. The damage roll uses the ability score modifier of the creature from whom the power was chosen. The damage does not include any bonuses or penalties to the damage roll that the owner of the power might have. In addition, the creeper gains any benefits from the power's Hit entry, using the ability score modifiers of the creature from whom the power was chosen but not including any bonuses or penalties."},{name:"Mossy Slide",action:"Triggered",description:"Trigger: An attack misses the creeper. Effect (Immediate Reaction): The creeper shifts 2 squares. Skills Acrobatics +17"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 156."] },
  { id:"mm3-mossling-grower",name:"Mossling Grower",source:"mm3",level:12,role:"Controller",roleModifier:"Minion",xp:0,size:"Small",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:1,ac:26,fort:23,ref:24,will:25,initiative:10,perception:9,speed:"8 (forest walk)",senses:["Blindsight 10"],powers:[{name:"Shield of Vines",action:"Aura",description:"Aura 1 Plant allies within the aura gain a +2 bonus to all defenses"},{name:"Mindmaster's Thrall",action:"Trait",description:"If the grower was created by an oblivion moss mindmaster, it acts immediately after its creator's turn"},{name:"Tendril Strike",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 10 damage, and the target is slowed until the end of its next turn."},{name:"Simulacrum Attack",action:"Standard",description:"Effect: When the grower first acts during the encounter, choose one at-will melee attack power belonging to an enemy that the grower can see. If the grower was created by an oblivion moss mindmaster, choose one at-will melee attack power belonging to the enemy that the mindmaster hit to create the grower. Attack: Melee 1 (one creature); +17 vs. AC Hit: The target takes damage and is subject to effects as though it were hit by the chosen attack. The damage roll uses the ability score modifier of the creature from whom the power was chosen. The damage does not include any bonuses or penalties to the damage roll that the owner of the power might have. In addition, the grower gains any benefits from the power's Hit entry, using the ability score modifiers of the creature from whom the power was chosen but not including any bonuses or penalties."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 157."] },
  { id:"mm3-mossling-guardian",name:"Mossling Guardian",source:"mm3",level:12,role:"Soldier",roleModifier:"Minion",xp:175,size:"Medium",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:1,ac:28,fort:25,ref:22,will:23,initiative:11,perception:10,speed:"6 (forest walk)",senses:["Blindsight 10"],powers:[{name:"Forgotten Purpose",action:"Aura",description:"Aura 1 Any enemy that starts its turn within the aura is slowed until the end of its next turn"},{name:"Mindmaster's Thrall",action:"Trait",description:"If the guardian was created by an oblivion moss mindmaster, it acts immediately after its creator's turn"},{name:"Tendril Strike",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 10 damage, and the guardian shifts 1 square and slides the target 1 square into the space it occupied."},{name:"Simulacrum Attack",action:"Standard",description:"Effect: When the guardian first acts during the encounter, choose one at-will melee attack power belonging to an enemy that the guardian can see. If the mossling was created by an oblivion moss mindmaster, choose one at-will melee attack power belonging to the enemy that the mindmaster hit to create the guardian. Attack: Melee 1 (one creature); +17 vs. AC Hit: The target takes damage and is subject to effects as though it were hit by the chosen attack. The damage roll uses the ability score modifier of the creature from whom the power was chosen. The damage does not include any bonuses or penalties to the damage roll that the owner of the power might have. In addition, the guardian gains any benefits from the power's Hit entry, using the ability score modifiers of the creature from whom the power was chosen but not including any bonuses or penalties."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 155."] },
  { id:"mm3-mossling-hurler",name:"Mossling Hurler",source:"mm3",level:12,role:"Artillery",roleModifier:"Minion",xp:175,size:"Small",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:1,ac:24,fort:22,ref:22,will:26,initiative:6,perception:12,speed:"6 (forest walk)",senses:["Blindsight 10"],powers:[{name:"Mindmaster's Thrall",action:"Trait",description:"If the hurler was created by an oblivion moss mindmaster, it acts immediately after its creator's turn"},{name:"Bash",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 8 damage."},{name:"Simulacrum Attack",action:"Standard",description:"Effect: When the hurler first acts during the encounter, choose one at-will ranged attack power belonging to an enemy that the hurler can see. If the hurler was created by an oblivion moss mindmaster, choose one at-will ranged attack power belonging to the enemy that the mindmaster hit to create the hurler. Attack: Ranged 10 (one creature); +19 vs. AC Hit: The target takes damage and is subject to effects as though it were hit by the chosen attack. The damage roll uses the ability score modifier of the creature from whom the power was chosen. The damage does not include any bonuses or penalties to the damage roll that the owner of the power might have. In addition, the hurler gains any benefits from the power's Hit entry, using the ability score modifiers of the creature from whom the power was chosen but not including any bonuses or penalties."},{name:"Memory Deathstorm",action:"Triggered",keywords:["psychic"],description:"Trigger: The hurler drops to 0 hit points.. Close burst 2 (enemies in the burst); +15 vs. Reflex Hit: 8 psychic damage, and the target is dazed (save ends)."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 156."] },
  { id:"mm3-mossling-vinecaller",name:"Mossling Vinecaller",source:"mm3",level:12,role:"Controller",roleModifier:"Minion",xp:175,size:"Small",origin:"Fey",type:"Humanoid",keywords:["plant"],hp:1,ac:26,fort:24,ref:23,will:25,initiative:9,perception:10,speed:"8 (forest walk)",senses:["Blindsight 10"],powers:[{name:"Writhing Moss",action:"Aura",description:"Aura 1 Enemies treat squares within the aura as difficult terrain"},{name:"Mindmaster's Thrall",action:"Trait",description:"If the vinecaller was created by an oblivion moss mindmaster, it acts immediately after its creator's turn"},{name:"Tendril Strike",action:"Standard",description:"Attack: Melee 3 (one creature); +17 vs. AC Hit: 10 damage, and the vinecaller slides the target 2 squares."},{name:"Simulacrum Attack",action:"Standard",description:"Effect: When the vinecaller first acts during the encounter, choose one at-will ranged attack power belonging to an enemy that the vinecaller can see. If the vinecaller was created by an oblivion moss mindmaster, choose one at-will ranged attack power belonging to the enemy that the mindmaster hit to create the vinecaller. Attack: Ranged 10 (one creature); +17 vs. AC Hit: The target takes damage and is subject to effects as though it were hit by the chosen attack. The damage roll uses the ability score modifier of the creature from whom the power was chosen. The damage does not include any bonuses or penalties to the damage roll that the owner of the power might have. In addition, the vinecaller gains any benefits from the power's Hit entry, using the ability score modifiers of the creature from whom the power was chosen but not including any bonuses or penalties."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 157."] },
  { id:"mm3-norker-stone-shield",name:"Norker Stone Shield",source:"mm3",level:12,role:"Soldier",xp:700,size:"Small",origin:"Elemental",type:"Humanoid",hp:124,ac:28,fort:25,ref:23,will:23,initiative:12,perception:8,speed:"6",senses:["Low-light vision"],powers:[{name:"Club",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 3d6 + 8 damage, and the target is marked until the end of the stone shield's next turn."},{name:"Javelin",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10/20 (one creature); +17 vs. AC Hit: 2d6 + 4 damage, and the target is marked until the end of the stone shield's next turn."},{name:"Elemental Rebuke",action:"Triggered",description:"Trigger: An enemy hits the stone shield with a melee attack. Attack (Immediate Reaction): Melee 1 (the triggering enemy); +19 vs. AC Hit: 1d8 + 4 damage."},{name:"Shield Slam",action:"Triggered",description:"Trigger: An enemy marked by the stone shield and adjacent to it shifts. Attack (Opportunity Action): Melee 1 (the triggering enemy); +15 vs. Fortitude Hit: 2d6 + 4 damage, and the target falls prone."}],alignment:"Unaligned",languages:["Common Equipment : club","javelin x3","light shield . Monster Manual 3","page(s) 148."] },
  { id:"mm3-oblivion-moss-mindmaster",name:"Oblivion Moss Mindmaster",source:"mm3",level:12,role:"Controller",roleModifier:"Elite",xp:1400,size:"Large",origin:"Fey",type:"Magical beast",keywords:["plant"],hp:250,ac:26,fort:24,ref:22,will:25,initiative:6,perception:12,speed:"2 (forest walk), climb 2",senses:["Blindsight 20"],powers:[{name:"Mind Blindness",action:"Aura",description:"Aura 1 Any enemy that starts its turn within the aura treats the mindmaster as invisible until the start of the enemy's next turn."},{name:"Corroding Touch",action:"Standard",keywords:["acid"],description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 1d8 + 5 acid damage, and ongoing 10 acid damage (save ends)."},{name:"Scramble the Mind",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 10 (one creature); +15 vs. Will Hit: 3d6 + 7 psychic damage, and the mindmaster slides the target 5 squares."},{name:"Scour the Mind",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 10 (one creature); +15 vs. Will Hit: 3d6 + 7 psychic damage, and the mindmaster or one of its allies is invisible to the target until the end of the mindmaster's next turn."},{name:"Absorb Memories",action:"Standard",keywords:["psychic"],recharge:"Recharge when no mossling duplicate remains",description:"Attack: Ranged 5 (one enemy); +15 vs. Will Hit: The target is dazed and cannot use its encounter or daily attack powers (save ends both). Effect: The mindmaster creates a mossling duplicate of the target within 5 squares of the mindmaster. Choose the mossling minion that best reflects the target's role and powers."},{name:"Direct Mossling",action:"Minor",description:"1/round Effect: One mossling minion within 10 squares of the mindmaster can move its speed as a free action."},{name:"Absorb Damage",action:"Triggered",description:"Trigger: A mossling within 20 squares of the mindmaster takes damage. Effect (Immediate Interrupt): The mindmaster takes the damage instead of the mossling."}],alignment:"Unaligned",languages:["Common","telepathy 10 Monster Manual 3","page(s) 155."] },
  { id:"mm3-pale-bloodfiend",name:"Pale Bloodfiend",source:"mm3",level:12,role:"Brute",xp:700,size:"Medium",origin:"Natural",type:"Humanoid",hp:140,ac:24,fort:25,ref:24,will:23,initiative:11,perception:10,speed:"8",senses:["Darkvision"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 2d8 + 6 damage."},{name:"Double Claw",action:"Standard",description:"Requirement: The bloodfiend must not have a creature grabbed. Effect: The bloodfiend uses claw twice against the same target. If both attacks hit, the bloodfiend grabs the target."},{name:"Goring Charge",action:"Standard",description:"Effect: The bloodfiend charges and makes the following attack in place of a melee basic attack. Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d10 + 10 damage, and the target falls prone."},{name:"Heart of the Vampire",action:"Minor",keywords:["healing"],description:"Recharge at the end of the bloodfiend's turn if the power misses Attack: Melee 1 (one creature grabbed by the bloodfiend); +15 vs. Fortitude Hit: 2d6 + 6 damage, and the target is dazed and weakened (save ends both). The bloodfiend regains 20 hit points."},{name:"Bloodfiend Ferocity",action:"Triggered",description:"Trigger: The bloodfiend drops to 0 hit points.. The bloodfiend uses claw. If the attack hits, the target is dazed until the end of the target's next turn. Skills Athletics +17, Intimidate +15"}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 140."] },
  { id:"mm3-su-alpha",name:"Su Alpha",source:"mm3",level:12,role:"Brute",xp:700,size:"Medium",origin:"Fey",type:"Beast",hp:149,ac:24,fort:25,ref:24,will:23,initiative:11,perception:10,speed:"7 (forest walk), climb 7",senses:["Darkvision"],vulnerable:["5 to all damage (save ends). Miss: Half damage, and the target gains vulnerable","5 to all damage until the end of the alpha's next turn. Triggered Actions ⚔ Flesh-Ripper ✦ At-Will Trigger: An enemy is pulled, pushed, or slid to a square adjacent to the alpha. Attack (Immediate Reaction): Melee","1 (one creature)","+17 vs. AC Hit:","1d12 +","6 damage. ⚔ Tribal Fury ✦ At-Will Trigger: An ally within","3 squares is first bloodied. Effect (Free Action): The alpha uses claw. Psionic Boost (psychic) ✦ Recharge when the alpha takes psychic damage Trigger: The alpha hits with claw, flesh-ripper, or backhand slam. Effect (Free Action): The attack deals","2d8 extra psychic damage. Skills Acrobatics +16, Athletics +17, Stealth +16"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +17 vs. AC Hit: 3d10 + 7 damage."},{name:"Backhand Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +15 vs. Fortitude Hit: 3d8 + 7 damage, and the alpha pushes the target 1 square."},{name:"Su Howl",action:"Standard",keywords:["psychic"],recharge:"Recharge when the alpha takes psychic damage",description:"Attack: Close burst 3 (enemies in the burst); +15 vs. Will Hit: 2d10 + 3 psychic damage, and the target gains vulnerable 5 to all damage (save ends). Miss: Half damage, and the target gains vulnerable 5 to all damage until the end of the alpha's next turn."},{name:"Flesh-Ripper",action:"Triggered",description:"Trigger: An enemy is pulled, pushed, or slid to a square adjacent to the alpha. Attack (Immediate Reaction): Melee 1 (one creature); +17 vs. AC Hit: 1d12 + 6 damage."},{name:"Tribal Fury",action:"Triggered",description:"Trigger: An ally within 3 squares is first bloodied. Effect (Free Action): The alpha uses claw. Psionic Boost (psychic) ✦ Recharge when the alpha takes psychic damage Trigger: The alpha hits with claw, flesh-ripper, or backhand slam. Effect (Free Action): The attack deals 2d8 extra psychic damage. Skills Acrobatics +16, Athletics +17, Stealth +16"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 189","Dungeon Magazine 196."] },
  { id:"mm3-babau",name:"Babau",source:"mm3",level:13,role:"Skirmisher",xp:800,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["demon"],hp:127,ac:26,fort:23,ref:25,will:24,initiative:13,perception:10,speed:"7",senses:["Darkvision"],resist:["5 acid"],powers:[{name:"Protective Slime",action:"Aura",keywords:["acid"],description:"Aura 1 Any enemy in the aura that hits the babau with a melee attack takes 5 acid damage."},{name:"Bite",action:"Standard",keywords:["acid"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d6 + 3 damage. The target also takes ongoing 5 acid damage, or ongoing 10 acid damage if the babau is bloodied (save ends)."},{name:"Claws",action:"Standard",description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d6 + 3 damage, and the babau can shift 1 square."},{name:"Babau's Advantage",action:"Standard",description:"Effect: The babau uses bite and claws against a creature granting combat advantage to it."},{name:"Murderous Abduction",action:"Minor",keywords:["teleportation"],recharge:"Recharge when the babau reduces an enemy to 0 hit points or fewer",description:"Effect: The babau teleports one creature adjacent to it up to 7 squares and then teleports to a square adjacent to that creature. The creature grants combat advantage to the babau until the end of the babau's next turn."},{name:"Variable Resistance",action:"Triggered",recharge:"2/Encounter",description:"Trigger: The babau takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The babau gains resist 20 to the triggering damage type until the end of the encounter or until it uses variable resistance again. Skills Athletics +14"}],alignment:"Unaligned",languages:["Abyssal Monster Manual 3","page(s) 40","Monster Vault","page(s) 45","Dungeon Magazine 220."] },
  { id:"mm3-cinderhoof-trampler",name:"Cinderhoof Trampler",source:"mm3",level:13,role:"Skirmisher",xp:800,size:"Medium",origin:"Natural",type:"Humanoid",hp:132,ac:27,fort:26,ref:26,will:23,initiative:14,perception:10,speed:"8",resist:["10 fire"],powers:[{name:"Combat Advantage",action:"Trait",keywords:["fire"],description:"Whenever the trampler hits a creature granting combat advantage to it, that creature takes ongoing 10 fire damage (save ends)"},{name:"Gore",action:"Standard",description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d10 + 5 damage."},{name:"Goring Charge",action:"Standard",description:"Effect: The trampler charges and makes the following attack in place of a melee basic attack. Attack: Melee 1 (one creature); +19 vs. AC Hit: 2d10 + 10 damage, and the target falls prone."},{name:"Heart of the Nightmare",action:"Standard",keywords:["fire"],recharge:"Recharge 5-6",description:"Effect: The trampler moves its speed and can move through enemies' spaces during the move. Any creature that hits the trampler with an opportunity attack provoked by this movement takes 10 fire damage. Each time the trampler enters an enemy's space for the first time during the move, it makes the following attack against that enemy. Attack: Melee 0 (creature in space); +16 vs. Reflex Hit: 3d6 + 7 damage, and the enemy falls prone."},{name:"Trampler Ferocity",action:"Triggered",description:"Trigger: The trampler drops to 0 hit points.. The trampler uses gore. If the attack hits, the trampler pushes the target 2 squares and knocks it prone. Skills Athletics +17, Stealth +17"}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 140."] },
  { id:"mm3-derro-warrior",name:"Derro Warrior",source:"mm3",level:13,role:"Artillery",xp:800,size:"Small",origin:"Natural",type:"Humanoid",hp:101,ac:27,fort:24,ref:27,will:24,initiative:12,perception:9,speed:"5",senses:["Darkvision"],powers:[{name:"Combat Advantage",action:"Trait",description:"The warrior deals 2d6 extra damage against any creature granting combat advantage to it"},{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 3d4 + 9 damage."},{name:"Bolt Spray",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Requirement: The warrior must be wielding a repeating hand crossbow. Attack: Close blast 5 (creatures in the blast); +20 vs. AC Hit: 2d8 + 7 damage, and the warrior pushes the target 1 square."},{name:"Repeating Hand Crossbow",action:"Minor",keywords:["weapon"],description:"Attack: Ranged 10/20 (one creature); +20 vs. AC Hit: 1d8 + 5 damage."},{name:"Strength of Madness",action:"Free",recharge:"Encounter",description:"Requirement: The warrior can use strength of madness only during its turn. Effect: Roll a d6 and add the result as a power bonus to the warrior's attack rolls until the end of its next turn. In addition, the warrior grants combat advantage until the end of its next turn. Skills Intimidate +13, Stealth +17"}],alignment:"Unaligned",languages:["Common","Deep Speech Equipment : repeating hand crossbow","dagger","leather armor . Monster Manual 3","page(s) 49."] },
  { id:"mm3-howler-doom-mastiff",name:"Howler Doom Mastiff",source:"mm3",level:13,role:"Skirmisher",xp:800,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["mount"],hp:129,ac:27,fort:25,ref:25,will:24,initiative:12,perception:9,speed:"8",senses:["Darkvision"],powers:[{name:"Guarding Spines",action:"Trait",keywords:["mount"],description:"The doom mastiff's rider gains a +2 bonus to AC"},{name:"Piercing Spines Whenever",action:"Trait",description:"a creature adjacent to the doom mastiff misses it or its rider with a melee attack, that creature takes 10 damage"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d8 + 7 damage."},{name:"Loping Bite",action:"Standard",description:"Effect: The doom mastiff shifts half its speed and uses bite."},{name:"Terrifying Howl",action:"Standard",keywords:["fear","psychic"],recharge:"Recharge 5-6",description:"Attack: Close blast 5 (enemies in the blast); +16 vs. Will Hit: The target takes ongoing 10 psychic damage and grants combat advantage (save ends both). The target cannot save against this effect while it is adjacent to any doom mastiff."}],alignment:"Unaligned",languages:["understands Abyssal Monster Manual 3","page(s) 111","Dungeon Magazine 209."] },
  { id:"mm3-meazel-strangler",name:"Meazel Strangler",source:"mm3",level:13,role:"Controller",xp:800,size:"Medium",origin:"Natural",type:"Humanoid",hp:125,ac:27,fort:24,ref:26,will:24,initiative:11,perception:9,speed:"6",senses:["Darkvision"],immune:["disease"],vulnerable:["5 to all damage. In addition, any ally of that creature that starts its turn adjacent to the cursed creature becomes affected by the curse of Baalzebul until the end of its next turn. Multiple curses do not stack."],powers:[{name:"Wretched Curse of Baalzebul",action:"Aura",description:"Aura 1 Any enemy that starts its turn within the aura is affected by the curse of Baalzebul until the end of its next turn"},{name:"While",action:"Trait",description:"a creature is affected by the curse of Baalzebul, it takes a -2 penalty to all defenses and gains vulnerable 5 to all damage. In addition, any ally of that creature that starts its turn adjacent to the cursed creature becomes affected by the curse of Baalzebul until the end of its next turn"},{name:"Multiple",action:"Trait",description:"curses do not stack"},{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d6 + 10 damage."},{name:"Garrote",action:"Standard",keywords:["weapon"],description:"Requirement: The strangler must not have a creature grabbed. Attack: Melee 1 (one creature granting combat advantage to the strangler); +16 vs. Reflex Hit: 1d10 + 5 damage, and the strangler grabs the target. Sustain Standard: The strangler sustains the grab, and the target takes 3d10 + 5 damage."},{name:"Plague Touch",action:"Standard",keywords:["necrotic"],recharge:"Encounter",description:"Attack: Melee 1 (one creature); +16 vs. Fortitude Hit: 2d6 + 5 damage, and the target is blinded and takes ongoing 5 necrotic damage (save ends both)."},{name:"Drag to the Feast",action:"Move",description:"Effect: The strangler moves its speed, pulling a creature it has grabbed with it. In addition, the creature remains grabbed, and the strangler does not provoke an opportunity attack from the grabbed creature. Any opportunity attacks against the strangler for this movement that miss the meazel instead hit the grabbed creature. Skills Athletics +14, Stealth +16, Thievery +16"}],alignment:"Unaligned",languages:["Common Equipment : garrote","leather armor","short sword . Monster Manual 3","page(s) 131."] },
  { id:"mm3-scarecrow-guardian",name:"Scarecrow Guardian",source:"mm3",level:13,role:"Soldier",xp:800,size:"Medium",origin:"Fey",type:"Animate",keywords:["construct"],hp:107,ac:29,fort:25,ref:23,will:24,initiative:10,perception:14,speed:"6",senses:["Low-light vision"],immune:["disease, poison, sleep"],vulnerable:["10 fire"],powers:[{name:"Claws",action:"Standard",description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d6 + 9 damage, and the target is marked until the end of the guardian's next turn."},{name:"Luring Gaze",action:"Standard",keywords:["charm","psychic"],description:"Attack: Ranged 10 (one creature); +16 vs. Will Hit: 1d6 + 5 psychic damage, and the guardian pulls the target 5 squares."},{name:"Horrid Gaze",action:"Minor",keywords:["fear"],recharge:"Encounter",description:"Attack: Close blast 3 (enemies in the blast); +18 vs. Will Hit: The target is immobilized until the end of the guardian's next turn."},{name:"Malleable Straw",action:"Triggered",description:"Trigger: An attack damages the guardian. Effect (Immediate Interrupt): The guardian takes half damage from the triggering attack. Skills Acrobatics +13"}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 169","Dungeon Magazine 196."] },
  { id:"mm3-scarecrow-haunter",name:"Scarecrow Haunter",source:"mm3",level:13,role:"Lurker",xp:800,size:"Medium",origin:"Fey",type:"Animate",keywords:["construct"],hp:99,ac:27,fort:24,ref:26,will:25,initiative:14,perception:9,speed:"6",senses:["Low-light vision"],immune:["disease, poison, sleep"],vulnerable:["10 fire"],powers:[{name:"Lurking Horror",action:"Trait",description:"When the haunter hits a creature that cannot see it, the attack deals 5 extra damage and increases any of the attack's forced movement by 2 squares"},{name:"Claws",action:"Standard",description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d6 + 9 damage."},{name:"Haunting Echoes",action:"Standard",keywords:["charm","fear","psychic"],description:"Attack: Area burst 2 within 10 (enemies in the burst); +18 vs. Will Hit: The haunter slides the target 2 squares. The target then makes a melee or a ranged basic attack against a creature of the haunter's choice. Fluttering Straw (polymorph) ✦ At-Will Effect: The haunter shifts 6 squares and then is invisible and insubstantial until the end of its next turn."},{name:"Terrifying Gaze",action:"Minor",keywords:["fear","psychic"],recharge:"Recharge 4-6",description:"Attack: Close blast 3 (enemies in the blast); +16 vs. Will Hit: 1d6 + 5 psychic damage, and the haunter pushes the target 2 squares. Skills Stealth +15"}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 169."] },
  { id:"mm3-son-of-kyuss",name:"Son of Kyuss",source:"mm3",level:13,role:"Brute",xp:800,size:"Medium",origin:"Natural",type:"Animate",keywords:["undead"],hp:158,ac:25,fort:25,ref:23,will:24,initiative:7,perception:6,speed:"5",senses:["Darkvision"],resist:["15 necrotic"],immune:["disease, fear, poison"],vulnerable:["5 fire,","5 radiant"],powers:[{name:"Fear of Worms",action:"Aura",keywords:["fear"],description:"Aura 1 Living creatures within the aura take a -2 penalty to attack rolls against the son of Kyuss."},{name:"Slam",action:"Standard",keywords:["disease"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 2d10 + 10 damage, and the target is exposed to touch of Kyuss."},{name:"Burrowing Worm",action:"Minor",keywords:["disease","necrotic"],recharge:"Recharge 4-6",description:"Attack: Close burst 1 (one living enemy in the burst); +16 vs. Fortitude Hit: The target takes ongoing 10 necrotic damage (save ends). In addition, the target is exposed to touch of Kyuss. First Failed Saving Throw: The ongoing damage increases to 15. Second Failed Saving Throw: The target is stunned, and the ongoing damage increases to 20 (save ends both). Special: The corpse of any humanoid killed by this attack becomes a wretch of Kyuss at the start of the son of Kyuss's next turn. The wretch must be destroyed before the creature can be raised."}],alignment:"Chaotic Evil",languages:["- Touch of Kyuss Level 16 Disease Stage 0 : The target recovers from the disease. Stage 1 : Initial Effect: The target regains only half the normal hit points when it spends a healing surge. If it dies","it rises immediately as a wretch of Kyuss. Stage 2 : The target loses two healing surges. If it drops to 0 or fewer healing surges","it dies and rises immediately as a son of Kyuss. Stage 3 : Final State: The target dies and immediately becomes a son of Kyuss. Check : At the end of each extended rest","the target makes an Endurance check if it is at stage 1 or 2. 19 or lower : The stage of the disease increases by one. 20-24 : No Change 25 or higher : The stage of the disease decreases by one. Monster Manual 3","page(s) 180","Dungeon Magazine 188."] },
  { id:"mm3-wretch-of-kyuss",name:"Wretch of Kyuss",source:"mm3",level:13,role:"Brute",roleModifier:"Minion",xp:200,size:"Medium",origin:"Natural",type:"Animate",keywords:["undead"],hp:1,ac:25,fort:26,ref:23,will:24,initiative:7,perception:8,speed:"5",senses:["Darkvision"],resist:["10 necrotic"],immune:["disease, fear, poison"],vulnerable:["5 radiant"],powers:[{name:"Slam",action:"Standard",keywords:["necrotic"],description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 13 necrotic damage."},{name:"Final Gift",action:"Triggered",keywords:["disease","necrotic"],description:"Trigger: A melee or a ranged attack drops the wretch to 0 hit points.. Close burst 1 (creatures in the burst); +16 vs. Fortitude Hit: 10 necrotic damage, and the target is exposed to touch of Kyuss."}],alignment:"Chaotic Evil",languages:["- Touch of Kyuss Level 16 Disease Stage 0 : The target recovers from the disease. Stage 1 : Initial Effect: The target regains only half the normal hit points when it spends a healing surge. If it dies","it rises immediately as a wretch of Kyuss. Stage 2 : The target loses two healing surges. If it drops to 0 or fewer healing surges","it dies and rises immediately as a son of Kyuss. Stage 3 : Final State: The target dies and immediately becomes a son of Kyuss. Check : At the end of each extended rest","the target makes an Endurance check if it is at stage 1 or 2. 19 or lower : The stage of the disease increases by one. 20-24 : No Change 25 or higher : The stage of the disease decreases by one. Monster Manual 3","page(s) 181","Dungeon Magazine 188."] },
  { id:"mm3-adult-earthquake-dragon",name:"Adult Earthquake Dragon",source:"mm3",level:14,role:"Soldier",roleModifier:"Elite",xp:2000,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["dragon","earth"],hp:288,ac:30,fort:27,ref:27,will:25,initiative:15,perception:12,speed:"8 (earth walk), burrow 4, fly 4 (clumsy)",senses:["Darkvision"],powers:[{name:"Quaking Earth",action:"Aura",description:"Aura 1 When any enemy within the aura makes an attack that does not include the dragon as a target, that enemy falls prone and takes 10 damage."},{name:"Bite",action:"Standard",description:"Attack: Melee 2 (one creature); +19 vs. AC Hit: 3d8 + 9 damage."},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +21 vs. AC Hit: 3d6 + 6 damage."},{name:"Double Attack",action:"Standard",description:"Effect: The dragon uses bite and claw or uses claw twice."},{name:"Earthen Maw",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Melee 2 (one creature); +19 vs. Reflex Hit: 3d10 + 6 damage, and the target is restrained (save ends). First Failed Saving Throw: The target is instead petrified (save ends)."},{name:"Rising Tremors",action:"Minor",description:"Recharge at the start of any turn when quaking earth is aura 1 Effect: The quaking earth expands to aura 3. At the start of the dragon's next turn, the quaking earth expands to aura 5. At the start of its following turn, the dragon makes the following attack. Attack (No Action): Close burst 5 (enemies in the burst); +17 vs. Reflex Hit: 3d8 + 9 damage, and the target falls prone and cannot stand up (save ends). Effect: The quaking earth aura reverts to its original state and size (aura 1)."},{name:"Sudden Quake",action:"Triggered",description:"Trigger: The dragon is pulled, pushed, slid, or knocked prone. Effect (Free Action): Each enemy in the dragon's aura falls prone."}],alignment:"Unaligned",languages:["Common","Draconic","Primordial Monster Manual 3","page(s) 69."] },
  { id:"mm3-derro-fanatic",name:"Derro Fanatic",source:"mm3",level:14,role:"Skirmisher",xp:1000,size:"Small",origin:"Natural",type:"Humanoid",hp:140,ac:27,fort:26,ref:25,will:25,initiative:13,perception:5,speed:"6",senses:["Darkvision"],powers:[{name:"Unleashed Madness",action:"Trait",description:"While the fanatic is bloodied, it takes a -2 penalty to attack rolls and deals 2d6 extra damage"},{name:"Battleaxe",action:"Standard",keywords:["weapon"],description:"Effect: The fanatic ends any mark on it, shifts 2 squares, and makes the following attack. Attack: Melee 1 (one creature); +19 vs. AC Hit: 2d10 + 11 damage."},{name:"Strength of Madness",action:"Free",recharge:"Encounter",description:"Requirement: The fanatic can use strength of madness only during its turn. Effect: Roll a d6 and add the result as a power bonus to the fanatic's attack rolls until the end of its next turn. In addition, the fanatic grants combat advantage until the end of its next turn."},{name:"Insane Bloodlust",action:"Triggered",description:"Trigger: The fanatic bloodies an enemy. Effect (Free Action): The fanatic uses battleaxe against the enemy. Skills Intimidate +15"}],alignment:"Unaligned",languages:["Common","Deep Speech Equipment : battleaxe","leather armor . Monster Manual 3","page(s) 49."] },
  { id:"mm3-derro-thug",name:"Derro Thug",source:"mm3",level:14,role:"Brute",roleModifier:"Minion",xp:250,size:"Small",origin:"Natural",type:"Humanoid",hp:1,ac:26,fort:25,ref:24,will:25,initiative:9,perception:5,speed:"5",senses:["Darkvision"],powers:[{name:"Club",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +19 vs. AC Hit: 14 damage."},{name:"Mad Sacrifice",action:"Triggered",recharge:"Encounter",description:"Trigger: The thug misses with an attack. Effect (Free Action): The attack instead hits, and the thug drops to 0 hit points."}],alignment:"Unaligned",languages:["Common","Deep Speech Equipment : club","leather armor","light shield . Monster Manual 3","page(s) 49","Dungeon Magazine 201."] },
  { id:"mm3-hill-giant-avalancher",name:"Hill Giant Avalancher",source:"mm3",level:14,role:"Skirmisher",xp:1000,size:"Large",origin:"Natural",type:"Humanoid",keywords:["giant"],hp:139,ac:28,fort:25,ref:27,will:24,initiative:15,perception:10,speed:"8",powers:[{name:"Greatclub",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +19 vs. AC Hit: 2d10 + 11 damage."},{name:"Rolling Rock",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 8 (one creature); +17 vs. Reflex Hit: 2d10 + 4 damage, and the avalancher slides the target 4 squares and knocks it prone."},{name:"Crushing Charge",action:"Standard",keywords:["weapon"],recharge:"Recharge 3-6",description:"Effect: The avalancher charges and makes the following attack in place of a melee basic attack. Attack: Melee 1 (one creature); +20 vs. AC Hit: 2d10 + 11 damage, and the target falls prone."},{name:"Stomping Shift",action:"Move",description:"Effect: The avalancher shifts 4 squares and can move through prone enemies' spaces. Each time the avalancher enters a prone enemy's space for the first time during the shift, that enemy takes 8 damage. Skills Athletics +17"}],alignment:"Unaligned",languages:["Giant Equipment : greatclub","hide armor . Monster Manual 3","page(s) 101","Dungeon Magazine 197."] },
  { id:"mm3-intellect-predator",name:"Intellect Predator",source:"mm3",level:14,role:"Controller",xp:1000,size:"Medium",origin:"Aberrant",type:"Magical beast",keywords:["blind"],hp:140,ac:25,fort:26,ref:23,will:27,initiative:12,perception:18,speed:"8",senses:["Blindsight 10"],immune:["blinded, gaze effects"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +19 vs. AC Hit: 4d6 + 8 damage."},{name:"Body Thief",action:"Standard",keywords:["charm","psychic"],description:"Attack: Melee 1 (one stunned creature); +17 vs. Will Hit: 2d6 + 6 psychic damage, and the target is dominated (save ends; the target takes a -2 penalty to the saving throw). While the target is dominated by the predator, the predator occupies the target's space and cannot be targeted or take damage. The predator cannot use claw while the target is dominated. When the target saves, the predator appears in the unoccupied space nearest to the target. Aftereffect: The target is dazed (save ends)."},{name:"Thought Lance",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Ranged 10 (one creature); +17 vs. Will Hit: The target is stunned until the end of the predator's next turn."},{name:"Mind Shock",action:"Standard",keywords:["psychic"],recharge:"Encounter",description:"Attack: Close burst 5 (enemies in the burst); +17 vs. Will Hit: 1d6 + 6 psychic damage, and the target is dazed (save ends). In addition, the predator slides the target 1 square."},{name:"Puppet Master",action:"Minor",keywords:["charm"],description:"1/round Effect: The predator causes the creature dominated by its body thief power to take a move action or a minor action."},{name:"Mind's Resilience",action:"Triggered",description:"Trigger: The predator takes damage while subject to an effect that a save can end. Effect (No Action): The predator makes a saving throw. Skills Stealth +17"}],alignment:"Unaligned",languages:["telepathy 10 Monster Manual 3","page(s) 119","Dungeon Magazine 201."] },
  { id:"mm3-ironskin-warrior",name:"Ironskin Warrior",source:"mm3",level:14,role:"Soldier",xp:1000,size:"Medium",origin:"Natural",type:"Humanoid",hp:140,ac:30,fort:27,ref:26,will:25,initiative:15,perception:13,speed:"6",resist:["10 poison"],powers:[{name:"Greataxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +19 vs. AC Hit: 2d12 + 9 damage, and the target is slowed and cannot shift (save ends both)."},{name:"Goring Charge",action:"Standard",description:"Effect: The warrior charges and makes the following attack in place of a melee basic attack. Attack: Melee 1 (one creature); +20 vs. AC Hit: 2d10 + 11 damage, and the target falls prone."},{name:"Heart of the Gorgon",action:"Standard",keywords:["poison"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +17 vs. Fortitude Hit: 3d6 + 5 poison damage, and the target is slowed (save ends). First Failed Saving Throw: The target is immobilized instead of slowed (save ends). Second Failed Saving Throw: The target is petrified."},{name:"Ironskin Ferocity",action:"Triggered",description:"Trigger: The warrior drops to 0 hit points.. The warrior uses greataxe. If the attack hits, the target is immobilized until the end of the target's next turn. Skills Athletics +18, Endurance +17"}],alignment:"Unaligned",languages:["Common Equipment : greataxe . Monster Manual 3","page(s) 141","Dungeon Magazine 201."] },
  { id:"mm3-kuo-toa-drowner",name:"Kuo-Toa Drowner",source:"mm3",level:14,role:"Soldier",xp:1000,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["aquatic"],hp:137,ac:30,fort:26,ref:26,will:24,initiative:15,perception:8,speed:"6, swim 6",senses:["Darkvision"],powers:[{name:"Aquatic",action:"Trait",description:"The drowner can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Hook",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +19 vs. AC Hit: 3d8 + 9 damage, and the drowner slides the target 3 squares to a square adjacent to it."},{name:"Dredging Hook",action:"Standard",keywords:["weapon"],description:"Requirement: The drowner must be wielding a hook. Attack: Melee 1 (one creature); +17 vs. Reflex Hit: 3d8 + 9 damage, and the drowner slides the target 3 squares to a square adjacent to it."},{name:"Barbed Net",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 5/10 (one creature); +17 vs. Reflex Hit: 2d6 + 6 damage. The target takes 8 extra damage if it moves willingly before the start of the drowner's next turn."},{name:"Slick Maneuver",action:"Move",description:"Requirement: The drowner must be adjacent to an enemy. Effect: The drowner shifts 3 squares to another square adjacent to the enemy."}],alignment:"Unaligned",languages:["Deep Speech Equipment : hook","page(s) 125","Dungeon Magazine 203."] },
  { id:"mm3-nagpa-carrion-lord",name:"Nagpa Carrion Lord",source:"mm3",level:14,role:"Artillery",xp:1000,size:"Medium",origin:"Elemental",type:"Humanoid",hp:111,ac:28,fort:23,ref:25,will:26,initiative:9,perception:11,speed:"6",senses:["Low-light vision"],powers:[{name:"Rotting Staff",action:"Standard",keywords:["necrotic","weapon"],description:"Attack: Melee 1 (one creature); +17 vs. Fortitude Hit: 2d6 + 8 necrotic damage."},{name:"Bolt of Putrescence",action:"Standard",keywords:["implement","necrotic"],description:"Attack: Ranged 20 (one creature); +19 vs. Reflex Hit: 2d10 + 10 necrotic damage."},{name:"Rain of Ruin",action:"Standard",keywords:["acid","implement"],recharge:"Recharge 4-6",description:"Attack: Ranged 10 (two or three creatures); +19 vs. Reflex Hit: 2d10 + 5 acid damage."},{name:"Consuming Shadows",action:"Standard",keywords:["implement","necrotic","zone"],recharge:"Encounter",description:"Attack: Area burst 1 within 10 (enemies in the burst); +19 vs. Fortitude Hit: 4d6 + 5 necrotic damage, and ongoing 5 necrotic damage (save ends). Effect: The burst creates a zone that lasts until the end of the carrion lord's next turn. The zone blocks line of sight for the carrion lord's enemies. Sustain Minor: The zone persists."},{name:"Ghostly Escape",action:"Minor",recharge:"Encounter",description:"Effect: The carrion lord is insubstantial and phasing until the end of its next turn. Skills Arcana +17, Bluff +17, Diplomacy +17, History +17"}],alignment:"Unaligned",languages:["Common","Primordial Equipment : staff implement . Monster Manual 3","page(s) 143","Dungeon Magazine 196."] },
  { id:"mm3-ogre-dreadnought",name:"Ogre Dreadnought",source:"mm3",level:14,role:"Soldier",xp:1000,size:"Large",origin:"Natural",type:"Humanoid",hp:140,ac:30,fort:28,ref:24,will:26,initiative:12,perception:12,speed:"8",powers:[{name:"Threatening Reach",action:"Trait",description:"The dreadnought can make opportunity attacks against all enemies within 2 squares of it"},{name:"Greatsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +19 vs. AC Hit: 1d12 + 16 damage, and the target is immobilized until the end of the dreadnought's next turn."},{name:"Dreadnought Resolve",action:"Triggered",recharge:"Recharge 3-6",description:"Trigger: The dreadnought fails a saving throw. Effect (No Action): The dreadnought rerolls the saving throw with a +2 bonus. Skills Athletics +19"}],alignment:"Chaotic Evil",languages:["Common","Giant Equipment : greatsword","plate armor . Monster Manual 3","page(s) 159."] },
  { id:"mm3-shadow-puppeteer",name:"Shadow Puppeteer",source:"mm3",level:14,role:"Lurker",xp:1000,size:"Medium",origin:"Shadow",type:"Humanoid",hp:74,ac:24,fort:25,ref:26,will:26,initiative:17,perception:9,speed:"8",senses:["Darkvision"],resist:["insubstantial"],vulnerable:["5 radiant"],powers:[{name:"Born",action:"Trait",description:"of Shadows The puppeteer can make a Stealth check to become hidden when it has concealment instead of needing total concealment"},{name:"Shadow Touch",action:"Standard",keywords:["necrotic","zone"],description:"Attack: Melee 1 (one creature); +17 vs. Reflex Hit: 3d6 + 12 necrotic damage, or 3d6 + 17 necrotic damage against a target that cannot see the puppeteer. Effect: The puppeteer creates a zone in the target's space and each square adjacent to it. The zone is lightly obscured, and it lasts until the end of the puppeteer's next turn."},{name:"Shadow Puppet",action:"Standard",keywords:["charm","necrotic"],recharge:"Recharge when the shadow hits a creature that cannot see it",description:"Attack: Melee 1 (one creature); +17 vs. Will Hit: 2d6 + 5 necrotic damage, or 2d6 + 10 necrotic damage against a target that cannot see the puppeteer. The target is dominated until it starts its turn not adjacent to the shadow. Skills Stealth +18"}],alignment:"Evil",languages:["Common Monster Manual 3","page(s) 173","Dungeon Magazine 196."] },
  { id:"mm3-abyssal-hulk",name:"Abyssal Hulk",source:"mm3",level:15,role:"Controller",xp:1200,size:"Large",origin:"Elemental",type:"Magical beast",hp:152,ac:29,fort:28,ref:26,will:27,initiative:9,perception:11,speed:"5, burrow 2 (tunneling)",senses:["Darkvision"],resist:["10 acid"],powers:[{name:"Claws",action:"Standard",description:"Attack: Melee 2 (one creature); +20 vs. AC Hit: 2d10 + 12 damage."},{name:"Gaze of Chaos",action:"Standard",keywords:["charm","psychic"],description:"Attack: Close blast 3 (enemies in the blast); +19 vs. Will Hit: 1d6 + 5 psychic damage, and the hulk slides the target 3 squares. The target then makes a melee basic attack as a free action against a creature of the hulk's choice."},{name:"Acidic Spew",action:"Standard",keywords:["acid"],recharge:"Recharge 5-6",description:"Attack: Close blast 5 (enemies in the blast); +19 vs. Fortitude Hit: Ongoing 10 acid damage (save ends)."},{name:"Gaze of Crushed Will",action:"Minor",keywords:["fear"],description:"1/round Attack: Close blast 5 (enemies in the blast); +19 vs. Will Hit: The hulk slides the target 3 squares, and the target takes a -5 penalty to any saving throws it makes during the move."}],alignment:"Unaligned",languages:["understands Deep Speech Monster Manual 3","page(s) 199."] },
  { id:"mm3-beholder-spawn",name:"Beholder Spawn",source:"mm3",level:15,role:"Artillery",roleModifier:"Minion",xp:300,size:"Medium",origin:"Aberrant",type:"Magical beast",hp:1,ac:27,fort:26,ref:28,will:27,initiative:13,perception:15,speed:"0, fly 6 (hover)",senses:["Darkvision"],powers:[{name:"All-Around Vision",action:"Trait",description:"Enemies can't gain combat advantage by flanking the beholder spawn"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +18 vs. AC Hit: 9 damage."},{name:"Eye Rays",action:"Standard",description:"Attack: Ranged 10 (one or two creatures); +18 vs. Reflex Hit: 11 acid, cold, fire, force, lightning, necrotic, poison, psychic, radiant, or thunder damage. This attack deals damage of the same type as the eye rays of the spawn's parent."},{name:"Desperate Flight",action:"Triggered",description:"Trigger: The spawn is hit or missed by a close or an area attack. Effect (Immediate Interrupt): The spawn shifts 2 squares."}],alignment:"Unaligned",languages:["Deep Speech Monster Manual 3","page(s) 22."] },
  { id:"mm3-derro-harvester",name:"Derro Harvester",source:"mm3",level:15,role:"Lurker",xp:1200,size:"Medium",origin:"Natural",type:"Humanoid",hp:116,ac:30,fort:27,ref:28,will:26,initiative:17,perception:10,speed:"6",senses:["Darkvision"],powers:[{name:"Combat Advantage",action:"Trait",description:"The harvester deals 2d6 extra damage against any creature granting combat advantage to it"},{name:"War Pick",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 3d8 + 10 damage."},{name:"Harvest",action:"Standard",keywords:["weapon"],description:"Requirement: The harvester must have started its turn hidden from the target. Attack: Melee 1 (one creature); +18 vs. Fortitude Hit: The target falls unconscious (save ends). Flee to the Shadows ✦ At-Will Effect: The harvester moves its speed. If it has concealment at the end of its move, it can attempt a Stealth check to become hidden. Life in Chains ✦ Encounter Requirement: The harvester must be holding shackles. Effect: The harvester shackles one Medium or smaller helpless creature that is adjacent to it until the creature succeeds at using the escape action against the harvester. While shackled, the creature is restrained. In addition, it falls prone whenever it is hit by a melee attack."},{name:"Strength of Madness",action:"Free",recharge:"Encounter",description:"Requirement: The harvester can use strength of madness only during its turn. Effect: Roll a d6 and add the result as a power bonus to the harvester's attack rolls until the end of its next turn. In addition, the harvester grants combat advantage until the end of its next turn. Skills Stealth +18"}],alignment:"Unaligned",languages:["Common","Deep Speech Equipment : 1 set of shackles","leather armor","war pick . Monster Manual 3","page(s) 50","Dungeon Magazine 201."] },
  { id:"mm3-derro-ironguard",name:"Derro Ironguard",source:"mm3",level:15,role:"Soldier",xp:1200,size:"Small",origin:"Natural",type:"Humanoid",hp:150,ac:31,fort:27,ref:24,will:27,initiative:9,perception:5,speed:"5",senses:["Darkvision"],powers:[{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 3d8 + 10 damage, or 3d8 + 15 against prone targets."},{name:"Hooking Jab",action:"Standard",keywords:["weapon"],description:"Requirement: The ironguard must not have a creature grabbed. Attack: Melee 1 (one creature); +20 vs. AC Hit: 2d8 + 5 damage, or 2d8 + 10 against prone targets, and the target is grabbed."},{name:"Unbalancing Thrust",action:"Minor",keywords:["weapon"],description:"1/round Requirement: The ironguard must be wielding a spear. Attack: Melee 1 (one creature grabbed by the ironguard); +20 vs. Fortitude Hit: The target falls prone."},{name:"Strength of Madness",action:"Free",recharge:"Encounter",description:"Requirement: The ironguard can use strength of madness only during its turn. Effect: Roll a d6 and add the result as a power bonus to the ironguard's attack rolls until the end of its next turn. In addition, the ironguard grants combat advantage until the end of its next turn. Skills Intimidate +17, Thievery +12"}],alignment:"Unaligned",languages:["Common","Deep Speech Equipment : scale armor","spear . Monster Manual 3","page(s) 50","Dungeon Magazine 201."] },
  { id:"mm3-flameborn",name:"Flameborn",source:"mm3",level:15,role:"Artillery",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:111,ac:27,fort:28,ref:28,will:28,initiative:8,perception:11,speed:"6",resist:["10 fire"],powers:[{name:"Fire Within",action:"Aura",description:"Aura 5 Allies within the aura gain resist 5 fire."},{name:"Flail",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 1d10 + 10 damage."},{name:"Fire Bolt",action:"Standard",keywords:["fire"],description:"Attack: Ranged 10 (one creature); +20 vs. Reflex Hit: 2d6 + 6 fire damage, and ongoing 10 fire damage (save ends)."},{name:"Blessing of Imix",action:"Standard",keywords:["fire"],recharge:"Encounter",description:"Attack: Close burst 3 (enemies in the burst); +18 vs. Reflex Hit: 3d6 + 6 fire damage, and the flameborn pushes the target 3 squares. Effect: Each ally in the burst gains 10 temporary hit points."},{name:"Fiery Eye",action:"Minor",description:"1/round Attack: Ranged 10 (one creature taking ongoing fire damage); +20 vs. Will Hit: The flameborn slides the target 2 squares, and the target grants combat advantage (save ends). Skills Arcana +15, Intimidate +18"}],alignment:"Unaligned",languages:["Common","Primordial Equipment : flail . Monster Manual 3","page(s) 116","Dungeon Magazine 216."] },
  { id:"mm3-hell-knight",name:"Hell Knight",source:"mm3",level:15,role:"Soldier",xp:1200,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["devil"],hp:146,ac:31,fort:27,ref:28,will:26,initiative:15,perception:11,speed:"6",senses:["Darkvision"],resist:["20 fire"],immune:["fear"],powers:[{name:"Hell's Rider",action:"Trait",description:"While the hell knight is mounted, its mount can make Athletics, Acrobatics, or Stealth checks using the hell knight's skill modifiers rather than its own"},{name:"Mace",action:"Standard",keywords:["fire","weapon"],description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 2d8 + 9 damage plus 5 fire damage, and the target falls prone."},{name:"Flame Lance",action:"Standard",keywords:["weapon"],description:"Requirement: The hell knight must be wielding a lance. Attack: Melee 2 (one creature); +20 vs. AC. When the hell knight charges while mounted, this attack can score a critical hit on a roll of 19-20. Hit: 2d10 + 12 fire damage."},{name:"Eyes of the Narzugon",action:"Minor",description:"Effect: One creature within 10 squares of the hell knight is marked and slowed until the end of the hell knight's next turn. Skills Athletics +17, Intimidate +15, Stealth +18"}],alignment:"Unaligned",languages:["Supernal Equipment : lance","heavy shield","mace","plate armor . Monster Manual 3","page(s) 57","Dungeon Magazine 196."] },
  { id:"mm3-kuo-toa-lash",name:"Kuo-Toa Lash",source:"mm3",level:15,role:"Artillery",xp:1200,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["aquatic"],hp:115,ac:27,fort:28,ref:27,will:26,initiative:12,perception:10,speed:"6, swim 6",senses:["Darkvision"],powers:[{name:"Aquatic",action:"Trait",description:"The lash can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Trident",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 2d8 + 9 damage."},{name:"Lightning Trident",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 3/6 (one creature); +22 vs. AC Hit: 3d8 + 10 lightning damage. Effect: The trident returns to the lash."},{name:"Fill Lungs",action:"Standard",description:"Attack: Ranged 20 (one creature); +20 vs. Fortitude Hit: 2d6 + 7 damage, and the target is slowed and takes ongoing 5 damage (save ends both)."},{name:"Forked Lightning",action:"Standard",keywords:["lightning"],recharge:"Recharge when the lash bloodies an enemy or reduces an enemy to 0 hit points or fewer",description:"Attack: Area burst 2 within 10 (one, two, or three creatures in the burst); +20 vs. Fortitude Hit: 2d6 + 6 lightning damage, and the target is blinded until the start of the lash's next turn."},{name:"Slick Maneuver",action:"Move",description:"Requirement: The lash must be adjacent to an enemy. Effect: The lash shifts 3 squares to another square adjacent to the enemy. Skills Dungeoneering +15, Religion +14"}],alignment:"Unaligned",languages:["Deep Speech Equipment : ceremonial knife","trident . Monster Manual 3","page(s) 125","Dungeon Magazine 204."] },
  { id:"mm3-norker-stone-walker",name:"Norker Stone Walker",source:"mm3",level:15,role:"Skirmisher",xp:1200,size:"Small",origin:"Elemental",type:"Humanoid",hp:150,ac:29,fort:27,ref:25,will:26,initiative:14,perception:11,speed:"6",senses:["Low-light vision"],powers:[{name:"Combat Advantage",action:"Trait",description:"The stone walker's attacks deal 5 extra damage against any creature granting combat advantage to it"},{name:"Nimble Reaction",action:"Trait",description:"The stone walker gains a +4 bonus to AC against opportunity attacks"},{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 3d6 + 13 damage."},{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 5/10 (one creature); +20 vs. AC Hit: 3d6 + 8 damage."},{name:"Earth Glide",action:"Move",description:"Effect: The stone walker moves its speed and can pass through earth and rock as if it were phasing."},{name:"Elemental Rebuke",action:"Triggered",description:"Trigger: An enemy hits the stone walker with a melee attack. Attack (Immediate Reaction): Melee 1 (the triggering enemy); +20 vs. AC Hit: 1d8 + 2 damage."}],alignment:"Unaligned",languages:["Common Equipment : handaxe x3. Monster Manual 3","page(s) 149."] },
  { id:"mm3-shardhorn-hunter",name:"Shardhorn Hunter",source:"mm3",level:15,role:"Lurker",xp:1200,size:"Medium",origin:"Natural",type:"Humanoid",hp:116,ac:29,fort:27,ref:28,will:26,initiative:17,perception:13,speed:"8",senses:["Darkvision"],powers:[{name:"Horn Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 4d4 + 10 damage."},{name:"Backstab",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature granting combat advantage to the hunter); +20 vs. AC Hit: 4d4 + 10 damage, and ongoing 10 damage (save ends)."},{name:"Goring Charge",action:"Standard",description:"Effect: The hunter charges and makes the following attack in place of a melee basic attack. Attack: Melee 1 (one creature); +21 vs. AC Hit: 2d10 + 10 damage, and the target falls prone."},{name:"Heart of the Unicorn",action:"Move",keywords:["illusion","teleportation"],recharge:"Recharge when the hunter uses backstab",description:"Effect: The hunter teleports 6 squares and becomes invisible until the end of its next turn or until it makes a melee attack roll."},{name:"Shardhorn Ferocity",action:"Triggered",description:"Trigger: The hunter drops to 0 hit points.. The hunter uses horn dagger. If the attack hits, the target is dazed until the end of the target's next turn. Skills Intimidate +17, Stealth +18"}],alignment:"Unaligned",languages:["Common Equipment : unicorn horn dagger Monster Manual 3","page(s) 141","Dungeon Magazine 189."] },
  { id:"mm3-stone-thrall",name:"Stone Thrall",source:"mm3",level:15,role:"Brute",xp:1200,size:"Large",origin:"Natural",type:"Humanoid",hp:184,ac:26,fort:29,ref:24,will:24,initiative:9,perception:9,speed:"7",powers:[{name:"Maul",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +20 vs. AC Hit: 4d8 + 6 damage, and the target grants combat advantage until the end of the thrall's next turn."},{name:"Crushing Smash",action:"Standard",keywords:["weapon"],description:"Requirement: The thrall must have combat advantage against the target. Attack: Melee 2 (one creature); +20 vs. AC Hit: 4d8 + 11 damage, the target falls prone, and it cannot stand up and is immobilized (save ends both)."},{name:"Wild Swing",action:"Standard",keywords:["weapon"],recharge:"Recharge when first bloodied",description:"Attack: Melee 2 (one or two creatures); +18 vs. AC Hit: 4d8 + 11 damage, and the target is dazed (save ends)."}],alignment:"Unaligned",languages:["Giant","understands Primordial Equipment : hide armor","maul . Monster Manual 3","page(s) 164."] },
  { id:"mm3-winter-nymph",name:"Winter Nymph",source:"mm3",level:15,role:"Artillery",xp:1200,size:"Medium",origin:"Fey",type:"Humanoid",hp:116,ac:27,fort:27,ref:28,will:26,initiative:15,perception:19,speed:"7 (forest walk), fly 10",senses:["Low-light vision"],powers:[{name:"Hunter's Knife",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +20 vs. AC Hit: 2d6 + 8 damage, and the nymph shifts 1 square."},{name:"Winter Wind",action:"Standard",keywords:["cold","weapon"],description:"Attack: Ranged 20/40 (one or two creatures); +22 vs. AC Hit: 2d6 + 5 cold damage, and the target is slowed (save ends)."},{name:"Nettling Wind",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Close blast 5 (one, two, or three creatures in the blast); +20 vs. AC Hit: 2d6 + 7 damage, and the target is immobilized (save ends)."},{name:"Hail of Arrows",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Attack: Area burst 3 within 20 (enemies in the burst); +22 vs. AC Hit: 2d8 + 5 damage, and ongoing 5 damage (save ends). Skills Athletics +18, Endurance +17, Nature +19, Stealth +20"}],alignment:"Unaligned",languages:["Common","Elven","Giant Equipment : arrow x40","dagger","longbow . Monster Manual 3","page(s) 152."] },
  { id:"mm3-banderhobb-warder",name:"Banderhobb Warder",source:"mm3",level:16,role:"Soldier",xp:1400,size:"Large",origin:"Shadow",type:"Magical beast",hp:160,ac:32,fort:30,ref:28,will:26,initiative:16,perception:15,speed:"6, swim 6",senses:["Darkvision"],powers:[{name:"Longfinger Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +21 vs. AC Hit: 3d8 + 11 damage, and the target is marked until the end of the warder's next turn."},{name:"Lightning Tongue",action:"Standard",keywords:["lightning"],description:"Attack: Ranged 5 (one creature); +19 vs. Reflex Hit: 2d8 + 7 lightning damage, and the target falls prone."},{name:"Longfinger Clutch",action:"Standard",description:"Attack: Melee 2 (one or two creatures); +21 vs. AC Hit: 2d8 + 7 damage, and the target is marked until the end of the warder's next turn."},{name:"Swallow",action:"Triggered",description:"Trigger: A Large or smaller enemy marked by the warder makes an attack that does not include the warder as a target. Effect (Immediate Reaction): The warder shifts 3 squares to a space adjacent to the triggering enemy and makes the following attack. Attack: Melee 1 (the triggering enemy); +19 vs. Fortitude Hit: The target is removed from play. Until the effect ends, the target takes ongoing 10 damage. The target can take actions as normal and can make melee and close attacks against the warder. The effect ends when the warder drops to 0 hit points or when the warder ends the effect as a free action. When the effect ends, the target appears in an unoccupied space of its choice adjacent to the warder. No Escape (teleportation) ✦ Encounter Trigger: An enemy marked by the warder ends its move. Effect (Immediate Reaction): The warder teleports 10 squares to a space adjacent to the triggering enemy. Skills Athletics +21"}],alignment:"Unaligned",languages:["understands Goblin Monster Manual 3","page(s) 18","Dungeon Magazine 180."] },
  { id:"mm3-derro-savant",name:"Derro Savant",source:"mm3",level:16,role:"Controller",xp:1400,size:"Small",origin:"Natural",type:"Humanoid",hp:154,ac:30,fort:27,ref:28,will:29,initiative:10,perception:6,speed:"5, teleport 3",senses:["Darkvision"],powers:[{name:"Scourge",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +21 vs. AC Hit: 3d8 + 11 damage, and the target takes a -2 penalty to attack rolls until the end of the savant's next turn."},{name:"Mind Scourge",action:"Standard",keywords:["implement","psychic"],description:"Attack: Ranged 5 (one creature); +19 vs. Will Hit: 3d6 + 8 psychic damage, and the target chooses either to take ongoing 10 psychic damage (save ends) or be dazed (save ends). Window to Madness (implement, psychic, zone) ✦ Recharge when this power's zone ends Effect: The savant creates a zone in an area burst 1 within 10 squares centered on an ally. The zone lasts until the end of the encounter. A nonderro that enters the zone or ends its turn there takes 10 psychic damage. The savant can end the zone as a minor action."},{name:"Dance of Madness",action:"Minor",description:"Effect: The savant slides each creature within the zone created by window to madness 2 squares."},{name:"Strength of Madness",action:"Free",recharge:"Encounter",description:"Requirement: The savant can use strength of madness only during its turn. Effect: Roll a d6 and add the result as a power bonus to the savant's attack rolls until the end of its next turn. In addition, the savant grants combat advantage until the end of its next turn. Skills Arcana +18"}],alignment:"Unaligned",languages:["Common","Deep Speech","telepathy 10 Equipment : orb implement","scourge . Monster Manual 3","page(s) 51","Dungeon Magazine 201."] },
  { id:"mm3-earth-weird",name:"Earth Weird",source:"mm3",level:16,role:"Controller",xp:1400,size:"Medium",origin:"Natural",type:"Humanoid",hp:148,ac:30,fort:26,ref:28,will:28,initiative:10,perception:12,speed:"5 (earth walk)",powers:[{name:"Morningstar",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +21 vs. AC Hit: 2d10 + 13 damage, and the weird pushes the target 1 square."},{name:"Quake Bolt",action:"Standard",description:"Attack: Ranged 5 (one creature); +19 vs. Reflex Hit: 3d6 + 8 damage, and the target falls prone."},{name:"Bury",action:"Standard",description:"Attack: Ranged 5 (one prone enemy); +19 vs. Fortitude Hit: The target cannot stand up, is immobilized, and takes ongoing 10 damage (save ends all). Aftereffect: The target is slowed until the end of its next turn."},{name:"Stoneburst",action:"Standard",keywords:["zone"],description:"Attack: Area burst 1 within 5 (creatures in the burst); +19 vs. Reflex Hit: 2d10 + 7 damage. Effect: The burst creates a zone of difficult terrain that lasts until the end of the earth weird's next turn."},{name:"Earthshock",action:"Minor",recharge:"Encounter",description:"Attack: Close burst 1 (enemies in the burst touching a solid surface); +19 vs. Fortitude Hit: The target falls prone. Skills Arcana +19"}],alignment:"Unaligned",languages:["Common","Primordial Equipment : morningstar . Monster Manual 3","page(s) 164."] },
  { id:"mm3-frost-giant-berserker",name:"Frost Giant Berserker",source:"mm3",level:16,role:"Skirmisher",xp:1400,size:"Large",origin:"Elemental",type:"Humanoid",keywords:["cold","giant"],hp:157,ac:30,fort:26,ref:29,will:28,initiative:17,perception:14,speed:"8 (ice walk)",resist:["15 cold"],powers:[{name:"Icebound Footing",action:"Trait",description:"When an effect pulls, pushes, or slides the giant, it can choose to move 2 squares fewer than the effect specifies"},{name:"The",action:"Trait",description:"giant can make a saving throw to avoid falling prone when an attack would knock it prone"},{name:"Freezing Greataxe",action:"Standard",keywords:["cold","weapon"],description:"Attack: Melee 2 (one creature); +21 vs. AC Hit: 1d12 + 10 damage plus 2d6 cold damage."},{name:"Storm Charge",action:"Standard",keywords:["cold","weapon"],description:"Effect: The berserker charges without provoking opportunity attacks and makes the following attack in place of a melee basic attack. Attack: Melee 2 (one creature); +22 vs. AC Hit: 2d12 + 12 damage."},{name:"Primordial Rage",action:"Standard",recharge:"Encounter",description:"Effect: The berserker shifts its speed and uses freezing greataxe three times during the shift, making each attack against a different target."},{name:"Giant Stride",action:"Move",recharge:"Recharge 3-6",description:"Effect: The berserker shifts 6 squares and can move through enemies' spaces during the shift. Skills Athletics +20"}],alignment:"Unaligned",languages:["Giant Equipment : greataxe","hide armor . Monster Manual 3","page(s) 98","Dungeon Magazine 199."] },
  { id:"mm3-greater-maw-demon",name:"Greater Maw Demon",source:"mm3",level:16,role:"Brute",xp:1400,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["demon"],hp:187,ac:28,fort:28,ref:27,will:26,initiative:8,perception:9,speed:"6",senses:["Darkvision"],resist:["20 to the triggering damage type until the end of the encounter or until it uses variable resistance again."],powers:[{name:"Snapping Jaws",action:"Aura",description:"Aura 1 Enemies within the aura grant combat advantage."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +19 vs. AC Hit: 3d12 + 11 damage."},{name:"Howling Hunger",action:"Standard",keywords:["thunder"],recharge:"Encounter",description:"Requirement: The demon must be bloodied. Attack: Close burst 3 (enemies in the burst); +18 vs. Will Hit: 3d10 + 8 thunder damage, and the target falls prone."},{name:"Ravenous Advance",action:"Move",description:"Effect: The demon shifts 5 squares to a square adjacent to the nearest bloodied enemy."},{name:"Variable Resistance",action:"Triggered",recharge:"2/Encounter",description:"Trigger: The demon takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The demon gains resist 20 to the triggering damage type until the end of the encounter or until it uses variable resistance again."}],alignment:"Unaligned",languages:["understands Abyssal Monster Manual 3","page(s) 42."] },
  { id:"mm3-impersonator-mimic",name:"Impersonator Mimic",source:"mm3",level:16,role:"Controller",xp:1400,size:"Medium",origin:"Aberrant",type:"Magical beast",hp:160,ac:30,fort:27,ref:28,will:27,initiative:14,perception:13,speed:"6",senses:["Darkvision"],resist:["10 acid"],powers:[{name:"Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +21 vs. AC Hit: 3d8 + 11 damage."},{name:"Forcible Conversion",action:"Standard",keywords:["charm"],recharge:"Recharge 4-6",description:"Attack: Melee 2 (one creature); +19 vs. Fortitude Hit: The target is dominated (save ends)."},{name:"Call to Harvest",action:"Minor",keywords:["charm"],description:"1/round Attack: Ranged 10 (one creature); +19 vs. Will Hit: The mimic slides the target 4 squares, and the target grants combat advantage until the end of the mimic's next turn."},{name:"Shapeshift",action:"Minor",keywords:["polymorph"],description:"1/round Effect: The mimic assumes one of the following forms. It can't change its size. It remains in the chosen form until it uses this power again. Ooze Form: The mimic becomes an ooze. When it squeezes while it is in this form, it moves at full speed rather than half speed, it doesn't take the -5 penalty to attack rolls, and it doesn't grant combat advantage for squeezing. Humanoid Form: The mimic gains a +4 bonus to Bluff checks. In addition, it can use all the languages known by the last humanoid creature it killed. Object Form: While in this form, the mimic has resist 10 to all damage, is immobilized, and cannot attack. In addition, a creature must succeed on a DC 31 Perception check to notice that the mimic is a living creature."},{name:"Absorb",action:"Free",description:"1/round Requirement: The mimic can use absorb only during its turn. Effect: The mimic reduces one mimic spawn that is adjacent to it or occupying its space (see the mimic spawn's one with master power) to 0 hit points. When it does so, it gains 1 action point. Skills Bluff +20, Stealth +19 (Bluff +24 while the mimic is in humanoid form)"}],alignment:"Unaligned",languages:["Common","Deep Speech Monster Manual 3","page(s) 135","Dungeon Magazine 203","Dungeon Magazine 209."] },
  { id:"mm3-kuo-toa-cutter",name:"Kuo-Toa Cutter",source:"mm3",level:16,role:"Skirmisher",xp:1400,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["aquatic"],hp:151,ac:30,fort:28,ref:30,will:27,initiative:17,perception:12,speed:"6, swim 6",senses:["Darkvision"],powers:[{name:"Aquatic",action:"Trait",description:"The cutter can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Barbed Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +21 vs. AC Hit: 4d4 + 14 damage."},{name:"Crippling Strike",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature granting combat advantage to the cutter); +21 vs. AC Hit: 2d4 + 4 damage, and the target is slowed and takes ongoing 10 damage (save ends both)."},{name:"Slick Maneuver",action:"Move",description:"Requirement: The cutter must be adjacent to an enemy. Effect: The cutter shifts 3 squares to another square adjacent to the enemy."},{name:"Swift Strike",action:"Triggered",description:"Trigger: An enemy misses the cutter with a melee attack. Effect (Immediate Reaction): The cutter shifts 4 squares and uses barbed dagger. Skills Acrobatics +20, Stealth +20"}],alignment:"Unaligned",languages:["Deep Speech Equipment : dagger . Monster Manual 3","page(s) 125","Dungeon Magazine 203","Dungeon Magazine 204."] },
  { id:"mm3-mimic-spawn",name:"Mimic Spawn",source:"mm3",level:16,role:"Lurker",roleModifier:"Minion",xp:350,size:"Medium",origin:"Aberrant",type:"Magical beast",hp:1,ac:30,fort:27,ref:29,will:26,initiative:18,perception:13,speed:"6",senses:["Darkvision"],resist:["10 acid"],powers:[{name:"One",action:"Trait",description:"with Master The mimic spawn can end its move in the same space as an impersonator mimic"},{name:"While",action:"Trait",description:"it occupies an impersonator mimic's space, the mimic spawn moves with the impersonator mimic and cannot attack, be targeted, or take damage"},{name:"Up",action:"Trait",description:"to four mimic spawns can occupy an impersonator mimic's space"},{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +21 vs. AC Hit: 12 damage."},{name:"Shapeshift",action:"Minor",keywords:["polymorph"],description:"1/round Effect: The mimic assumes one of the following forms. It can't change its size. It remains in the chosen form until it uses this power again. Ooze Form: The mimic becomes an ooze. When it squeezes while it is in this form, it moves at full speed rather than half speed, it doesn't take the -5 penalty to attack rolls, and it doesn't grant combat advantage for squeezing, Object Form: While in this form, the mimic has resist 10 to all damage, is immobilized, and cannot attack. In addition, a creature must succeed on a DC 31 Perception check to notice that the mimic is a living creature. Skills Stealth +19"}],alignment:"Unaligned",languages:["Common","Deep Speech Monster Manual 3","page(s) 135","Dungeon Magazine 203","Dungeon Magazine 209."] },
  { id:"mm3-passion-devil",name:"Passion Devil",source:"mm3",level:16,role:"Controller",xp:1400,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["devil","shapechanger"],hp:156,ac:30,fort:27,ref:28,will:29,initiative:14,perception:12,speed:"6, fly 6 (hover)",senses:["Darkvision"],resist:["20 fire"],powers:[{name:"Object of Desire",action:"Aura",keywords:["charm"],description:"Aura 1 Enemies within the aura take a -2 penalty to saving throws against effects that daze."},{name:"Claws",action:"Standard",keywords:["fire"],description:"Attack: Melee 1 (one creature); +19 vs. Reflex Hit: 3d8 + 11 fire damage."},{name:"Fiery Touch",action:"Standard",keywords:["charm","fire"],description:"Attack: Melee 1 (one creature dazed by this devil's beckoning whispers); +19 vs. Reflex Hit: 1d8 + 11 fire damage, and the target is dominated until the end of the devil's next turn."},{name:"Beckoning Whispers",action:"Standard",keywords:["charm"],description:"Attack: Close blast 5 (enemies in the blast); +19 vs. Will Hit: The devil pulls the target 5 squares, and the target is dazed (save ends)."},{name:"Passion's Flames",action:"Standard",keywords:["fire"],recharge:"Recharge 4-6",description:"Attack: Close burst 3 (one creature in the burst); +19 vs. Reflex Hit: The target takes ongoing 15 fire damage (save ends). If the target is dominated by the devil, the target also makes a melee basic attack as a free action against a creature of the devil's choice."},{name:"Change Shape",action:"Minor",keywords:["polymorph"],description:"Effect: The devil alters its physical form to appear as a Medium humanoid until it attacks, until it uses change shape again, or until it drops to 0 hit points. The creature retains its statistics in its new form. Its clothing, armor, and other possessions do not change. To assume a specific individual's form, the devil must have seen that individual. Other creatures can make a DC 36 Insight check to discern that the form is a disguise. Skills Bluff +20, Diplomacy +20, Insight +17"}],alignment:"Unaligned",languages:["Common","Supernal Monster Manual 3","page(s) 59","Dungeon Magazine 196."] },
  { id:"mm3-slime-devil",name:"Slime Devil",source:"mm3",level:16,role:"Lurker",xp:1400,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["devil","ooze"],hp:123,ac:30,fort:28,ref:29,will:28,initiative:18,perception:13,speed:"6, swim 6",senses:["Darkvision"],resist:["20 acid"],powers:[{name:"Mercurial Body",action:"Trait",description:"The slime devil ignores difficult terrain and does not provoke opportunity attacks by moving"},{name:"Caustic Slam",action:"Standard",keywords:["acid"],description:"Attack: Melee 1 (one creature); +19 vs. Fortitude Hit: 3d8 + 11 acid damage."},{name:"Diabolical Engulfment",action:"Standard",keywords:["acid"],description:"Attack: Melee 1 (one Medium or smaller enemy); +19 vs. Reflex Hit: The devil grabs the target and shifts 1 square into the target's square. Until the grab ends, the target is dazed and takes ongoing 10 acid damage. While the devil has the target grabbed, attacks against the devil deal half damage to it and half damage to the grabbed creature. When the devil moves, it pulls the target with it. In addition, the target remains grabbed, and the devil does not provoke an opportunity attack from the target."},{name:"Acidic Tendrils",action:"Standard",keywords:["acid"],recharge:"Recharge 4-6",description:"Attack: Melee 3 (one, two, or three creatures); +19 vs. Reflex Hit: 1d8 + 7 acid damage, and ongoing 10 acid damage (save ends). In addition, the devil pulls the target 2 squares."},{name:"Scour the Mind",action:"Minor",keywords:["psychic"],description:"(1/round) Attack: Melee 1 (one creature grabbed by the devil); +19 vs. Will Hit: The devil telepathically asks the target a question, and the target must answer the question truthfully or else take 3d8 + 11 psychic damage. Skills Acrobatics +19, Bluff +12, Stealth +19"}],alignment:"Unaligned",languages:["Supernal","telepathy 5 Monster Manual 3","page(s) 61","Dungeon Magazine 188","Dungeon Magazine 196."] },
  { id:"mm3-varoot-nerra",name:"Varoot Nerra",source:"mm3",level:16,role:"Lurker",xp:1400,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["shapechanger"],hp:116,ac:30,fort:27,ref:30,will:28,initiative:17,perception:14,speed:"6",powers:[{name:"Shard Blade",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +21 vs. AC Hit: 2d8 + 15 damage. Reflection Theft (polymorph) ✦ At-Will Effect: The varoot becomes a perfect duplicate of one enemy within 10 squares of it. The effect lasts until the end of the encounter or until the varoot attacks. While the varoot is in this form and adjacent to the duplicated enemy, whenever a creature other than the duplicated enemy makes a melee or a ranged attack against the varoot, roll a d20. On a result of 10 or higher, the attack targets the enemy instead of the varoot. In addition, the varoot gains a +2 bonus to attack rolls and a +5 bonus to damage rolls against the enemy it duplicated."},{name:"Mirror Step",action:"Move",keywords:["teleportation"],description:"Effect: The varoot teleports 5 squares to a square adjacent to a mirror or another nerra."},{name:"Mirrored Grasp",action:"Minor",keywords:["teleportation"],description:"Effect: One Tiny or smaller unattended object of up to 20 pounds that the varoot can see and is within 10 squares of it is teleported to the varoot's hand. Skills Bluff +20, Diplomacy +20, Insight +14, Thievery +18"}],alignment:"Unaligned",languages:["Supernal Equipment : longsword . Monster Manual 3","page(s) 145."] },
  { id:"mm3-warped-slave",name:"Warped Slave",source:"mm3",level:16,role:"Brute",xp:1400,size:"Large",origin:"Aberrant",type:"Humanoid",hp:193,ac:28,fort:29,ref:26,will:29,initiative:11,perception:7,speed:"6 (can't shift)",senses:["Darkvision"],powers:[{name:"Disintegrating Mind",action:"Aura",keywords:["psychic"],description:"Aura 1 Any enemy that ends its turn within the aura takes 5 psychic damage"},{name:"Whenever",action:"Trait",description:"a derro within the aura uses strength of madness, the warped slave can use tentacle as a free action"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +21 vs. AC Hit: 3d12 + 6 damage."},{name:"Tentacle",action:"Standard",description:"Attack: Melee 2 (one creature); +19 vs. Reflex Hit: 2d12 + 6 damage, and the warped slave grabs the target. The warped slave then pulls the target 1 square."},{name:"Flailing Tentacles",action:"Standard",description:"Requirement: The warped slave must be bloodied. Attack: Close burst 2 (enemies in the burst); +21 vs. AC Hit: 2d12 + 6 damage, and the warped slave pulls the target 1 square."}],alignment:"Unaligned",languages:["Common","Deep Speech Monster Manual 3","page(s) 51","Dungeon Magazine 201."] },
  { id:"mm3-astral-hulk",name:"Astral Hulk",source:"mm3",level:17,role:"Soldier",xp:1600,size:"Large",origin:"Immortal",type:"Magical beast",hp:167,ac:33,fort:29,ref:28,will:29,initiative:13,perception:12,speed:"5, burrow 2 (tunneling)",senses:["Darkvision"],powers:[{name:"Claws",action:"Standard",description:"Attack: Melee 2 (one creature); +22 vs. AC Hit: 2d10 + 14 damage, and the target is marked until the end of the hulk's next turn."},{name:"Gaze of Lassitude",action:"Standard",keywords:["charm"],description:"Attack: Close blast 5 (enemies in the blast); +20 vs. Fortitude Hit: 2d6 + 3 damage, and the hulk pulls the target 4 squares. In addition, the target is slowed (save ends)."},{name:"Gaze of Annihilation",action:"Standard",recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +20 vs. Fortitude Hit: 2d10 + 5 damage. Miss: Half damage. Effect: The target is marked until the end of the hulk's next turn."},{name:"Entrapping Mandibles",action:"Triggered",description:"Requirement: The hulk must not have a creature grabbed. Trigger: An enemy marked by the hulk shifts. Attack (Immediate Interrupt): Melee 1 (the triggering enemy); +22 vs. Fortitude Hit: The target is grabbed."}],alignment:"Unaligned",languages:["understands Deep Speech Monster Manual 3","page(s) 199","Dungeon Magazine 203."] },
  { id:"mm3-banderhobb-filch",name:"Banderhobb Filch",source:"mm3",level:17,role:"Skirmisher",xp:0,size:"Small",origin:"Shadow",type:"Magical beast",hp:164,ac:31,fort:28,ref:32,will:27,initiative:18,perception:14,speed:"6, climb 3, swim 6",senses:["Darkvision"],powers:[{name:"Quick Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +22 vs. AC Hit: 3d6 + 15 damage, and the filch shifts 1 square."},{name:"Stinking Gob",action:"Standard",description:"Attack: Ranged 5 (one creature); +22 vs. AC Hit: 2d12 + 4 damage. Effect: The filch shifts 1 square."},{name:"Hook Strike",action:"Standard",description:"Attack: Melee 1 (one creature); +20 vs. Reflex Hit: 3d6 + 4 damage, and the filch grabs the target."},{name:"Shadow Blink",action:"Standard",keywords:["teleportation"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +22 vs. AC Hit: 4d8 + 20 damage. Effect: The filch teleports 5 squares before or after the attack."},{name:"Distracting Frenzy",action:"Standard",recharge:"Encounter",description:"Attack: Close burst 1 (enemies in the burst); +22 vs. AC Hit: 2d8 + 5 damage. Effect: An ally within 5 squares of the filch immediately takes a standard action as a free action."},{name:"Drag Away",action:"Move",description:"Requirement: The filch must have a creature grabbed. Effect: The filch moves its speed, pulling the grabbed creature with it. The filch and the creature grabbed by it do not provoke opportunity attacks from each other for this movement. Skills Athletics +20, Stealth +21"}],alignment:"Unaligned",languages:["understands Goblin Monster Manual 3","page(s) 19","Dungeon Magazine 180."] },
  { id:"mm3-elder-blizzard-dragon",name:"Elder Blizzard Dragon",source:"mm3",level:17,role:"Controller",roleModifier:"Elite",xp:3200,size:"Huge",origin:"Elemental",type:"Magical beast",keywords:["cold","dragon"],hp:338,ac:31,fort:29,ref:30,will:28,initiative:16,perception:14,speed:"10 (ice walk), fly 10 (clumsy)",senses:["Darkvision"],powers:[{name:"Freezing Winds",action:"Aura",description:"Aura 1 The dragon slides any enemy that ends its turn in the aura 2 squares."},{name:"Bite",action:"Standard",keywords:["cold"],description:"Attack: Melee 3 (one creature); +22 vs. AC Hit: 3d8 + 6 cold damage, and the target is immobilized until the end of the dragon's next turn."},{name:"Claw",action:"Standard",keywords:["cold"],description:"Attack: Melee 3 (one creature); +22 vs. AC Hit: 4d6 + 11 cold damage, and the dragon slides the target 3 squares."},{name:"Double Attack",action:"Standard",description:"Effect: The dragon uses bite and claw or uses claw twice."},{name:"Rising Winds",action:"Minor",keywords:["cold"],description:"Recharge at the start of any turn when freezing winds is aura 1 Effect: The freezing winds expands to aura 3. At the start of the dragon's next turn, the freezing winds expands to aura 5. At the start of its following turn, the dragon makes the following attack. Attack (No Action): Close burst 5 (enemies in the burst); +20 vs. Fortitude Hit: 4d8 + 8 cold damage, and the target is restrained and blinded (save ends both). Effect: The freezing winds aura reverts to its original state and size (aura 1)."},{name:"Chill Rebuke",action:"Triggered",keywords:["cold"],recharge:"Recharge when first bloodied",description:"Trigger: An enemy's melee attack deals damage to the dragon. Attack (Immediate Reaction): Close blast 5 (enemies in the blast); +20 vs. Fortitude Hit: 1d10 + 12 cold damage, and the target is slowed (save ends). Sudden Flurry ✦ At-Will Trigger: The dragon is hit by a cold attack. Effect (Free Action): The dragon slides each enemy in its aura 2 squares."}],alignment:"Unaligned",languages:["Common","Draconic","Primordial Monster Manual 3","page(s) 67","Dungeon Magazine 199."] },
  { id:"mm3-fire-giant-lavamaster",name:"Fire Giant Lavamaster",source:"mm3",level:17,role:"Controller",xp:0,size:"Large",origin:"Elemental",type:"Humanoid",keywords:["fire","giant"],hp:164,ac:31,fort:31,ref:27,will:28,initiative:12,perception:13,speed:"8",resist:["15 fire"],powers:[{name:"Hearthflames",action:"Aura",keywords:["fire","healing"],description:"Aura 2 Any enemy that enters the aura or ends its turn there takes 10 fire damage"},{name:"Any",action:"Trait",description:"bloodied ally of the lavamaster that starts its turn within the aura regains 10 hit points"},{name:"Molten Sword",action:"Standard",keywords:["fire","weapon"],description:"Attack: Melee 2 (one creature); +22 vs. AC Hit: 2d10 + 14 fire damage."},{name:"Magma Lash",action:"Standard",keywords:["fire"],recharge:"Recharge when no creature is grabbed by the lavamaster",description:"Attack: Ranged 5 (one creature); +20 vs. Reflex Hit: 2d8 + 10 fire damage, and the lavamaster pulls the target up to 4 squares. If the target ends the movement adjacent to the lavamaster, it is grabbed by the lavamaster (escape DC 23)."},{name:"Magma Burst",action:"Standard",keywords:["fire","zone"],description:"Attack: Area burst 1 within 10 (enemies in the burst); +20 vs. Fortitude Hit: 2d6 + 10 fire damage. Effect: The burst creates a zone of difficult terrain that lasts until the end of the lavamaster's next turn. Any enemy that enters the zone or ends its turn there takes 10 fire damage. A creature can take this damage only once per turn."},{name:"Fiery Vendetta",action:"Triggered",description:"Trigger: An enemy grabbed by the lavamaster attacks it. Effect (Immediate Reaction): The lavamaster or one of its allies can make a melee basic attack against the triggering enemy as a free action."}],alignment:"Unaligned",languages:["Giant Equipment : chainmail","greatsword . Monster Manual 3","page(s) 96","Dungeon Magazine 196","Dungeon Magazine 199","Dungeon Magazine 200","Dungeon Magazine 216."] },
  { id:"mm3-girallon-alpha",name:"Girallon Alpha",source:"mm3",level:17,role:"Brute",xp:1600,size:"Large",origin:"Natural",type:"Beast",hp:195,ac:29,fort:29,ref:28,will:27,initiative:14,perception:17,speed:"8, climb 6",powers:[{name:"Threatening Claws",action:"Aura",description:"Aura 1 Enemies within the aura grant combat advantage"},{name:"Combat Climber",action:"Trait",description:"The alpha does not provoke opportunity attacks by climbing"},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +21 vs. AC Hit: 3d12 + 10 damage."},{name:"Claw Flurry",action:"Standard",recharge:"Recharge 4-6",description:"Effect: The alpha makes the following attack four times. Attack: Melee 2 (one creature); +21 vs. AC Hit: 1d12 + 8 damage."},{name:"Rend and Tear",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Close blast 3 (enemies in the blast); +19 vs. Fortitude Hit: 3d12 + 10 damage, and the alpha slides the target 3 squares."},{name:"Whirling Claws",action:"Triggered",description:"Trigger: An enemy starts its turn within 2 squares of the alpha. Effect (Free Action): The alpha slides the target 1 square. Skills Acrobatics +19, Athletics +20"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 103."] },
  { id:"mm3-gremlin-conniver",name:"Gremlin Conniver",source:"mm3",level:17,role:"Controller",xp:1600,size:"Small",origin:"Fey",type:"Humanoid",hp:162,ac:31,fort:28,ref:31,will:29,initiative:13,perception:18,speed:"6",senses:["Low-light vision"],powers:[{name:"Claw",action:"Standard",keywords:["teleportation"],description:"Attack: Melee 1 (one creature); +22 vs. AC Hit: 4d6 + 10 damage, and the conniver teleports the target 5 squares."},{name:"Connive",action:"Standard",keywords:["charm"],description:"Attack: Ranged 10 (one creature); +20 vs. Will Hit: The target is dominated (save ends). The conniver can have only one creature dominated at a time."},{name:"Beguiling Fog",action:"Minor",recharge:"Recharge 5-6",description:"Attack: Area burst 2 within 10 (enemies in the burst); +20 vs. Will Hit: The target is dazed (save ends). Miss: The target is dazed until the end of its next turn."},{name:"Gremlin Tactics",action:"Triggered",description:"Trigger: An enemy adjacent to the conniver misses it with a melee attack. Effect (Immediate Reaction): The conniver swaps positions with the triggering enemy. Skills Bluff +16, Stealth +18, Thievery +18"}],alignment:"Unaligned",languages:["Common","Elven","Goblin Monster Manual 3","page(s) 107."] },
  { id:"mm3-gremlin-prankster",name:"Gremlin Prankster",source:"mm3",level:17,role:"Controller",roleModifier:"Minion",xp:400,size:"Small",origin:"Fey",type:"Humanoid",hp:1,ac:31,fort:27,ref:30,will:29,initiative:14,perception:18,speed:"6",senses:["Low-light vision"],powers:[{name:"Sabotaging Presence",action:"Aura",description:"Aura 5 Enemies within the aura take a -5 penalty to skill checks."},{name:"Claw",action:"Standard",description:"Attack: Melee 1 (one creature); +22 vs. AC Hit: 12 damage."},{name:"Slip Up",action:"Minor",description:"1/round Attack: Ranged 5 (one creature); +20 vs. Will Hit: The prankster slides the target 3 squares and knocks it prone. Skills Stealth +19, Thievery +19"}],alignment:"Unaligned",languages:["Common","Elven","Goblin Monster Manual 3","page(s) 107."] },
  { id:"mm3-tanarukk-flame-speaker",name:"Tanarukk Flame Speaker",source:"mm3",level:17,role:"Artillery",xp:1600,size:"Medium",origin:"Natural",type:"Humanoid",hp:129,ac:29,fort:29,ref:29,will:29,initiative:11,perception:11,speed:"6",senses:["Darkvision"],resist:["10 fire"],powers:[{name:"Staff",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +22 vs. AC Hit: 3d6 + 10 damage."},{name:"Fire Bolt",action:"Standard",keywords:["fire","implement"],description:"Attack: Ranged 10 (one creature); +22 vs. Reflex Hit: 3d8 + 12 fire damage."},{name:"Fire Barrage",action:"Standard",keywords:["fire","implement"],recharge:"Recharge 4-6",description:"Attack: Ranged 10 (one, two, or three creatures); +22 vs. Reflex Hit: 2d10 + 7 fire damage."},{name:"Winds of Fire",action:"Standard",keywords:["fire","implement","zone"],recharge:"Encounter",description:"Attack: Area burst 2 within 20 (creatures in the burst); +22 vs. Reflex Hit: 3d6 + 6 fire damage. Effect: The burst creates a zone that lasts until the end of the encounter. Any creature that enters the zone or ends its turn there takes 10 fire damage and is pulled 1 square toward the burst's origin square."}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : staff implement . Monster Manual 3","page(s) 191."] },
  { id:"mm3-tanarukk-marauder",name:"Tanarukk Marauder",source:"mm3",level:17,role:"Skirmisher",xp:1600,size:"Medium",origin:"Natural",type:"Humanoid",hp:165,ac:31,fort:29,ref:28,will:28,initiative:12,perception:11,speed:"6",senses:["Darkvision"],resist:["5 fire"],powers:[{name:"Nimble Reaction",action:"Trait",description:"The marauder gains a +4 bonus to AC against opportunity attacks"},{name:"Greataxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +22 vs. AC Hit: 2d12 + 12 damage."},{name:"Brutal Rampage",action:"Standard",description:"Effect: The marauder moves its speed and can move through enemies' spaces during the move. At any point during the move, the marauder can use greataxe. The marauder gains a +5 bonus to the damage roll for each opportunity attack made against it during the move before the attack."},{name:"Hand Axe",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 5/10 (one creature); +22 vs. AC Hit: 2d6 + 12 damage."},{name:"Flame Harrower",action:"Standard",keywords:["fire","weapon"],recharge:"Encounter",description:"Attack: Melee 1 (one creature); +20 vs. Fortitude Hit: 2d12 + 10 fire damage, and the target takes ongoing 15 fire damage and grants combat advantage (save ends both)."}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : greataxe","handaxe x3","hide armor . Monster Manual 3","page(s) 190."] },
  { id:"mm3-banderhobb-abductor",name:"Banderhobb Abductor",source:"mm3",level:18,role:"Brute",xp:2000,size:"Large",origin:"Shadow",type:"Magical beast",hp:211,ac:30,fort:29,ref:32,will:30,initiative:17,perception:16,speed:"6, swim 6",senses:["Darkvision"],powers:[{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +23 vs. AC Hit: 3d12 + 13 damage."},{name:"Grasping Tongue",action:"Standard",description:"Attack: Ranged 5 (one creature); +21 vs. Reflex Hit: 2d12 + 3 damage, and the abductor pulls the target 4 squares to a space adjacent to the abductor and grabs the creature."},{name:"Gobble",action:"Standard",description:"Requirement: The abductor must be bloodied. Attack: Melee 1 (one creature); +23 vs. AC Hit: 4d12 + 7 damage, and the abductor grabs the target. If the target is bloodied, the abductor recharges swallow and uses it against the target."},{name:"Swallow",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Melee 1 (one bloodied creature grabbed by the abductor); +21 vs. Fortitude Hit: The target is removed from play. Until the effect ends, the target takes ongoing 10 damage. The target can take actions as normal and can make melee and close attacks against the abductor. The effect ends when the abductor drops to 0 hit points or when the abductor ends the effect as a free action. When the effect ends, the target appears in an unoccupied space of its choice adjacent to the abductor."},{name:"Cross into Shadow",action:"Triggered",keywords:["teleportation"],recharge:"Encounter",description:"Trigger: The abductor is first bloodied. Effect (No Action): The abductor is removed from play until the start of its next turn. The abductor then appears in an unoccupied space within 10 squares of its last location. Skills Athletics +20, Stealth +22"}],alignment:"Unaligned",languages:["understands Goblin Monster Manual 3","page(s) 19","Dungeon Magazine 180."] },
  { id:"mm3-catoblepas-tragedian",name:"Catoblepas Tragedian",source:"mm3",level:18,role:"Controller",roleModifier:"Elite",xp:4000,size:"Huge",origin:"Shadow",type:"Beast",hp:360,ac:32,fort:30,ref:28,will:30,initiative:15,perception:15,speed:"6",senses:["Blindsight 5"],resist:["10 necrotic"],vulnerable:["5 to all damage (save ends both). Aftereffect:","20 necrotic damage."],powers:[{name:"Raven Queen's Presence",action:"Aura",description:"Aura 5 Any creature within the aura that fails a death saving throw takes damage equal to half its bloodied value."},{name:"Gore",action:"Standard",description:"Attack: Melee 1 (one creature); +23 vs. AC Hit: 3d8 + 13 damage."},{name:"Poison Breath",action:"Standard",keywords:["poison"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (creatures in the blast); +21 vs. Fortitude Hit: 2d6 + 9 poison damage, and ongoing 10 poison damage (save ends)."},{name:"Withering Gaze",action:"Standard",recharge:"Recharge when no enemy is affected by this power",description:"Attack: Close burst 10 (one bloodied creature in the burst); +21 vs. Will Hit: 1d8 + 9 necrotic damage, and the target is weakened (save ends). First Failed Saving Throw: The target is weakened and blinded (save ends both). Second Failed Saving Throw: The target's hit points drop to -1."},{name:"Inevitable Call",action:"Minor",keywords:["charm"],description:"Effect: Choose one enemy within 20 squares. The tragedian pulls that enemy 3 squares."},{name:"Final Glance",action:"Triggered",keywords:["charm","necrotic"],description:"Trigger: An enemy within 5 squares of the tragedian willingly moves away from it. Attack (Opportunity Action): Close burst 10 (the triggering enemy in the burst); +21 vs. Will Hit: 10 necrotic damage, and the target is immobilized and gains vulnerable 5 to all damage (save ends both). Aftereffect: 20 necrotic damage."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 27."] },
  { id:"mm3-cloaker-lord",name:"Cloaker Lord",source:"mm3",level:18,role:"Controller",xp:2000,size:"Large",origin:"Aberrant",type:"Magical beast",hp:172,ac:30,fort:30,ref:29,will:27,initiative:12,perception:16,speed:"2 (clumsy), fly 8 (hover)",senses:["Darkvision"],powers:[{name:"Unnerving Moan",action:"Aura",keywords:["fear"],description:"Aura 2, or 5 while the lord is bloodied Nondeafened enemies within the aura take a -2 penalty to attack rolls."},{name:"Tail Slap",action:"Standard",description:"Attack: Melee 2 (one creature); +23 vs. AC Hit: 2d10 + 15 damage, and the target is grabbed."},{name:"Envelop",action:"Standard",description:"Requirement: The lord must not have a creature grabbed. Attack: Melee 1 (one creature); +21 vs. Reflex Hit: The lord slides the target 1 square to a square within the lord's space, and the target is grabbed. While the target is grabbed by the lord, it is blinded, dazed, restrained, and takes ongoing 20 damage. In addition, whenever an attack deals damage to the lord while it has the target grabbed, the attack deals half damage to the lord and half damage to the target."},{name:"Terrifying Moan",action:"Standard",keywords:["fear","psychic"],recharge:"Recharge 3-6",description:"Attack: Close burst 2, or 5 while the lord is bloodied (enemies in the burst); +21 vs. Will Hit: 3d8 + 8 psychic damage, and the target moves its speed away from the lord."},{name:"Hypnotic Moan",action:"Standard",recharge:"Encounter",description:"Attack: Close burst 2, or 5 while the lord is bloodied (enemies in the burst); +21 vs. Will Hit: The target is stunned until the end of the lord's next turn. Miss: The target is dazed until the end of the lord's next turn."},{name:"Shadow Shift",action:"Minor",keywords:["illusion"],description:"Effect: The lord gains concealment until the start of its next turn. If the lord is in an obscured square, it gains total concealment until the start of its next turn. Skills Stealth +17"}],alignment:"Unaligned",languages:["Deep Speech Monster Manual 3","page(s) 35","Dungeon Magazine 204."] },
  { id:"mm3-fire-giant-flamedancer",name:"Fire Giant Flamedancer",source:"mm3",level:18,role:"Skirmisher",xp:2000,size:"Large",origin:"Elemental",type:"Humanoid",keywords:["giant"],hp:174,ac:32,fort:31,ref:29,will:27,initiative:17,perception:13,speed:"8",resist:["15 fire"],powers:[{name:"Nimble Reaction",action:"Trait",description:"The flamedancer gains a +4 bonus to AC against opportunity attacks"},{name:"Whirling Spear",action:"Standard",keywords:["fire","weapon"],description:"Attack: Melee 2 (one creature); +23 vs. AC Hit: 2d8 + 8 fire damage, and the flamedancer shifts 2 squares."},{name:"Double Attack",action:"Standard",description:"Effect: The flamedancer uses whirling spear twice, making each attack against a different target."},{name:"Flameburst Leap",action:"Move",keywords:["fire","teleportation"],recharge:"Encounter",description:"Effect: The flamedancer teleports 8 squares. Any enemy adjacent to the flamedancer at the start of the teleport takes ongoing 10 fire damage (save ends). Skills Acrobatics +20, Athletics +21"}],alignment:"Unaligned",languages:["Giant Equipment : hide armor","spear . Monster Manual 3","page(s) 97","Dungeon Magazine 216."] },
  { id:"mm3-frost-giant-shield-bearer",name:"Frost Giant Shield Bearer",source:"mm3",level:18,role:"Soldier",xp:2000,size:"Large",origin:"Elemental",type:"Humanoid",keywords:["cold","giant"],hp:174,ac:34,fort:32,ref:31,will:28,initiative:17,perception:14,speed:"8 (ice walk)",resist:["15 cold"],powers:[{name:"Coordinated Attack",action:"Trait",description:"The shield bearer has combat advantage against an enemy while another frost giant shield bearer is adjacent to that enemy"},{name:"Icebound Footing",action:"Trait",description:"When an effect pulls, pushes, or slides the giant, it can choose to move 2 squares fewer than the effect specifies"},{name:"The",action:"Trait",description:"giant can make a saving throw to avoid falling prone when an attack would knock it prone"},{name:"Icy Battleaxe",action:"Standard",keywords:["cold","weapon"],description:"Attack: Melee 2 (one creature); +23 vs. AC Hit: 3d10 + 10 cold damage, and the target is marked until the end of the shield bearer's next turn."},{name:"Protective Strike",action:"Standard",recharge:"Encounter",description:"Effect: The shield bearer uses icy battleaxe. On a hit, the attack deals 10 extra cold damage, and one ally within 10 squares of the shield bearer gains 25 temporary hit points."},{name:"Defensive Stand",action:"Minor",description:"1/round Effect: Choose one enemy within 10 squares of the shield bearer that is not marked by it. If that enemy moves adjacent to the shield bearer before the end of the shield bearer's next turn, the shield bearer can use icy battleaxe against the enemy as a free action. Skills Athletics +21, Intimidate +16"}],alignment:"Unaligned",languages:["Giant Equipment : battleaxe","heavy shield","hide armor . Monster Manual 3","page(s) 99","Dungeon Magazine 199."] },
  { id:"mm3-ghost-beholder",name:"Ghost Beholder",source:"mm3",level:18,role:"Controller",roleModifier:"Elite",xp:4000,size:"Large",origin:"Aberrant",type:"Magical beast",keywords:["undead"],hp:254,ac:30,fort:29,ref:30,will:30,initiative:16,perception:17,speed:"0, fly 6 (hover); phasing",senses:["Darkvision"],resist:["insubstantial"],immune:["disease, poison"],vulnerable:["10 radiant"],powers:[{name:"All-Around Vision",action:"Trait",description:"Enemies can't gain combat advantage by flanking the ghost beholder"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +21 vs. Reflex Hit: 3d8 + 13 necrotic damage."},{name:"Eye Ray",action:"Standard",description:"Effect: The beholder uses one of the following eye rays without provoking an opportunity attack. 1. Chill of the Grave (cold, necrotic) Attack: Ranged 10 (one creature); +21 vs. Fortitude Hit: 4d8 + 8 cold and necrotic damage, and the target is slowed (save ends). First Failed Saving Throw: The target is immobilized instead of slowed (save ends). 2. Ghostly Possession (psychic) Attack: Ranged 10 (one creature); +21 vs. Will Hit: Ongoing 15 psychic damage (save ends). First Failed Saving Throw: In addition to the ongoing damage, the target is dazed (save ends both). Second Failed Saving Throw: The target is dominated instead of dazed and continues to take the ongoing damage (save ends both). The beholder is removed from play until the effect ends. When the effect ends, the beholder reappears in an unoccupied space within 10 squares of the target. The beholder can end the effect as a free action. 3. Killing Thought (psychic) Attack: Ranged 10 (one creature); +21 vs. Will Hit: 1d8 + 9 psychic damage, and the target makes a melee basic attack against itself as a free action. If the target is not wielding a melee weapon, it drops a held item and draws a melee weapon as a free action and then makes the attack."},{name:"Central Eye",action:"Minor",keywords:["fear"],description:"1/round Attack: Ranged 10 (one creature); +21 vs. Will Hit: The beholder slides the target 5 squares, and the target gains vulnerable 5 necrotic and vulnerable 5 psychic until the start of the beholder's next turn."},{name:"Eyes of the Beholder",action:"Triggered",description:"Trigger: An enemy starts its turn within 5 squares of the beholder. Effect (Free Action): The beholder uses eye ray against the triggering enemy. Determine which ray it uses by rolling a d4, rerolling the die on a result of 4."}],alignment:"Evil",languages:["Deep Speech Monster Manual 3","page(s) 23."] },
  { id:"mm3-meerak-nerra",name:"Meerak Nerra",source:"mm3",level:18,role:"Soldier",roleModifier:"Minion",xp:500,size:"Medium",origin:"Immortal",type:"Humanoid",hp:1,ac:34,fort:30,ref:29,will:29,initiative:16,perception:14,speed:"6",powers:[{name:"Mirror Slash",action:"Standard",description:"Attack: Melee 1 (one creature); +23 vs. AC Hit: 13 damage, and the target is marked until the end of the meerak's next turn."},{name:"Mirror Step",action:"Move",keywords:["teleportation"],description:"Effect: The meerak teleports 5 squares to a square adjacent to a mirror or another nerra."}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 145."] },
  { id:"mm3-spell-howler-of-vecna",name:"Spell Howler of Vecna",source:"mm3",level:18,role:"Artillery",xp:2000,size:"Medium",origin:"Natural",type:"Humanoid",hp:130,ac:32,fort:28,ref:30,will:30,initiative:10,perception:11,speed:"6",powers:[{name:"Maddening Touch",action:"Standard",keywords:["psychic"],description:"Attack: Melee 1 (one creature); +21 vs. Will Hit: 2d8 + 12 psychic damage."},{name:"Word of Force",action:"Standard",keywords:["force"],description:"Attack: Ranged 10 (one creature); +23 vs. Fortitude Hit: 2d10 + 15 force damage."},{name:"Word of Doom",action:"Standard",keywords:["psychic"],description:"Requirement: The spell howler must be affected by horrific visage. Attack: Ranged 10 (one creature); +23 vs. Will Hit: 2d8 + 6 psychic damage, and the target is dazed until the end of the spell howler's next turn."},{name:"Word of Madness",action:"Standard",keywords:["psychic"],description:"Recharge if the power misses Attack: Melee 1 (one creature); +21 vs. Will Hit: 2d8 + 5 psychic damage. The spell howler slides the target up to 3 squares, and the target makes a basic attack as a free action against a creature of the spell howler's choice."},{name:"Word of Pain",action:"Standard",keywords:["necrotic"],recharge:"Encounter",description:"Attack: Ranged 10 (one creature); +23 vs. Fortitude Hit: 4d10 + 10 necrotic damage. Miss: Half damage."},{name:"Horrific Visage",action:"Triggered",keywords:["psychic"],recharge:"Encounter",description:"Trigger: The spell howler is first bloodied. Attack (No Action): Close burst 2 (enemies in the burst); +22 vs. Will Hit: 2d6 + 4 psychic damage, and the spell howler pushes the target up to 3 squares. Effect: Until the end of the encounter, the spell howler cannot use any powers except maddening touch and word of doom."}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 171","The Book of Vile Darkness","page(s) 2-94."] },
  { id:"mm3-swarm-devil",name:"Swarm Devil",source:"mm3",level:18,role:"Skirmisher",xp:2000,size:"Large",origin:"Immortal",type:"Magical beast",keywords:["devil","swarm"],hp:174,ac:32,fort:30,ref:31,will:29,initiative:18,perception:14,speed:"0, fly 10 (hover)",senses:["Darkvision"],resist:["20 acid, half damage from melee and ranged attacks"],vulnerable:["10 against close and area attacks"],powers:[{name:"Swarm Attack",action:"Aura",keywords:["acid"],description:"Aura 1 Any enemy that starts its turn within the aura takes 10 acid damage and is slowed until the end of its next turn"},{name:"Swarm",action:"Trait",description:"The swarm devil can occupy the same space as another creature, and an enemy can enter its space, which is difficult terrain"},{name:"The",action:"Trait",description:"swarm devil cannot be pulled, pushed, or slid by melee or ranged attacks"},{name:"It",action:"Trait",description:"can squeeze through any opening that is large enough for at least one of the creatures it comprises"},{name:"Slam",action:"Standard",keywords:["acid"],description:"Attack: Melee 1 (one creature); +21 vs. Reflex Hit: Ongoing 10 acid damage (save ends)."},{name:"Acidic Curse",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 10 (one creature taking ongoing acid damage); +21 vs. Will Hit: 3d8 + 13 psychic damage, and the target takes a -2 penalty to attack rolls until the end of the devil's next turn."},{name:"Spew of Flies",action:"Standard",keywords:["acid"],recharge:"Recharge when first bloodied",description:"Attack: Close blast 3 (enemies in the blast); +21 vs. Fortitude Hit: The target takes ongoing 10 acid damage and grants combat advantage (save ends both). Swarm Shift (acid) ✦ Recharge ⚄ ⚅ Effect: The devil shifts its speed and can move through enemies' spaces during the shift. Each time the devil enters an enemy's space for the first time during the move, the enemy takes 15 acid damage."}],alignment:"Unaligned",languages:["Supernal","telepathy 10 Monster Manual 3","page(s) 62."] },
  { id:"mm3-tanarukk-steel-warrior",name:"Tanarukk Steel Warrior",source:"mm3",level:18,role:"Soldier",xp:2000,size:"Medium",origin:"Natural",type:"Humanoid",hp:177,ac:33,fort:30,ref:29,will:30,initiative:13,perception:12,speed:"5",senses:["Darkvision"],resist:["5 fire"],powers:[{name:"Broadsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +23 vs. AC Hit: 3d10 + 10 damage. Effect: The target is marked until the end of the steel warrior's next turn."},{name:"Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 15/30 (one creature); +23 vs. AC Hit: 3d8 + 6 damage."},{name:"Burning Cage",action:"Standard",keywords:["fire","weapon"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +21 vs. Reflex Hit: 3d10 + 20 fire damage, and the target takes 5 fire damage whenever it enters a square during its turn (save ends)."},{name:"Combat Awareness",action:"Triggered",description:"Trigger: An enemy marked by the steel warrior shifts or makes an attack that does not include the steel warrior as a target. Effect (Opportunity Action): The steel warrior can use broadsword against the triggering enemy. Indomitable Fury Trigger: The steel warrior drops to 0 hit points for the first time. Effect (No Action): The steel warrior instead has 1 hit point, and it gains a +2 bonus to attack rolls and a +4 bonus to damage rolls until the end of the encounter. Skills Athletics +20"}],alignment:"Unaligned",languages:["Abyssal","Common Equipment : broadsword","crossbow","crossbow bolt x10","heavy shield","plate armor . Monster Manual 3","page(s) 191","Dungeon Magazine 201","Dungeon Magazine 209."] },
  { id:"mm3-dream-hag",name:"Dream Hag",source:"mm3",level:19,role:"Controller",xp:2400,size:"Medium",origin:"Fey",type:"Humanoid",hp:179,ac:33,fort:29,ref:31,will:32,initiative:11,perception:21,speed:"6",senses:["Low-light vision"],powers:[{name:"Nightmare Weaver",action:"Aura",keywords:["charm"],description:"Aura 3 Any unconscious enemy that starts its turn within the aura stands up and is dominated until the end of its next turn"},{name:"The",action:"Trait",description:"enemy remains unconscious but takes a single action during its turn, chosen by the dream hag"},{name:"Staff of Mindless Reverie",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +24 vs. AC Hit: 2d6 + 10 damage, and the target is dazed until the end of the hag's next turn."},{name:"Nightmare Visions",action:"Standard",keywords:["charm","implement","psychic"],description:"Attack: Ranged 5 (one creature); +22 vs. Will Hit: 3d8 + 14 psychic damage, and the hag slides the target 5 squares."},{name:"Dust of Dreams",action:"Standard",keywords:["charm","sleep"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (enemies in the blast); +22 vs. Will Hit: The target is dazed (save ends). First Failed Saving Throw: The target falls unconscious (save ends)."},{name:"Sleep's Undeniable Grasp",action:"Standard",keywords:["implement","sleep"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +22 vs. Will Hit: The target falls unconscious (save ends). This effect also ends if the target is attacked by the hag or one of its allies. Skills Bluff +18, Diplomacy +18, Insight +21"}],alignment:"Unaligned",languages:["Common","Elven","Supernal Equipment : staff implement . Monster Manual 3","page(s) 109","Dungeon Magazine 185."] },
  { id:"mm3-elder-earthquake-dragon",name:"Elder Earthquake Dragon",source:"mm3",level:19,role:"Soldier",roleModifier:"Elite",xp:4800,size:"Huge",origin:"Elemental",type:"Magical beast",keywords:["dragon","earth"],hp:374,ac:35,fort:32,ref:32,will:30,initiative:19,perception:16,speed:"8 (earth walk), burrow 4, fly 6 (clumsy)",senses:["Darkvision"],powers:[{name:"Quaking Earth",action:"Aura",description:"Aura 1 When any enemy within the aura makes an attack that does not include the dragon as a target, that enemy falls prone and takes 10 damage."},{name:"Bite",action:"Standard",description:"Attack: Melee 2 (one creature); +24 vs. AC Hit: 4d8 + 9 damage."},{name:"Claw",action:"Standard",description:"Attack: Melee 3 (one creature); +26 vs. AC Hit: 4d6 + 6 damage."},{name:"Double Attack",action:"Standard",description:"Effect: The dragon uses bite and claw or uses claw twice."},{name:"Earthen Maw",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Melee 2 (one creature); +24 vs. Reflex Hit: 3d10 + 11 damage, and the target is restrained (save ends). First Failed Saving Throw: The target is instead petrified (save ends)."},{name:"Rising Tremors",action:"Minor",description:"Recharge at the start of any turn when quaking earth is aura 1 Effect: The quaking earth expands to aura 3. At the start of the dragon's next turn, the quaking earth expands to aura 5. At the start of its following turn, the dragon makes the following attack. Attack (No Action): Close burst 5 (enemies in the burst); +22 vs. Reflex Hit: 4d8 + 9 damage, and the target falls prone and cannot stand up (save ends). Effect: The quaking earth aura reverts to its original state and size (aura 1)."},{name:"Sudden Quake",action:"Triggered",description:"Trigger: The dragon is pulled, pushed, slid, or knocked prone. Effect (Free Action): Each enemy in the dragon's aura falls prone."}],alignment:"Unaligned",languages:["Common","Draconic","Primordial Monster Manual 3","page(s) 70."] },
  { id:"mm3-fire-giant-smokecaller",name:"Fire Giant Smokecaller",source:"mm3",level:19,role:"Lurker",xp:2400,size:"Large",origin:"Elemental",type:"Humanoid",keywords:["giant"],hp:140,ac:33,fort:32,ref:31,will:30,initiative:18,perception:13,speed:"10",resist:["15 fire"],powers:[{name:"Smoldering Whip",action:"Standard",keywords:["fire","weapon"],description:"Attack: Melee 5 (one creature); +22 vs. Reflex Hit: 3d8 + 10 fire damage, and the smokecaller pulls the target 3 squares."},{name:"Cindersmoke",action:"Standard",keywords:["fire"],description:"Requirement: The smokecaller must be within a smokecloud zone. Attack: Close blast 5 (enemies in the blast); +22 vs. Fortitude Hit: 3d8 + 8 fire damage. Effect: The smokecloud zone ends. Smokecloud (zone) ✦ Recharge when this power ends Effect: The smokecaller creates a zone in a close burst 3 that lasts until the end of the smokecaller's next turn. The zone blocks line of sight for all creatures except the smokecaller. Skills Acrobatics +19, Stealth +19"}],alignment:"Unaligned",languages:["Giant Equipment : chainmail","whip . Monster Manual 3","page(s) 98","Dungeon Magazine 216."] },
  { id:"mm3-hellwasp-colony-guard",name:"Hellwasp Colony Guard",source:"mm3",level:19,role:"Skirmisher",roleModifier:"Minion",xp:600,size:"Medium",origin:"Immortal",type:"Magical beast",keywords:["devil"],hp:1,ac:33,fort:29,ref:31,will:28,initiative:18,perception:18,speed:"0, fly 8 (hover)",senses:["Darkvision"],powers:[{name:"Sword Talons",action:"Standard",description:"Attack: Melee 1 (one creature); +24 vs. AC Hit: 13 damage. Effect: The guard shifts half its speed before or after the attack."},{name:"Hellwasp Sting",action:"Standard",keywords:["fire","poison"],recharge:"Encounter",description:"Attack: Melee 1 (one creature); +22 vs. Fortitude Hit: 13 fire and poison damage, and the target is slowed and can't shift until the end of the guard's next turn."}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 58."] },
  { id:"mm3-kalareem-nerra",name:"Kalareem Nerra",source:"mm3",level:19,role:"Soldier",xp:2400,size:"Medium",origin:"Immortal",type:"Humanoid",hp:175,ac:34,fort:32,ref:31,will:30,initiative:17,perception:14,speed:"6",powers:[{name:"Shard Blade",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +24 vs. AC Hit: 3d8 + 14 damage, and the target is marked until the end of the kalareem's next turn."},{name:"Shard Blast",action:"Standard",description:"Attack: Close blast 3 (enemies in the blast); +24 vs. AC Hit: 3d6 + 8 damage, and the target is marked until the end of the kalareem's next turn."},{name:"Mirror Step",action:"Move",keywords:["teleportation"],description:"Effect: The kalareem teleports 5 squares to a square adjacent to a mirror or another nerra."},{name:"Mirror Image",action:"Triggered",description:"Trigger: An enemy marked by the kalareem and adjacent to it makes a melee or a ranged attack that does not include the kalareem as a target. Effect (Immediate Interrupt): The triggering enemy targets the kalareem instead."},{name:"Mirror Defense",action:"Triggered",description:"Recharge if the power misses Trigger: An enemy hits the kalareem with a melee attack. Attack (Immediate Interrupt): Melee 1 (the triggering enemy); +25 vs. Will Hit: The target takes the same damage dealt by its attack. Skills Insight +19"}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 146."] },
  { id:"mm3-putrid-slaad",name:"Putrid Slaad",source:"mm3",level:19,role:"Brute",xp:2400,size:"Large",origin:"Elemental",type:"Animate",keywords:["undead"],hp:227,ac:30,fort:34,ref:30,will:29,initiative:14,perception:13,speed:"5, teleport 3",senses:["Darkvision"],resist:["20 acid,","20 necrotic"],immune:["disease, poison"],vulnerable:["10 radiant"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +24 vs. AC Hit: 2d10 + 10 damage, and the slaad pulls the target 1 square."},{name:"Grasping Claws",action:"Standard",description:"Requirement: The slaad must not have a creature grabbed. Effect: The slaad uses claw twice against one creature. If both attacks hit, the slaad grabs the target. Cast Aside ✦ At-Will Requirement: The slaad must have a creature grabbed. Effect: The slaad pushes a creature grabbed by it 5 squares, and the pushed creature takes 2d6 + 7 damage. The slaad then makes the following attack centered on the pushed creature. Attack: Close burst 1 (enemies in the burst); +22 vs. Reflex Hit: 2d6 + 7 damage, and the target falls prone."},{name:"Horrific Spew",action:"Standard",keywords:["acid","necrotic"],recharge:"Recharge 5-6",description:"Attack: Close blast 3 (creatures in the blast); +22 vs. Fortitude, or +24 against a creature grabbed by the slaad Hit: 2d12 + 5 acid and necrotic damage, and ongoing 20 acid and necrotic damage (save ends)."}],alignment:"Chaotic Evil",languages:["Primordial Monster Manual 3","page(s) 179."] },
  { id:"mm3-red-arcanian",name:"Red Arcanian",source:"mm3",level:19,role:"Artillery",xp:2400,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["undead"],hp:131,ac:31,fort:27,ref:30,will:28,initiative:13,perception:10,speed:"6",powers:[{name:"Fiery Touch",action:"Standard",keywords:["fire"],description:"Attack: Melee 1 (one creature); +20 vs. Reflex Hit: 3d10 + 11 fire damage."},{name:"Scorching Burst",action:"Standard",keywords:["fire","implement"],description:"Attack: Area burst 1 within 10 (creatures in the burst); +22 vs. Reflex Hit: 3d6 + 8 fire damage."},{name:"Burning Hands",action:"Standard",keywords:["fire","implement"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast); +22 vs. Reflex Hit: 4d8 + 9 fire damage, and the arcanian pushes the target 3 squares."},{name:"Wand of Accuracy",action:"Minor",recharge:"Encounter",description:"Effect: The arcanian gains a +4 bonus to its next attack roll before the end of the arcanian's next turn."},{name:"Arcane Surge",action:"Triggered",recharge:"Encounter",description:"Trigger: The arcanian hits an enemy with an implement attack. Effect (Free Action): The attack deals maximum damage to the enemy. Skills Arcana +20"}],alignment:"Unaligned",languages:["Common Equipment : wand implement . Monster Manual 3","page(s) 17."] },
  { id:"mm3-secret-of-vecna",name:"Secret of Vecna",source:"mm3",level:19,role:"Skirmisher",xp:2400,size:"Medium",origin:"Natural",type:"Humanoid",hp:176,ac:33,fort:31,ref:31,will:31,initiative:18,perception:11,speed:"8, teleport 4",powers:[{name:"Shocking Grasp",action:"Standard",keywords:["lightning"],description:"Attack: Melee 1 (one creature); +24 vs. AC Hit: 2d10 + 16 lightning damage, plus 10 extra lightning damage if the secret is invisible to the target."},{name:"Thundering Claws",action:"Standard",keywords:["thunder"],description:"Requirement: The secret must be affected by horrific visage. Attack: Melee 1 (one creature); +24 vs. AC Hit: 3d10 + 17 thunder damage. The secret slides the target 1 square and knocks it prone."},{name:"Cloak of Ignorance",action:"Standard",keywords:["charm","psychic"],description:"Attack: Close burst 3 (enemies in the burst); +22 vs. Will Hit: 3d6 + 6 psychic damage, and the secret is invisible to the target (save ends)."},{name:"Horrific Visage",action:"Triggered",keywords:["psychic"],recharge:"Encounter",description:"Trigger: The secret is first bloodied. Attack (No Action): Close burst 2 (enemies in the burst); +22 vs. Will Hit: 2d6 + 4 psychic damage, and the secret pushes the target 3 squares. Effect: Until the end of the encounter, the secret cannot use any power except thundering claws."}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 171."] },
  { id:"mm3-sillit-nerra",name:"Sillit Nerra",source:"mm3",level:19,role:"Controller",xp:2400,size:"Medium",origin:"Immortal",type:"Humanoid",hp:181,ac:31,fort:30,ref:31,will:32,initiative:10,perception:11,speed:"6",powers:[{name:"Mirror Portal",action:"Standard",keywords:["teleportation"],description:"Attack: Melee 1 (one creature); +22 vs. Will Hit: 3d8 + 9 damage, and the sillit teleports the target to a space adjacent to one of the sillit's allies within 10 squares of the sillit."},{name:"Warped Image",action:"Standard",keywords:["teleportation"],description:"Attack: Ranged 5 (one creature); +22 vs. Fortitude Hit: 2d10 + 16 damage, and the sillit teleports the target 3 squares."},{name:"Captured Image",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Ranged 10 (one creature); +22 vs. Will Hit: The target is removed from play (save ends). Until the effect ends, whenever the sillit takes damage from an enemy, the target takes 20 damage. When the effect ends, the target appears in an unoccupied square of the sillit's choice within 5 squares of the sillit. If the sillit drops to 0 hit points, the effect ends."},{name:"Mirror Step",action:"Move",keywords:["teleportation"],description:"Effect: The sillit teleports 5 squares to a square adjacent to a mirror or another nerra."},{name:"Mirrored Grasp",action:"Minor",keywords:["teleportation"],description:"Effect: One Tiny or smaller unattended object of up to 20 pounds that the sillit can see and is within 10 squares of it is teleported to the sillit's hand. Skills Arcana +20, Bluff +18, Diplomacy +18, Insight +16"}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 146."] },
  { id:"mm3-conflagration-orb",name:"Conflagration Orb",source:"mm3",level:20,role:"Artillery",xp:2800,size:"Medium",origin:"Elemental",type:"Animate",keywords:["fire"],hp:143,ac:34,fort:30,ref:35,will:34,initiative:17,perception:13,speed:"6, fly 8 (hover)",resist:["20 fire"],immune:["disease"],powers:[{name:"Roiling Flame",action:"Standard",keywords:["fire"],description:"Attack: Melee 1 (one creature); +23 vs. Reflex Hit: 2d6 + 6 fire damage, and ongoing 10 fire damage (save ends). Effect: The conflagration orb shifts 1 square."},{name:"Scorching Bolts",action:"Standard",keywords:["fire"],description:"Attack: Ranged 10 (one or two creatures); +25 vs. Reflex Hit: 3d6 + 8 fire damage, and ongoing 10 fire damage (save ends)."},{name:"Fire Tempest",action:"Standard",keywords:["fire"],recharge:"Recharge 4-6",description:"Effect: The conflagration orb makes the following attack three times, and each burst must have an area of effect that doesn't share any squares with the attack's other bursts. Attack: Area burst 1 within 10 (creatures in the burst); +25 vs. Reflex Hit: 2d6 + 7 fire damage, and if the target has ongoing fire damage, the ongoing damage increases by 5."},{name:"Waves of Flame",action:"Standard",keywords:["fire","zone"],recharge:"Recharge when first bloodied",description:"Attack: Close burst 3 (creatures in the burst); +23 vs. Reflex Hit: 3d6 + 7 fire damage, and the conflagration orb pushes the target 3 squares. Effect: The burst creates a zone that lasts until the end of the orb's next turn. The zone is lightly obscured, and any creature that enters the zone or ends its turn there takes 10 fire damage."}],alignment:"Unaligned",languages:["Primordial Monster Manual 3","page(s) 117","Dungeon Magazine 216."] },
  { id:"mm3-delphar-nerra",name:"Delphar Nerra",source:"mm3",level:20,role:"Soldier",xp:0,size:"Large",origin:"Immortal",type:"Humanoid",hp:187,ac:35,fort:32,ref:30,will:32,initiative:16,perception:20,speed:"8",powers:[{name:"Mirrored Rampart",action:"Aura",description:"Aura 5 Nerras within the aura can teleport 10 squares with mirror step instead of 5."},{name:"Shard Blade",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +25 vs. AC Hit: 4d8 + 10 damage, and the target is marked until the end of the delphar's next turn."},{name:"Razor Blast",action:"Standard",description:"Attack: Ranged 10 (one creature); +23 vs. Reflex Hit: 4d6 + 7 damage, and the target is marked until the end of the delphar's next turn."},{name:"Mirror Step",action:"Move",keywords:["teleportation"],description:"Effect: The delphar teleports 5 squares to a space adjacent to a mirror or another nerra."},{name:"Mirrored Grasp",action:"Triggered",keywords:["teleportation"],description:"Trigger: An enemy marked by the delphar makes an attack that does not include the delphar as a target. Attack (Immediate Reaction): Close burst 10 (the triggering enemy in the burst); +25 vs. Will Hit: The delphar teleports the target adjacent to it. Skills History +21, Insight +20"}],alignment:"Unaligned",languages:["Supernal Equipment : longsword . Monster Manual 3","page(s) 147."] },
  { id:"mm3-frost-giant-chieftain",name:"Frost Giant Chieftain",source:"mm3",level:20,role:"Controller",xp:2800,size:"Large",origin:"Elemental",type:"Humanoid",keywords:["cold","giant"],hp:190,ac:34,fort:33,ref:29,will:30,initiative:15,perception:14,speed:"8 (ice walk)",resist:["15 cold"],powers:[{name:"Emanating Cold",action:"Aura",description:"Aura 2 Enemies within the aura grant combat advantage to cold creatures"},{name:"Icebound Footing",action:"Trait",description:"When an effect pulls, pushes, or slides the chieftain, it moves 2 squares less than the effect specifies. In addition, the chieftain can make a saving throw to avoid falling prone"},{name:"Icy Greataxe",action:"Standard",keywords:["cold","weapon"],description:"Attack: Melee 2 (one creature); +25 vs. AC Hit: 2d12 + 5 cold damage."},{name:"Eye of the Storm",action:"Standard",keywords:["cold"],description:"Attack: Ranged 5 (one creature); +23 vs. Reflex Hit: 2d8 + 9 cold damage, and the target takes ongoing 10 cold damage and is slowed (save ends both)."},{name:"Pillar of Ice",action:"Minor",description:"1/round Effect: The chieftain creates a Medium or Large pillar of ice on a solid surface in an unoccupied square within 10 squares of it. The pillar occupies the space in which it's created, and it lasts until the end of the chieftain's next turn. Any enemy that starts its turn adjacent to the pillar is slowed until the start of its next turn. The pillar blocks line of sight, and while adjacent to the pillar, an enemy grants combat advantage. Grip of Winter (cold, zone) ✦ Recharge when first bloodied Effect: The chieftain creates a zone in an area burst 2 within 10 squares that lasts until the end of the encounter. The zone is difficult terrain, and any enemy that ends its turn within the zone takes 15 cold damage. Skills Athletics +22, Intimidate +21"}],alignment:"Unaligned",languages:["Giant","Primordial Equipment : greataxe","hide armor . Monster Manual 3","page(s) 99."] },
  { id:"mm3-golden-slaad",name:"Golden Slaad",source:"mm3",level:20,role:"Controller",xp:2800,size:"Huge",origin:"Elemental",type:"Humanoid",hp:193,ac:32,fort:33,ref:30,will:29,initiative:15,perception:12,speed:"8, teleport 6",senses:["Low-light vision"],immune:["chaos phage"],powers:[{name:"Bite",action:"Standard",description:"Attack: Melee 3 (one creature); +25 vs. AC Hit: 2d10 + 13 damage. If the attack roll is odd, the slaad slides the target 3 squares. If the attack roll is even, the target is dazed until the end of the slaad's next turn."},{name:"Chaos Croak",action:"Standard",keywords:["disease","psychic"],recharge:"Recharge 4-6",description:"Attack: Close burst 5 (enemies in the burst); +23 vs. Will Hit: 2d6 + 8 psychic damage. For each target, roll a d6 to determine an additional effect.1. The target teleports 1d6 squares in a random direction (roll a d8 to determine the direction).2. The target makes a melee basic attack as a free action against a random creature adjacent to it.3. The target is stunned until the end of its next turn.4. The target is slowed (save ends).5. The target takes 10 damage of a random type. Roll a d10: (1) acid, (2) cold, (3) fire, (4) force, (5) lightning, (6) necrotic, (7) poison, (8) psychic, (9) radiant, (10) thunder.6. The target is exposed to chaos phage. In addition, if the target is dazed by the slaad's bite, it becomes dazed (save ends)."},{name:"Amniotic Transformation",action:"Triggered",keywords:["polymorph"],description:"Trigger: The slaad is first bloodied. Effect (No Action): The slaad collapses into a viscous heap until the end of the encounter. While in this form, the slaad cannot teleport and its speed drops to 4."},{name:"Corrosive Pseudopodia",action:"Triggered",keywords:["acid","healing"],description:"Requirement: The slaad must be affected by amniotic transformation. Trigger: An enemy adjacent to the slaad moves or makes an attack. Attack (Opportunity Action): Melee 1 (the triggering enemy); +25 vs. AC Hit: 1d6 + 8 acid damage, and the slaad grabs the target. Sustain Minor: The slaad sustains all its grabs, and each creature grabbed by the slaad takes 2d6 + 8 acid damage. The slaad regains 5 hit points for each creature grabbed by it. Skills Athletics +23, Intimidate +19"}],alignment:"Unaligned",languages:["Primordial Monster Manual 3","page(s) 178."] },
  { id:"mm3-greater-air-elemental",name:"Greater Air Elemental",source:"mm3",level:20,role:"Lurker",xp:2800,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["air"],hp:143,ac:34,fort:31,ref:33,will:32,initiative:22,perception:10,speed:"0, fly 10 (hover)",vulnerable:["10 fire"],powers:[{name:"Phantom",action:"Trait",description:"on the Wind The greater air elemental becomes invisible whenever it starts its turn without an enemy adjacent to it"},{name:"The",action:"Trait",description:"invisibility lasts until the end of its next turn or until it attacks"},{name:"Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +25 vs. AC Hit: 3d10 + 8 damage."},{name:"Engulfing Winds",action:"Standard",description:"Attack: Melee 2 (one creature that can't see the elemental); +23 vs. Fortitude Hit: The elemental slides the target 1 square into its space, and the target is grabbed. Until the grab ends, the target is dazed and takes ongoing 20 damage. When the elemental moves, the grabbed creature moves with it, remaining in the elemental's space. The elemental moves at full speed while it has a creature grabbed, and it need not spend a standard action or make an attack roll to move a grabbed creature. Skills Stealth +23"}],alignment:"Unaligned",languages:["understands Primordial Monster Manual 3","page(s) 80","Dungeon Magazine 215."] },
  { id:"mm3-greater-water-elemental",name:"Greater Water Elemental",source:"mm3",level:20,role:"Controller",xp:2800,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["aquatic","water"],hp:185,ac:34,fort:33,ref:32,will:31,initiative:15,perception:10,speed:"8, swim 8",vulnerable:["cold (see sensitive to cold)"],powers:[{name:"Aquatic",action:"Trait",description:"The elemental can breathe underwater. In aquatic combat, it gains a +2 bonus to attack rolls against nonaquatic creatures"},{name:"Sensitive",action:"Trait",description:"to Cold Whenever the greater water elemental takes cold damage, it gains vulnerable 10 against the next attack that hits it before the end of its next turn"},{name:"Slam",action:"Standard",description:"Attack: Melee 1 (one creature); +23 vs. Reflex Hit: 4d6 damage, and ongoing 15 damage (save ends)."},{name:"Surging Waves",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Close blast 3 (enemies in the blast); +23 vs. Fortitude Hit: 5d6 + 7 damage, and the elemental slides the target 5 squares."},{name:"Drowning Essence",action:"Minor",description:"1/round Effect: The elemental slides each creature that has ongoing damage from its slam 4 squares."}],alignment:"Unaligned",languages:["understands Primordial Monster Manual 3","page(s) 83","Dungeon Magazine 215."] },
  { id:"mm3-mind-flayer-inquisitor",name:"Mind Flayer Inquisitor",source:"mm3",level:20,role:"Controller",xp:2800,size:"Medium",origin:"Aberrant",type:"Humanoid",hp:190,ac:34,fort:31,ref:33,will:33,initiative:15,perception:16,speed:"7",senses:["Darkvision"],powers:[{name:"Tentacles",action:"Standard",description:"Requirement: The inquisitor must not have a creature grabbed. Attack: Melee 1 (one creature); +23 vs. Reflex Hit: 3d6 + 13 damage, and the inquisitor grabs the target."},{name:"Implant Delusions",action:"Standard",keywords:["charm","psychic"],description:"Attack: Melee 1 (one creature grabbed by the inquisitor); +23 vs. Will Hit: 3d8 + 15 psychic damage, and the target begins suffering delusions (save ends). While the target is suffering delusions, allies adjacent to it take a -2 penalty to attack rolls and a -2 penalty to all defenses."},{name:"Mind Blast",action:"Standard",keywords:["psychic"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (enemies in the blast); +23 vs. Will Hit: 2d8 + 6 psychic damage, and the target is dazed (save ends). Miss: Half damage. Own Worst Enemy (charm) ✦ Recharge when first bloodied Effect: Each enemy in an area burst 2 within 10 squares uses one of its ranged or melee at-will attack powers of the mind flayer's choice against itself as a free action."},{name:"Unwilling Confession",action:"Minor",keywords:["charm"],description:"1/round Attack: Close burst 10 (one creature in the burst); +23 vs. Will Hit: The target is dazed, cannot be the target of healing powers, and cannot be affected by powers that grant a saving throw (save ends all)."},{name:"Forceful Submission",action:"Triggered",description:"Trigger: An enemy the inquisitor can see succeeds on a saving throw. Effect (Immediate Interrupt): The triggering enemy makes the saving throw again with a -2 penalty. Skills Bluff +22, Insight +21"}],alignment:"Unaligned",languages:["Deep Speech","telepathy 10 Monster Manual 3","page(s) 137."] },
  { id:"mm3-nalfeshnee-swine-guard",name:"Nalfeshnee Swine Guard",source:"mm3",level:20,role:"Brute",xp:2800,size:"Huge",origin:"Elemental",type:"Humanoid",keywords:["demon"],hp:237,ac:32,fort:34,ref:32,will:32,initiative:11,perception:16,speed:"6, fly 4 (clumsy)",senses:["Darkvision"],resist:["10 poison"],powers:[{name:"Halberd",action:"Standard",keywords:["weapon"],description:"Attack: Melee 3 (one creature); +25 vs. AC Hit: 3d12 + 16 damage, and the swine guard pushes the target 2 squares."},{name:"Noisome Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 2 (one creature); +25 vs. AC Hit: 3d8 + 12 damage, and ongoing 10 poison damage (save ends)."},{name:"Variable Resistance",action:"Triggered",recharge:"2/Encounter",description:"Trigger: The swine guard takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The swine guard gains resist 20 to the triggering damage type until the end of the encounter or until it uses variable resistance again."},{name:"Shattered Minds",action:"Triggered",keywords:["psychic"],recharge:"Encounter",description:"Trigger: The swine guard is first bloodied. Attack (Free Action): Close burst 3 (enemies in the burst); +23 vs. Will Hit: 2d8 + 6 psychic damage, and the target is dazed (save ends). First Failed Saving Throw: The swine guard slides the target 3 squares. The target is stunned instead of dazed (save ends). Skills Intimidate +20"}],alignment:"Unaligned",languages:["Abyssal Equipment : halberd","plate armor . Monster Manual 3","page(s) 44."] },
  { id:"mm3-greater-fire-elemental",name:"Greater Fire Elemental",source:"mm3",level:21,role:"Skirmisher",xp:3200,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["fire"],hp:187,ac:34,fort:32,ref:34,will:33,initiative:21,perception:11,speed:"12, fly 8",vulnerable:["cold (see frozen in place)"],powers:[{name:"Frozen",action:"Trait",description:"in Place Whenever the greater fire elemental takes cold damage, it cannot shift until the end of its next turn"},{name:"Slam",action:"Standard",keywords:["fire"],description:"Attack: Melee 1 (one creature); +24 vs. Reflex Hit: Ongoing 15 fire damage (save ends)."},{name:"Flickering Flame",action:"Minor",description:"Effect: The elemental shifts 6 squares."},{name:"Hungry Flames",action:"Triggered",keywords:["fire"],description:"Trigger: An enemy attacks the elemental. Attack (Immediate Reaction): Close burst 3 (enemies in the burst); +24 vs. Reflex Hit: 2d6 + 2 fire damage."}],alignment:"Unaligned",languages:["understands Primordial Monster Manual 3","page(s) 83","Dungeon Magazine 215","Dungeon Magazine 216."] },
  { id:"mm3-intellect-glutton",name:"Intellect Glutton",source:"mm3",level:21,role:"Controller",xp:3200,size:"Large",origin:"Aberrant",type:"Magical beast",keywords:["blind"],hp:196,ac:35,fort:32,ref:33,will:35,initiative:16,perception:20,speed:"8, climb 6 (spider climb)",senses:["Blindsight 10"],immune:["blinded, gaze"],powers:[{name:"Thought Static",action:"Aura",description:"Aura 5 Enemies within the aura take a -2 penalty to Will."},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +26 vs. AC Hit: 3d8 + 16 damage."},{name:"Mind Rend",action:"Standard",keywords:["fear","psychic"],description:"Attack: Ranged 10 (one creature); +23 vs. Will Hit: 1d12 + 7 psychic damage, and the intellect glutton slides the target 1 square. Special: While the intellect glutton has a creature dominated, it can use this power once per round as a minor action. Mockery of Life (charm, healing) ✦ Recharge when no creature is dominated by this power Effect: One dead creature regains 20 hit points and is dominated until the end of the encounter or until it drops to 0 hit points or fewer."},{name:"Thought Feast",action:"Standard",keywords:["charm","psychic"],recharge:"Recharge when no creature is dominated by this power",description:"Attack: Ranged 10 (one creature); +23 vs. Will Hit: The target is dominated and takes ongoing 10 psychic damage (save ends both). While the target is dominated by the intellect glutton, the intellect glutton is insubstantial."},{name:"Mind's Resilience",action:"Triggered",description:"Trigger: The intellect glutton takes damage while subject to an effect that a save can end. Effect (No Action): The intellect glutton makes a saving throw. Skills Arcana +16, Bluff +23, Insight +20, Stealth +21"}],alignment:"Unaligned",languages:["telepathy 10 Monster Manual 3","page(s) 119."] },
  { id:"mm3-mind-flayer-scourge",name:"Mind Flayer Scourge",source:"mm3",level:21,role:"Skirmisher",xp:3200,size:"Medium",origin:"Aberrant",type:"Humanoid",hp:199,ac:35,fort:31,ref:34,will:33,initiative:18,perception:16,speed:"7",senses:["Darkvision"],resist:["10 psychic"],powers:[{name:"Mind Leech Whenever",action:"Trait",description:"the mind flayer scourge starts its turn with a creature grabbed, the scourge can make a saving throw or an extra recharge roll"},{name:"It",action:"Trait",description:"can recharge psychic assault but must roll a 6 on the recharge roll"},{name:"Tentacles",action:"Standard",description:"Requirement: The scourge must not have a creature grabbed. Attack: Melee 1 (one creature); +24 vs. Reflex Hit: 2d8 + 5 damage, and the scourge grabs the target. Until the grab ends, the target is dazed."},{name:"Mind Blast",action:"Standard",keywords:["psychic"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (enemies in the blast); +24 vs. Will Hit: 2d8 + 5 psychic damage, and the target is dazed (save ends). Miss: Half damage."},{name:"Psychic Assault",action:"Standard",keywords:["charm"],recharge:"Encounter",description:"Attack: Melee 1 (one creature grabbed by the scourge); +24 vs. Will Hit: 1d8 + 5 damage, and the target is dominated (save ends; the target takes a -4 penalty to the saving throw). Miss: Half damage, and the target is dominated (save ends)."},{name:"Alter Reality",action:"Minor",keywords:["teleportation"],description:"Effect: The scourge teleports a creature adjacent to it 2 squares."}],alignment:"Unaligned",languages:["Deep Speech","telepathy 10 Monster Manual 3","page(s) 137."] },
  { id:"mm3-teltarym-nerra",name:"Teltarym Nerra",source:"mm3",level:21,role:"Brute",xp:3200,size:"Large",origin:"Immortal",type:"Humanoid",hp:237,ac:33,fort:33,ref:30,will:31,initiative:15,perception:16,speed:"8",powers:[{name:"Hammer Fist",action:"Standard",description:"Attack: Melee 2 (one creature); +26 vs. AC Hit: 2d10 + 10 damage, and the teltarym pushes the target 1 square."},{name:"Hammer Flurry",action:"Standard",description:"Effect: The teltarym uses hammer fist twice."},{name:"Mirror Step",action:"Move",keywords:["teleportation"],description:"Effect: The teltarym teleports 5 squares to a space adjacent to a mirror or another nerra."},{name:"Reflected Pain",action:"Triggered",recharge:"Recharge when first bloodied",description:"Trigger: An enemy hits the teltarym with a melee attack. Effect (Immediate Reaction): The triggering enemy takes damage equal to half the damage of the attack."}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 147."] },
  { id:"mm3-ancient-blizzard-dragon",name:"Ancient Blizzard Dragon",source:"mm3",level:22,role:"Controller",roleModifier:"Elite",xp:8300,size:"Huge",origin:"Elemental",type:"Magical beast",keywords:["cold","dragon"],hp:422,ac:36,fort:34,ref:35,will:33,initiative:20,perception:18,speed:"10 (ice walk), fly 10 (clumsy)",senses:["Darkvision"],powers:[{name:"Freezing Winds",action:"Trait",description:"✦ Aura The dragon slides any enemy that ends its turn in the aura 3 squares"},{name:"Bite",action:"Standard",keywords:["cold"],description:"Attack: Melee 3 (one creature); +27 vs. AC Hit: 3d8 + 10 cold damage, and the target is immobilized until the end of the dragon's next turn."},{name:"Claw",action:"Standard",keywords:["cold"],description:"Attack: Melee 3 (one creature); +27 vs. AC Hit: 4d6 + 16 cold damage, and the dragon slides the target 4 squares."},{name:"Double Attack",action:"Standard",description:"Effect: The dragon uses bite and claw or uses claw twice."},{name:"Deep Freeze",action:"Standard",keywords:["cold"],recharge:"Encounter",description:"Requirement: The dragon must be bloodied. Attack: Close burst 5 (enemies in the burst); +25 vs. Fortitude Hit: 3d10 + 5 cold damage. The target is immobilized and takes a -5 penalty to Fortitude (save ends both). Miss: Half damage. The target is immobilized and takes a -5 penalty to Fortitude until the end of the dragon's next turn."},{name:"Rising Winds",action:"Minor",keywords:["cold"],description:"Recharge at the start of any turn when freezing winds is aura 1 Effect: The freezing winds expands to aura 3. At the start of the dragon's next turn, the freezing winds expands to aura 5. At the start of its following turn, the dragon makes the following attack. Attack (No Action): Close burst 5 (enemies in the burst); +25 vs. Fortitude Hit: 4d8 + 12 cold damage, and the target falls unconscious (save ends). Effect: The freezing winds aura reverts to its original state and size (aura 1)."},{name:"Chill Rebuke",action:"Triggered",keywords:["cold"],recharge:"Recharge when first bloodied",description:"Trigger: An enemy's melee attack deals damage to the dragon. Attack (Immediate Reaction): Close blast 5 (enemies in the blast); +25 vs. Fortitude Hit: 1d10 + 16 cold damage, and the target is slowed (save ends). Sudden Flurry ✦ At-Will Trigger: The dragon is hit by a cold attack. Effect (Free Action): The dragon slides each enemy in its aura 2 squares."}],alignment:"Unaligned",languages:["Common","Draconic","Primordial Monster Manual 3","page(s) 67."] },
  { id:"mm3-chosen-of-imix",name:"Chosen of Imix",source:"mm3",level:22,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:207,ac:34,fort:33,ref:32,will:36,initiative:15,perception:12,speed:"6",resist:["15 fire"],vulnerable:["10 fire until the end of the chosen's next turn. (➶) Fiery Orb (fire) ✦ At-Will Attack: Ranged","5 (one creature)","+25 vs. Reflex Hit:","3d8 +","15 fire damage, and each enemy adjacent to the target takes","5 fire damage. Servants of Elemental Fire (fire) ✦ Recharge when no fire grue is within","10 squares of the chosen at the start of its turn Effect: The chosen creates four fire grues, or six while the chosen is bloodied, each in an unoccupied square within","10 squares of it. The grues cannot take actions. Any creature that starts its turn adjacent to one or more grues takes","10 fire damage. The grues have defenses equal to the chosen's and","1 hit point each. A missed attack never damages a grue. Each grue lasts until the end of the encounter or until the chosen ends its turn more than","10 squares from it. As a minor action, the chosen can move each grue up to","6 squares. ᗕ Fire's Fury (fire) ✦ Encounter Effect: The chosen reduces a fire grue within","10 squares of it to","0 hit points and makes the following attack centered on the grue. Attack: Close burst","1 (enemies in the burst)","+25 vs. Reflex Hit:","2d8 +","8 fire damage, and the target is dazed (save ends). Triggered Actions ᗕ Demand Focus ✦ At-Will Trigger: An enemy willingly moves away from a fire grue without shifting. Attack (Opportunity Action): Close burst","10 (the triggering enemy in the burst)","+25 vs. Will Hit: The target is slowed until the end of its next turn. ⚔ Firepulse (fire) ✦ Encounter Trigger: An enemy hits the chosen with a melee attack. Attack (Immediate Reaction): Melee","1 (the triggering enemy)","+25 vs. Reflex Hit:","3d6 +","9 fire damage. ᗕ Claimed by Imix (fire) Trigger: The chosen drops to","0 hit points. Attack (No Action): Close burst","3 (enemies in the burst)","+25 vs. Reflex Hit:","2d8 +","9 fire damage, and the target is dazed (save ends). Skills Arcana +18, Intimidate +25"],powers:[{name:"Fire Within",action:"Aura",description:"Aura 5 Allies within the aura gain resist 10 fire."},{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +27 vs. AC Hit: 2d4 + 10 damage, and the target gains vulnerable 10 fire until the end of the chosen's next turn."},{name:"Fiery Orb",action:"Standard",keywords:["fire"],description:"Attack: Ranged 5 (one creature); +25 vs. Reflex Hit: 3d8 + 15 fire damage, and each enemy adjacent to the target takes 5 fire damage. Servants of Elemental Fire (fire) ✦ Recharge when no fire grue is within 10 squares of the chosen at the start of its turn Effect: The chosen creates four fire grues, or six while the chosen is bloodied, each in an unoccupied square within 10 squares of it. The grues cannot take actions. Any creature that starts its turn adjacent to one or more grues takes 10 fire damage. The grues have defenses equal to the chosen's and 1 hit point each. A missed attack never damages a grue. Each grue lasts until the end of the encounter or until the chosen ends its turn more than 10 squares from it. As a minor action, the chosen can move each grue up to 6 squares."},{name:"Fire's Fury",action:"Standard",keywords:["fire"],recharge:"Encounter",description:"Effect: The chosen reduces a fire grue within 10 squares of it to 0 hit points and makes the following attack centered on the grue. Attack: Close burst 1 (enemies in the burst); +25 vs. Reflex Hit: 2d8 + 8 fire damage, and the target is dazed (save ends)."},{name:"Demand Focus",action:"Triggered",description:"Trigger: An enemy willingly moves away from a fire grue without shifting. Attack (Opportunity Action): Close burst 10 (the triggering enemy in the burst); +25 vs. Will Hit: The target is slowed until the end of its next turn."},{name:"Firepulse",action:"Triggered",keywords:["fire"],recharge:"Encounter",description:"Trigger: An enemy hits the chosen with a melee attack. Attack (Immediate Reaction): Melee 1 (the triggering enemy); +25 vs. Reflex Hit: 3d6 + 9 fire damage."},{name:"Claimed by Imix",action:"Triggered",keywords:["fire"],description:"Trigger: The chosen drops to 0 hit points.. Close burst 3 (enemies in the burst); +25 vs. Reflex Hit: 2d8 + 9 fire damage, and the target is dazed (save ends). Skills Arcana +18, Intimidate +25"}],alignment:"Unaligned",languages:["Common","Primordial Equipment : dagger . Monster Manual 3","page(s) 117."] },
  { id:"mm3-corruption-devil",name:"Corruption Devil",source:"mm3",level:22,role:"Controller",xp:0,size:"Large",origin:"Immortal",type:"Humanoid",keywords:["devil"],hp:208,ac:36,fort:34,ref:34,will:35,initiative:13,perception:19,speed:"4, fly 6 (hover)",senses:["Darkvision"],powers:[{name:"Corruptive Presence",action:"Aura",description:"Aura 5 Enemies within the aura take a -2 penalty to saving throws."},{name:"Corrupting Claws",action:"Standard",keywords:["psychic"],description:"Attack: Melee 2 (one creature); +27 vs. AC Hit: Ongoing 10 psychic damage (save ends)."},{name:"Word of Corruption",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 20 (one creature); +25 vs. Will Hit: Ongoing 5 psychic damage (save ends)."},{name:"Sway the Corrupt",action:"Minor",keywords:["charm"],description:"1/round Effect: One enemy within 10 squares of the devil that is taking ongoing psychic damage is dominated until the end of its next turn. Doom the Corrupt (psychic) ✦ Recharge ⚄ ⚅ Effect: One ally or dominated creature within 10 squares of the devil makes a melee basic attack against a creature of the devil's choice. If that attack hits, the target of the attack is also immobilized (save ends)."},{name:"Desperate Measures",action:"Minor",recharge:"Recharge when first bloodied",description:"Effect: One of the devil's allies within 5 squares of it can make a basic attack as a free action and can score a critical hit on a roll of 19–20 with this attack. The ally grants combat advantage until the devil's next turn. While the devil is bloodied, this power affects each of the devil's allies within 5 squares. Skills Bluff +23, Diplomacy +23, Insight +24"}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 52."] },
  { id:"mm3-greater-earth-elemental",name:"Greater Earth Elemental",source:"mm3",level:22,role:"Soldier",xp:4150,size:"Large",origin:"Elemental",type:"Magical beast",keywords:["earth"],hp:212,ac:37,fort:35,ref:32,will:33,initiative:11,perception:11,speed:"9, burrow 9",senses:["Tremorsense 5"],vulnerable:["thunder (see brittle skin)"],powers:[{name:"Earth Glide",action:"Trait",description:"The greater earth elemental can pass through earth and rock as if it were phasing"},{name:"Brittle Skin Whenever",action:"Trait",description:"the greater earth elemental takes thunder damage, it takes a -2 penalty to all defenses until the end of its next turn"},{name:"Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +27 vs. AC Hit: 4d8 + 12 damage, and the target cannot shift until the end of the elemental's next turn."},{name:"Flattening Stomp",action:"Standard",recharge:"Recharge when first bloodied",description:"Attack: Melee 2 (one creature); +25 vs. Reflex Hit: 5d8 + 20 damage. Effect: The target and each enemy within 2 squares of it falls prone."}],alignment:"Unaligned",languages:["understands Primordial Monster Manual 3","page(s) 81","Dungeon Magazine 215."] },
  { id:"mm3-howler-terror-incarnate",name:"Howler Terror Incarnate",source:"mm3",level:22,role:"Lurker",xp:4,size:"Large",origin:"Shadow",type:"Magical beast",hp:155,ac:36,fort:34,ref:34,will:35,initiative:22,perception:16,speed:"8, fly 6",senses:["Darkvision"],powers:[{name:"Terror Incarnate",action:"Aura",keywords:["fear","psychic"],description:"Aura 3 Any enemy that starts and ends its turn within the aura takes 10 psychic damage. Shadow Spines (necrotic) Whenever a creature adjacent to the terror incarnate misses it or its rider with a melee attack, that creature takes 15 necrotic damage."},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +27 vs. AC Hit: 2d8 + 7 damage."},{name:"Shadow of Terror",action:"Standard",keywords:["charm","psychic"],description:"Attack: Melee 1 (one creature that cannot see the terror incarnate and has not yet been dominated by it during this encounter); +25 vs. Will Hit: The target is dominated and its at-will attacks deal 1d8 extra psychic damage and target Will (save ends; the target takes a -4 penalty to the saving throw; the effect ends if the target takes radiant damage). Until the effect ends, the howler is removed from play. When the effect ends, the howler appears in the unoccupied space nearest to the target. Aftereffect: The target is dazed (save ends)."},{name:"Death Howl",action:"Standard",keywords:["fear","psychic"],recharge:"Encounter",description:"Attack: Close blast 5 (enemies in the blast that cannot see the terror incarnate); +25 vs. Will Hit: 3d8 + 5 psychic damage, and the target is dazed (save ends)."},{name:"Shadow Lope",action:"Move",keywords:["illusion"],recharge:"Recharge 3-6",description:"Effect: The terror incarnate becomes invisible and can move its speed. It remains invisible until the end of its next turn. Skills Stealth +23"}],alignment:"Unaligned",languages:["Abyssal","Giant Monster Manual 3","page(s) 111."] },
  { id:"mm3-infernal-girallon",name:"Infernal Girallon",source:"mm3",level:22,role:"Brute",xp:4150,size:"Large",origin:"Immortal",type:"Beast",keywords:["devil"],hp:249,ac:34,fort:34,ref:30,will:32,initiative:18,perception:16,speed:"8, climb 6",senses:["Darkvision"],powers:[{name:"Threatening Claws",action:"Aura",description:"Aura 1 Enemies within the aura grant combat advantage."},{name:"Burning Soul",action:"Aura",keywords:["fire"],description:"Aura 2 Any enemy that starts its turn within the aura takes 10 fire damage, or 20 fire damage if the girallon is bloodied"},{name:"Combat Climber",action:"Trait",description:"The infernal girallon does not provoke opportunity attacks by climbing"},{name:"Claw",action:"Standard",description:"Attack: Melee 2 (one creature); +26 vs. AC Hit: 3d12 + 10 damage."},{name:"Claw Flurry",action:"Standard",description:"Effect: The alpha makes the following attack four times. Attack: Melee 2 (one creature); +26 vs. AC Hit: 1d12 + 8 damage."},{name:"Burning Ichor",action:"Standard",keywords:["fire"],recharge:"Recharge 4-6",description:"Attack: Close blast 3 (enemies in the blast); +24 vs. Reflex Hit: 3d10 + 15 fire damage, and ongoing 10 fire damage (save ends). Skills Acrobatics +23, Athletics +24"}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 103."] },
  { id:"mm3-thoon-hulk",name:"Thoon Hulk",source:"mm3",level:22,role:"Brute",xp:4150,size:"Large",origin:"Natural",type:"Humanoid",hp:255,ac:34,fort:35,ref:33,will:32,initiative:18,perception:19,speed:"6",senses:["Darkvision"],resist:["10 psychic"],powers:[{name:"Eviscerate",action:"Standard",description:"Attack: Melee 2 (one creature); +27 vs. AC Hit: 4d10 + 16 damage (6d10 + 16 against a creature grabbed by the Thoon hulk)."},{name:"Mind Blast",action:"Standard",keywords:["psychic"],recharge:"Recharge 5-6",description:"Attack: Close blast 5 (enemies in the blast); +25 vs. Will Hit: 1d12 + 7 psychic damage, and the target is dazed (save ends)."},{name:"Call of Thoon",action:"Standard",keywords:["charm","psychic"],recharge:"Encounter",description:"Attack: Ranged 10 (one creature); +25 vs. Will Hit: 4d12 + 20 psychic damage. Effect: The Thoon hulk pulls the target 10 squares to a square adjacent to it."},{name:"Tentacles",action:"Minor",description:"Requirement: The Thoon hulk must not have a creature grabbed. Attack: Melee 1 (one creature); +25 vs. Reflex Hit: The Thoon hulk grabs the target."},{name:"Psychic Explosion",action:"Triggered",keywords:["psychic"],description:"Trigger: The Thoon hulk drops to 0 hit points.. Close burst 2 (enemies in the burst); +26 vs. Will Hit: Ongoing 15 psychic damage (save ends)."}],alignment:"Unaligned",languages:["Deep Speech","telepathy 10 Monster Manual 3","page(s) 138","Dungeon Magazine 201."] },
  { id:"mm3-tulgar-flesh-hunter",name:"Tulgar Flesh Hunter",source:"mm3",level:22,role:"Skirmisher",xp:4150,size:"Medium",origin:"Natural",type:"Humanoid",hp:209,ac:36,fort:34,ref:35,will:33,initiative:21,perception:22,speed:"7 (forest walk)",powers:[{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +27 vs. AC Hit: 2d8 + 10 damage."},{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 5/10 (one creature); +27 vs. AC Hit: 2d6 + 8 damage."},{name:"Hunter's Onslaught",action:"Standard",description:"Effect: The flesh hunter uses spear and then uses handaxe against a different target. Special: Using handaxe as part of this power does not provoke opportunity attacks. When charging, the flesh hunter can use this power in place of a spear attack."},{name:"Rotting Strike",action:"Standard",keywords:["necrotic","weapon"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +27 vs. AC Hit: 2d8 + 8 damage, and the target is dazed and takes ongoing 10 necrotic damage (save ends both)."}],alignment:"Unaligned",languages:["Common Equipment : handaxe x4","hide armor","spear . Monster Manual 3","page(s) 195."] },
  { id:"mm3-tulgar-savage",name:"Tulgar Savage",source:"mm3",level:22,role:"Brute",roleModifier:"Minion",xp:1038,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:34,fort:35,ref:33,will:35,initiative:17,perception:24,speed:"7 (forest walk)",powers:[{name:"Critical Threat",action:"Trait",description:"The savage can score a critical hit on a roll of 19–20"},{name:"When",action:"Trait",description:"the savage scores a critical hit with greataxe, one ally within 2 squares of it can make a melee basic attack as a free action"},{name:"Greataxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +27 vs. AC Hit: 18 damage."},{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 5/10 (one creature); +27 vs. AC Hit: 12 damage."}],alignment:"Unaligned",languages:["Common Equipment : greataxe","handaxe","hide armor . Monster Manual 3","page(s) 195."] },
  { id:"mm3-ultrodemon-schemer",name:"Ultrodemon Schemer",source:"mm3",level:22,role:"Controller",xp:0,size:"Medium",origin:"Elemental",type:"Humanoid",keywords:["demon"],hp:205,ac:36,fort:32,ref:34,will:34,initiative:15,perception:21,speed:"6",resist:["20 to the triggering damage type until the end of the encounter. Self-Preservation (illusion, teleportation) ✦ Encounter Trigger: An enemy bloodies the schemer. Effect (Immediate Reaction): The schemer teleports, swapping places with an ally it can see within","10 squares. The schemer becomes invisible until the end of its next turn, and the ally can make a melee basic attack as a free action against the enemy that bloodied the schemer if it is within the ally's reach. Skills Arcana +22, Bluff +23, Intimidate +23, Stealth +20"],powers:[{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +27 vs. AC Hit: 3d8 + 10 damage, and the target is dazed until the end of the schemer's next turn."},{name:"Fiery Rays",action:"Standard",keywords:["fire"],description:"Attack: Ranged 10 (one or two creatures); +25 vs. Reflex Hit: 3d6 + 7 fire damage. Demonic Authority ✦ Recharge when first bloodied Effect: Each ally adjacent to the schemer makes a melee basic attack with combat advantage as a free action."},{name:"Hypnotic Gaze",action:"Minor",keywords:["charm"],recharge:"Recharge 3-6",description:"Attack: Ranged 5 (one creature); +25 vs. Will Hit: The target is immobilized (save ends). Effect: The target cannot attack the schemer until the end of the target's next turn."},{name:"Treacherous Gaze",action:"Minor",keywords:["charm"],recharge:"Recharge 5-6",description:"Attack: Ranged 5 (one creature); +25 vs. Will Hit: The target is dominated until the end of the schemer's next turn."},{name:"Variable Resistance",action:"Triggered",recharge:"Encounter",description:"Trigger: The schemer takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The schemer gains resist 20 to the triggering damage type until the end of the encounter. Self-Preservation (illusion, teleportation) ✦ Encounter Trigger: An enemy bloodies the schemer. Effect (Immediate Reaction): The schemer teleports, swapping places with an ally it can see within 10 squares. The schemer becomes invisible until the end of its next turn, and the ally can make a melee basic attack as a free action against the enemy that bloodied the schemer if it is within the ally's reach. Skills Arcana +22, Bluff +23, Intimidate +23, Stealth +20"}],alignment:"Unaligned",languages:["Abyssal Equipment : longsword . Monster Manual 3","page(s) 47."] },
  { id:"mm3-drow-zealot",name:"Drow Zealot",source:"mm3",level:23,role:"Brute",xp:5100,size:"Medium",origin:"Fey",type:"Humanoid",hp:265,ac:35,fort:36,ref:35,will:33,initiative:18,perception:11,speed:"7",senses:["Darkvision"],resist:["10 poison"],powers:[{name:"Spider Host",action:"Aura",keywords:["poison"],description:"Aura 1 While the zealot is bloodied, any enemy within the zealot's aura that becomes bloodied takes ongoing 20 poison damage (save ends)."},{name:"Fullblade",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +28 vs. AC Hit: 3d12 + 19 damage. Miss: The zealot gains a +2 bonus to melee attack rolls and a +5 bonus to melee damage rolls until the end of its next turn."},{name:"Darkfire",action:"Minor",recharge:"Encounter",description:"Attack: Ranged 10 (one creature); +26 vs. Reflex Hit: The target grants combat advantage and cannot benefit from invisibility or concealment until the end of the zealot's next turn."}],alignment:"Unaligned",languages:["Abyssal","Common","Elven Equipment : fullblade . Monster Manual 3","page(s) 76","Dungeon Magazine 212."] },
  { id:"mm3-elder-brain",name:"Elder Brain",source:"mm3",level:23,role:"Controller",roleModifier:"Elite",xp:10200,size:"Large",origin:"Aberrant",type:"Magical beast",keywords:["blind"],hp:436,ac:37,fort:33,ref:35,will:37,initiative:17,perception:19,speed:"2, teleport 6",senses:["Blindsight 10"],immune:["blinded, gaze"],powers:[{name:"Warp Reality",action:"Aura",description:"Aura 5 Any enemy that teleports while within the aura takes 10 damage"},{name:"Absorb Thoughts Whenever",action:"Trait",description:"a nonminion ally within 10 squares of the elder brain drops to 0 hit points, the elder brain makes a saving throw or a power recharge roll"},{name:"Unseeing Telepathy",action:"Trait",description:"The elder brain can communicate with other creatures telepathically even if it does not have line of effect to those creatures"},{name:"Tentacle Warp",action:"Standard",keywords:["teleportation"],description:"Attack: Melee 3 (one creature); +26 vs. AC Hit: 1d8 + 8 damage. The elder brain teleports the target 3 squares, and the target is immobilized until the end of the elder brain's next turn."},{name:"Flailing Warp",action:"Standard",description:"Effect: The elder brain uses tentacle warp three times, making each attack against a different target."},{name:"Mind Burst",action:"Standard",keywords:["psychic"],recharge:"Recharge 4-6",description:"Attack: Close burst 5 (enemies in the burst); +27 vs. Will Hit: 3d8 + 6 psychic damage, and the target is dazed (save ends). Miss: Half damage."},{name:"Sensory Overload",action:"Minor",keywords:["psychic","teleportation"],recharge:"Recharge 4-6",description:"Attack: Close burst 5 (enemies in the burst); +27 vs. Will Hit: 2d8 + 6 psychic damage, and the target is blinded and deafened until the end of the elder brain's next turn. The elder brain then teleports the target 3 squares."},{name:"Baleful Transfer",action:"Triggered",description:"Trigger: The elder brain saves against an effect. Effect (No Action): An enemy within 5 squares of the elder brain is subjected to the same effect the elder brain saved against (save ends). Skills Arcana +25, Bluff +24, Diplomacy +24, Dungeoneering +24"}],alignment:"Unaligned",languages:["Deep Speech","telepathy 50 Monster Manual 3","page(s) 139","Dungeon Magazine 201."] },
  { id:"mm3-hellwasp-devil",name:"Hellwasp Devil",source:"mm3",level:23,role:"Skirmisher",xp:5100,size:"Large",origin:"Immortal",type:"Magical beast",keywords:["devil"],hp:212,ac:37,fort:34,ref:35,will:32,initiative:21,perception:20,speed:"0, fly 8 (hover)",senses:["Darkvision"],powers:[{name:"Drag Off",action:"Trait",description:"When the hellwasp moves while it has a creature grabbed, it can pull that creature with it. In addition, the creature remains grabbed, and the hellwasp does not provoke an opportunity attack from the creature"},{name:"Sword Talons",action:"Standard",description:"Attack: Melee 1 (one creature); +28 vs. AC Hit: 2d8 + 7 damage."},{name:"Talon Skewer",action:"Standard",description:"Requirement: The hellwasp must be flying. Effect: The hellwasp flies its speed. At any point during its movement, the hellwasp can use sword talons twice. If both attacks hit the same target, that target is grabbed. The devil does not provoke an opportunity attack for moving away from the target of the attacks."},{name:"Hellwasp Sting",action:"Standard",keywords:["fire","poison"],recharge:"Recharge 4-6",description:"Attack: Melee 1 (one creature); +26 vs. Fortitude Hit: 2d10 + 10 poison damage, and the target is slowed, cannot shift, and takes ongoing 15 fire damage (save ends all)."}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 58."] },
  { id:"mm3-nalfeshnee-tyrant",name:"Nalfeshnee Tyrant",source:"mm3",level:23,role:"Controller",xp:5100,size:"Huge",origin:"Elemental",type:"Humanoid",keywords:["demon"],hp:215,ac:37,fort:35,ref:34,will:36,initiative:12,perception:22,speed:"6, fly 4 (clumsy)",senses:["Darkvision"],resist:["20 to the triggering damage type until the end of the encounter or until it uses variable resistance again. Skills Arcana +23, Bluff +24, Insight +22, Intimidate +24"],vulnerable:["15 psychic. ✻ Unholy Whispers ✦ Recharge ⚄ ⚅ Attack: Area burst burst","2 within","10 (enemies in the burst)","+26 vs. Will Hit:","3d6 +","14 psychic damage, and the target is dazed (save ends). Miss: Half damage. Minor Actions ➶ Vile Glare ✦ Recharge ⚅ Attack: Ranged","5 (one creature)","+26 vs. Will Hit: The only attacks the target can make are basic attacks (save ends). Each Failed"],powers:[{name:"Claws",action:"Standard",description:"Attack: Melee 3 (one creature); +28 vs. AC Hit: 4d6 + 17 damage, and the tyrant slides the target 2 squares."},{name:"Black Lightning",action:"Standard",keywords:["necrotic"],description:"Attack: Ranged 10 (one creature); +26 vs. Reflex Hit: 2d6 + 9 necrotic damage, and until the end of the tyrant's next turn, the target is slowed and gains vulnerable 15 psychic."},{name:"Unholy Whispers",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Area burst burst 2 within 10 (enemies in the burst); +26 vs. Will Hit: 3d6 + 14 psychic damage, and the target is dazed (save ends). Miss: Half damage."},{name:"Vile Glare",action:"Minor",recharge:"Recharge 5-6",description:"Attack: Ranged 5 (one creature); +26 vs. Will Hit: The only attacks the target can make are basic attacks (save ends). Each Failed Saving Throw: Vile glare recharges."},{name:"Variable Resistance",action:"Triggered",recharge:"3/Encounter",description:"Trigger: The tyrant takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The tyrant gains resist 20 to the triggering damage type until the end of the encounter or until it uses variable resistance again. Skills Arcana +23, Bluff +24, Insight +22, Intimidate +24"}],alignment:"Unaligned",languages:["Abyssal","Common Monster Manual 3","page(s) 45","Dungeon Magazine 212."] },
  { id:"mm3-tulgar-half-spirit",name:"Tulgar Half-Spirit",source:"mm3",level:23,role:"Lurker",xp:5100,size:"Medium",origin:"Natural",type:"Humanoid",hp:116,ac:35,fort:35,ref:36,will:36,initiative:23,perception:24,speed:"6",resist:["insubstantial"],powers:[{name:"Spirit Shock Whenever",action:"Trait",description:"the half-spirit hits an enemy that cannot see the half-spirit, that enemy is dazed until the end of its next turn"},{name:"Claw",action:"Standard",keywords:["illusion","necrotic"],description:"Attack: Melee 1 (one creature); +28 vs. AC Hit: 1d6 + 8 necrotic damage, and the target is immobilized until the end of the half-spirit's next turn. Effect: The half-spirit becomes invisible until the end of its next turn."},{name:"Handaxe",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 5/10 (one creature); +28 vs. AC Hit: 2d6 + 8 damage."},{name:"Unleash the Inner Spirit",action:"Triggered",keywords:["illusion","necrotic","teleportation"],recharge:"Encounter",description:"Trigger: The half-spirit is first bloodied. Attack (Free Action): Close burst 3 (enemies in the burst); +26 vs. Fortitude Hit: 2d6 + 3 necrotic damage, and the target is stunned until the end of the half-spirit's next turn. Effect: The half-spirit becomes invisible until the end of its next turn. The half-spirit can then teleport 5 squares. Unbroken Spirit Trigger: The half-spirit drops to 0 hit points. Effect (No Action): The half-spirit's nearest ally gains 10 temporary hit points and a +2 bonus to attack rolls, damage rolls, and all defenses until the end of its next turn. Skills Stealth +24"}],alignment:"Unaligned",languages:["Common Equipment : handaxe x2. Monster Manual 3","page(s) 196."] },
  { id:"mm3-tulgar-warrior",name:"Tulgar Warrior",source:"mm3",level:23,role:"Brute",xp:5100,size:"Medium",origin:"Natural",type:"Humanoid",hp:265,ac:35,fort:36,ref:34,will:35,initiative:18,perception:24,speed:"7 (forest walk)",powers:[{name:"Inveterate Warrior",action:"Trait",description:"The warrior can score a critical hit on a roll of 19-20 and deals 3d12 extra damage on a critical hit"},{name:"Greataxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +28 vs. AC Hit: 2d12 + 19 damage, and the target takes a -2 penalty to AC until the end of the warrior's next turn."},{name:"Whirling Frenzy",action:"Standard",keywords:["weapon"],recharge:"Encounter",description:"Attack: Close burst 1 (enemies in the burst); +28 vs. AC Hit: 3d12 + 6 damage. Effect: The warrior shifts 3 squares and makes a secondary attack. Secondary Attack: Close burst 1 (enemies in the burst not hit by the primary attack); +26 vs. AC Hit: 2d12 + 6 damage."}],alignment:"Unaligned",languages:["Common Equipment : greataxe","hide armor . Monster Manual 3","page(s) 196","Dungeon Magazine 212."] },
  { id:"mm3-ancient-earthquake-dragon",name:"Ancient Earthquake Dragon",source:"mm3",level:24,role:"Soldier",roleModifier:"Elite",xp:12100,size:"Huge",origin:"Elemental",type:"Magical beast",keywords:["dragon","earth"],hp:456,ac:40,fort:37,ref:37,will:35,initiative:22,perception:19,speed:"8 (earth walk), burrow 4, fly 6 (clumsy)",senses:["Darkvision"],powers:[{name:"Quaking Earth",action:"Aura",description:"Aura 1 When any enemy within the aura makes an attack that does not include the dragon as a target, that enemy falls prone and takes 15 damage"},{name:"Threatening Reach",action:"Trait",description:"The dragon can make opportunity attacks using claw against enemies within 3 squares of it"},{name:"Bite",action:"Standard",description:"Attack: Melee 2 (one creature); +29 vs. AC Hit: 4d8 + 14 damage."},{name:"Claw",action:"Standard",description:"Attack: Melee 3 (one creature); +31 vs. AC Hit: 4d6 + 10 damage."},{name:"Double Attack",action:"Standard",description:"Effect: The dragon uses bite and claw or uses claw twice."},{name:"Earthen Maw",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Melee 2 (one creature); +29 vs. Reflex Hit: 4d10 + 11 damage, and the target is restrained (save ends). First Failed Saving Throw: The target is instead petrified (save ends)."},{name:"Rising Tremors",action:"Minor",description:"Recharge at the start of any turn when quaking earth is aura 1 Effect: The quaking earth expands to aura 3. At the start of the dragon's next turn, the quaking earth expands to aura 5. At the start of its following turn, the dragon makes the following attack. Attack (No Action): Close burst 5 (enemies in the burst); +27 vs. Reflex Hit: 4d8 + 14 damage, and the target falls prone and cannot stand up (save ends). Effect: The quaking earth aura reverts to its original state and size (aura 1)."},{name:"Sudden Quake",action:"Triggered",description:"Trigger: The dragon is pulled, pushed, slid, or knocked prone. Effect (Free Action): Each enemy in the dragon's aura falls prone."}],alignment:"Unaligned",languages:["Common","Draconic","Primordial Monster Manual 3","page(s) 70","Dungeon Magazine 205."] },
  { id:"mm3-chthonic-apostle",name:"Chthonic Apostle",source:"mm3",level:24,role:"Soldier",xp:6050,size:"Large",origin:"Natural",type:"Humanoid",hp:225,ac:40,fort:37,ref:32,will:35,initiative:17,perception:18,speed:"8",resist:["10 to all damage."],powers:[{name:"Stone Cursed",action:"Trait",description:"While bloodied, the chthonic apostle has speed 4 and resist 10 to all damage"},{name:"Greatspear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 3 (one creature); +29 vs. AC Hit: 2d12 + 14 damage, and the target is marked until the end of the apostle's next turn."},{name:"Impale",action:"Standard",keywords:["weapon"],description:"Attack: Melee 3 (one creature the apostle has marked); +29 vs. AC Hit: 1d12 + 8 damage, and the target enters the apostle's space. The target is immobilized and takes ongoing 10 damage (save ends). The target automatically moves with the apostle while immobilized, and each time the apostle hits with a greatspear attack, the immobilized target takes 10 damage and is dazed until the end of the apostle's next turn. When an immobilized creature saves against the effect, it shifts to a square adjacent to the apostle."}],alignment:"Unaligned",languages:["Giant","Primordial Equipment : greatspear","plate armor . Monster Manual 3","page(s) 165."] },
  { id:"mm3-chthonic-stoneshaper",name:"Chthonic Stoneshaper",source:"mm3",level:24,role:"Artillery",xp:6050,size:"Medium",origin:"Natural",type:"Humanoid",hp:175,ac:34,fort:36,ref:34,will:36,initiative:16,perception:18,speed:"6 (earth walk)",powers:[{name:"Warhammer",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +29 vs. AC Hit: 2d10 + 13 damage."},{name:"Stony Embrace",action:"Standard",description:"Attack: Ranged 10 (one creature); +29 vs. Reflex Hit: 2d6 + 7 damage, and the target is restrained and takes ongoing 10 damage (save ends both)."},{name:"Rending Earth",action:"Standard",description:"Attack: Ranged 20 (one creature restrained by the stoneshapers's stony embrace); +29 vs. Fortitude Hit: 2d8 + 7 damage, and the target is stunned (save ends)."},{name:"Unruly Earth",action:"Minor",recharge:"Recharge 3-6",description:"Attack: Close burst 2 (enemies in the burst); +29 vs. Reflex Hit: 2d6 + 8 damage, and the stoneshaper pushes the target 3 squares and knocks it prone. Skills Arcana +19, Endurance +24, Intimidate +26"}],alignment:"Unaligned",languages:["Common","Primordial Equipment : ceremonial knife","warhammer . Monster Manual 3","page(s) 165."] },
  { id:"mm3-corrupted-lecher",name:"Corrupted Lecher",source:"mm3",level:24,role:"Lurker",roleModifier:"Minion",xp:1513,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:38,fort:36,ref:36,will:37,initiative:22,perception:16,speed:"6",powers:[{name:"Focused Carnality",action:"Trait",description:"The lecher cannot be targeted by an attack unless it is the nearest enemy to an attacker"},{name:"Touch of Lust",action:"Standard",keywords:["charm"],description:"Attack: Melee 1 or Ranged 10 (one creature); +27 vs. Will Hit: 16 damage. Choose one of the lecher's allies within 5 squares of the target. Until the end of the target's next turn, the target is marked by that creature. In addition, if the target has any creatures marked, those marks end."}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 54."] },
  { id:"mm3-draegloth-abomination",name:"Draegloth Abomination",source:"mm3",level:24,role:"Lurker",xp:6050,size:"Huge",origin:"Elemental",type:"Magical beast",keywords:["demon"],hp:175,ac:38,fort:37,ref:35,will:33,initiative:23,perception:20,speed:"8, climb 8 (spider climb)",senses:["Darkvision"],resist:["20 to the triggering damage type until the end of the encounter or until it uses variable resistance again. Dark Leap (teleportation) ✦ Recharge when first bloodied Trigger: An enemy damages the abomination. Effect (Immediate Reaction): Maddening darkness recharges, and the abomination uses it. The abomination then teleports","8 squares. Skills Religion +23, Stealth +24"],powers:[{name:"Claw",action:"Standard",description:"Attack: Melee 3 (one creature); +29 vs. AC Hit: 2d10 + 10 damage, or 4d10 + 10 against dazed creatures."},{name:"Slashing Claws",action:"Standard",description:"Effect: The abomination uses claw against two different targets."},{name:"Tethering Web",action:"Standard",keywords:["poison"],description:"Attack: Ranged 5 (one creature, or two creatures while the abomination is bloodied); +27 vs. Reflex Hit: 1d10 + 10 poison damage, and the target is tethered (save ends). While the target is tethered, it is dazed, and the abomination can pull the target to a square adjacent to it during the abomination's turn as a free action."},{name:"Maddening Darkness",action:"Minor",keywords:["psychic","zone"],recharge:"Encounter",description:"Attack: Close burst 2 (creatures in the burst); +27 vs. Will Hit: The target is slowed and dazed until the end of the abomination's next turn. Effect: The burst creates a zone that lasts until the end of the abomination's next turn. The zone blocks line of sight for all creatures except the abomination. Any creature other than the abomination is blinded while within the zone."},{name:"Variable Resistance",action:"Triggered",recharge:"3/Encounter",description:"Trigger: The abomination takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The abomination gains resist 20 to the triggering damage type until the end of the encounter or until it uses variable resistance again. Dark Leap (teleportation) ✦ Recharge when first bloodied Trigger: An enemy damages the abomination. Effect (Immediate Reaction): Maddening darkness recharges, and the abomination uses it. The abomination then teleports 8 squares. Skills Religion +23, Stealth +24"}],alignment:"Unaligned",languages:["Abyssal","Elven Monster Manual 3","page(s) 77."] },
  { id:"mm3-drow-shadowblade",name:"Drow Shadowblade",source:"mm3",level:24,role:"Lurker",xp:6050,size:"Medium",origin:"Fey",type:"Humanoid",hp:171,ac:39,fort:34,ref:37,will:36,initiative:24,perception:24,speed:"7; phasing",senses:["Darkvision"],powers:[{name:"Short Sword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +29 vs. AC Hit: 2d6 + 15 damage."},{name:"Shadow Strike",action:"Standard",keywords:["necrotic","weapon","zone"],description:"Attack: Melee 1 (one creature flanked by the shadowblade and its animated shadow); +29 vs. AC Hit: 2d6 + 15 damage plus 10 necrotic damage, and the animated shadow ends and creates a zone in a close burst 2 centered on its square and including its square. The zone lasts until the end of the shadowblade's next turn. The zone blocks line of sight for all creatures except the shadowblade. Any creature other than the shadowblade is blinded while within the zone."},{name:"Animated Shadow",action:"Standard",recharge:"Recharge when the shadowblade's animated shadow ends",description:"Effect: The shadowblade creates an animated shadow in an unoccupied square within 10 squares of it. The shadow lasts until the end of the shadowblade's next turn. The shadow counts as an ally for the purpose of flanking with the shadowblade. When the shadowblade moves on its turn, it slides the shadow an equal number of squares."},{name:"Soulrot Venom",action:"Minor",keywords:["necrotic","poison"],recharge:"Recharge when first bloodied",description:"Effect: The next enemy the shadowblade hits before the end of the encounter is weakened (save ends). First Failed Saving Throw: The enemy takes ongoing 15 necrotic and poison damage (save ends). Second Failed Saving Throw: The enemy cannot benefit from immunities or resistances (save ends)."},{name:"Persistent Blade",action:"Triggered",recharge:"Recharge 3-6",description:"Trigger: The shadowblade misses an enemy with a melee attack. Effect (Free Action): The shadowblade uses short sword against a different enemy. Skills Acrobatics +25, Stealth +25, Thievery +25"}],alignment:"Chaotic Evil",languages:["Common","Elven","Abyssal Equipment : leather armor","short sword . Monster Manual 3","page(s) 78."] },
  { id:"mm3-tulgar-spirit-talker",name:"Tulgar Spirit Talker",source:"mm3",level:24,role:"Controller",xp:6050,size:"Medium",origin:"Natural",type:"Humanoid",hp:225,ac:37,fort:35,ref:37,will:37,initiative:18,perception:25,speed:"7 (forest walk)",powers:[{name:"Primal Barrier",action:"Aura",description:"Aura 2 Squares within the aura are difficult terrain to creatures that are not phasing or do not have forest walk."},{name:"Spear",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +29 vs. AC Hit: 4d8 + 14 damage, and the target is marked by an ally within 10 squares of the spirit talker until the end of the spirit talker's next turn."},{name:"Incite Savagery",action:"Standard",keywords:["psychic"],description:"Attack: Ranged 10 (one creature); +27 vs. Will Hit: 4d10 + 10 psychic damage. If the target does not make a melee attack during its next turn, it grants combat advantage until the end of its following turn."},{name:"Dismissal",action:"Minor",recharge:"Recharge 3-6",description:"Special: Choose a conjuration, a summoned creature, or a zone that is within 10 squares of the spirit talker, which then makes the following attack. Attack: Ranged 10 (creator of the chosen effect); +29 vs. Will Hit: The chosen effect ends. Call Spirit Warrior ✦ Recharge ⚅ Effect: A tulgar savage appears within 5 squares of the spirit talker. The savage's initiative follows the spirit talker's."}],alignment:"Unaligned",languages:["Common Equipment : spear . Monster Manual 3","page(s) 197."] },
  { id:"mm3-aspect-of-lolth",name:"Aspect of Lolth",source:"mm3",level:25,role:"Lurker",roleModifier:"Elite",xp:14000,size:"Large",origin:"Immortal",type:"Magical beast",keywords:["shapechanger","spider"],hp:368,ac:38,fort:37,ref:36,will:34,initiative:24,perception:23,speed:"6, climb 6 (spider climb)",senses:["Blindsight 5"],resist:["30 poison"],powers:[{name:"Combat Advantage",action:"Trait",description:"When the aspect of Lolth hits a creature granting combat advantage to it, that creature is weakened and takes ongoing 20 poison damage (save ends both)"},{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +30 vs. AC Hit: 4d6 + 19 damage."},{name:"Acid Webs",action:"Standard",keywords:["acid"],recharge:"Recharge 3-6",description:"Attack: Close blast 5 (enemies in the blast); +28 vs. Reflex Hit: 3d8 + 8 acid damage, and the target is slowed (save ends). First Failed Saving Throw: The target takes ongoing 20 acid damage (save ends)."},{name:"Worthy Sacrifice",action:"Standard",keywords:["zone"],recharge:"Recharge when first bloodied",description:"Effect: Choose a nonminion demon, drow, or spider ally within 10 squares of the aspect of Lolth. The chosen ally drops to 0 hit points. Attack: Area burst 2 within 10 centered on the chosen ally (enemies in the burst); +28 vs. Reflex Hit: The target is immobilized (save ends). Effect: The burst creates a zone that lasts until the end of the encounter. The zone is difficult terrain, and any nonspider that ends its move within the zone is immobilized (save ends)."},{name:"Cloud of Darkness",action:"Minor",keywords:["zone"],description:"1/round Effect: The aspect creates a zone in a close burst 1 that lasts until the end of the aspect's next turn. The zone blocks line of sight for all creatures except the aspect. Any creature other than the aspect is blinded while within the zone. Change Shape (polymorph) ✦ At-Will Effect: The aspect alters its physical form to appear as a Medium drow until it uses change shape again or until it drops to 0 hit points. The creature retains its statistics in its new form. Its clothing, armor, and other possessions do not change. To assume a specific individual's form, the aspect must have seen that individual. Other creatures can make a DC 43 Insight check to discern that the form is a disguise."},{name:"Impaling Legs",action:"Triggered",keywords:["poison"],description:"Trigger: An enemy moves to a square adjacent to the aspect. Attack (Immediate Interrupt): Melee 1 (the triggering enemy); +30 vs. AC Hit: 2d6 + 4 damage, and the target is grabbed. Until the grab ends, the target takes ongoing 10 poison damage. Skills Bluff +26, Diplomacy +26, Insight +23, Intimidate +26"}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 128."] },
  { id:"mm3-astral-kraken",name:"Astral Kraken",source:"mm3",level:25,role:"Controller",roleModifier:"Solo",xp:35000,size:"Gargantuan",origin:"Aberrant",type:"Magical beast",hp:928,ac:39,fort:41,ref:37,will:39,initiative:19,perception:24,speed:"fly 10 (hover)",senses:["Blindsight 20"],powers:[{name:"Threatening Reach",action:"Trait",description:"The astral kraken can make opportunity attacks against all enemies within 4 squares of it"},{name:"Tentacles from Beyond",action:"Standard",keywords:["psychic"],description:"Attack: Melee 4 (one creature); +30 vs. AC Hit: 3d8 + 9 damage, and the kraken grabs the target. The kraken can grab up to eight creatures at one time. Sustain Minor: The kraken sustains all its grabs, and each creature grabbed by the kraken takes 15 psychic damage."},{name:"Absorb Psyche",action:"Standard",keywords:["psychic"],description:"Attack: Melee 4 (each creature grabbed by the kraken); +28 vs. Will Hit: 2d8 + 9 psychic damage, and until the end of the encounter, the kraken gains a +5 bonus to attack rolls with touch of madness against the target."},{name:"Devourer of Ships",action:"Standard",description:"Attack: Melee 4 (one vehicle); +28 vs. Fortitude Hit: 2d10 + 10 damage, and the target is restrained while the kraken remains within 4 squares of it. While restrained by this power, the vehicle takes 20 damage at the start of the kraken's turn. The pilot of the vehicle can spend a standard action to give the vehicle a saving throw. On a save, the vehicle is no longer restrained."},{name:"Touch of Madness",action:"Standard",description:"Attack: Melee 4 (one creature); +28 vs. Will Hit: The target uses its highest-level encounter attack power against a creature or creatures of the kraken's choice. This use of the power does not expend it. The target uses the power even if the power has been expended."},{name:"Nullifying Pulse",action:"Minor",recharge:"Recharge 4-6",description:"Attack: Close blast 4 (enemies in the blast); +28 vs. Will Hit: The target is dazed (save ends)."},{name:"Psychic Scream",action:"Triggered",keywords:["psychic"],recharge:"Encounter",description:"Trigger: The kraken is first bloodied. Attack (No Action): Close burst 10 (enemies in the burst); +28 vs. Will Hit: 4d10 + 9 psychic damage, and the target is stunned (save ends). Miss: Half damage, and the target is dazed (save ends)."},{name:"Behold the Horror",action:"Triggered",keywords:["charm","psychic"],description:"Trigger: An enemy misses the kraken. Attack (Immediate Reaction): Close burst 10 (the triggering enemy in the burst); +28 vs. Will Hit: 3d8 + 9 psychic damage, and the target is dominated until the end of its next turn. Skills Stealth +26"}],alignment:"Unaligned",languages:["telepathy 20 Monster Manual 3","page(s) 123."] },
  { id:"mm3-corrupted-glutton",name:"Corrupted Glutton",source:"mm3",level:25,role:"Soldier",roleModifier:"Minion",xp:1750,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:41,fort:38,ref:37,will:36,initiative:16,perception:13,speed:"6",powers:[{name:"Bite",action:"Standard",description:"Requirement: The glutton must not have a creature grabbed. Attack: Melee 1 (one creature); +30 vs. Will Hit: 12 damage, and the target is grabbed. Chew ✦ At-Will Effect: One creature grabbed by the glutton takes 12 damage."}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 54."] },
  { id:"mm3-drow-archmage",name:"Drow Archmage",source:"mm3",level:25,role:"Artillery",xp:7000,size:"Medium",origin:"Fey",type:"Humanoid",hp:178,ac:37,fort:36,ref:37,will:39,initiative:19,perception:14,speed:"7",senses:["Darkvision"],powers:[{name:"Dagger",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +30 vs. AC Hit: 2d4 + 15 damage, and the target takes a -4 penalty to attack rolls until the end of the archmage's next turn."},{name:"Abyssal Bolt",action:"Standard",keywords:["acid","poison"],description:"Attack: Ranged 20 (one creature); +30 vs. Reflex Hit: 4d8 + 15 acid and poison damage."},{name:"Cruel Banishing",action:"Standard",keywords:["teleportation"],recharge:"Encounter",description:"Attack: Melee 1 (one creature); +30 vs. Fortitude Hit: The archmage teleports the target 7 squares, and the target is dazed (save ends)."},{name:"Demonic Grasp",action:"Standard",keywords:["poison"],recharge:"Encounter",description:"Attack: Ranged 10 (one creature); +30 vs. Fortitude Hit: The target is immobilized and suspended 1 square up (save ends both). While this effect lasts, whenever the target or one of its allies deals damage to a demon, drow, or spider, the target takes 10 poison damage."},{name:"Unwholesome Sacrifice",action:"Minor",keywords:["necrotic"],recharge:"Recharge 4-6",description:"Effect: The archmage deals 20 damage to an ally adjacent to it. In addition, the archmage recharges one encounter power or deals 10 extra damage on its next ranged attack before the end of its next turn."},{name:"Darkfire",action:"Minor",recharge:"Encounter",description:"Attack: Ranged 10 (one creature); +30 vs. Reflex Hit: The target grants combat advantage and cannot benefit from invisibility or concealment until the end of the archmage's next turn. Skills Arcana +23"}],alignment:"Unaligned",languages:["Abyssal","Common","Elven Equipment : dagger . Monster Manual 3","page(s) 78","Dungeon Magazine 212."] },
  { id:"mm3-drow-exalted-consort",name:"Drow Exalted Consort",source:"mm3",level:25,role:"Skirmisher",xp:7000,size:"Medium",origin:"Fey",type:"Humanoid",hp:224,ac:39,fort:35,ref:39,will:37,initiative:23,perception:17,speed:"6",senses:["Darkvision"],powers:[{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +30 vs. AC Hit: 2d8 + 9 damage."},{name:"Warding Blades",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +30 vs. AC Hit: 4d8 + 9 damage, and the consort gains a +6 bonus to AC against opportunity attacks until the start of its next turn."},{name:"Blurring Steel",action:"Standard",recharge:"Recharge when the consort moves at least 3 squares during its turn.",description:"Effect: The consort uses longsword three times. Two of these attacks can target the same creature."},{name:"Darkfire Revelation",action:"Minor",keywords:["fire"],recharge:"Encounter",description:"Attack: Close burst 1 (enemies in the burst); +28 vs. Reflex Hit: 2d8 + 9 fire damage. Effect: The target grants combat advantage and cannot benefit from invisibility or concealment (save ends both)."},{name:"Lolth's Favor",action:"Triggered",keywords:["teleportation"],recharge:"Encounter",description:"Trigger: The consort becomes bloodied. Effect (Immediate Reaction): The consort teleports 7 squares, and each enemy adjacent to the consort after the teleport grants combat advantage until the end of the encounter."}],alignment:"Unaligned",languages:["Abyssal","Common","Elven Equipment : longsword x2. Monster Manual 3","page(s) 78","Dungeon Magazine 212."] },
  { id:"mm3-lolth-s-reaver",name:"Lolth's Reaver",source:"mm3",level:25,role:"Brute",xp:7000,size:"Large",origin:"Elemental",type:"Beast",keywords:["mount","spider"],hp:287,ac:37,fort:37,ref:34,will:35,initiative:14,perception:19,speed:"8, climb 6 (spider climb)",senses:["Tremorsense 5"],powers:[{name:"Web Saddle",action:"Trait",keywords:["mount"],description:"✦ At-Will While a friendly rider of 25th level or higher is mounted on the Lolth's reaver, the rider cannot be dismounted from the reaver by forced movement"},{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +30 vs. AC Hit: 3d10 + 5 damage, and ongoing 20 poison damage (save ends)."},{name:"Grasping Thread",action:"Standard",description:"Attack: Ranged 10 (one creature); +28 vs. Reflex Hit: The reaver pulls the target 5 squares, and the target is restrained (save ends). Each Failed Saving Throw: The reaver pulls the target 5 squares."},{name:"Web Leap",action:"Standard",recharge:"Encounter",description:"Effect: The reaver jumps 8 squares without provoking opportunity attacks. The reaver then makes the following attack. Attack: Close blast 3 (enemies in the blast); +28 vs. Reflex Hit: 3d12 + 12 damage, and the target falls prone and cannot stand up (save ends)."}],alignment:"Unaligned",languages:["Elven","Abyssal Monster Manual 3","page(s) 183."] },
  { id:"mm3-summer-nymph",name:"Summer Nymph",source:"mm3",level:25,role:"Controller",xp:0,size:"Medium",origin:"Fey",type:"Humanoid",hp:233,ac:39,fort:36,ref:37,will:38,initiative:16,perception:25,speed:"6 (forest walk)",senses:["Low-light vision"],powers:[{name:"Renewing Growth",action:"Aura",description:"Aura 5 Squares within the aura are difficult terrain for enemies"},{name:"Any",action:"Trait",description:"enemy within the aura that does not move during its turn is slowed until the end of its next turn"},{name:"Wisdom's Touch",action:"Standard",description:"Attack: Melee 1 (one creature); +28 vs. Will Hit: 3d8 + 10 damage, and the target is dazed until the end of the nymph's next turn."},{name:"Eyes of Summer",action:"Standard",keywords:["radiant"],description:"Attack: Ranged 10 (one creature); +28 vs. Reflex Hit: 3d6 + 3 radiant damage, and the target is blinded (save ends)."},{name:"Call Storm Winds",action:"Standard",keywords:["lightning","thunder","zone"],recharge:"Recharge 4-6",description:"Attack: Area burst 3 within 20 (enemies in the burst); +28 vs. Fortitude Hit: 4d8 + 10 thunder and lightning damage, and the nymph slides the target 3 squares. Effect: The burst creates a zone that lasts until the end of the nymph's next turn. Sustain Minor: The zone persists, and the nymph slides each enemy within the zone 3 squares."},{name:"Omniscient Strategy",action:"Move",description:"Effect: The nymph shifts 1 square, and one ally within 5 squares of it moves its speed as a free action. Skills Arcana +26, History +26, Insight +25, Nature +25"}],alignment:"Unaligned",languages:["Common","Draconic","Elven Monster Manual 3","page(s) 153."] },
  { id:"mm3-battle-weaver",name:"Battle Weaver",source:"mm3",level:26,role:"Soldier",roleModifier:"Elite",xp:18000,size:"Medium",origin:"Immortal",type:"Humanoid",hp:488,ac:42,fort:39,ref:36,will:39,initiative:20,perception:22,speed:"6, teleport 6",senses:["Darkvision"],powers:[{name:"Blade Mastery",action:"Aura",description:"Aura 1 Any enemy that starts its turn within the aura takes 10 damage and is marked until the end of the battle weaver's next turn"},{name:"Multitasking Brain",action:"Trait",description:"While dazed, the battle weaver can spend a standard action and a minor action instead of only a standard action, and it can still take immediate actions"},{name:"Longsword",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +31 vs. AC Hit: 3d8 + 11 damage."},{name:"Quick Jab",action:"Minor",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +31 vs. AC Hit: 1d8 + 11 damage, and the weaver slides the target 3 squares to a square adjacent to it."},{name:"Sidestep Stab",action:"Minor",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +31 vs. AC Hit: 1d8 + 11 damage. Effect: The weaver shifts 3 squares to a square adjacent to the target."},{name:"Extract Martial Soul",action:"Minor",keywords:["healing","psychic"],recharge:"Recharge 4-6",description:"Requirement: The weaver must be holding a chromatic disk. Attack: Ranged 5 (one bloodied creature that has martial powers); +29 vs. Will Hit: 2d12 + 12 psychic damage, and the target is dazed (save ends). Miss: Half damage. Effect: The weaver regains 24 hit points."},{name:"Marked Assault",action:"Triggered",keywords:["teleportation"],description:"Trigger: An enemy marked by the weaver and within 10 squares of it makes an attack that does not include the weaver as a target. Effect (Immediate Interrupt): The weaver teleports to a square adjacent to the triggering enemy and makes a melee basic attack against the enemy as a free action. Skills Acrobatics +23, Athletics +25, Endurance +27"}],alignment:"Unaligned",languages:["telepathy 40 Equipment : chromatic disk","longsword x4. Monster Manual 3","page(s) 204."] },
  { id:"mm3-coil-of-zehir",name:"Coil of Zehir",source:"mm3",level:26,role:"Controller",xp:9,size:"Large",origin:"Natural",type:"Magical Beast",keywords:["reptile"],hp:235,ac:39,fort:38,ref:39,will:38,initiative:17,perception:15,speed:"7, climb 7",resist:["15 poison"],powers:[{name:"Slam",action:"Standard",description:"Attack: Melee 3 (one creature); +31 vs. AC Hit: 3d10 + 10 damage, and the coil of Zehir pulls the target 2 squares and grabs it. The coil of Zehir can have only one creature grabbed at a time."},{name:"Crushing Coils",action:"Standard",description:"Attack: Melee 3 (one creature grabbed by the coil of Zehir); +31 vs. Fortitude Hit: 40 damage, and the target is dazed until the end of the coil of Zehir's next turn."},{name:"Tail Sweep",action:"Minor",recharge:"Recharge 3-6",description:"Attack: Close burst 3 (enemies in the burst); +31 vs. Reflex Hit: The target falls prone."}],alignment:"Unaligned",languages:["Draconic Monster Manual 3","page(s) 213."] },
  { id:"mm3-corrupted-monger",name:"Corrupted Monger",source:"mm3",level:26,role:"Artillery",roleModifier:"Minion",xp:2250,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:40,fort:37,ref:38,will:39,initiative:20,perception:16,speed:"6",powers:[{name:"Touch of Greed",action:"Standard",keywords:["charm"],description:"Attack: Melee 1 (one creature); +28 vs. Will Hit: 12 damage, and the monger slides the target 5 squares to a square adjacent to one of the monger's allies."},{name:"Filch Magic",action:"Standard",description:"Attack: Ranged 10 (one creature); +31 vs. Reflex Hit: 16 damage, and the target loses one of its daily magic item uses until the end of the encounter."}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 55."] },
  { id:"mm3-forsaken-fearwrack",name:"Forsaken Fearwrack",source:"mm3",level:26,role:"Artillery",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["blind"],hp:150,ac:38,fort:37,ref:39,will:39,initiative:20,perception:21,speed:"6",senses:["Blindsight 20"],immune:["blinded, gaze"],powers:[{name:"Inspire Fear",action:"Aura",keywords:["fear"],description:"Aura 1 Enemies within the aura take a -2 penalty to all defenses against fear attacks."},{name:"Fear Strike",action:"Standard",keywords:["fear","implement","psychic"],description:"Attack: Melee 1 (one creature); +29 vs. Will Hit: 2d6 + 7 psychic damage, and the target moves its speed away from the fearwrack. The fearwrack chooses the path the target takes, but each square it moves must take it farther away from the fearwrack."},{name:"Terror Bolt",action:"Standard",keywords:["fear","implement","psychic"],description:"Attack: Ranged 10 (one or two creatures); +31 vs. Will Hit: 2d6 + 7 psychic damage, and one of the fearwrack's allies adjacent to the target can make a melee basic attack against the target as a free action."},{name:"Curse of Mortality",action:"Standard",keywords:["fear","implement"],recharge:"Recharge 3-6",description:"Attack: Ranged 20 (one creature); +31 vs. Fortitude Hit: Ongoing 20 damage (save ends). The target takes a -2 penalty to the saving throw. Each Failed Saving Throw: The ongoing damage increases by 5, to a maximum of ongoing 30 damage."},{name:"Sign of Death",action:"Standard",keywords:["implement"],recharge:"Encounter",description:"Attack: Area burst 2 within 10 (enemies in the burst); +29 vs. Fortitude Hit: Until the end of the fearwrack's next turn, the next attack made against the target gains a +5 power bonus to the attack roll."},{name:"Cleansing Wounds",action:"Triggered",recharge:"Encounter",description:"Trigger: The fearwrack is first bloodied. Effect (No Action): Enemy effects on the fearwrack end."},{name:"Fragment of Immortality",action:"Triggered",recharge:"Encounter",description:"Trigger: The fearwrack drops to 0 hit points. Effect (No Action): The fearwrack is removed from play until the start of its next turn. The fearwrack then appears within 5 squares of its last location with 37 hit points and without any effects on it. Skills Intimidate +27"}],alignment:"Unaligned",languages:["Common","Supernal Equipment : Rod Monster Manual 3","page(s) 85."] },
  { id:"mm3-molt-of-zehir",name:"Molt of Zehir",source:"mm3",level:26,role:"Skirmisher",roleModifier:"Minion",xp:2250,size:"Medium",origin:"Natural",type:"Beast",keywords:["reptile"],hp:1,ac:39,fort:38,ref:39,will:37,initiative:21,perception:16,speed:"7",resist:["15 poison"],powers:[{name:"Bite",action:"Standard",description:"Attack: Melee 1 (one creature); +31 vs. AC Hit: 17 damage."},{name:"Horde of Snakes",action:"Triggered",keywords:["poison"],description:"Trigger: The molt drops to 0 hit points.. Close burst 1 (enemies in the burst); +30 vs. Fortitude Hit: 10 damage, and ongoing 15 poison damage (save ends)."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 215."] },
  { id:"mm3-prison-of-mual-tar",name:"Prison of Mual-Tar",source:"mm3",level:26,role:"Soldier",xp:9000,size:"Large",origin:"Immortal",type:"Animate",keywords:["construct"],hp:242,ac:41,fort:39,ref:38,will:36,initiative:22,perception:17,speed:"6",resist:["15 force"],powers:[{name:"Cloying Chains",action:"Aura",description:"Aura 5 Any enemy that starts its turn within the aura is marked by the prison of Mual-Tar until the start of the enemy's next turn"},{name:"Agent",action:"Trait",description:"of Divine Will The prison of Mual-Tar ignores insubstantial, concealment, and cover (but not total concealment or superior cover)"},{name:"Fettering Lash",action:"Standard",description:"Attack: Melee 4 (one creature); +31 vs. AC Hit: 3d8+21 damage. If the target makes an attack that doesn't include the prison of Mual-Tar before the end of the target's next turn, the prison of Mual-Tar pulls the target 10 squares to the nearest square as a free action."},{name:"Double Attack",action:"Standard",description:"Effect: The prison of Mual-Tar uses fettering lash twice, making each attack against a different target."},{name:"Reactive Coils",action:"Triggered",description:"Trigger: An enemy pushes, pulls, or slides the prison of Mual-Tar. Effect (Immediate Reaction): The prison of Mual-Tar pulls the triggering enemy 10 squares to a square adjacent to the prison of Mual-Tar. The triggering enemy is immobilized until the end of its next turn."},{name:"Unfettered Apocalypse",action:"Triggered",recharge:"Encounter",description:"Trigger: An enemy scores a critical hit against the prison of Mual-Tar or the prison of Mual-Tar is first bloodied. Effect (No Action): The prison of Mual-Tar creates a duplicate of itself, which appears in the nearest unoccupied squares. The duplicate has the same hit points as the prison of Mual-Tar, is considered to have expended the same powers as the prison of Mual-Tar, and acts during the prison of Mual-Tar's next turn. Any effects on the prison of Mual-Tar do not transfer to the duplicate. At the end of the prison of Mual-Tar's next turn, the duplicate disappears."}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 12."] },
  { id:"mm3-spawn-of-ulban",name:"Spawn of Ulban",source:"mm3",level:26,role:"Controller",xp:9000,size:"Medium",origin:"Aberrant",type:"Humanoid",hp:241,ac:40,fort:37,ref:39,will:38,initiative:22,perception:25,speed:"8",senses:["Darkvision"],immune:["dominate (any enemy that hits with a power that would dominate the spawn is instead dominated by it [save ends])"],powers:[{name:"Bluefire Strike",action:"Standard",keywords:["cold","fire"],description:"Attack: Melee 1 (one creature); +29 vs. Reflex Hit: 3d8 + 12 cold and fire damage, and the target is dazed until the end of its next turn."},{name:"Touch of Strife",action:"Standard",keywords:["charm"],description:"Attack: Melee 1 (one creature); +29 vs. Will Hit: 2d10 + 5 psychic damage, and the target makes a melee or a ranged basic attack as a free action against a creature of the spawn's choice."},{name:"Ripple of Betrayal",action:"Standard",keywords:["charm","psychic"],recharge:"Recharge 4-6",description:"Attack: Close burst 1 (enemies in the burst); +29 vs. Will Hit: 3d10 + 5 psychic damage, and the target is dominated (save ends)."},{name:"Far Realm Reflection",action:"Minor",description:"Effect: Choose one creature the spawn of Ulban can see. The spawn forms an eldritch bond with that creature until the end of the encounter or until the spawn uses this power again. Whenever the target of this power shifts, the spawn can shift an equal number of squares as a free action."},{name:"Psionic Boost",action:"Triggered",keywords:["psychic"],recharge:"Recharge when the spawn takes psychic damage",description:"Trigger: The spawn hits with bluefire strike or touch of strife. Effect (Free Action): The attack deals 3d10 extra psychic damage. Skills Bluff +26, Diplomacy +26, Insight +25"}],alignment:"Evil",languages:["Common","Deep Speech Monster Manual 3","page(s) 184."] },
  { id:"mm3-yuan-ti-abomination-berserker",name:"Yuan-ti Abomination Berserker",source:"mm3",level:26,role:"Brute",xp:9000,size:"Large",origin:"Natural",type:"Magical beast",keywords:["reptile"],hp:293,ac:37,fort:38,ref:37,will:36,initiative:15,perception:16,speed:"7",resist:["15 poison"],powers:[{name:"Slam",action:"Standard",description:"Attack: Melee 2 (one creature); +31 vs. AC Hit: 4d10 + 15 damage."},{name:"Roundhouse Slam",action:"Standard",recharge:"Recharge 3-6",description:"Effect: The berserker uses slam against each enemy adjacent to it."},{name:"Berserk Attack",action:"Triggered",description:"Requirement: The berserker must be bloodied. Trigger: An attack hits the berserker. Effect (Immediate Reaction): The berserker uses slam."}],alignment:"Unaligned",languages:["Draconic Monster Manual 3","page(s) 213","Dungeon Magazine 200."] },
  { id:"mm3-corrupted-idler",name:"Corrupted Idler",source:"mm3",level:27,role:"Soldier",roleModifier:"Minion",xp:2750,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:43,fort:40,ref:39,will:38,initiative:16,perception:22,speed:"6",powers:[{name:"Aura of Weariness",action:"Aura",description:"Aura 1 Any enemy that starts its turn within the aura is slowed until the end of its next turn."},{name:"Slothful Touch",action:"Standard",keywords:["charm"],description:"Attack: Melee 1 (one creature); +30 vs. Will Hit: 17 damage, and the target cannot take move actions until the end of the idler's next turn."}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 55."] },
  { id:"mm3-drow-lady-of-spiders",name:"Drow Lady of Spiders",source:"mm3",level:27,role:"Controller",roleModifier:"Elite",xp:0,size:"Medium",origin:"Fey",type:"Humanoid",hp:494,ac:41,fort:37,ref:40,will:42,initiative:21,perception:20,speed:"7",senses:["Darkvision"],powers:[{name:"Lolth's Blessings",action:"Aura",keywords:["healing"],description:"Aura 2 Any bloodied demon, drow, or spider ally that starts its turn within the aura regains 10 hit points"},{name:"Sensitive",action:"Trait",description:"to Light Whenever the Lady of Spiders takes radiant damage, her Lolth's blessings aura doesn't function until the end of her next turn"},{name:"Scourge",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +32 vs. AC Hit: 3d8 + 22 damage, and the Lady of Spiders slides the target 2 squares."},{name:"Conjure Venom",action:"Standard",keywords:["poison"],description:"Attack: Ranged 10 (one creature); +30 vs. Fortitude Hit: 2d10 + 15 poison damage."},{name:"Cocooning Webs",action:"Standard",keywords:["poison"],description:"Attack: Ranged 5 (one creature); +30 vs. Reflex Hit: The target is restrained and takes ongoing 25 poison damage (save ends both). Aftereffect: The target is slowed (save ends)."},{name:"Irrefutable Command",action:"Standard",keywords:["charm"],recharge:"Recharge 4-6",description:"Attack: Close burst 3 (one or two creatures in the burst); +32 vs. Will Hit: The target chooses either to take 50 psychic damage or to charge a creature that the Lady of Spiders designates."},{name:"Bring Forth the Widows",action:"Standard",keywords:["poison"],recharge:"Recharge when the created spider drops to 0 hit points",description:"Effect: The Lady of Spiders creates a Medium demonic spider in an unoccupied square within 10 squares of her. The spider occupies 1 square and lasts until the end of the encounter or until it drops to 0 hit points. The spider has 100 hit points and uses the Lady of Spiders' defenses. The spider has speed 8 and climb 8 (spider climb), and it can move its speed when the Lady of Spiders takes a move action. The spider must remain on a solid surface."},{name:"Widow Attack",action:"Minor",description:"1/round Effect: The demonic spider created by the Lady of Spiders makes the following attack. Attack: Melee 1 (one creature adjacent to the spider); +32 vs. AC Hit: 2d8 + 9 damage, and ongoing 10 poison damage (save ends)."},{name:"Widow Counterattack",action:"Triggered",description:"Trigger: An enemy would provoke an opportunity attack from the demonic spider created by the Lady of Spiders. Attack (Opportunity Action): Melee 1 (the triggering enemy); +32 vs. AC Hit: 2d8 + 9 damage, and ongoing 10 poison damage (save ends)."},{name:"Fearsome Wrath",action:"Triggered",keywords:["fear"],recharge:"Recharge when first bloodied",description:"Trigger: An enemy hits the Lady of Spiders with a melee attack. Attack (Immediate Reaction): Close blast 5 (enemies in the blast, which must include the triggering enemy); +31 vs. Will Hit: The Lady of Spiders pushes the target 5 squares, and the target is stunned until the end of its next turn. Skills Bluff +27, Diplomacy +27, Intimidate +27"}],alignment:"Chaotic Evil",languages:["Abyssal","Common","Elven Equipment : scourge . Monster Manual 3","page(s) 79."] },
  { id:"mm3-forsaken-infiltrator",name:"Forsaken Infiltrator",source:"mm3",level:27,role:"Skirmisher",xp:11000,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["blind"],hp:200,ac:41,fort:38,ref:39,will:39,initiative:22,perception:21,speed:"6",senses:["Blindsight 20"],immune:["blinded, gaze"],powers:[{name:"Combat Advantage Whenever",action:"Trait",description:"the infiltrator hits a creature granting combat advantage to it, that creature is immobilized until the end of its next turn and the infiltrator can shift 2 squares"},{name:"Punishing Response Whenever",action:"Trait",description:"an enemy hits the infiltrator with an opportunity attack, that enemy takes damage equal to the damage dealt by that attack plus 5 extra damage"},{name:"Khopesh",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +32 vs. AC Hit: 4d8 + 17 damage."},{name:"Hand Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10/20 (one creature); +31 vs. AC Hit: 4d6 + 12 damage."},{name:"Careful Attack",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +32 vs. AC Hit: 3d8 + 15 damage, and the infiltrator gains a +2 bonus to all defenses against the target until the end of the infiltrator's next turn."},{name:"Fragment of Immortality",action:"Triggered",recharge:"Encounter",description:"Trigger: The infiltrator drops to 0 hit points. Effect (No Action): The infiltrator is removed from play until the start of its next turn. The infiltrator then appears within 5 squares of its last location with 50 hit points and without any effects on it. Skills Bluff +27, Diplomacy +27, Insight +26, Stealth +25"}],alignment:"Unaligned",languages:["Common","Supernal Equipment : crossbow bolt x10","hand crossbow","khopesh","leather armor . Monster Manual 3","page(s) 85."] },
  { id:"mm3-forsaken-loreseeker",name:"Forsaken Loreseeker",source:"mm3",level:27,role:"Soldier",roleModifier:"Minion",xp:2750,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["blind"],hp:1,ac:43,fort:40,ref:38,will:39,initiative:22,perception:22,speed:"6",senses:["Blindsight 20"],immune:["blinded, gaze"],powers:[{name:"Theft of Memory",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +32 vs. AC Hit: 14 damage. During the target's next turn, the target treats all enemies except the loreseeker as invisible unless the loreseeker is affected by fragment of immortality."},{name:"Hand Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10/20 (one creature); +32 vs. AC Hit: 12 damage, and the target is marked until the end of the target's next turn."},{name:"Fragment of Immortality",action:"Triggered",recharge:"Encounter",description:"Trigger: The loreseeker drops to 0 hit points. Effect (No Action): The loreseeker is removed from play until the start of its next turn. The loreseeker then appears within 5 squares of its last location with 1 hit point and without any effects on it. Skills Arcana +26, History +26, Religion +26"}],alignment:"Unaligned",languages:["Common","Supernal Equipment : chainmail","crossbow bolt x10","hand crossbow","khopesh . Monster Manual 3","page(s) 86."] },
  { id:"mm3-herald-of-colorless-fire",name:"Herald of Colorless Fire",source:"mm3",level:27,role:"Skirmisher",xp:11000,size:"Medium",origin:"Natural",type:"Animate",keywords:["construct","fire"],hp:244,ac:41,fort:37,ref:40,will:37,initiative:25,perception:19,speed:"8, fly 6",resist:["15 fire"],powers:[{name:"Frozen",action:"Trait",description:"in Place Whenever the herald of colorless fire takes cold damage, it cannot use flickering flame until the end of its next turn"},{name:"Caress of Flame",action:"Standard",keywords:["fire","force"],description:"Attack: Melee 1 (one creature); +32 vs. AC Hit: 3d10 + 19 fire and force damage."},{name:"Storm of Colorless Fire",action:"Standard",keywords:["fire","force"],recharge:"Recharge 4-6",description:"Effect: The herald makes the following attack twice, shifting half its speed between the attacks. The herald cannot target the same creature with both attacks. Attack: Close burst 1 (enemies in the burst); +30 vs. Reflex Hit: 4d10+16 fire and force damage, and ongoing 15 fire damage (save ends)."},{name:"Flickering Flame",action:"Minor",description:"Effect: The herald shifts 4 squares."},{name:"Unfettered Apocalypse",action:"Triggered",recharge:"Encounter",description:"Trigger: An enemy scores a critical hit against the herald or the herald is first bloodied. Effect (No Action): The herald creates a duplicate of itself, which appears in the nearest unoccupied square. The duplicate has the same hit points as the herald, is considered to have expended the same powers as the herald, and acts during the herald's turn. Any effects on the herald do not transfer to the duplicate. At the end of the herald's next turn, the duplicate disappears."}],alignment:"Unaligned",languages:["Primordial Monster Manual 3","page(s) 13."] },
  { id:"mm3-hex-weaver",name:"Hex Weaver",source:"mm3",level:27,role:"Lurker",roleModifier:"Elite",xp:22000,size:"Medium",origin:"Immortal",type:"Humanoid",hp:382,ac:41,fort:37,ref:40,will:40,initiative:26,perception:18,speed:"6, teleport 6",senses:["Darkvision"],powers:[{name:"Multitasking Brain",action:"Trait",description:"While dazed, the hex weaver can spend a standard action and a minor action instead of only a standard action, and it can still take immediate actions"},{name:"Shadow Grasp",action:"Standard",description:"Attack: Melee 10 (one or two creatures); +30 vs. Fortitude Hit: 3d6 + 9 damage. Effect: The weaver is invisible to the target until the end of the weaver's next turn."},{name:"Stinging Shroud",action:"Standard",keywords:["necrotic"],description:"Attack: Close burst 1 (enemies in the burst); +30 vs. Fortitude Hit: 2d8 + 9 necrotic damage. The attack deals 20 extra damage if the target is granting combat advantage to the weaver. Shadow Mask (illusion) ✦ Encounter Effect: The weaver becomes invisible until the end of its next turn."},{name:"Shrouded Eye",action:"Minor",description:"1/round Attack: Melee 1 (one creature); +30 vs. Reflex Hit: 2d10 + 9 damage. Effect: The weaver is invisible to the target until the end of the weaver's next turn."},{name:"Extract Shadow Soul",action:"Minor",keywords:["healing","psychic"],recharge:"Recharge 4-6",description:"Requirement: The weaver must be holding a chromatic disk. Attack: Ranged 10 (one bloodied creature that has shadow powers); +30 vs. Will Hit: 2d8 + 9 psychic damage, and the target is dazed (save ends). Miss: Half damage. Effect: The weaver ends one condition currently affecting it."},{name:"Step into Shadow",action:"Triggered",keywords:["illusion","teleportation"],recharge:"Recharge 3-6",description:"Trigger: The weaver takes damage. Effect (Immediate Reaction): The weaver is insubstantial until the end of its next turn. The weaver then teleports its speed. Skills Arcana +25, Stealth +27"}],alignment:"Unaligned",languages:["telepathy 40 Equipment : chromatic disk Monster Manual 3","page(s) 205."] },
  { id:"mm3-mist-hag",name:"Mist Hag",source:"mm3",level:27,role:"Controller",xp:0,size:"Medium",origin:"Fey",type:"Humanoid",hp:247,ac:41,fort:37,ref:38,will:39,initiative:17,perception:27,speed:"8",senses:["Low-light vision"],powers:[{name:"Mist Shroud",action:"Aura",description:"Aura 1 Allies within the aura are insubstantial."},{name:"Mist Staff",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +32 vs. AC Hit: 3d6 + 10 damage, and the mist hag pushes the target 5 squares. The hag can push the target through creatures or through solid objects as if the target were phasing. The hag does not need line of effect to any of the squares to which it pushes the target."},{name:"Mist on the Wind",action:"Standard",keywords:["implement","teleportation"],description:"Attack: Ranged 10 (one creature); +30 vs. Fortitude Hit: 1d10 + 7 damage, and the target is removed from play until the start of the hag's next turn. The target then appears in an unoccupied square of the hag's choice within 4 squares of its last location."},{name:"Choking Mist",action:"Standard",keywords:["implement"],recharge:"Recharge 4-6",description:"Attack: Ranged 10 (one creature); +30 vs. Reflex Hit: 3d10 + 15 damage, and ongoing 20 damage (save ends). Each Failed Saving Throw: The hag slides the target 3 squares as a free action."},{name:"Maze of Mist",action:"Triggered",description:"Trigger: An enemy enters a square within 2 squares of the hag. Effect (No Action): Roll a d20. On a 10 or higher, the hag slides the enemy 1 square. Skills Arcana +25, Bluff +24, History +25, Insight +27, Religion +25"}],alignment:"Unaligned",languages:["Common","Elven","Supernal Equipment : staff implement . Monster Manual 3","page(s) 109","Dungeon Magazine 212."] },
  { id:"mm3-thought-weaver",name:"Thought Weaver",source:"mm3",level:27,role:"Controller",roleModifier:"Elite",xp:0,size:"Medium",origin:"Immortal",type:"Humanoid",hp:500,ac:41,fort:38,ref:38,will:41,initiative:20,perception:24,speed:"6, teleport 6",senses:["Darkvision"],powers:[{name:"Multitasking Brain",action:"Trait",description:"While dazed, the thought weaver can spend a standard action and a minor action instead of only a standard action, and it can still take immediate actions"},{name:"Coordinated Strike Once",action:"Trait",description:"per round during its turn, the weaver can spend a standard action, a move action, or a minor action to allow one ally within 5 squares of it to immediately use an action of the same type as a free action"},{name:"Command the Puppet",action:"Standard",keywords:["charm","psychic"],description:"Effect: One creature dominated by the weaver within 10 squares of it takes 2d6 + 10 psychic damage. In addition, the weaver slides the creature 5 squares. The creature then uses an at-will attack of the weaver's choice against one of its allies of the weaver's choice."},{name:"Mental Puppet",action:"Standard",keywords:["charm"],recharge:"Recharge when no creature is dominated by this power",description:"Attack: Ranged 10 (one creature); +32 vs. Will Hit: The weaver slides the target 5 squares. The target then makes a basic attack against one of its allies of the weaver's choice. In addition, the target is dominated (save ends)."},{name:"Quick Strike",action:"Minor",description:"Attack: Melee 1 (one creature); +32 vs. AC Hit: 2d6 + 10 damage."},{name:"Mind Spike",action:"Minor",keywords:["psychic"],description:"Attack: Ranged 10 (one creature); +31 vs. Will Hit: 2d6 + 10 psychic damage, the target takes a -2 penalty to all defenses until the end of the thought weaver's next turn, and the thought weaver slides the target 3 squares."},{name:"Extract Psionic Soul",action:"Minor",keywords:["healing","psychic"],recharge:"Recharge 4-6",description:"Requirement: The weaver must be holding a chromatic disk. Attack: Ranged 5 (one bloodied creature that has psionic powers); +30 vs. Will Hit: 2d12 + 12 psychic damage, and the target is dazed (save ends). Miss: Half damage. Effect: The weaver regains 25 hit points."},{name:"Guardian Puppet",action:"Triggered",keywords:["charm"],description:"Trigger: An enemy willingly leaves a square adjacent to a creature dominated by the weaver. Effect (Immediate Interrupt): The dominated creature makes a basic attack against the triggering enemy. Skills Insight +29"}],alignment:"Unaligned",languages:["telepathy 40 Equipment : chromatic disk Monster Manual 3","page(s) 205."] },
  { id:"mm3-yuan-ti-abomination-spitter",name:"Yuan-ti Abomination Spitter",source:"mm3",level:27,role:"Artillery",xp:11000,size:"Large",origin:"Natural",type:"Magical beast",keywords:["reptile"],hp:186,ac:39,fort:39,ref:39,will:37,initiative:18,perception:22,speed:"7, climb 7",resist:["15 poison"],powers:[{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature); +32 vs. AC Hit: 2d6 + 8 damage, and ongoing 15 poison damage (save ends)."},{name:"Spit Venom",action:"Standard",keywords:["poison"],description:"Attack: Ranged 20 (one creature); +32 vs. Reflex Hit: 3d6 + 9 poison damage, and ongoing 15 poison damage (save ends)."},{name:"Venom Spray",action:"Standard",keywords:["poison"],recharge:"Recharge 3-6",description:"Attack: Close burst 5 (enemies in the burst); +32 vs. Fortitude Hit: 2d8 + 5 poison damage, and the target is dazed (save ends). Miss: Half damage."},{name:"Cobra Hood",action:"Triggered",description:"Trigger: An attack hits the spitter. Effect (Immediate Reaction): The spitter gains a +4 bonus to AC until the end of its next turn."}],alignment:"Unaligned",languages:["Draconic Monster Manual 3","page(s) 214","Dungeon Magazine 200."] },
  { id:"mm3-yuan-ti-malison-guard",name:"Yuan-ti Malison Guard",source:"mm3",level:27,role:"Soldier",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:242,ac:42,fort:39,ref:38,will:37,initiative:21,perception:15,speed:"7",resist:["15 poison"],powers:[{name:"Overlapping Scales",action:"Aura",description:"Aura 1 Allies within the aura gain a +2 power bonus to AC."},{name:"Scimitar",action:"Standard",keywords:["poison","weapon"],description:"Attack: Melee 1 (one creature); +32 vs. AC Hit: 2d8 + 11 damage, and the target is marked and takes ongoing 15 poison damage (save ends both)."},{name:"Longbow",action:"Standard",keywords:["poison","weapon"],description:"Attack: Ranged 20/40 (one creature); +32 vs. AC Hit: 2d10 + 4 damage, and ongoing 15 poison damage (save ends). Skills Athletics +23, Endurance +22"}],alignment:"Unaligned",languages:["Draconic Equipment : arrow x20","longbow","scimitar . Monster Manual 3","page(s) 213."] },
  { id:"mm3-corrupted-lunatic",name:"Corrupted Lunatic",source:"mm3",level:28,role:"Brute",roleModifier:"Minion",xp:3250,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:40,fort:41,ref:40,will:39,initiative:21,perception:17,speed:"6",powers:[{name:"Touch of Wrath",action:"Standard",keywords:["charm"],description:"Attack: Melee 1 (one creature); +31 vs. Will Hit: 8 damage, and the target makes a basic attack as a free action against its nearest ally."},{name:"Retributive Strike",action:"Triggered",description:"Trigger: An enemy misses the lunatic. Effect (Immediate Reaction): The lunatic uses touch of wrath against the triggering enemy. Spread of Wrath Trigger: An enemy reduces the lunatic to 0 hit points. Effect (No Action): The triggering enemy makes a basic attack as a free action against its nearest ally."}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 56","Dungeon Magazine 219."] },
  { id:"mm3-eclavdra",name:"Eclavdra",source:"mm3",level:28,role:"Soldier",roleModifier:"Elite",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",hp:508,ac:44,fort:38,ref:42,will:40,initiative:26,perception:20,speed:"7",senses:["Darkvision"],powers:[{name:"Spider Queen's Emissary",action:"Aura",description:"Aura 5 Any demon, drow, or spider ally within the aura gains a +2 power bonus to attack rolls and can shift 1 square as a minor action."},{name:"Tentacle Rod",action:"Standard",keywords:["weapon"],description:"Requirement: Eclavdra must be wielding a tentacle rod. Attack: Melee 3 (one creature); +33 vs. AC Hit: 3d8 + 18 damage."},{name:"Tentacle Lash",action:"Standard",keywords:["weapon"],description:"Requirement: Eclavdra must be wielding a tentacle rod. Attack: Melee 3 (one, two, or three creatures); +33 vs. AC Hit: 3d8 + 18 damage, and the target cannot benefit from immunity or resistance to poison until the end of the encounter. In addition, the target is slowed (save ends). First Failed Saving Throw: The target is immobilized instead of slowed (save ends). Second Failed Saving Throw: The target is immobilized and weakened instead of immobilized (save ends both)."},{name:"Insidious Offer",action:"Standard",keywords:["charm","psychic"],recharge:"Recharge when first bloodied",description:"Attack: Ranged 10 (one creature); +31 vs. Will Hit: 1d10 + 9 psychic damage, and the target chooses either to take 30 extra psychic damage or to become dominated (save ends)."},{name:"Entrancing Beauty",action:"Minor",keywords:["charm","psychic"],description:"1/round Attack: Close burst 5 (enemies in the burst); +31 vs. Will Hit: 1d6 + 9 psychic damage, and Eclavdra pulls the target 2 squares."},{name:"On Your Knees",action:"Minor",keywords:["weapon"],recharge:"Recharge 4-6",description:"Requirement: Eclavdra must be wielding a tentacle rod. Attack: Melee 3 (one creature); +33 vs. Will Hit: The target falls prone and cannot stand up (save ends)."},{name:"Blinking Escape",action:"Triggered",keywords:["teleportation"],description:"Trigger: Eclavdra is hit by an area or a close attack. Effect (Immediate Reaction): Eclavdra teleports 6 squares and gains concealment until the end of her next turn. Skills Bluff +27, Insight +25, Intimidate +27, Religion +26"}],alignment:"Unaligned",languages:["Abyssal","Common","Elven Equipment : tentacle rod Monster Manual 3","page(s) 129."] },
  { id:"mm3-emissary-of-caiphon",name:"Emissary of Caiphon",source:"mm3",level:28,role:"Controller",xp:0,size:"Medium",origin:"Aberrant",type:"Humanoid",hp:257,ac:42,fort:38,ref:41,will:41,initiative:23,perception:21,speed:"6",senses:["Darkvision"],powers:[{name:"Aura of Ruin",action:"Aura",description:"Aura 2 Enemies within the aura take a -2 penalty to saving throws"},{name:"Blinding Backfire",action:"Trait",description:"Any enemy that hits with a power that would blind the emissary of Caiphon is instead blinded (save ends)"},{name:"Touch of Despair",action:"Standard",keywords:["psychic"],description:"Attack: Melee 1 (one creature); +31 vs. Reflex Hit: 4d6 + 12 damage, and the target takes 20 psychic damage the first time it fails a saving throw before the start of the emissary's next turn."},{name:"Blinded by Greed",action:"Standard",keywords:["charm","psychic"],description:"Attack: Ranged 10 (one creature); +31 vs. Will Hit: 3d6 + 8 psychic damage, and the emissary slides the target 2 squares. The target then makes a melee basic attack as a free action against a target of the emissary's choice."},{name:"Blinded by Need",action:"Standard",keywords:["charm","psychic"],description:"Attack: Ranged 10 (one creature); +31 vs. Will Hit: 3d8 + 18 psychic damage, and the emissary chooses one of its allies. The target is marked by this ally. Until the end of the emissary's next turn, the emissary and all its allies except the chosen ally are invisible to the target."},{name:"Deceptive Veil",action:"Minor",keywords:["illusion"],description:"Effect: The emissary can disguise itself to appear as any Medium or Small humanoid. A creature that succeeds on a DC 40 Insight check can see through the illusion."},{name:"Invocation of Calamity",action:"Minor",recharge:"Recharge when first bloodied",description:"Attack: Ranged 5 (one creature); +33 vs. Will Hit: The target fails any saving throws it makes until the end of the emissary's next turn."},{name:"Psionic Boost",action:"Triggered",keywords:["psychic"],recharge:"Recharge when the emissary takes psychic damage",description:"Trigger: The emissary hits with blinded by greed or blinded by need. Effect (Free Action): The attack deals 3d10 extra psychic damage. Foretelling Of Doom Trigger: The emissary drops to 0 hit points. Effect (Immediate Interrupt): One enemy within 10 squares of the emissary that is subject to an effect that a save can end takes a -5 penalty to all saving throws against that effect until the end of the encounter. Skills Bluff +26, Diplomacy +26, Insight +25"}],alignment:"Unaligned",languages:["Common","Deep Speech Monster Manual 3","page(s) 185."] },
  { id:"mm3-forsaken-slaughterer",name:"Forsaken Slaughterer",source:"mm3",level:28,role:"Brute",xp:13000,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["blind"],hp:253,ac:40,fort:41,ref:40,will:39,initiative:22,perception:22,speed:"6",senses:["Blindsight 20"],resist:["10 against ranged and area attacks."],immune:["blinded, gaze"],powers:[{name:"Relentless Slaughter",action:"Aura",description:"Aura 1 Enemies within the aura gain only half the benefit of healing effects"},{name:"Proximal Resistance",action:"Trait",description:"While no enemy is adjacent to it, the slaughterer gains resist 10 against ranged and area attacks"},{name:"Khopesh",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +33 vs. AC Hit: 6d8 + 18 damage."},{name:"Unstoppable Cut",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +33 vs. AC Hit: 3d8 + 18 damage, and one enemy adjacent to the target takes the same amount of damage."},{name:"Blood for Blood",action:"Triggered",keywords:["weapon"],recharge:"Encounter",description:"Trigger: The slaughterer is first bloodied. Attack (Free Action): Close burst 1 (enemies in the burst); +33 vs. AC Hit: The target takes damage equal to its healing surge value. Fragment of Immortality ✦ Encounter Trigger: The slaughterer drops to 0 hit points. Effect (No Action): The slaughterer is removed from play until the start of its next turn. The slaughterer then appears within 5 squares of its last location with 63 hit points and without any effects on it. Skills Athletics +29, Intimidate +26"}],alignment:"Unaligned",languages:["Common","Supernal Equipment : khopesh x2","scale armor . Monster Manual 3","page(s) 86."] },
  { id:"mm3-godslayer-inferno",name:"Godslayer Inferno",source:"mm3",level:28,role:"Artillery",xp:13000,size:"Medium",origin:"Elemental",type:"Animate",keywords:["construct","fire"],hp:194,ac:42,fort:40,ref:42,will:39,initiative:24,perception:21,speed:"6",resist:["15 fire"],powers:[{name:"Elemental Inferno",action:"Aura",description:"Aura 2 Enemies within the aura do not benefit from fire resistance and cannot save against effects that include ongoing fire damage."},{name:"Fiery Claw",action:"Standard",keywords:["fire"],description:"Attack: Melee 2 (one creature); +31 vs. AC Hit: Ongoing 20 fire damage (save ends)."},{name:"Fire Bolt",action:"Standard",keywords:["fire"],description:"Attack: Ranged 10 (one or two creatures); +31 vs. Reflex Hit: Ongoing 25 fire damage (save ends). Cloying Flames (fire) ✦ At-Will Effect: Each enemy within 10 squares taking ongoing fire damage immediately takes fire damage equal to its ongoing fire damage."},{name:"Godsbane Inferno",action:"Standard",keywords:["fire"],recharge:"Recharge when first bloodied",description:"Attack: Area burst 2 within 10 (enemies in the burst); +31 vs. Reflex Hit: 2d10+5 fire damage, and ongoing 15 fire damage (save ends). Aftereffect: Ongoing 10 fire damage (save ends)."},{name:"Unfettered Apocalypse",action:"Triggered",recharge:"Encounter",description:"Trigger: An enemy scores a critical hit against the inferno or the inferno is first bloodied. Effect (No Action): The inferno creates a duplicate of itself, which appears in the nearest unoccupied square. The duplicate has the same hit points as the inferno, is considered to have expended the same powers as the inferno, and acts during the inferno's turn. Any effects on the inferno do not transfer to the duplicate. At the end of the inferno's next turn, the duplicate disappears."}],alignment:"Unaligned",languages:["Primordial Monster Manual 3","page(s) 14."] },
  { id:"mm3-klurichir",name:"Klurichir",source:"mm3",level:28,role:"Soldier",xp:13000,size:"Huge",origin:"Elemental",type:"Humanoid",keywords:["demon"],hp:258,ac:42,fort:42,ref:37,will:40,initiative:19,perception:19,speed:"8, fly 12 (clumsy)",senses:["Blindsight 5"],resist:["30 to the triggering damage type until the end of the encounter or until it uses variable resistance again. ᗕ Blasphemous Utterance (necrotic) ✦ Encounter Trigger: The klurichir is first bloodied. Attack (Free Action): Close blast","5 (enemies in the blast)","+31 vs. Will Hit:","3d6 +","8 necrotic damage, and the target is dazed (save ends)."],immune:["fear"],powers:[{name:"Malign Influence",action:"Aura",keywords:["fear"],description:"Aura 2 Enemies within the aura cannot regain hit points."},{name:"Klurichir's Axe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 3 (one creature); +33 vs. AC Hit: 3d8 + 13 damage, or 4d8 + 18 while the klurichur is bloodied, and the target is marked until the end of the klurichir's next turn."},{name:"Savage Hew",action:"Standard",keywords:["weapon"],recharge:"Recharge 4-6",description:"Attack: Close burst 3 (enemies in the burst); +33 vs. AC Hit: 3d8 + 13 damage, or 4d8 + 18 while the klurichur is bloodied, and the target is marked until the end of the klurichir's next turn."},{name:"Pincers",action:"Triggered",description:"Requirement: The klurichir must not have a creature grabbed. Trigger: An enemy marked by the klurichir moves. Attack (Immediate Reaction): Melee 2 (the triggering enemy); +31 vs. Reflex Hit: 2d8 + 13 damage, and the target is grabbed. Sustain Minor: The klurichir sustains the grab, and the target takes 2d8 + 13 damage. Variable Resistance ✦ 3/Encounter Trigger: The klurichir takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The klurichir gains resist 30 to the triggering damage type until the end of the encounter or until it uses variable resistance again."},{name:"Blasphemous Utterance",action:"Triggered",keywords:["necrotic"],recharge:"Encounter",description:"Trigger: The klurichir is first bloodied. Attack (Free Action): Close blast 5 (enemies in the blast); +31 vs. Will Hit: 3d6 + 8 necrotic damage, and the target is dazed (save ends)."}],alignment:"Unaligned",languages:["Abyssal Equipment : greataxe . Monster Manual 3","page(s) 41."] },
  { id:"mm3-shard-of-uralinda",name:"Shard of Uralinda",source:"mm3",level:28,role:"Soldier",roleModifier:"Minion",xp:3250,size:"Medium",origin:"Fey",type:"Animate",keywords:["cold","construct"],hp:1,ac:44,fort:40,ref:40,will:40,initiative:22,perception:18,speed:"6",resist:["15 cold"],powers:[{name:"Seething Cold",action:"Standard",keywords:["cold","psychic"],description:"Attack: Melee 1 (one creature); +33 vs. Fortitude Hit: 18 cold and psychic damage, and the target is immobilized until the end of the shard's next turn."},{name:"Unfettered Apocalypse",action:"Triggered",recharge:"Encounter",description:"Trigger: An enemy scores a critical hit against the shard or drops the shard to 0 hit points. Effect (No Action): The shard creates a duplicate of itself, which appears in the nearest unoccupied square. Any effects on the shard do not transfer to the duplicate. The duplicate cannot use this power. At the end of the shard's next turn, the duplicate disappears."}],alignment:"Unaligned",languages:["Elven Monster Manual 3","page(s) 14","Dungeon Magazine 219."] },
  { id:"mm3-spell-weaver",name:"Spell Weaver",source:"mm3",level:28,role:"Artillery",roleModifier:"Elite",xp:26000,size:"Medium",origin:"Immortal",type:"Humanoid",hp:400,ac:40,fort:38,ref:41,will:41,initiative:22,perception:27,speed:"6, teleport 6",senses:["Darkvision"],powers:[{name:"Multitasking Brain",action:"Trait",description:"While dazed, the spell weaver can spend a standard action and a minor action instead of only a standard action, and it can still take immediate actions"},{name:"Chilling Echo",action:"Standard",keywords:["cold"],description:"Effect: One or two creatures that the weaver has damaged since the start of its turn take 15 cold damage."},{name:"Esoteric Touch",action:"Minor",keywords:["force"],description:"Attack: Melee 1 (one creature); +31 vs. Reflex Hit: 2d10 + 4 force damage, and the weaver pushes the target 5 squares."},{name:"Dimensional Ray",action:"Minor",keywords:["teleportation"],description:"Effect: The weaver teleports 2 squares and makes the following attack. Attack: Ranged 20 (one creature); +33 vs. Fortitude Hit: 2d8 + 4 damage, and the weaver teleports the target 2 squares."},{name:"Esoteric Blast",action:"Minor",keywords:["fire"],description:"Attack: Ranged 20 (one creature); +33 vs. Fortitude Hit: 2d6 + 4 fire damage, and each creature adjacent to the target takes 10 fire damage."},{name:"Extract Arcane Soul",action:"Minor",keywords:["healing","psychic"],recharge:"Recharge 4-6",description:"Requirement: The weaver must be holding a chromatic disk. Attack: Ranged 10 (one bloodied creature that has arcane powers); +33 vs. Will Hit: 2d8 + 9 psychic damage, and the target is dazed (save ends). Miss: Half damage. Effect: The weaver regains 20 hit points."},{name:"Defensive Jaunt",action:"Triggered",keywords:["illusion","teleportation"],recharge:"Encounter",description:"Trigger: The weaver takes damage. Effect (Immediate Reaction): The weaver becomes invisible until the end of its next turn. In addition, the weaver teleports 20 squares. Skills Arcana +29, Insight +27"}],alignment:"Unaligned",languages:["telepathy 40 Equipment : chromatic disk Monster Manual 3","page(s) 203."] },
  { id:"mm3-yuan-ti-malison-assassin",name:"Yuan-ti Malison Assassin",source:"mm3",level:28,role:"Lurker",xp:13000,size:"Medium",origin:"Natural",type:"Humanoid",hp:194,ac:41,fort:39,ref:40,will:40,initiative:28,perception:26,speed:"8",resist:["15 poison"],powers:[{name:"Longsword",action:"Standard",keywords:["poison","weapon"],description:"Attack: Melee 1 (one creature); +33 vs. AC Hit: 2d8 + 9 damage, and the target is blinded until the end of the assassin's next turn."},{name:"Death Strike",action:"Standard",keywords:["poison"],description:"Attack: Melee 1 (one creature that cannot see the assassin); +33 vs. AC Hit: 4d8 + 18 damage, and the target takes ongoing 15 damage and a -2 penalty to saving throws (save ends both). First Failed Saving Throw: The ongoing damage increases by 5, and the penalty to saving throws worsens by 1."},{name:"Shield of Zehir",action:"Triggered",description:"Trigger: A ranged or a melee attack hits the assassin. Effect (Immediate Reaction): The triggering attack also hits a blinded enemy adjacent to the assassin of the assassin's choice. Skills Athletics +23, Bluff +22, Stealth +29"}],alignment:"Unaligned",languages:["Common","Draconic Equipment : longsword . Monster Manual 3","page(s) 215","Dungeon Magazine 212."] },
  { id:"mm3-yuan-ti-malison-blessed",name:"Yuan-ti Malison Blessed",source:"mm3",level:28,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:250,ac:39,fort:36,ref:39,will:38,initiative:23,perception:27,speed:"7",resist:["15 poison"],powers:[{name:"Zehir's Favor",action:"Aura",description:"Aura 3 Any ally within the aura can reroll one failed power recharge roll at the start of its turn."},{name:"Zehir's Agony",action:"Aura",keywords:["poison"],description:"Aura 5 Any enemy that starts its turn within the aura takes 15 poison damage"},{name:"Slither Away",action:"Trait",description:"While the blessed is bloodied, it gains a +2 bonus to speed and a +5 bonus to all defenses"},{name:"Scimitar",action:"Standard",keywords:["poison","weapon"],description:"Attack: Melee 1 (one creature); +33 vs. AC Hit: 3d8 + 8 damage, and the target loses poison resistance and takes a -2 penalty to saving throws against poison effects (save ends both)."},{name:"Zehir's Command",action:"Minor",recharge:"Recharge 5-6",description:"Effect: One or two allies within 5 squares of the blessed can each either make a melee basic attack as a free action or shift its speed as a free action."},{name:"Shifting Feet",action:"Triggered",description:"Trigger: An enemy within 5 squares of the blessed shifts. Effect (Immediate Reaction): The blessed slides the triggering enemy 2 squares."}],alignment:"Evil",languages:["Draconic Equipment : scimitar . Monster Manual 3","page(s) 214","Dungeon Magazine 212."] },
  { id:"mm3-yuan-ti-malison-stalker-mm3",name:"Yuan-ti Malison Stalker (MM3)",source:"mm3",level:28,role:"Skirmisher",xp:13000,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["reptile"],hp:254,ac:42,fort:40,ref:40,will:41,initiative:24,perception:21,speed:"8",resist:["15 poison"],powers:[{name:"Doom",action:"Trait",description:"of Zehir If the only creature adjacent to the stalker is the target of its melee attack, the stalker rolls the attack twice and takes the higher of the two results"},{name:"Greataxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +33 vs. AC Hit: 3d12 + 17 damage."},{name:"Serpent's Dance",action:"Minor",keywords:["teleportation"],description:"Effect: The stalker teleports 3 squares. Skills Athletics +23, Religion +21, Stealth +27"}],alignment:"Unaligned",languages:["Common","Draconic Equipment : greataxe . Monster Manual 3","page(s) 215."] },
  { id:"mm3-corrupted-craven",name:"Corrupted Craven",source:"mm3",level:29,role:"Controller",roleModifier:"Minion",xp:3750,size:"Medium",origin:"Natural",type:"Humanoid",hp:1,ac:43,fort:39,ref:41,will:42,initiative:24,perception:22,speed:"6",powers:[{name:"Touch of the Coward",action:"Standard",description:"Attack: Melee 1 (one creature); +32 vs. Will Hit: 15 damage, and the target moves its speed away from the craven, avoiding danger if possible."}],alignment:"Unaligned",languages:["Common Monster Manual 3","page(s) 56."] },
  { id:"mm3-forsaken-mastermind",name:"Forsaken Mastermind",source:"mm3",level:29,role:"Controller",xp:0,size:"Medium",origin:"Natural",type:"Humanoid",keywords:["blind"],hp:213,ac:43,fort:40,ref:42,will:41,initiative:22,perception:22,speed:"6",senses:["Blindsight 20"],immune:["blinded, gaze"],powers:[{name:"Inspire Resilience",action:"Aura",description:"Aura 5 Allies within the aura that use fragment of immortality also gain 40 temporary hit points."},{name:"Khopesh",action:"Standard",keywords:["weapon"],description:"Attack: Melee 1 (one creature); +34 vs. AC Hit: 4d8 + 19 damage, and the target is marked by one of the mastermind's allies within 5 squares of the mastermind until the end of the target's next turn."},{name:"Hand Crossbow",action:"Standard",keywords:["weapon"],description:"Attack: Ranged 10/20 (one creature); +34 vs. AC Hit: 4d6 + 14 damage."},{name:"Tainted Wave",action:"Standard",description:"Attack: Close blast 3 (enemies in the blast); +32 vs. Fortitude Hit: 2d8 + 12 damage. The target loses any temporary hit points and cannot regain hit points until the end of the mastermind's next turn."},{name:"Delayed Retribution",action:"Standard",recharge:"Recharge 4-6",description:"Attack: Area burst 1 within 10 (enemies in the burst); +32 vs. Reflex Hit: 3d10 + 16 damage, and if the target attacks the mastermind during the target's next turn, the target is stunned until the end of its subsequent turn. Miss: Half damage."},{name:"Wrath of the Forsaken",action:"Triggered",description:"Trigger: An enemy uses a divine power within 10 squares of the mastermind. Effect (Immediate Reaction): The mastermind ends any enemy effects on one ally within 10 squares of it, and that ally can make a recharge roll to regain one expended recharge power."},{name:"Fragment of Immortality",action:"Triggered",recharge:"Encounter",description:"Trigger: The mastermind drops to 0 hit points. Effect (No Action): The mastermind is removed from play until the start of its next turn. The mastermind then appears within 5 squares of its last location with 53 hit points and without any effects on it. Skills Arcana +29, History +29, Insight +27, Religion +29"}],alignment:"Unaligned",languages:["Common","Supernal Equipment : crossbow bolt x10","hand crossbow","khopesh . Monster Manual 3","page(s) 87."] },
  { id:"mm3-molydeus",name:"Molydeus",source:"mm3",level:29,role:"Soldier",roleModifier:"Elite",xp:30000,size:"Large",origin:"Elemental",type:"Humanoid",keywords:["demon"],hp:544,ac:45,fort:44,ref:39,will:43,initiative:22,perception:26,speed:"8",senses:["Blindsight 5"],resist:["30 to the triggering damage type until the end of the encounter or until it uses variable resistance again. Skills Bluff +28, History +24, Insight +26, Intimidate +28"],immune:["fear"],powers:[{name:"Demonic Weight",action:"Aura",description:"Aura 2 Any enemy that starts its turn within the aura is slowed and cannot teleport until the start of its next turn. All-Around Vision Enemies can't gain combat advantage by flanking the molydeus"},{name:"Double Actions",action:"Trait",description:"The molydeus rolls initiative twice and takes its turn on both results"},{name:"It",action:"Trait",description:"regains the use of its immediate action at the start of each turn"},{name:"Dual Brain At",action:"Trait",description:"the end of each of its turns, the molydeus automatically saves against dazing or stunning effects that a save can end, and against any charm effect that a save can end"},{name:"Battleaxe",action:"Standard",keywords:["weapon"],description:"Attack: Melee 2 (one creature); +34 vs. AC Hit: 4d10 + 15 damage, and the target is marked until the end of its next turn."},{name:"Wolf Bite",action:"Standard",description:"Attack: Melee 2 (one creature); +34 vs. AC Hit: 4d8 + 19 damage, and the molydeus slides the target 6 squares to a square adjacent to the molydeus."},{name:"Snake Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 3 (one creature); +34 vs. AC Hit: 1d6 + 10 damage, and the target grants combat advantage and takes ongoing 20 poison damage (save ends both)."},{name:"Dread Word",action:"Standard",keywords:["fear"],recharge:"Encounter",description:"Attack: Close burst 5 (enemies in the burst); +32 vs. Will Hit: The target is dazed (save ends). Miss: The target is slowed and takes a -2 penalty to attack rolls (save ends both)."},{name:"Variable Resistance",action:"Triggered",recharge:"3/Encounter",description:"Trigger: The molydeus takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): The molydeus gains resist 30 to the triggering damage type until the end of the encounter or until it uses variable resistance again. Skills Bluff +28, History +24, Insight +26, Intimidate +28"}],alignment:"Unaligned",languages:["Abyssal Equipment : battleaxe . Monster Manual 3","page(s) 43","Dungeon Magazine 212."] },
  { id:"mm3-serpent-of-nihal",name:"Serpent of Nihal",source:"mm3",level:29,role:"Lurker",roleModifier:"Minion",xp:3750,size:"Medium",origin:"Aberrant",type:"Beast",hp:1,ac:43,fort:40,ref:43,will:40,initiative:28,perception:22,speed:"7",senses:["Darkvision"],resist:["20 all damage"],powers:[{name:"Mindbite",action:"Standard",keywords:["psychic"],description:"Attack: Melee 1 (one creature); +32 vs. Will Hit: 15 psychic damage, and if the target has two or more of the serpent's allies adjacent to it, the target takes 8 extra damage and cannot spend action points or power points (save ends)."},{name:"Depart Reality",action:"Triggered",description:"Trigger: An enemy misses the serpent. Effect (Immediate Reaction): The serpent is removed from play until the start of its next turn. The serpent then appears in an unoccupied square within 20 squares of its original location and adjacent to an enemy."},{name:"Sudden Reality Warp",action:"Triggered",recharge:"Encounter",description:"Trigger: The serpent rolls initiative. Effect (Free Action): The serpent is removed from play. At the start of the serpent's first turn, it appears in an unoccupied square within 20 squares of its original location and adjacent to an enemy."}],alignment:"Unaligned",languages:["- Monster Manual 3","page(s) 186."] },
  { id:"mm3-sire-of-corruption",name:"Sire of Corruption",source:"mm3",level:29,role:"Controller",roleModifier:"Elite",xp:0,size:"Medium",origin:"Immortal",type:"Humanoid",keywords:["devil"],hp:530,ac:44,fort:40,ref:42,will:43,initiative:21,perception:22,speed:"6",resist:["15 fire"],powers:[{name:"Lasting Corruption",action:"Aura",description:"Aura 5 Enemies within the aura take a -2 penalty to saving throws against charm effects."},{name:"Corrupting Touch",action:"Standard",keywords:["psychic"],description:"Attack: Melee 1 (one or two creatures); +32 vs. Will Hit: 4d6 + 10 psychic damage, and the target takes a -2 penalty to defenses against charm effects until the end of the sire of corruption's next turn."},{name:"Touch of Vice",action:"Standard",keywords:["charm","psychic"],recharge:"Recharge 3-6",description:"Attack: Melee 1 (one or two creatures); +32 vs. Will Hit: 4d6 + 10 psychic damage, and choose one of the following: * Lust: The target is marked by one enemy within 5 squares of it (save ends). * Excess: The target is dazed (save ends). * Greed: The sire of corruption slides the target 5 squares to a square adjacent to one of the target's allies. The target must make an opportunity attack against any ally that takes an action that would provoke opportunity attacks from enemies (save ends). * Fear: The sire of corruption pushes the target 5 squares. The target cannot willingly move nearer to the sire than the square where the target started its turn (save ends). * Sloth: The target is immobilized (save ends). * Vengeance: The target takes 2d10 + 10 damage whenever it uses an attack power (save ends). Call to Corruption ✦ Recharge when first bloodied Effect: Six corrupted followers appear in unoccupied squares within 5 squares of the sire of corruption. The corrupted followers act immediately after the sire of corruption in the initiative order."},{name:"Spread Depravity",action:"Minor",description:"1/round Effect: One corrupted follower within 10 squares of the sire of corruption can make a basic attack as a free action."},{name:"Lasting Vice",action:"Triggered",keywords:["charm","psychic"],description:"Trigger: The sire of corruption drops to 0 hit points.. Close burst 5 (enemies in the burst); +32 vs. Will Hit: 4d6 + 10 psychic damage, and the target is subject to one of touch of vice's effects chosen by the sire of corruption."}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 53."] },
  { id:"mm3-allabar-opener-of-the-way",name:"Allabar, Opener of the Way",source:"mm3",level:30,role:"Soldier",roleModifier:"Solo",xp:95000,size:"Gargantuan",origin:"Aberrant",type:"Animate",hp:1100,ac:45,fort:43,ref:41,will:43,initiative:25,perception:25,speed:"6, fly 6 (hover)",senses:["Darkvision"],powers:[{name:"Gravity Well",action:"Aura",description:"Aura 20 Any enemy that starts its turn within the aura is pulled a number of squares depending on Allabar's current hit points: 776 to 1,100, 1 square; 551 to 775, 2 squares; 226 to 550, 4 squares; 1 to 225, 8 squares. All-Around Vision Enemies can't gain combat advantage by flanking Allabar"},{name:"Bloodied Fury Whenever Allabar",action:"Trait",description:"is bloodied, it gains an extra standard action during each turn, even if it is dazed"},{name:"Tentacle",action:"Standard",description:"Attack: Melee 4 (one creature); +35 vs. AC Hit: 3d8 + 15 damage, and the target is restrained until the end of Allabar's next turn."},{name:"Triple Attack",action:"Standard",description:"Effect: Allabar uses tentacle three times, making each attack against a different target."},{name:"Devour Body",action:"Standard",description:"Attack: Close burst 1 (enemies in the burst at 0 hit points or fewer); +33 vs. Fortitude Hit: Allabar pulls the target into its space, the target dies, and psionic boost recharges."},{name:"Wrath of the Forsaken World",action:"Standard",keywords:["psychic"],recharge:"Recharge 4-6",description:"Attack: Close blast 5 (enemies in the blast); +33 vs. Fortitude Hit: 4d10 + 25 psychic damage, and the target sprouts a hostile tentacle (save ends). While the target is affected by the hostile tentacle, any ally of the target that ends its turn within 2 squares of the target takes 20 damage."},{name:"Unravel Essence",action:"Minor",recharge:"Recharge when no enemy is affected by this power",description:"Attack: Melee 4 (one creature); +33 vs. Fortitude Hit: Ongoing 20 damage (save ends). First Failed Saving Throw: The ongoing damage increases to 25. Second Failed Saving Throw: The target is also weakened and insubstantial (save ends all). Third Failed Saving Throw: The target drops to 0 hit points unless it is already below 0 hit points."},{name:"Psionic Boost",action:"Triggered",keywords:["psychic"],recharge:"Recharge when Allabar takes psychic damage",description:"Trigger: Allabar hits with tentacle. Effect (Free Action): The attack deals 4d10 extra psychic damage."},{name:"Psychic Feedback",action:"Triggered",description:"Trigger: An enemy damages Allabar. Effect (Immediate Reaction): The triggering enemy is dazed (save ends). Skills Arcana +29, Dungeoneering +30, History +29, Religion +29"}],alignment:"Unaligned",languages:["Deep Speech","telepathy 50 Monster Manual 3","page(s) 187."] },
  { id:"mm3-light-of-amoth",name:"Light of Amoth",source:"mm3",level:30,role:"Brute",xp:19000,size:"Large",origin:"Immortal",type:"Animate",keywords:["construct"],hp:341,ac:40,fort:44,ref:41,will:42,initiative:22,perception:23,speed:"6",powers:[{name:"Wave",action:"Trait",description:"of Retribution Whenever the light of Amoth takes damage, any enemy within 2 squares of that creature takes 5 damage"},{name:"Fist of Wrath",action:"Standard",description:"Attack: Melee 2 (one creature); +35 vs. AC Hit: 4d10+20 damage"},{name:"Fury of the Dead",action:"Standard",recharge:"Recharge 5-6",description:"Effect: The light of Amoth uses fist of wrath against each enemy within 2 squares of it."},{name:"Legacy of Kalandurren",action:"Minor",keywords:["cold"],recharge:"Encounter",description:"Attack: Close burst 2 (enemies in the burst); +32 vs. Fortitude Hit: 4d10+20 cold damage, and the target is immobilized (save ends)."},{name:"Unfettered Apocalypse",action:"Triggered",recharge:"Encounter",description:"Trigger: An enemy scores a critical hit against the light of Amoth or the light of Amoth is first bloodied. Effect (No Action): The light of Amoth creates a duplicate of itself, which appears in the nearest unoccupied squares. The duplicate has the same hit points as the light of Amoth, is considered to have expended the same powers as the light of Amoth, and acts during the light of Amoth's turn. Any effects on the light of Amoth do not transfer to the duplicate. At the end of the light of Amoth's next turn, the duplicate disappears."}],alignment:"Unaligned",languages:["Supernal Monster Manual 3","page(s) 15."] },
  { id:"mm3-imix",name:"Imix",source:"mm3",level:32,role:"Controller",roleModifier:"Solo",xp:135000,size:"Huge",origin:"Elemental",type:"Humanoid",keywords:["fire","primordial"],hp:1140,ac:47,fort:42,ref:45,will:44,initiative:27,perception:29,speed:"10, fly 8 (hover)",senses:["Darkvision"],immune:["disease, fire"],powers:[{name:"Withering Flames",action:"Aura",description:"Aura 5 Enemies within the aura do not benefit from fire resistance."},{name:"Blazing Blade",action:"Standard",keywords:["fire","weapon"],description:"Attack: Melee 3 (one creature); +37 vs. AC Hit: 2d10 + 9 fire damage, and ongoing 20 fire damage (save ends)."},{name:"Blazing Arc",action:"Standard",description:"Effect: Imix uses blazing blade against each enemy within reach."},{name:"Volcanic Circle",action:"Standard",keywords:["fire","zone"],description:"Effect: Imix reduces a fire grue within 10 squares of him to 0 hit points and makes the following attack centered on the grue. Attack: Close burst 1 (creatures in the burst); +35 vs. Reflex Hit: 6d6 + 19 fire damage. Effect: The burst creates a zone that lasts until the end of the encounter. Any enemy that enters the zone or ends its turn there takes 20 fire damage. Servants of Elemental Fire (fire) (fire) ✦ Recharge when no fire grue is within 10 squares of Imix at the start of his turn Effect: Imix creates four fire grues, or six while Imix is bloodied, each in an unoccupied square within 10 squares of him. The grues cannot take actions. Any creature that starts its turn adjacent to one or more grues takes 15 fire damage. The grues have defenses equal to Imix's and 1 hit point each. A missed attack never damages a grue. Each grue lasts until the end of the encounter or until Imix ends his turn more than 10 squares from it. As a minor action, Imix can move each grue up to 6 squares."},{name:"Blinding Flare",action:"Minor",keywords:["fire"],recharge:"Recharge when first bloodied",description:"Attack: Close burst 10 (enemies adjacent to fire grues); +35 vs. Fortitude Hit: 3d6 + 10 fire damage, and the target is blinded (save ends). Miss: Half damage, and the target takes a -2 penalty to attack rolls until the end of Imix's next turn."},{name:"Hungry Flames",action:"Minor",keywords:["fire"],recharge:"Encounter",description:"Attack: Close burst 10 (enemies taking ongoing fire damage); +35 vs. Fortitude Hit: The target is weakened (save ends). Each creature adjacent to at least one target takes 10 fire damage."},{name:"Demand Focus",action:"Triggered",description:"Trigger: An enemy willingly moves away from a fire grue without shifting. Attack (Opportunity Action): Close burst 10 (the triggering enemy in the burst); +35 vs. Will Hit: The target is dazed until the end of its next turn. Formed of Fire (fire) ✦ At-Will Trigger: An enemy misses Imix with a melee attack. Effect (Immediate Reaction): The triggering enemy and each of its adjacent allies take 10 fire damage. Eternal Resilience ✦ At-Will Trigger: Imix is affected by an effect that a save can end. Effect (No Action): Imix makes a saving throw against the effect. Skills Arcana +31, Bluff +30, Intimidate +30, Religion +31"}],alignment:"Unaligned",languages:["Primordial Equipment : greatsword . Monster Manual 3","page(s) 113."] },
  { id:"mm3-ogr-moch",name:"Ogrémoch",source:"mm3",level:34,role:"Soldier",roleModifier:"Solo",xp:195000,size:"Gargantuan",origin:"Elemental",type:"Humanoid",keywords:["earth","primordial"],hp:1244,ac:50,fort:48,ref:45,will:47,initiative:24,perception:26,speed:"8 (earth walk), burrow 8, climb 8",senses:["Darkvision"],resist:["20 to the triggering damage type until the end of the encounter or until it uses variable resistance again."],immune:["disease, poison, sleep"],powers:[{name:"Jagged Earth",action:"Aura",description:"Aura 5 Squares within the aura are difficult terrain"},{name:"The",action:"Trait",description:"first time any creature enters a square within the aura during its turn, it must succeed on a DC 32 Athletics or Acrobatics check or take 20 damage"},{name:"Creatures",action:"Trait",description:"that have earth walk ignore the aura's effects"},{name:"Earthbound",action:"Trait",description:"While standing on a solid surface, Ogrémoch can ignore forced movement and cannot be knocked prone. Earth Glide Ogrémoch can pass through earth and rock as if it were phasing"},{name:"Slam",action:"Standard",description:"Attack: Melee 4 (one creature); +39 vs. AC Hit: 4d8 + 24 damage, and each enemy adjacent to the target is dazed until the end of Ogrémoch's next turn."},{name:"Ogrémoch's Fury",action:"Standard",description:"Effect: Ogrémoch uses slam twice, or three times while he is bloodied. If Ogrémoch hits the same target more than once, he pushes the target 10 squares and the target is treated as having failed a saving throw against encasing shards if he or she is currently affected by it."},{name:"Earth Smash",action:"Standard",description:"Attack: Close blast 5 (creatures in the blast); +37 vs. Reflex Hit: 2d8 + 12 damage, and the target falls prone and is dazed (save ends). Miss: Half damage."},{name:"Tremendous Quake",action:"Standard",recharge:"Recharge when first bloodied",description:"Attack: Close burst 10 (creatures in the burst); +37 vs. Fortitude Hit: 5d8 + 12 damage, and Ogrémoch slides the target 4 squares and knocks it prone. In addition, the target cannot stand up and is dazed (save ends both). Miss: Half damage, and Ogrémoch slides the target 1 square and knocks it prone."},{name:"Earthshatter",action:"Minor",description:"1/round Requirement: Ogrémoch must be bloodied. Target: A petrified creature within 10 squares of Ogrémoch Effect: The creature is no longer petrified, and Ogrémoch makes the following attack centered on the creature and including the creature. Attack: Close burst 3 (creatures in the burst); +37 vs. Fortitude Hit: 3d8 + 12 damage."},{name:"Encasing Shards",action:"Minor",recharge:"Recharge 4-6",description:"Attack: Close blast 5 (creatures in the blast); +37 vs. Fortitude Hit: The target is immobilized (save ends). First Failed Saving Throw: The target is stunned (save ends). Second Failed Saving Throw: The target is petrified (save ends; the target takes a -5 penalty to the saving throw)."},{name:"Jagged Eruption",action:"Triggered",description:"Trigger: An enemy hits Ogrémoch with a melee attack. Attack (Immediate Reaction): Close burst 3 (enemies in the burst); +37 vs. Reflex Hit: 2d8 + 12 damage, and the target is immobilized (save ends). Aftereffect: The target takes 10 damage. Eternal Resilience ✦ At-Will Trigger: Ogrémoch is subjected to an effect that a save can end. Effect (No Action): Ogrémoch makes a saving throw against the effect. Variable Resistance ✦ 3/Encounter Trigger: Ogrémoch takes acid, cold, fire, lightning, or thunder damage. Effect (Free Action): Ogrémoch gains resist 20 to the triggering damage type until the end of the encounter or until it uses variable resistance again."}],alignment:"Unaligned",languages:["Primordial Monster Manual 3","page(s) 160."] },
  { id:"mm3-lolth",name:"Lolth",source:"mm3",level:35,role:"Lurker",roleModifier:"Solo",xp:235000,size:"Medium",origin:"Natural",type:"Humanoid",hp:634,ac:51,fort:46,ref:49,will:49,initiative:33,perception:31,speed:"8, climb 8 (spider climb), teleport 8",senses:["Blindsight 20"],immune:["poison"],vulnerable:["20 to all damage (save ends both). Aftereffect: Lolth pushes the target its"],powers:[{name:"Lolth's Retribution",action:"Trait",keywords:["poison"],description:"Whenever an enemy taking ongoing poison damage attacks Lolth, that enemy cannot save against ongoing poison damage until its next turn"},{name:"Scourge",action:"Standard",keywords:["poison","weapon"],description:"Attack: Melee 3 (one creature); +40 vs. AC Hit: 4d4 + 13 damage, and Lolth slides the target 3 squares. Effect: The target takes ongoing 20 poison damage (save ends). Insidious Poison (charm, poison) ✦ Recharge ⚃ ⚄ ⚅ Effect: Choose one enemy within 10 squares of Lolth that is taking ongoing poison damage. That enemy makes a basic attack against a creature of Lolth's choice, and the attack deals 3d10 + 9 extra poison damage."},{name:"Lolth's Kiss",action:"Minor",keywords:["poison"],description:"1/round Attack: Melee 1 (one creature); +38 vs. Reflex Hit: 2d10 + 12 damage, and the target takes ongoing 20 poison damage (save ends). Aftereffect: The target is dazed (save ends)."},{name:"Poison Strands",action:"Minor",keywords:["poison"],description:"1/round Attack: Ranged 10 (one creature); +38 vs. Reflex Hit: The target is immobilized (save ends). First Failed Saving Throw: The target is restrained instead of immobilized (save ends). Second Failed Saving Throw: The target is instead restrained and takes ongoing 50 poison damage (save ends both)."},{name:"Impenetrable Darkfire",action:"Minor",keywords:["fire","zone"],recharge:"Encounter",description:"Attack: Close burst 5 (creatures in the burst); +36 vs. Will Hit: The target is blinded, takes ongoing 20 fire damage and cannot benefit from invisibility or concealment (save ends all). Effect: The burst creates a zone that lasts until the end of Lolth's next turn. The zone blocks line of sight for all creatures but Lolth. Any creature other than Lolth is blinded while within the zone."},{name:"Dominating Rebuke",action:"Triggered",keywords:["charm"],description:"Trigger: An enemy hits Lolth. Effect (Immediate Reaction): The triggering enemy is dominated until the end of the enemy's next turn."},{name:"Immortal Resilience",action:"Triggered",description:"Trigger: Lolth is subjected to an effect that a save can end. Effect (No Action): Lolth makes a saving throw against the effect. Form of the Spider Queen (fear, polymorph) ✦ Encounter Trigger: Lolth drops to 0 hit points. Attack (No Action): Close burst 10 (enemies in the burst); +36 vs. Will Hit: The target is stunned and gains vulnerable 20 to all damage (save ends both). Aftereffect: Lolth pushes the target its speed, and the target is dazed until the end of its next turn. Effect: Lolth assumes the form of the Spider Queen until the end of the encounter. While in the form of the Spider Queen, she gains new powers and cannot use powers from her former form. Skills Arcana +31, Bluff +34, Diplomacy +34, Insight +31, Intimidate +34, Religion +31, Stealth +34"}],alignment:"Chaotic Evil",languages:["Supernal","telepathy 20 Equipment : scourge . Monster Manual 3","page(s) 126."] },
  { id:"mm3-lolth-the-spider-queen",name:"Lolth the Spider Queen",source:"mm3",level:35,role:"Brute",roleModifier:"Solo",xp:0,size:"Huge",origin:"Immortal",type:"Magical beast",keywords:["shapechanger","spider"],hp:634,ac:49,fort:46,ref:49,will:49,initiative:29,perception:31,speed:"8, climb 8 (spider climb), teleport 8",senses:["Blindsight 20"],immune:["poison"],powers:[{name:"Bite",action:"Standard",keywords:["poison"],description:"Attack: Melee 3 (one creature); +40 vs. AC Hit: 4d10 + 12 damage. Effect: The target takes ongoing 20 poison damage (save ends)."},{name:"Insidious Poison",action:"Standard",keywords:["charm","poison"],recharge:"Recharge 5-6",description:"Effect: Choose one enemy within 10 squares of Lolth that is taking ongoing poison damage. That enemy makes a basic attack against a creature of Lolth's choice, and the attack deals 4d10 + 18 extra poison damage."},{name:"Burning Webs",action:"Minor",keywords:["acid"],description:"1/round Attack: Close blast 5 (enemies in the blast); +38 vs. Reflex Hit: 2d8 + 12 acid damage, and the target is immobilized (save ends). First Failed Saving Throw: The target is instead immobilized and takes ongoing 30 acid damage (save ends both)."},{name:"Impaling Legs",action:"Triggered",keywords:["poison"],description:"Trigger: An enemy enters a square within 3 squares of Lolth. Attack (Immediate Interrupt): Melee 3 (one creature); +40 vs. AC Hit: 4d8 + 12 damage, and the target is restrained and takes ongoing 20 poison damage (save ends). Immortal Resilience ✦ At-Will Trigger: Lolth is subjected to an effect that a save can end. Effect (No Action): Lolth makes a saving throw against the effect. Divine Discorporation ✦ Encounter Trigger: Lolth drops to 317 hit points or fewer. Effect (No Action): Lolth discorporates. Skills Arcana +31, Bluff +34, Diplomacy +34, Insight +31, Intimidate +34, Religion +31, Stealth +34"}],alignment:"Unaligned",languages:["Supernal","telepathy 20 Monster Manual 3","page(s) 127."] }
